UPDATE hadiths SET urdu = 'ہم سے حدیث بیان کی مسدد نے، ان کو یحییٰ نے، انہوں نے شعبہ سے نقل کیا، انہوں نے قتادہ سے، انہوں نے انس رضی اللہ عنہ خادم رسول اللہ صلی اللہ علیہ وسلم سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا۔ اور شعبہ نے حسین معلم سے بھی روایت کیا، انہوں نے قتادہ سے، انہوں نے انس رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے نقل فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تم میں سے کوئی شخص ایماندار نہ ہو گا جب تک اپنے بھائی کے لیے وہ نہ چاہے جو اپنے نفس کے لیے چاہتا ہے۔' WHERE id = 14;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبیداللہ نے یہ حدیث بیان کی، ان سے ابراہیم بن سعد نے، وہ صالح سے روایت کرتے ہیں، وہ ابن شہاب سے، وہ ابوامامہ بن سہل بن حنیف سے راوی ہیں، وہ ابو سعید خدری رضی اللہ عنہ سے، وہ کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں ایک وقت سو رہا تھا، میں نے خواب میں دیکھا کہ لوگ میرے سامنے پیش کیے جا رہے ہیں اور وہ کرتے پہنے ہوئے ہیں۔ کسی کا کرتہ سینے تک ہے اور کسی کا اس سے نیچا ہے۔ ( پھر ) میرے سامنے عمر بن الخطاب لائے گئے۔ ان ( کے بدن ) پر ( جو ) کرتا تھا۔ اسے وہ گھسیٹ رہے تھے۔ ( یعنی ان کا کرتہ زمین تک نیچا تھا ) صحابہ نے پوچھا کہ یا رسول اللہ! اس کی کیا تعبیر ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ( اس سے ) دین مراد ہے۔' WHERE id = 24;
UPDATE hadiths SET urdu = 'ہم سے سلیمان ابوالربیع نے بیان کیا، ان سے اسماعیل بن جعفر نے، ان سے نافع بن ابی عامر ابوسہیل نے، وہ اپنے باپ سے، وہ ابوہریرہ رضی اللہ عنہ سے روایت کرتے ہیں، وہ رسول اللہ صلی اللہ علیہ وسلم سے نقل کرتے ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا، منافق کی علامتیں تین ہیں۔ جب بات کرے جھوٹ بولے، جب وعدہ کرے اس کے خلاف کرے اور جب اس کو امین بنایا جائے تو خیانت کرے۔' WHERE id = 34;
UPDATE hadiths SET urdu = 'ہم سے محمد بن المثنی نے بیان کیا، ان سے یحییٰ نے ہشام کے واسطے سے نقل کیا، وہ کہتے ہیں مجھے میرے باپ (عروہ) نے عائشہ رضی اللہ عنہا سے روایت نقل کی کہ رسول اللہ صلی اللہ علیہ وسلم ( ایک دن ) ان کے پاس آئے، اس وقت ایک عورت میرے پاس بیٹھی تھی، آپ نے دریافت کیا یہ کون ہے؟ میں نے عرض کیا، فلاں عورت اور اس کی نماز ( کے اشتیاق اور پابندی ) کا ذکر کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا ٹھہر جاؤ ( سن لو کہ ) تم پر اتنا ہی عمل واجب ہے جتنے عمل کی تمہارے اندر طاقت ہے۔ اللہ کی قسم! ( ثواب دینے سے ) اللہ نہیں اکتاتا، مگر تم ( عمل کرتے کرتے ) اکتا جاؤ گے، اور اللہ کو دین ( کا ) وہی عمل زیادہ پسند ہے جس کی ہمیشہ پابندی کی جا سکے۔ ( اور انسان بغیر اکتائے اسے انجام دے ) ۔' WHERE id = 44;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہوں نے ابوجمرہ سے نقل کیا کہ میں عبداللہ بن عباس رضی اللہ عنہما کے پاس بیٹھا کرتا تھا وہ مجھ کو خاص اپنے تخت پر بٹھاتے ( ایک دفعہ ) کہنے لگے کہ تم میرے پاس مستقل طور پر رہ جاؤ میں اپنے مال میں سے تمہارا حصہ مقرر کر دوں گا۔ تو میں دو ماہ تک ان کی خدمت میں رہ گیا۔ پھر کہنے لگے کہ عبدالقیس کا وفد جب نبی کریم صلی اللہ علیہ وسلم کے پاس آیا تو آپ نے پوچھا کہ یہ کون سی قوم کے لوگ ہیں یا یہ وفد کہاں کا ہے؟ انہوں نے کہا کہ ربیعہ خاندان کے لوگ ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا مرحبا اس قوم کو یا اس وفد کو نہ ذلیل ہونے والے نہ شرمندہ ہونے والے ( یعنی ان کا آنا بہت خوب ہے ) وہ کہنے لگے اے اللہ کے رسول! ہم آپ کی خدمت میں صرف ان حرمت والے مہینوں میں آ سکتے ہیں کیونکہ ہمارے اور آپ کے درمیان مضر کے کافروں کا قبیلہ آباد ہے۔ پس آپ ہم کو ایک ایسی قطعی بات بتلا دیجئیے جس کی خبر ہم اپنے پچھلے لوگوں کو بھی کر دیں جو یہاں نہیں آئے اور اس پر عمل درآمد کر کے ہم جنت میں داخل ہو جائیں اور انہوں نے آپ سے اپنے برتنوں کے بارے میں بھی پوچھا۔ آپ صلی اللہ علیہ وسلم نے ان کو چار باتوں کا حکم دیا اور چار قسم کے برتنوں کو استعمال میں لانے سے منع فرمایا۔ ان کو حکم دیا کہ ایک اکیلے اللہ پر ایمان لاؤ۔ پھر آپ صلی اللہ علیہ وسلم نے پوچھا کہ جانتے ہو ایک اکیلے اللہ پر ایمان لانے کا مطلب کیا ہے؟ انہوں نے کہا کہ اللہ اور اس کے رسول ہی کو معلوم ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس بات کی گواہی دینا کہ اللہ کے سوا کوئی مبعود نہیں اور یہ کہ محمد صلی اللہ علیہ وسلم اس کے سچے رسول ہیں اور نماز قائم کرنا اور زکوٰۃ ادا کرنا اور رمضان کے روزے رکھنا اور مال غنیمت سے جو ملے اس کا پانچواں حصہ ( مسلمانوں کے بیت المال میں ) داخل کرنا اور چار برتنوں کے استعمال سے آپ صلی اللہ علیہ وسلم نے ان کو منع فرمایا۔ سبز لاکھی مرتبان سے اور کدو کے بنائے ہوئے برتن سے، لکڑی کے کھودے ہوئے برتن سے، اور روغنی برتن سے اور فرمایا کہ ان باتوں کو حفظ کر لو اور ان لوگوں کو بھی بتلا دینا جو تم سے پیچھے ہیں اور یہاں نہیں آئے ہیں۔' WHERE id = 54;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث نے بیان کیا، انہوں نے سعید مقبری سے، انہوں نے شریک بن عبداللہ بن ابی نمر سے، انہوں نے انس بن مالک سے سنا کہ ایک بار ہم مسجد میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ بیٹھے ہوئے تھے، اتنے میں ایک شخص اونٹ پر سوار ہو کر آیا اور اونٹ کو مسجد میں بٹھا کر باندھ دیا۔ پھر پوچھنے لگا ( بھائیو ) تم لوگوں میں محمد ( صلی اللہ علیہ وسلم ) کون سے ہیں۔ نبی کریم صلی اللہ علیہ وسلم اس وقت لوگوں میں تکیہ لگائے بیٹھے ہوئے تھے۔ ہم نے کہا ( ) محمد ( صلی اللہ علیہ وسلم ) یہ سفید رنگ والے بزرگ ہیں جو تکیہ لگائے ہوئے تشریف فرما ہیں۔ تب وہ آپ سے مخاطب ہوا کہ اے عبدالمطلب کے فرزند! آپ صلی اللہ علیہ وسلم نے فرمایا۔ کہو میں آپ کی بات سن رہا ہوں۔ وہ بولا میں آپ صلی اللہ علیہ وسلم سے کچھ دینی باتیں دریافت کرنا چاہتا ہوں اور ذرا سختی سے بھی پوچھوں گا تو آپ اپنے دل میں برا نہ مانئے گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں جو تمہارا دل چاہے پوچھو۔ تب اس نے کہا کہ میں آپ کو آپ کے رب اور اگلے لوگوں کے رب تبارک وتعالیٰ کی قسم دے کر پوچھتا ہوں کیا آپ کو اللہ نے دنیا کے سب لوگوں کی طرف رسول بنا کر بھیجا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا ہاں یا میرے اللہ! پھر اس نے کہا میں آپ صلی اللہ علیہ وسلم کو اللہ کی قسم دیتا ہوں کیا اللہ نے آپ صلی اللہ علیہ وسلم کو رات دن میں پانچ نمازیں پڑھنے کا حکم فرمایا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا ہاں یا میرے اللہ! پھر کہنے لگا میں آپ کو اللہ کی قسم دے کر پوچھتا ہوں کہ کیا اللہ نے آپ کو یہ حکم دیا ہے کہ سال بھر میں اس مہینہ رمضان کے روزے رکھو۔ آپ صلی اللہ علیہ وسلم نے فرمایا ہاں یا میرے اللہ! پھر کہنے لگا میں آپ صلی اللہ علیہ وسلم کو اللہ کی قسم دے کر پوچھتا ہوں کہ کیا اللہ نے آپ کو یہ حکم دیا ہے کہ آپ ہم میں سے جو مالدار لوگ ہیں ان سے زکوٰۃ وصول کر کے ہمارے محتاجوں میں بانٹ دیا کریں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہاں یا میرے اللہ! تب وہ شخص کہنے لگا جو حکم آپ صلی اللہ علیہ وسلم اللہ کے پاس سے لائے ہیں، میں ان پر ایمان لایا اور میں اپنی قوم کے لوگوں کا جو یہاں نہیں آئے ہیں بھیجا ہوا ( تحقیق حال کے لیے ) آیا ہوں۔ میرا نام ضمام بن ثعلبہ ہے، میں بنی سعد بن بکر کے خاندان سے ہوں۔ اس حدیث کو ( لیث کی طرح ) موسیٰ اور علی بن عبدالحمید نے سلیمان سے روایت کیا، انہوں نے ثابت سے، انہوں نے انس سے، انہوں نے یہی مضمون نبی کریم صلی اللہ علیہ وسلم سے نقل کیا ہے۔' WHERE id = 64;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، ان سے سفیان نے، ان سے اسماعیل بن ابی خالد نے دوسرے لفظوں میں بیان کیا، ان لفظوں کے علاوہ جو زہری نے ہم سے بیان کئے، وہ کہتے ہیں میں نے قیس بن ابی حازم سے سنا، انہوں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا، وہ کہتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم کا ارشاد ہے کہ حسد صرف دو باتوں میں جائز ہے۔ ایک تو اس شخص کے بارے میں جسے اللہ نے دولت دی ہو اور وہ اس دولت کو راہ حق میں خرچ کرنے پر بھی قدرت رکھتا ہو اور ایک اس شخص کے بارے میں جسے اللہ نے حکمت ( کی دولت ) سے نوازا ہو اور وہ اس کے ذریعہ سے فیصلہ کرتا ہو اور ( لوگوں کو ) اس حکمت کی تعلیم دیتا ہو۔' WHERE id = 74;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، ان سے مالک نے ابن شہاب کے واسطے سے بیان کیا، وہ عیسیٰ بن طلحہ بن عبیداللہ سے روایت کرتے ہیں، وہ عبداللہ بن عمرو بن العاص سے نقل کرتے ہیں کہ حجۃ الوداع میں رسول اللہ صلی اللہ علیہ وسلم لوگوں کے مسائل دریافت کرنے کی وجہ سے منیٰ میں ٹھہر گئے۔ تو ایک شخص آیا اور اس نے کہا کہ میں نے بےخبری میں ذبح کرنے سے پہلے سر منڈا لیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا ( اب ) ذبح کر لے اور کچھ حرج نہیں۔ پھر دوسرا آدمی آیا، اس نے کہا کہ میں نے بےخبری میں رمی کرنے سے پہلے قربانی کر لی۔ آپ صلی اللہ علیہ وسلم نے فرمایا ( اب ) رمی کر لے۔ ( اور پہلے کر دینے سے ) کچھ حرج نہیں۔ ابن عمرو کہتے ہیں ( اس دن ) آپ صلی اللہ علیہ وسلم سے جس چیز کا بھی سوال ہوا، جو کسی نے آگے اور پیچھے کر لی تھی۔ تو آپ صلی اللہ علیہ وسلم نے یہی فرمایا کہ اب کر لے اور کچھ حرج نہیں۔' WHERE id = 84;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہیں شعیب نے زہری سے خبر دی، انہیں انس بن مالک نے بتلایا کہ ( ایک دن ) رسول اللہ صلی اللہ علیہ وسلم گھر سے نکلے تو عبداللہ بن حذافہ کھڑے ہو کر پوچھنے لگے کہ یا رسول اللہ! میرا باپ کون ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا: حذافہ، پھر آپ صلی اللہ علیہ وسلم نے باربار فرمایا کہ مجھ سے پوچھو، تو عمر رضی اللہ عنہ نے دو زانو ہو کر عرض کیا کہ ہم اللہ کے رب ہونے پر، اسلام کے دین ہونے، اور محمد صلی اللہ علیہ وسلم کے نبی ہونے پر راضی ہیں ( اور یہ جملہ ) تین مرتبہ ( دہرایا ) پھر ( یہ سن کر ) رسول اللہ صلی اللہ علیہ وسلم خاموش ہو گئے۔' WHERE id = 94;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، انہیں نافع بن عمر نے خبر دی، انہیں ابن ابی ملیکہ نے بتلایا کہ رسول اللہ صلی اللہ علیہ وسلم کی بیوی عائشہ رضی اللہ عنہا جب کوئی ایسی باتیں سنتیں جس کو سمجھ نہ پاتیں تو دوبارہ اس کو معلوم کرتیں تاکہ سمجھ لیں۔ چنانچہ ( ایک مرتبہ ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس سے حساب لیا گیا اسے عذاب کیا جائے گا۔ عائشہ رضی اللہ عنہا فرماتی ہیں کہ ( یہ سن کر ) میں نے کہا کہ کیا اللہ نے یہ نہیں فرمایا کہ عنقریب اس سے آسان حساب لیا جائے گا؟ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ یہ صرف ( اللہ کے دربار میں ) پیشی کا ذکر ہے۔ لیکن جس کے حساب میں جانچ پڑتال کی گئی ( سمجھو ) وہ غارت ہو گیا۔' WHERE id = 104;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، ان سے سفیان نے، ان سے عمرو نے، وہ کہتے ہیں کہ مجھے وہب بن منبہ نے اپنے بھائی کے واسطے سے خبر دی، وہ کہتے ہیں کہ میں نے ابوہریرہ رضی اللہ عنہ کو کہتے ہوئے سنا کہ رسول اللہ صلی اللہ علیہ وسلم کے صحابہ میں عبداللہ بن عمرو رضی اللہ عنہما کے علاوہ مجھ سے زیادہ کوئی حدیث بیان کرنے والا نہیں تھا۔ مگر وہ لکھ لیا کرتے تھے اور میں لکھتا نہیں تھا۔ دوسری سند سے معمر نے وہب بن منبہ کی متابعت کی، وہ ہمام سے روایت کرتے ہیں، وہ ابوہریرہ رضی اللہ عنہ سے۔' WHERE id = 114;
UPDATE hadiths SET urdu = 'ہم سے عثمان نے بیان کیا، کہا ہم سے جریر نے منصور کے واسطے سے بیان کیا، وہ ابووائل سے روایت کرتے ہیں، وہ ابوموسیٰ رضی اللہ عنہ سے روایت کرتے ہیں کہ ایک شخص رسول اللہ صلی اللہ علیہ وسلم کی خدمت اقدس میں حاضر ہوا اور اس نے عرض کیا کہ یا رسول اللہ! اللہ کی راہ میں لڑائی کی کیا صورت ہے؟ کیونکہ ہم میں سے کوئی غصہ کی وجہ سے اور کوئی غیرت کی وجہ سے جنگ کرتا ہے تو آپ صلی اللہ علیہ وسلم نے اس کی طرف سر اٹھایا، اور سر اسی لیے اٹھایا کہ پوچھنے والا کھڑا ہوا تھا، پھر آپ صلی اللہ علیہ وسلم نے فرمایا جو اللہ کے کلمے کو سربلند کرنے کے لیے لڑے، وہ اللہ کی راہ میں ( لڑتا ) ہے۔' WHERE id = 124;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم کو لیث بن سعد نے خبر دی، ان سے نافع مولیٰ عبداللہ بن عمر بن الخطاب نے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے روایت کیا کہ ( ایک مرتبہ ) ایک آدمی نے مسجد میں کھڑے ہو کر عرض کیا، یا رسول اللہ! آپ ہمیں کس جگہ سے احرام باندھنے کا حکم دیتے ہیں؟ تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، مدینہ والے ذوالحلیفہ سے احرام باندھیں، اور اہل شام جحفہ سے اور نجد والے قرن المنازل سے۔ ابن عمر رضی اللہ عنہما نے فرمایا، کہ لوگوں کا خیال ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ یمن والے یلملم سے احرام باندھیں۔ اور ابن عمر رضی اللہ عنہما کہا کرتے تھے کہ مجھے یہ ( آخری جملہ ) رسول اللہ صلی اللہ علیہ وسلم سے یاد نہیں۔' WHERE id = 134;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا کہ ہم سے ہاشم ابن القاسم نے، کہا کہ ان سے ورقاء بن یشکری نے عبیداللہ بن ابی یزید سے نقل کیا، وہ ابن عباس رضی اللہ عنہما سے روایت کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم بیت الخلاء میں تشریف لے گئے۔ میں نے ( بیت الخلاء کے قریب ) آپ صلی اللہ علیہ وسلم کے لیے وضو کا پانی رکھ دیا۔ ( باہر نکل کر ) آپ صلی اللہ علیہ وسلم نے پوچھا یہ کس نے رکھا؟ جب آپ صلی اللہ علیہ وسلم کو بتلایا گیا تو آپ نے ( میرے لیے دعا کی اور ) فرمایا «اللهم فقهه في الدين» اے اللہ! اس کو دین کی سمجھ عطا فرمائیو۔' WHERE id = 144;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام دستوائی نے یحییٰ بن ابی کثیر کے واسطے سے بیان کیا، وہ عبداللہ بن ابی قتادہ سے، وہ اپنے باپ ابوقتادہ رضی اللہ عنہ سے روایت کرتے ہیں۔ وہ کہتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، جب تم میں سے کوئی پانی پئے تو برتن میں سانس نہ لے اور جب بیت الخلاء میں جائے تو اپنی شرمگاہ کو داہنے ہاتھ سے نہ چھوئے اور نہ داہنے ہاتھ سے استنجاء کرے۔' WHERE id = 154;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ نے بیان کیا، ان سے ابوعوانہ نے، وہ ابوبشر سے، وہ یوسف بن ماہک سے، وہ عبداللہ بن عمرو رضی اللہ عنہما سے روایت کرتے ہیں، وہ کہتے ہیں کہ ( ایک مرتبہ ) رسول اللہ صلی اللہ علیہ وسلم ایک سفر میں ہم سے پیچھے رہ گئے۔ پھر ( تھوڑی دیر بعد ) آپ صلی اللہ علیہ وسلم نے ہم کو پا لیا اور عصر کا وقت آ پہنچا تھا۔ ہم وضو کرنے لگے اور ( اچھی طرح پاؤں دھونے کی بجائے جلدی میں ) ہم پاؤں پر مسح کرنے لگے۔ آپ صلی اللہ علیہ وسلم نے فرمایا «ويل للأعقاب من النار» ”ایڑیوں کے لیے آگ کا عذاب ہے“ دو مرتبہ یا تین مرتبہ فرمایا۔' WHERE id = 164;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، کہا ہم کو عبدالصمد نے خبر دی، کہا ہم کو عبدالرحمٰن بن عبداللہ بن دینار نے بیان کیا، انہوں نے اپنے باپ سے سنا، وہ ابوصالح سے، وہ ابوہریرہ رضی اللہ عنہ سے، وہ رسول اللہ صلی اللہ علیہ وسلم سے نقل کرتے ہیں آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایک شخص نے ایک کتے کو دیکھا، جو پیاس کی وجہ سے گیلی مٹی کھا رہا تھا۔ تو اس شخص نے اپنا موزہ لیا اور اس سے پانی بھر کر پلانے لگا، حتیٰ کہ اس کو خوب سیراب کر دیا۔ اللہ نے اس شخص کے اس کام کی قدر کی اور اسے جنت میں داخل کر دیا۔' WHERE id = 174;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے امام مالک نے مخرمہ بن سلیمان کے واسطے سے نقل کیا، وہ کریب ابن عباس رضی اللہ عنہما کے آزاد کردہ غلام سے نقل کرتے ہیں کہ عبداللہ بن عباس رضی اللہ عنہما نے انہیں خبر دی کہ انہوں نے ایک رات رسول اللہ صلی اللہ علیہ وسلم کی زوجہ مطہرہ اور اپنی خالہ میمونہ رضی اللہ عنہا کے گھر میں گزاری۔ ( وہ فرماتے ہیں کہ ) میں تکیہ کے عرض ( یعنی گوشہ ) کی طرف لیٹ گیا اور رسول اللہ صلی اللہ علیہ وسلم اور آپ کی اہلیہ نے ( معمول کے مطابق ) تکیہ کی لمبائی پر ( سر رکھ کر ) آرام فرمایا۔ رسول اللہ صلی اللہ علیہ وسلم سوتے رہے اور جب آدھی رات ہو گئی یا اس سے کچھ پہلے یا اس کے کچھ بعد آپ بیدار ہوئے اور اپنے ہاتھوں سے اپنی نیند کو دور کرنے کے لیے آنکھیں ملنے لگے۔ پھر آپ نے سورۃ آل عمران کی آخری دس آیتیں پڑھیں، پھر ایک مشکیزہ کے پاس جو ( چھت میں ) لٹکا ہوا تھا آپ کھڑے ہو گئے اور اس سے وضو کیا، خوب اچھی طرح، پھر کھڑے ہو کر نماز پڑھنے لگے۔ ابن عباس رضی اللہ عنہما کہتے ہیں میں نے بھی کھڑے ہو کر اسی طرح کیا، جس طرح آپ صلی اللہ علیہ وسلم نے وضو کیا تھا۔ پھر جا کر میں بھی آپ کے پہلوئے مبارک میں کھڑا ہو گیا۔ آپ نے اپنا داہنا ہاتھ میرے سر پر رکھا اور میرا دایاں کان پکڑ کر اسے مروڑنے لگے۔ پھر آپ نے دو رکعتیں پڑھیں۔ اس کے بعد پھر دو رکعتیں پڑھیں۔ پھر دو رکعتیں پڑھیں۔ پھر دو رکعتیں، پھر دو رکعتیں، پھر دو رکعتیں پڑھ کر اس کے بعد آپ نے وتر پڑھا اور لیٹ گئے، پھر جب مؤذن آپ صلی اللہ علیہ وسلم کے پاس آیا، تو آپ نے اٹھ کر دو رکعت معمولی ( طور پر ) پڑھیں۔ پھر باہر تشریف لا کر صبح کی نماز پڑھی۔' WHERE id = 184;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو مالک نے نافع سے خبر دی، وہ عبداللہ بن عمر رضی اللہ عنہما سے روایت کرتے ہیں۔ وہ فرماتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں عورت اور مرد سب ایک ساتھ ( ایک ہی برتن سے ) وضو کیا کرتے تھے۔ ( یعنی وہ مرد اور عورتیں جو ایک دوسرے کے محرم ہوتے ) ۔' WHERE id = 194;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد الحرانی نے بیان کیا، کہا ہم سے لیث نے یحییٰ بن سعید کے واسطے سے نقل کیا، وہ سعد بن ابراہیم سے، وہ نافع بن جبیر سے وہ عروہ ابن المغیرہ سے وہ اپنے باپ مغیرہ بن شعبہ سے روایت کرتے ہیں وہ رسول اللہ صلی اللہ علیہ وسلم سے نقل کرتے ہیں۔ ( ایک دفعہ ) آپ صلی اللہ علیہ وسلم رفع حاجت کے لیے باہر گئے تو مغیرہ پانی کا ایک برتن لے کر آپ صلی اللہ علیہ وسلم کے پیچھے گئے، جب آپ صلی اللہ علیہ وسلم قضاء حاجت سے فارغ ہو گئے تو مغیرہ نے ( آپ صلی اللہ علیہ وسلم کو وضو کراتے ہوئے ) آپ صلی اللہ علیہ وسلم ( کے اعضاء مبارکہ ) پر پانی ڈالا۔ آپ صلی اللہ علیہ وسلم نے وضو کیا اور موزوں پر مسح فرمایا۔' WHERE id = 204;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے، کہا ہم سے ایوب نے ابوقلابہ کے واسطے سے نقل کیا، وہ انس رضی اللہ عنہ سے روایت کرتے ہیں، وہ رسول اللہ صلی اللہ علیہ وسلم سے آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم نماز میں اونگھنے لگو تو سو جانا چاہیے۔ پھر اس وقت نماز پڑھے جب جان لے کہ وہ کیا پڑھ رہا ہے۔' WHERE id = 214;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہمیں مالک نے ابن شہاب سے خبر دی، وہ عبیداللہ بن عبداللہ بن عتبہ (بن مسعود) سے یہ حدیث روایت کرتے ہیں، وہ ام قیس بنت محصن نامی ایک خاتون سے کہ وہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت اقدس میں اپنا چھوٹا بچہ لے کر آئیں۔ جو کھانا نہیں کھاتا تھا۔ ( یعنی شیرخوار تھا ) رسول اللہ صلی اللہ علیہ وسلم نے اسے اپنی گود میں بٹھا لیا۔ اس بچے نے آپ صلی اللہ علیہ وسلم کے کپڑے پر پیشاب کر دیا۔ آپ صلی اللہ علیہ وسلم نے پانی منگا کر کپڑے پر چھڑک دیا اور اسے نہیں دھویا۔' WHERE id = 224;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے حماد بن زید سے، وہ ایوب سے، وہ ابوقلابہ سے، وہ انس رضی اللہ عنہ سے روایت کرتے ہیں کہ کچھ لوگ عکل یا عرینہ ( قبیلوں ) کے مدینہ میں آئے اور بیمار ہو گئے۔ رسول اللہ صلی اللہ علیہ وسلم نے انہیں لقاح میں جانے کا حکم دیا اور فرمایا کہ وہاں اونٹوں کا دودھ اور پیشاب پئیں۔ چنانچہ وہ لقاح چلے گئے اور جب اچھے ہو گئے تو رسول اللہ صلی اللہ علیہ وسلم کے چرواہے کو قتل کر کے وہ جانوروں کو ہانک کر لے گئے۔ علی الصبح رسول اللہ صلی اللہ علیہ وسلم کے پاس ( اس واقعہ کی ) خبر آئی۔ تو آپ نے ان کے پیچھے آدمی دوڑائے۔ دن چڑھے وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پکڑ کر لائے گئے۔ آپ کے حکم کے مطابق ان کے ہاتھ پاؤں کاٹ دئیے گئے اور آنکھوں میں گرم سلاخیں پھیر دی گئیں اور ( مدینہ کی ) پتھریلی زمین میں ڈال دئیے گئے۔ ( پیاس کی شدت سے ) وہ پانی مانگتے تھے مگر انہیں پانی نہیں دیا جاتا تھا۔ ابوقلابہ نے ( ان کے جرم کی سنگینی ظاہر کرتے ہوئے ) کہا کہ ان لوگوں نے چوری کی اور چرواہوں کو قتل کیا اور ( آخر ) ایمان سے پھر گئے اور اللہ اور اس کے رسول سے جنگ کی۔' WHERE id = 234;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے ابن ابی حازم کے واسطے سے نقل کیا، انہوں نے سہل بن سعد الساعدی سے سنا کہ لوگوں نے ان سے پوچھا، اور ( میں اس وقت سہل کے اتنا قریب تھا کہ ) میرے اور ان کے درمیان کوئی دوسرا حائل نہ تھا کہ رسول اللہ صلی اللہ علیہ وسلم کے ( احد کے ) زخم کا علاج کس دوا سے کیا گیا تھا۔ انہوں نے کہا کہ اس بات کا جاننے والا ( اب ) مجھ سے زیادہ کوئی نہیں رہا۔ علی رضی اللہ عنہ اپنی ڈھال میں پانی لاتے اور فاطمہ رضی اللہ عنہا آپ صلی اللہ علیہ وسلم کے منہ سے خون دھوتیں پھر ایک بوریا کا ٹکڑا جلایا گیا اور آپ صلی اللہ علیہ وسلم کے زخم میں بھر دیا گیا۔' WHERE id = 244;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے روایت کی، انہوں نے کہا کہ ہم سے سفیان بن عیینہ نے عمرو کے واسطہ سے بیان کیا، وہ جابر بن زید سے، وہ عبداللہ بن عباس سے کہ نبی کریم صلی اللہ علیہ وسلم اور میمونہ رضی اللہ عنہا ایک برتن میں غسل کر لیتے تھے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) فرماتے ہیں کہ ابن عیینہ اخیر عمر میں اس حدیث کو یوں روایت کرتے تھے ابن عباس رضی اللہ عنہما سے انہوں نے میمونہ رضی اللہ عنہا سے اور صحیح وہی روایت ہے جو ابونعیم نے کی ہے۔' WHERE id = 254;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا۔ کہا ہم سے شعبہ نے ابوبکر بن حفص کے واسطے سے بیان کیا، وہ عروہ سے، وہ عائشہ رضی اللہ عنہا سے، انہوں نے کہا کہ میں اور نبی کریم صلی اللہ علیہ وسلم ( دونوں مل کر ) ایک ہی برتن میں غسل جنابت کرتے تھے۔ اور شعبہ نے عبدالرحمٰن بن قاسم سے، انہوں نے اپنے والد ( قاسم بن محمد بن ابی بکر رضی اللہ عنہ ) سے وہ عائشہ رضی اللہ عنہا سے۔ اسی طرح روایت کرتے ہیں۔' WHERE id = 264;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے عثمان بن عمر نے بیان کیا، کہا ہم کو یونس نے خبر دی زہری کے واسطے سے، وہ ابوسلمہ سے، وہ ابوہریرہ رضی اللہ عنہ سے کہ نماز کی تکبیر ہوئی اور صفیں برابر ہو گئیں، لوگ کھڑے تھے کہ رسول اللہ صلی اللہ علیہ وسلم اپنے حجرے سے ہماری طرف تشریف لائے۔ جب آپ صلی اللہ علیہ وسلم مصلے پر کھڑے ہو چکے تو یاد آیا کہ آپ جنبی ہیں۔ پس آپ صلی اللہ علیہ وسلم نے ہم سے فرمایا کہ اپنی جگہ کھڑے رہو اور آپ واپس چلے گئے۔ پھر آپ صلی اللہ علیہ وسلم نے غسل کیا اور واپس ہماری طرف تشریف لائے تو سر سے پانی کے قطرے ٹپک رہے تھے۔ آپ صلی اللہ علیہ وسلم نے نماز کے لیے تکبیر کہی اور ہم نے آپ صلی اللہ علیہ وسلم کے ساتھ نماز ادا کی۔ عثمان بن عمر سے اس روایت کی متابعت کی ہے عبدالاعلیٰ نے معمر سے اور وہ زہری سے۔ اور اوزاعی نے بھی زہری سے اس حدیث کو روایت کیا ہے۔' WHERE id = 275;
UPDATE hadiths SET urdu = 'ہم سے عیاش نے بیان کیا، انہوں نے کہا ہم سے عبدالاعلیٰ نے بیان کیا، انہوں نے کہا ہم سے حمید نے بکر کے واسطہ سے بیان کیا، انہوں نے ابورافع سے، وہ ابوہریرہ رضی اللہ عنہ سے، کہا کہ میری ملاقات رسول اللہ صلی اللہ علیہ وسلم سے ہوئی۔ اس وقت میں جنبی تھا۔ آپ صلی اللہ علیہ وسلم نے میرا ہاتھ پکڑ لیا اور میں آپ صلی اللہ علیہ وسلم کے ساتھ چلنے لگا۔ آخر آپ صلی اللہ علیہ وسلم ایک جگہ بیٹھ گئے اور میں آہستہ سے اپنے گھر آیا اور غسل کر کے حاضر خدمت ہوا۔ آپ صلی اللہ علیہ وسلم ابھی بیٹھے ہوئے تھے، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا اے ابوہریرہ! کہاں چلے گئے تھے، میں نے واقعہ بیان کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا سبحان اللہ! مومن تو نجس نہیں ہوتا۔' WHERE id = 285;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہمیں خبر دی مالک نے ہشام بن عروہ سے، وہ اپنے والد سے، وہ عائشہ رضی اللہ عنہا سے نقل کرتے ہیں کہ آپ نے فرمایا میں رسول اللہ صلی اللہ علیہ وسلم کے سر مبارک کو حائضہ ہونے کی حالت میں بھی کنگھا کیا کرتی تھی۔' WHERE id = 295;
UPDATE hadiths SET urdu = 'ہم سے اصبغ نے بیان کیا، انہوں نے کہا مجھ سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا مجھ سے عمرو بن حارث نے عبدالرحمٰن بن قاسم کے واسطے سے بیان کیا، انہوں نے اپنے والد قاسم بن محمد سے بیان کیا، وہ عائشہ رضی اللہ عنہا سے کہ آپ نے فرمایا کہ ہمیں حیض آتا تو کپڑے کو پاک کرتے وقت ہم خون کو مل دیتے، پھر اس جگہ کو دھو لیتے اور تمام کپڑے پر پانی بہا دیتے اور اسے پہن کر نماز پڑھتے۔' WHERE id = 306;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے حماد بن زید نے عبیداللہ بن ابی بکر کے واسطے سے، وہ انس بن مالک رضی اللہ عنہ سے، وہ نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ رحم مادر میں اللہ تعالیٰ نے ایک فرشتہ مقرر کیا ہے۔ وہ کہتا ہے کہ اے رب! اب یہ «نطفة» ہے، اے رب! اب یہ «علقة» ہو گیا ہے، اے رب! اب یہ «مضغة‏» ہو گیا ہے۔ پھر جب اللہ چاہتا ہے کہ اس کی خلقت پوری کرے تو کہتا ہے کہ مذکر یا مونث، بدبخت ہے یا نیک بخت، روزی کتنی مقدر ہے اور عمر کتنی۔ پس ماں کے پیٹ ہی میں یہ تمام باتیں فرشتہ لکھ دیتا ہے۔' WHERE id = 316;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا ہمیں امام مالک نے خبر دی، انہوں نے عبداللہ بن ابی بکر بن عمرو بن حزم سے، انہوں نے اپنے باپ ابوبکر سے، انہوں نے عبدالرحمٰن کی بیٹی عمرہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا سے کہ انھوں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ یا رسول اللہ! صفیہ بنت حیی رضی اللہ عنہا کو ( حج میں ) حیض آ گیا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، شاید کہ وہ ہمیں روکیں گی۔ کیا انہوں نے تمہارے ساتھ طواف ( زیارت ) نہیں کیا۔ عورتوں نے جواب دیا کہ کر لیا ہے۔ آپ نے اس پر فرمایا کہ پھر نکلو۔' WHERE id = 326;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے حکم کے واسطہ سے حدیث بیان کی، وہ ذر بن عبداللہ سے، وہ ابن عبدالرحمٰن بن ابزی سے، وہ اپنے والد سے کہ وہ عمر رضی اللہ عنہ کی خدمت میں حاضر تھے اور عمار رضی اللہ عنہ نے ان سے کہا کہ ہم ایک لشکر میں گئے ہوئے تھے۔ پس ہم دونوں جنبی ہو گئے۔ اور ( اس میں ہے کہ بجائے «نفخ فيهما‏» کے ) انہوں نے «تفل فيهما‏» کہا۔' WHERE id = 337;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا ہمیں خبر دی امام مالک نے صالح بن کیسان سے، انہوں نے عروہ بن زبیر سے، انہوں نے ام المؤمنین عائشہ رضی اللہ عنہا سے، آپ نے فرمایا کہ اللہ تعالیٰ نے پہلے نماز میں دو دو رکعت فرض کی تھی۔ سفر میں بھی اور اقامت کی حالت میں بھی۔ پھر سفر کی نماز تو اپنی اصلی حالت پر باقی رکھی گئی اور حالت اقامت کی نمازوں میں زیادتی کر دی گئی۔' WHERE id = 347;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا ہم سے شیبان بن عبدالرحمٰن نے یحییٰ بن ابی کثیر کے واسطہ سے، انہوں نے عکرمہ سے، یحییٰ نے کہا میں نے عکرمہ سے سنایا میں نے ان سے پوچھا تھا تو عکرمہ نے کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، وہ فرماتے تھے۔ میں اس کی گواہی دیتا ہوں کہ رسول اللہ صلی اللہ علیہ وسلم کو میں نے یہ ارشاد فرماتے سنا تھا کہ جو شخص ایک کپڑے میں نماز پڑھے اسے کپڑے کے دونوں کناروں کو اس کے مخالف سمت کے کندھے پر ڈال لینا چاہیے۔' WHERE id = 357;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا مجھ سے عبدالرحمٰن بن ابی الموال نے محمد بن منکدر سے، کہا میں جابر بن عبداللہ انصاری کی خدمت میں حاضر ہوا۔ وہ ایک کپڑا اپنے بدن پر لپیٹے ہوئے نماز پڑھ رہے تھے، حالانکہ ان کی چادر الگ رکھی ہوئی تھی۔ جب آپ نماز سے فارغ ہوئے تو ہم نے کہا اے ابوعبداللہ! آپ کی چادر رکھی ہوئی ہے اور آپ ( اسے اوڑھے بغیر ) نماز پڑھ رہے ہیں۔ انہوں نے فرمایا، میں نے چاہا کہ تم جیسے جاہل لوگ مجھے اس طرح نماز پڑھتے دیکھ لیں، میں نے بھی نبی کریم صلی اللہ علیہ وسلم کو اسی طرح ایک کپڑے میں نماز پڑھتے دیکھا تھا۔' WHERE id = 367;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا کہا کہ ہمیں امام مالک نے خبر دی اسحاق بن عبداللہ بن ابی طلحہ سے، انہوں نے انس بن مالک رضی اللہ عنہ سے کہ ان کی نانی ملیکہ نے رسول اللہ صلی اللہ علیہ وسلم کو کھانا تیار کر کے کھانے کے لیے بلایا۔ آپ صلی اللہ علیہ وسلم نے کھانے کے بعد فرمایا کہ آؤ تمہیں نماز پڑھا دوں۔ انس رضی اللہ عنہ نے کہا کہ میں نے اپنے گھر سے ایک بوریا اٹھایا جو کثرت استعمال سے کالا ہو گیا تھا۔ میں نے اس پر پانی چھڑکا۔ پھر رسول اللہ صلی اللہ علیہ وسلم نماز کے لیے ( اسی بورئیے پر ) کھڑے ہوئے اور میں اور ایک یتیم ( کہ رسول اللہ صلی اللہ علیہ وسلم کے غلام ابوضمیرہ کے لڑکے ضمیرہ ) آپ کے پیچھے صف باندھ کر کھڑے ہو گئے اور بوڑھی عورت ( انس کی نانی ملیکہ ) ہمارے پیچھے کھڑی ہوئیں۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے ہمیں دو رکعت نماز پڑھائی اور واپس گھر تشریف لے گئے۔' WHERE id = 377;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا مجھ سے حدیث بیان کی بکر بن مضر نے جعفر سے، وہ ابن ہرمز سے، انہوں نے عبداللہ بن مالک بن بحینہ سے کہ نبی کریم صلی اللہ علیہ وسلم جب نماز پڑھتے تو اپنے بازوؤں کے درمیان اس قدر کشادگی کر دیتے کہ دونوں بغلوں کی سفیدی ظاہر ہونے لگتی تھی اور لیث نے یوں کہا کہ مجھ سے جعفر بن ربیعہ نے اسی طرح حدیث بیان کی۔' WHERE id = 387;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عون نے بیان کیا، کہا ہم سے ہشیم نے حمید کے واسطہ سے، انہوں نے انس بن مالک رضی اللہ عنہ کے واسطہ سے کہ عمر رضی اللہ عنہ نے فرمایا کہ میری تین باتوں میں جو میرے منہ سے نکلا میرے رب نے ویسا ہی حکم فرمایا۔ میں نے کہا تھا کہ یا رسول اللہ! اگر ہم مقام ابراہیم کو نماز پڑھنے کی جگہ بنا سکتے تو اچھا ہوتا۔ اس پر یہ آیت نازل ہوئی۔ ”اور تم مقام ابراہیم کو نماز پڑھنے کی جگہ بنا لو“ دوسری آیت پردہ کے بارے میں ہے۔ میں نے کہا تھا کہ یا رسول اللہ کاش! آپ اپنی عورتوں کو پردہ کا حکم دیتے، کیونکہ ان سے اچھے اور برے ہر طرح کے لوگ بات کرتے ہیں۔ اس پر پردہ کی آیت نازل ہوئی اور ایک مرتبہ نبی کریم صلی اللہ علیہ وسلم کی بیویاں جوش و خروش میں آپ کی خدمت میں اتفاق کر کے کچھ مطالبات لے کر حاضر ہوئیں۔ میں نے ان سے کہا کہ ہو سکتا ہے کہ اللہ پاک تمہیں طلاق دلا دیں اور تمہارے بدلے تم سے بہتر مسلمہ بیویاں اپنے رسول صلی اللہ علیہ وسلم کو عنایت کریں، تو یہ آیت نازل ہوئی «عسى ربه إن طلقكن أن يبدله أزواجا خيرا منكن‏» اور سعید ابن ابی مریم نے کہا کہ مجھے یحییٰ بن ایوب نے خبر دی، کہا کہ ہم سے حمید نے بیان کیا، کہا میں نے انس رضی اللہ عنہ سے یہ حدیث سنی۔' WHERE id = 398;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، انہوں نے کہا ہمیں عبدالرزاق نے معمر بن راشد سے، انہوں نے ہمام بن منبہ سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا وہ نبی کریم صلی اللہ علیہ وسلم سے نقل کرتے ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا جب کوئی شخص نماز کے لیے کھڑا ہو تو سامنے نہ تھوکے کیونکہ وہ جب تک اپنی نماز کی جگہ میں ہوتا ہے تو اللہ تعالیٰ سے سرگوشی کرتا رہتا ہے اور دائیں طرف بھی نہ تھوکے کیونکہ اس طرف فرشتہ ہوتا ہے، ہاں بائیں طرف یا قدم کے نیچے تھوک لے اور اسے مٹی میں چھپا دے۔' WHERE id = 411;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم کو شعبہ نے خبر دی اشعث بن سلیم کے واسطہ سے، انہوں نے مسروق سے، انہوں نے عائشہ رضی اللہ عنہا سے، آپ فرماتی ہیں کہ رسول اللہ صلی اللہ علیہ وسلم اپنے تمام کاموں میں جہاں تک ممکن ہوتا دائیں طرف سے شروع کرنے کو پسند فرماتے تھے۔ طہارت کے وقت بھی، کنگھا کرنے اور جوتا پہننے میں بھی۔' WHERE id = 421;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، انہوں نے کہا ہم سے ہشیم نے بیان کیا، انہوں نے کہا ہم سے ابوالحکم سیار نے بیان کیا، انہوں نے کہا ہم سے یزید فقیر نے، کہا ہم سے جابر بن عبداللہ رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا۔ مجھے پانچ ایسی چیزیں عطا کی گئی ہیں جو مجھ سے پہلے انبیاء کو نہیں دی گئی تھیں۔ ( 1 ) ایک مہینے کی راہ سے میرا رعب ڈال کر میری مدد کی گئی۔ ( 2 ) میرے لیے تمام زمین میں نماز پڑھنے اور پاکی حاصل کرنے کی اجازت ہے۔ اس لیے میری امت کے جس آدمی کی نماز کا وقت ( جہاں بھی ) آ جائے اسے ( وہیں ) نماز پڑھ لینی چاہیے۔ ( 3 ) میرے لیے مال غنیمت حلال کیا گیا۔ ( 4 ) پہلے انبیاء خاص اپنی قوموں کی ہدایت کے لیے بھیجے جاتے تھے۔ لیکن مجھے دنیا کے تمام انسانوں کی ہدایت کے لیے بھیجا گیا ہے۔ ( 5 ) مجھے شفاعت عطا کی گئی ہے۔' WHERE id = 432;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا کہ کہا ہم سے عبدالعزیز نے ابوحازم کے واسطہ سے، انہوں نے سہل رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک عورت کے پاس ایک آدمی بھیجا کہ وہ اپنے بڑھئی غلام سے کہے کہ میرے لیے ( منبر ) لکڑیوں کے تختوں سے بنا دے جن پر میں بیٹھا کروں۔' WHERE id = 442;
UPDATE hadiths SET urdu = 'ہم سے احمد بن واقد نے بیان کیا کہ، کہا ہم سے حماد بن زید نے ثابت بنانی کے واسطہ سے، انہوں نے ابورافع سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ ایک عورت یا مرد مسجد میں جھاڑو دیا کرتا تھا۔ ابورافع نے کہا، میرا خیال ہے کہ وہ عورت ہی تھی۔ پھر انہوں نے نبی کریم صلی اللہ علیہ وسلم کی حدیث نقل کی کہ آپ صلی اللہ علیہ وسلم نے اس کی قبر پر نماز پڑھی۔' WHERE id = 453;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ بن جعفر نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، انہوں نے کہا کہ ہم سے جعید بن عبدالرحمٰن نے بیان کیا، انہوں نے کہا مجھ سے یزید بن خصیفہ نے بیان کیا، انہوں نے سائب بن یزید سے بیان کیا، انہوں نے بیان کیا کہ میں مسجد نبوی میں کھڑا ہوا تھا، کسی نے میری طرف کنکری پھینکی۔ میں نے جو نظر اٹھائی تو دیکھا کہ عمر بن خطاب رضی اللہ عنہ سامنے ہیں۔ آپ نے فرمایا کہ یہ سامنے جو دو شخص ہیں انہیں میرے پاس بلا کر لاؤ۔ میں بلا لایا۔ آپ نے پوچھا کہ تمہارا تعلق کس قبیلہ سے ہے یا یہ فرمایا کہ تم کہاں رہتے ہو؟ انہوں نے بتایا کہ ہم طائف کے رہنے والے ہیں۔ آپ نے فرمایا کہ اگر تم مدینہ کے ہوتے تو میں تمہیں سزا دئیے بغیر نہ چھوڑتا۔ رسول اللہ صلی اللہ علیہ وسلم کی مسجد میں آواز اونچی کرتے ہو؟' WHERE id = 463;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے نضر بن شمیل نے، انہوں نے کہا کہ ہمیں عبداللہ ابن عون نے خبر دی، انہوں نے محمد بن سیرین سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں دوپہر کے بعد کی دو نمازوں میں سے کوئی نماز پڑھائی۔ ( ظہر یا عصر کی ) ابن سیرین نے کہا کہ ابوہریرہ رضی اللہ عنہ نے اس کا نام تو لیا تھا۔ لیکن میں بھول گیا۔ ابوہریرہ رضی اللہ عنہ نے بتلایا کہ آپ صلی اللہ علیہ وسلم نے ہمیں دو رکعت نماز پڑھا کر سلام پھیر دیا۔ اس کے بعد ایک لکڑی کی لاٹھی سے جو مسجد میں رکھی ہوئی تھی آپ صلی اللہ علیہ وسلم ٹیک لگا کر کھڑے ہو گئے۔ ایسا معلوم ہوتا تھا کہ جیسے آپ بہت ہی خفا ہوں اور آپ صلی اللہ علیہ وسلم نے اپنے دائیں ہاتھ کو بائیں ہاتھ پر رکھا اور ان کی انگلیوں کو ایک دوسرے میں داخل کیا اور آپ نے اپنے دائیں رخسار مبارک کو بائیں ہاتھ کی ہتھیلی سے سہارا دیا۔ جو لوگ نماز پڑھ کر جلدی نکل جایا کرتے تھے وہ مسجد کے دروازوں سے پار ہو گئے۔ پھر لوگ کہنے لگے کہ کیا نماز کم کر دی گئی ہے۔ حاضرین میں ابوبکر اور عمر ( رضی اللہ عنہما ) بھی موجود تھے۔ لیکن انہیں بھی آپ سے بولنے کی ہمت نہ ہوئی۔ انہیں میں ایک شخص تھے جن کے ہاتھ لمبے تھے اور انہیں ذوالیدین کہا جاتا تھا۔ انہوں نے پوچھا یا رسول اللہ! کیا آپ صلی اللہ علیہ وسلم بھول گئے یا نماز کم کر دی گئی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہ میں بھولا ہوں اور نہ نماز میں کوئی کمی ہوئی ہے۔ پھر آپ صلی اللہ علیہ وسلم نے لوگوں سے پوچھا۔ کیا ذوالیدین صحیح کہہ رہے ہیں۔ حاضرین بولے کہ جی ہاں! یہ سن کر آپ صلی اللہ علیہ وسلم آگے بڑھے اور باقی رکعتیں پڑھیں۔ پھر سلام پھیرا پھر تکبیر کہی اور سہو کا سجدہ کیا۔ معمول کے مطابق یا اس سے بھی لمبا سجدہ۔ پھر سر اٹھایا اور تکبیر کہی۔ پھر تکبیر کہی اور دوسرا سجدہ کیا۔ معمول کے مطابق یا اس سے بھی طویل پھر سر اٹھایا اور تکبیر کہی، لوگوں نے باربار ابن سیرین سے پوچھا کہ کیا پھر سلام پھیرا تو وہ جواب دیتے کہ مجھے خبر دی گئی ہے کہ عمران بن حصین کہتے تھے کہ پھر سلام پھیرا۔' WHERE id = 474;
UPDATE hadiths SET urdu = 'اور عبداللہ بن عمر رضی اللہ عنہما نے نافع سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اس پہاڑ کے دونوں کونوں کا رخ کیا جو اس کے اور جبل طویل کے درمیان کعبہ کی سمت ہیں۔ آپ صلی اللہ علیہ وسلم اس مسجد کو جو اب وہاں تعمیر ہوئی ہے اپنی بائیں طرف کر لیتے ٹیلے کے کنارے۔ اور نبی کریم صلی اللہ علیہ وسلم کے نماز پڑھنے کی جگہ اس سے نیچے سیاہ ٹیلے پر تھی ٹیلے سے تقریباً دس ہاتھ چھوڑ کر پہاڑ کی دونوں گھاٹیوں کی طرف رخ کر کے نماز پڑھتے جو تمہارے اور کعبہ کے درمیان ہے۔' WHERE id = 484;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا ہم سے یزید بن ابی عبید نے بیان کیا، کہا کہ میں سلمہ بن اکوع رضی اللہ عنہ کے ساتھ ( مسجد نبوی میں ) حاضر ہوا کرتا تھا۔ سلمہ رضی اللہ عنہ ہمیشہ اس ستون کو سامنے کر کے نماز پڑھتے جہاں قرآن شریف رکھا رہتا تھا۔ میں نے ان سے کہا کہ اے ابومسلم! میں دیکھتا ہوں کہ آپ ہمیشہ اسی ستون کو سامنے کر کے نماز پڑھتے ہیں۔ انہوں نے فرمایا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا آپ صلی اللہ علیہ وسلم خاص طور سے اسی ستون کو سامنے کر کے نماز پڑھا کرتے تھے۔' WHERE id = 494;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، کہا کہ ہم سے ہشام بن عروہ نے بیان کیا، کہا مجھ سے میرے باپ نے عائشہ رضی اللہ عنہا کے واسطے سے بیان کیا، وہ فرماتی تھیں کہ نبی کریم صلی اللہ علیہ وسلم نماز پڑھتے رہتے اور میں ( آپ صلی اللہ علیہ وسلم کے سامنے ) بچھونے پڑ آڑی سوتی ہوئی پڑی ہوتی۔ جب آپ صلی اللہ علیہ وسلم وتر پڑھنا چاہتے تو مجھے بھی جگا دیتے اور میں بھی وتر پڑھ لیتی تھی۔' WHERE id = 504;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن سعید قطان نے کہا کہ ہم سے اسماعیل بن ابی خالد نے بیان کیا، انہوں نے کہا کہ ہم سے قیس بن ابی حازم نے جریر بن عبداللہ رضی اللہ عنہ کی روایت سے بیان کیا کہ جریر بن عبداللہ بجلی رضی اللہ عنہ نے فرمایا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کے دست مبارک پر نماز قائم کرنے، زکوٰۃ دینے، اور ہر مسلمان کے ساتھ خیر خواہی کرنے پر بیعت کی۔' WHERE id = 515;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا کہا مجھ سے میرے باپ نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا کہ ہم سے ابوصالح ذکوان نے ابو سعید خدری رضی اللہ عنہ کے واسطہ سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ( کہ گرمی کے موسم میں ) ظہر کو ٹھنڈے وقت میں پڑھا کرو، کیونکہ گرمی کی شدت جہنم کی بھاپ سے پیدا ہوتی ہے۔ اس حدیث کی متابعت سفیان ثوری، یحییٰ اور ابوعوانہ نے اعمش کے واسطہ سے کی ہے۔' WHERE id = 527;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، وہ امام مالک رحمہ اللہ علیہ سے، انہوں نے اسحاق بن عبداللہ بن ابی طلحہ سے روایت کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے اس حدیث کو روایت کیا، انہوں نے فرمایا کہ ہم عصر کی نماز پڑھ چکتے اور اس کے بعد کوئی بنی عمرو بن عوف ( قباء ) کی مسجد میں جاتا تو ان کو وہاں عصر کی نماز پڑھتے ہوئے پاتا۔' WHERE id = 537;
UPDATE hadiths SET urdu = 'ہم سے ابوکریب محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے برید بن عبداللہ کے واسطہ سے بیان کیا، انہوں نے ابوبردہ عامر بن عبداللہ سے، انہوں نے اپنے باپ ابوموسیٰ اشعری عبداللہ بن قیس رضی اللہ عنہ سے۔ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مسلمانوں اور یہود و نصاری کی مثال ایک ایسے شخص کی سی ہے کہ جس نے کچھ لوگوں سے مزدوری پر رات تک کام کرنے کے لیے کہا۔ انہوں نے آدھے دن کام کیا۔ پھر جواب دے دیا کہ ہمیں تمہاری اجرت کی ضرورت نہیں، ( یہ یہود تھے ) پھر اس شخص نے دوسرے مزدور بلائے اور ان سے کہا کہ دن کا جو حصہ باقی بچ گیا ہے ( یعنی آدھا دن ) اسی کو پورا کر دو۔ شرط کے مطابق مزدوری تمہیں ملے گی۔ انہوں نے بھی کام شروع کیا لیکن عصر تک وہ بھی جواب دے بیٹھے۔ ( یہ نصاریٰ تھے ) پس اس تیسرے گروہ نے ( جو اہل اسلام ہیں ) پہلے دو گروہوں کے کام کی پوری مزدوری لے لی۔' WHERE id = 547;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، انہوں نے کہا ہم سے عبدالوہاب ثقفی نے بیان کیا، انہوں نے کہا کہ ہم سے خالد حذاء نے بیان کیا ابوالمنہال سے، انہوں نے ابوبرزہ اسلمی رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم عشاء سے پہلے سونے اور اس کے بعد بات چیت کرنے کو ناپسند فرماتے تھے۔' WHERE id = 557;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم سے امام مالک نے ابن شہاب سے، انہوں نے ابوسلمہ بن عبدالرحمٰن بن عوف رضی اللہ عنہ سے انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے ایک رکعت نماز ( باجماعت ) پا لی اس نے نماز ( باجماعت کا ثواب ) پا لیا۔' WHERE id = 568;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، کہا ہم سے شیبانی نے بیان کیا، کہا ہم سے عبدالرحمٰن بن اسود نے بیان کیا، انہوں نے اپنے باپ سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ آپ نے فرمایا کہ دو رکعتوں کو رسول اللہ صلی اللہ علیہ وسلم نے کبھی ترک نہیں فرمایا، پوشیدہ ہو یا عام لوگوں کے سامنے، صبح کی نماز سے پہلے دو رکعات اور عصر کی نماز کے بعد دو رکعات۔' WHERE id = 579;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل نے بیان کیا، کہا کہ ہم سے معتمر بن سلیمان نے بیان کیا، ان سے ان کے باپ سلیمان بن طرخان نے، کہا کہ ہم سے ابوعثمان نہدی نے عبدالرحمٰن بن ابی بکر رضی اللہ عنہما سے یہ حدیث بیان کی کہ اصحاب صفہ نادار مسکین لوگ تھے اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس کے گھر میں دو آدمیوں کا کھانا ہو تو وہ تیسرے ( اصحاب صفہ میں سے کسی ) کو اپنے ساتھ لیتا جائے۔ اور جس کے ہاں چار آدمیوں کا کھانا ہے تو وہ پانچویں یا چھٹے آدمی کو سائبان والوں میں سے اپنے ساتھ لے جائے۔ پس ابوبکر رضی اللہ عنہ تین آدمی اپنے ساتھ لائے۔ اور نبی کریم صلی اللہ علیہ وسلم دس آدمیوں کو اپنے ساتھ لے گئے۔ عبدالرحمٰن بن ابی بکر رضی اللہ عنہما نے بیان کیا کہ گھر کے افراد میں اس وقت باپ، ماں اور میں تھا۔ ابوعثمان راوی کا بیان ہے کہ مجھے یاد نہیں کہ عبدالرحمٰن بن ابی بکر نے یہ کہا یا نہیں کہ میری بیوی اور ایک خادم جو میرے اور ابوبکر رضی اللہ عنہ دونوں کے گھر کے لیے تھا یہ بھی تھے۔ خیر ابوبکر رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے یہاں ٹھہر گئے۔ ( اور غالباً کھانا بھی وہیں کھایا۔ صورت یہ ہوئی کہ ) نماز عشاء تک وہیں رہے۔ پھر ( مسجد سے ) نبی کریم صلی اللہ علیہ وسلم کے حجرہ مبارک میں آئے اور وہیں ٹھہرے رہے تاآنکہ نبی کریم صلی اللہ علیہ وسلم نے بھی کھانا کھا لیا۔ اور رات کا ایک حصہ گزر جانے کے بعد جب اللہ تعالیٰ نے چاہا تو آپ گھر تشریف لائے تو ان کی بیوی ( ام رومان ) نے کہا کہ کیا بات پیش آئی کہ مہمانوں کی خبر بھی آپ نے نہ لی، یا یہ کہ مہمان کی خبر نہ لی۔ آپ نے پوچھا، کیا تم نے ابھی انہیں رات کا کھانا نہیں کھلایا۔ ام رومان نے کہا کہ میں کیا کروں آپ کے آنے تک انہوں نے کھانے سے انکار کیا۔ کھانے کے لیے ان سے کہا گیا تھا لیکن وہ نہ مانے۔ عبدالرحمٰن بن ابی بکر رضی اللہ عنہما نے بیان کیا کہ میں ڈر کر چھپ گیا۔ ابوبکر رضی اللہ عنہ نے پکارا اے غنثر! ( یعنی او پاجی ) آپ نے برا بھلا کہا اور کوسنے دئیے۔ فرمایا کہ کھاؤ تمہیں مبارک نہ ہو! اللہ کی قسم! میں اس کھانے کو کبھی نہیں کھاؤں گا۔ ( آخر مہمانوں کو کھانا کھلایا گیا ) ( عبدالرحمٰن رضی اللہ عنہ نے کہا ) اللہ گواہ ہے کہ ہم ادھر ایک لقمہ لیتے تھے اور نیچے سے پہلے سے بھی زیادہ کھانا ہو جاتا تھا۔ بیان کیا کہ سب لوگ شکم سیر ہو گئے۔ اور کھانا پہلے سے بھی زیادہ بچ گیا۔ ابوبکر رضی اللہ عنہ نے دیکھا تو کھانا پہلے ہی اتنا یا اس سے بھی زیادہ تھا۔ اپنی بیوی سے بولے۔ بنوفراس کی بہن! یہ کیا بات ہے؟ انہوں نے کہا کہ میری آنکھ کی ٹھنڈک کی قسم! یہ تو پہلے سے تین گنا ہے۔ پھر ابوبکر رضی اللہ عنہ نے بھی وہ کھانا کھایا اور کہا کہ میرا قسم کھانا ایک شیطانی وسوسہ تھا۔ پھر ایک لقمہ اس میں سے کھایا۔ اور نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بقیہ کھانا لے گئے اور آپ کی خدمت میں حاضر ہوئے۔ وہ صبح تک آپ کے پاس رکھا رہا۔ عبدالرحمٰن نے کہا کہ ہم مسلمانوں کا ایک دوسرے قبیلے کے لوگوں سے معاہدہ تھا۔ اور معاہدہ کی مدت پوری ہو چکی تھی۔ ( اس قبیلہ کا وفد معاہدہ سے متعلق بات چیت کرنے مدینہ میں آیا ہوا تھا ) ہم نے ان میں سے بارہ آدمی جدا کئے اور ہر ایک کے ساتھ کتنے آدمی تھے اللہ کو ہی معلوم ہے ان سب نے ان میں سے کھایا۔ عبدالرحمٰن رضی اللہ عنہ نے کچھ ایسا ہی کہا۔' WHERE id = 589;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام دستوائی نے یحییٰ بن ابی کثیر سے بیان کیا، انہوں نے محمد بن ابراہیم بن حارث سے کہا کہ مجھ سے عیسیٰ بن طلحہ نے بیان کیا کہ انھوں نے معاویہ بن ابی سفیان سے ایک دن سنا آپ ( جواب میں ) مؤذن کے ہی الفاظ کو دہرا رہے تھے۔ «أشهد أن محمدا رسول الله» تک۔ ہم سے اسحاق بن راہویہ نے بیان کیا، کہا کہ ہم سے وہب بن جریر نے بیان کیا، کہا کہ ہم سے ہشام دستوائی نے یحییٰ بن ابی کثیر سے اسی طرح حدیث بیان کی۔' WHERE id = 599;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن شاہین واسطی نے بیان کیا، کہا کہ ہم سے خالد بن عبداللہ طحان نے سعد بن ایاس جریری سے بیان کیا، انہوں نے عبداللہ بن بریدہ سے، انہوں نے عبداللہ بن مغفل مزنی سے کہ رسول اللہ صلی اللہ علیہ وسلم نے تین مرتبہ فرمایا کہ ہر دو اذانوں ( اذان و اقامت ) کے درمیان ایک نماز ( کا فصل ) دوسری نماز سے ہونا چاہیے ( تیسری مرتبہ فرمایا کہ ) جو شخص ایسا کرنا چاہے۔' WHERE id = 610;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے عون بن ابی حجیفہ سے بیان کیا، انہوں نے اپنے باپ سے کہ انھوں نے بلال رضی اللہ عنہ کو اذان دیتے ہوئے دیکھا۔ وہ کہتے ہیں میں بھی ان کے منہ کے ساتھ ادھر ادھر منہ پھیرنے لگا۔' WHERE id = 620;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہمیں امام مالک نے ابوالزناد سے خبر دی، انہوں نے اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اس ذات کی قسم جس کے ہاتھ میں میری جان ہے میں نے ارادہ کر لیا تھا کہ لکڑیوں کے جمع کرنے کا حکم دوں۔ پھر نماز کے لیے کہوں، اس کے لیے اذان دی جائے پھر کسی شخص سے کہوں کہ وہ امامت کرے اور میں ان لوگوں کی طرف جاؤں ( جو نماز باجماعت میں حاضر نہیں ہوتے ) پھر انہیں ان کے گھروں سمیت جلا دوں۔ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے اگر یہ جماعت میں نہ شریک ہونے والے لوگ اتنی بات جان لیں کہ انہیں مسجد میں ایک اچھے قسم کی گوشت والی ہڈی مل جائے گی یا دو عمدہ کھر ہی مل جائیں گے تو یہ عشاء کی جماعت کے لیے مسجد میں ضرور حاضر ہو جائیں' WHERE id = 630;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا کہ ہم سے میرے باپ نے بیان کیا، انہوں نے کہا کہ ہم سے اعمش نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوصالح ذکوان نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے روایت کیا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ منافقوں پر فجر اور عشاء کی نماز سے زیادہ اور کوئی نماز بھاری نہیں اور اگر انہیں معلوم ہوتا کہ ان کا ثواب کتنا زیادہ ہے ( اور چل نہ سکتے ) تو گھٹنوں کے بل گھسیٹ کر آتے اور میرا تو ارادہ ہو گیا تھا کہ مؤذن سے کہوں کہ وہ تکبیر کہے، پھر میں کسی کو نماز پڑھانے کے لیے کہوں اور خود آگ کی چنگاریاں لے کر ان سب کے گھروں کو جلا دوں جو ابھی تک نماز کے لیے نہیں نکلے۔' WHERE id = 640;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی عتبان نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا، انہوں نے کہا ہم سے ابن شہاب نے بیان کیا، انہوں نے محمود بن ربیع انصاری سے کہ بن مالک انصاری رضی اللہ عنہ نابینا تھے اور وہ اپنی قوم کے امام تھے۔ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے عرض کیا کہ یا رسول اللہ! اندھیری اور سیلاب کی راتیں ہوتی ہیں اور میں اندھا ہوں، اس لیے آپ میرے گھر میں کسی جگہ نماز پڑھ لیجیئے تاکہ میں وہیں اپنی نماز کی جگہ بنا لوں۔ پھر رسول اللہ صلی اللہ علیہ وسلم ان کے گھر تشریف لائے اور پوچھا کہ تم کہاں نماز پڑھنا پسند کرو گے۔ انہوں نے گھر میں ایک جگہ بتلا دی اور رسول اللہ صلی اللہ علیہ وسلم نے وہاں نماز پڑھی۔' WHERE id = 650;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے وہیب بن خالد نے بیان کیا، کہا کہ ہم سے ایوب سختیانی نے ابوقلابہ عبداللہ بن زید سے بیان کیا، انہوں نے کہا کہ مالک بن حویرث (صحابی) ایک دفعہ ہماری اس مسجد میں تشریف لائے اور فرمایا کہ میں تم لوگوں کو نماز پڑھاؤں گا اور میری نیت نماز پڑھنے کی نہیں ہے، میرا مقصد صرف یہ ہے کہ تمہیں نماز کا وہ طریقہ سکھا دوں جس طریقہ سے نبی کریم صلی اللہ علیہ وسلم نماز پڑھا کرتے تھے۔ میں نے ابوقلابہ سے پوچھا کہ انہوں نے کس طرح نماز پڑھی تھی؟ انہوں نے بتلایا کہ ہمارے شیخ ( عمر بن سلمہ ) کی طرح۔ شیخ جب سجدہ سے سر اٹھاتے تو ذرا بیٹھ جاتے پھر کھڑے ہوتے۔' WHERE id = 660;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا کہ ہمیں زائدہ بن قدامہ نے موسیٰ بن ابی عائشہ سے خبر دی، انہوں نے عبیداللہ بن عبداللہ بن عتبہ سے، انہوں نے کہا کہ میں عائشہ رضی اللہ عنہا کی خدمت میں حاضر ہوا اور کہا، کاش! رسول اللہ صلی اللہ علیہ وسلم کی بیماری کی حالت آپ ہم سے بیان کرتیں، ( تو اچھا ہوتا ) انہوں نے فرمایا کہ ہاں ضرور سن لو۔ آپ صلی اللہ علیہ وسلم کا مرض بڑھ گیا۔ تو آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا لوگوں نے نماز پڑھ لی؟ ہم نے عرض کی جی نہیں یا رسول اللہ! لوگ آپ کا انتظام کر رہے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرے لیے ایک لگن میں پانی رکھ دو۔ عائشہ رضی اللہ عنہا نے کہا کہ ہم نے پانی رکھ دیا اور آپ صلی اللہ علیہ وسلم نے بیٹھ کر غسل کیا۔ پھر آپ اٹھنے لگے، لیکن آپ بیہوش ہو گئے۔ جب ہوش ہوا تو پھر آپ نے پوچھا کہ کیا لوگوں نے نماز پڑھ لی ہے۔ ہم نے عرض کی نہیں، یا رسول اللہ! لوگ آپ کا انتظار کر رہے ہیں۔ آپ صلی اللہ علیہ وسلم نے ( پھر ) فرمایا کہ لگن میں میرے لیے پانی رکھ دو۔ عائشہ رضی اللہ عنہا فرماتی ہیں کہ ہم نے پھر پانی رکھ دیا اور آپ صلی اللہ علیہ وسلم نے بیٹھ کر غسل فرمایا۔ پھر اٹھنے کی کوشش کی لیکن ( دوبارہ ) پھر آپ بیہوش ہو گئے۔ جب ہوش ہوا تو آپ نے پھر یہی فرمایا کہ کیا لوگوں نے نماز پڑھ لی ہے۔ ہم نے عرض کی کہ نہیں یا رسول اللہ! لوگ آپ کا انتظار کر رہے ہیں۔ آپ صلی اللہ علیہ وسلم نے پھر فرمایا کہ لگن میں پانی لاؤ اور آپ صلی اللہ علیہ وسلم نے بیٹھ کر غسل کیا۔ پھر اٹھنے کی کوشش کی، لیکن پھر آپ بیہوش ہو گئے۔ پھر جب ہوش ہوا تو آپ صلی اللہ علیہ وسلم نے پوچھا کہ کیا لوگوں نے نماز پڑھ لی ہم نے عرض کی کہ نہیں یا رسول اللہ! وہ آپ کا انتظار کر رہے ہیں۔ لوگ مسجد میں عشاء کی نماز کے لیے بیٹھے ہوئے نبی کریم صلی اللہ علیہ وسلم کا انتظار کر رہے تھے۔ آخر آپ صلی اللہ علیہ وسلم نے ابوبکر رضی اللہ عنہ کے پاس آدمی بھیجا اور حکم فرمایا کہ وہ نماز پڑھا دیں۔ بھیجے ہوئے شخص نے آ کر کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے آپ کو نماز پڑھانے کے لیے حکم فرمایا ہے۔ ابوبکر رضی اللہ عنہ بڑے نرم دل انسان تھے۔ انہوں نے عمر رضی اللہ عنہ سے کہا کہ تم نماز پڑھاؤ، لیکن عمر رضی اللہ عنہ نے جواب دیا کہ آپ اس کے زیادہ حقدار ہیں۔ آخر ( بیماری ) کے دنوں میں ابوبکر رضی اللہ عنہ نماز پڑھاتے رہے۔ پھر جب نبی کریم صلی اللہ علیہ وسلم کو مزاج کچھ ہلکا معلوم ہوا تو دو مردوں کا سہارا لے کر جن میں ایک عباس رضی اللہ عنہ تھے ظہر کی نماز کے لیے گھر سے باہر تشریف لائے اور ابوبکر رضی اللہ عنہ نماز پڑھا رہے تھے، جب انہوں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا تو پیچھے ہٹنا چاہا، لیکن نبی کریم صلی اللہ علیہ وسلم نے اشارے سے انہیں روکا کہ پیچھے نہ ہٹو! پھر آپ نے ان دونوں مردوں سے فرمایا کہ مجھے ابوبکر کے بازو میں بٹھا دو۔ چنانچہ دونوں نے آپ کو ابوبکر رضی اللہ عنہ کے بازو میں بٹھا دیا۔ راوی نے کہا کہ پھر ابوبکر رضی اللہ عنہ نماز میں نبی کریم صلی اللہ علیہ وسلم کی پیروی کر رہے تھے اور لوگ ابوبکر رضی اللہ عنہ کی نماز کی پیروی کر رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم بیٹھے بیٹھے نماز پڑھ رہے تھے۔ عبیداللہ نے کہا کہ پھر میں عبداللہ بن عباس رضی اللہ عنہما کی خدمت میں گیا اور ان سے عرض کی کہ عائشہ رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم کی بیماری کے بارے میں جو حدیث بیان کی ہے کیا میں وہ آپ کو سناؤں؟ انہوں نے فرمایا کہ ضرور سناؤ۔ میں نے یہ حدیث سنا دی۔ انہوں نے کسی بات کا انکار نہیں کیا۔ صرف اتنا کہا کہ عائشہ رضی اللہ عنہا نے ان صاحب کا نام بھی تم کو بتایا جو عباس رضی اللہ عنہ کے ساتھ تھے۔ میں نے کہا نہیں۔ آپ نے فرمایا وہ علی رضی اللہ عنہ تھے۔' WHERE id = 670;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے شعبہ نے حکم سے بیان کیا، انہوں نے کہا کہ میں نے سعید بن جبیر سے سنا، وہ ابن عباس رضی اللہ عنہما سے بیان کرتے تھے کہ انہوں نے بتلایا کہ ایک رات میں اپنی خالہ ام المؤمنین میمونہ رضی اللہ عنہا کے گھر پر رہ گیا۔ رسول اللہ صلی اللہ علیہ وسلم عشاء کی نماز کے بعد جب ان کے گھر تشریف لائے تو یہاں چار رکعت نماز پڑھی۔ پھر آپ صلی اللہ علیہ وسلم سو گئے پھر نماز ( تہجد کے لیے ) آپ صلی اللہ علیہ وسلم اٹھے ( اور نماز پڑھنے لگے ) تو میں بھی اٹھ کر آپ صلی اللہ علیہ وسلم کی بائیں طرف کھڑا ہو گیا، لیکن آپ صلی اللہ علیہ وسلم نے مجھے اپنی داہنی طرف کر لیا۔ آپ صلی اللہ علیہ وسلم نے پانچ رکعت نماز پڑھی۔ پھر دو رکعت ( سنت فجر ) پڑھ کر سو گئے اور میں نے آپ صلی اللہ علیہ وسلم کے خراٹے کی آواز بھی سنی۔ پھر آپ صلی اللہ علیہ وسلم فجر کی نماز کے لیے برآمد ہوئے۔' WHERE id = 681;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہم سے ولید بن مسلم نے بیان کیا، کہا کہ ہم سے امام عبدالرحمٰن بن عمرو اوزاعی نے یحییٰ بن ابی کثیر سے بیان کیا، انہوں نے عبداللہ بن ابی قتادہ سے، انہوں نے اپنے باپ ابوقتادہ حارث بن ربعی سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نماز دیر تک پڑھنے کے ارادہ سے کھڑا ہوتا ہوں۔ لیکن کسی بچے کے رونے کی آواز سن کر نماز کو ہلکی کر دیتا ہوں، کیونکہ اس کی ماں کو ( جو نماز میں شریک ہو گی ) تکلیف میں ڈالنا برا سمجھتا ہوں۔ ولید بن مسلم کے ساتھ اس روایت کی متابعت بشر بن بکر، بقیہ بن ولید اور ابن مبارک نے اوزاعی کے واسطہ سے کی ہے۔' WHERE id = 691;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ مجھ سے عمرو بن مرہ نے بیان کیا، انہوں نے کہا کہ میں نے سالم بن ابوالجعد سے سنا، انہوں نے کہا کہ میں نے نعمان بن بشیر رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ نماز میں اپنی صفوں کو برابر کر لو، نہیں تو اللہ تعالیٰ تمہارا منہ الٹ دے گا۔' WHERE id = 701;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی نے بیان کیا، کہا کہ ہم سے عبدہ بن سلیمان نے یحییٰ بن سعید انصاری کے واسطہ سے بیان کیا، انہوں نے عمرہ بنت عبدالرحمٰن سے، انہوں نے عائشہ رضی اللہ عنہا سے، آپ نے بتلایا کہ رسول اللہ صلی اللہ علیہ وسلم رات میں اپنے حجرہ کے اندر ( تہجد کی ) نماز پڑھتے تھے۔ حجرے کی دیواریں پست تھیں اس لیے لوگوں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھ لیا اور کچھ لوگ آپ صلی اللہ علیہ وسلم کی اقتداء میں نماز کے لیے کھڑے ہو گئے۔ صبح کے وقت لوگوں نے اس کا ذکر دوسروں سے کیا۔ پھر جب دوسری رات آپ صلی اللہ علیہ وسلم کھڑے ہوئے تو کچھ لوگ آپ صلی اللہ علیہ وسلم کی اقتداء میں اس رات بھی کھڑے ہو گئے۔ یہ صورت دو یا تین رات تک رہی۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم بیٹھ رہے اور نماز کے مقام پر تشریف نہیں لائے۔ پھر صبح کے وقت لوگوں نے اس کا ذکر کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں ڈرا کہ کہیں رات کی نماز ( تہجد ) تم پر فرض نہ ہو جائے۔ ( اس خیال سے میں نے یہاں کا آنا ناغہ کر دیا ) ۔' WHERE id = 712;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن ولید نے بیان کیا، کہا کہ ہم سے عبدالاعلیٰ بن عبدالاعلی نے بیان کیا، کہا کہ ہم سے عبیداللہ عمری نے نافع سے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما جب نماز میں داخل ہوتے تو پہلے تکبیر تحریمہ کہتے اور ساتھ ہی رفع یدین کرتے۔ اسی طرح جب وہ رکوع کرتے تب اور جب «سمع الله لمن حمده» کہتے تب بھی ( رفع یدین کرتے ) دونوں ہاتھوں کو اٹھاتے اور جب قعدہ اولیٰ سے اٹھتے تب بھی رفع یدین کرتے۔ آپ نے اس فعل کو نبی کریم صلی اللہ علیہ وسلم تک پہنچایا۔ ( کہ نبی کریم صلی اللہ علیہ وسلم اسی طرح نماز پڑھا کرتے تھے۔)' WHERE id = 722;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، انہوں نے کہا کہ ہم سے فلیح بن سلیمان نے بیان کیا، انہوں نے کہا کہ ہم سے ہلال بن علی نے بیان کیا انس بن مالک رضی اللہ عنہ سے۔ آپ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے ہم کو نماز پڑھائی۔ پھر منبر پر تشریف لائے اور اپنے ہاتھ سے قبلہ کی طرف اشارہ کر کے فرمایا کہ ابھی جب میں نماز پڑھا رہا تھا تو جنت اور دوزخ کو اس دیوار پر دیکھا۔ اس کی تصویریں اس دیوار میں قبلہ کی طرف نمودار ہوئیں تو میں نے آج کی طرح خیر اور شر کبھی نہیں دیکھی۔ آپ صلی اللہ علیہ وسلم نے قول مذکور تین بار فرمایا۔' WHERE id = 732;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، انہوں نے کہا کہ ہم سے شیبان نے بیان کیا، انہوں نے یحییٰ بن ابی کثیر سے بیان کیا، انہوں نے عبداللہ بن ابی قتادہ سے، انہوں نے اپنے باپ ابوقتادہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم ظہر کی پہلی دو رکعتوں میں سورۃ فاتحہ اور ہر رکعت میں ایک ایک سورت پڑھتے تھے، ان میں بھی قرآت کرتے تھے لیکن آخری دو رکعتیں ہلکی پڑھاتے تھے کبھی کبھی ہم کو بھی کوئی آیت سنا دیا کرتے تھے۔ عصر میں آپ صلی اللہ علیہ وسلم سورۃ فاتحہ اور سورتیں پڑھتے تھے، اس کی بھی پہلی دو رکعتیں لمبی پڑھتے۔ اسی طرح صبح کی نماز کی پہلی رکعت لمبی کرتے اور دوسری ہلکی۔' WHERE id = 742;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، انہوں نے کہا کہ ہم سے مسعر بن کدام نے بیان کیا، انہوں نے کہا کہ مجھ سے عدی بن ثابت نے کہا۔ انہوں نے براء رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو عشاء میں «والتين والزيتون‏» پڑھتے سنا۔ میں نے آپ صلی اللہ علیہ وسلم سے زیادہ اچھی آواز یا اچھی قرآت والا کسی کو نہیں پایا۔' WHERE id = 752;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام دستوائی نے بیان کیا، انہوں نے یحییٰ بن ابی کثیر سے بیان کیا، انہوں نے عبداللہ بن ابی قتادہ سے، انہوں نے اپنے والد ابوقتادہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم ظہر کی پہلی رکعت میں ( قرآت ) طویل کرتے تھے اور دوسری رکعت میں مختصر۔ صبح کی نماز میں بھی آپ صلی اللہ علیہ وسلم اسی طرح کرتے تھے۔' WHERE id = 763;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے عقیل بن خالد کے واسطے سے بیان کیا، انہوں نے ابن شہاب سے، انہوں نے کہا کہ مجھے ابوبکر بن عبدالرحمٰن بن حارث نے خبری دی کہ انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم جب نماز کے لیے کھڑے ہوتے تو تکبیر کہتے۔ پھر جب رکوع کرتے تب بھی تکبیر کہتے تھے۔ پھر جب سر اٹھاتے تو «سمع الله لمن حمده‏» کہتے اور کھڑے ہی کھڑے «ربنا لك الحمد‏» کہتے۔ پھر جب ( دوسرے ) سجدہ کے لیے جھکتے تب تکبیر کہتے اور جب سجدہ سے سر اٹھاتے تب بھی تکبیر کہتے۔ اسی طرح آپ تمام نماز پوری کر لیتے تھے۔ قعدہ اولیٰ سے اٹھنے پر بھی تکبیر کہتے تھے۔ ( اس حدیث میں ) عبداللہ بن صالح نے لیث کے واسطے سے ( بجائے «ربنا لك الحمد‏» کے ) «ربنا ولك الحمد‏» نقل کیا ہے۔ ( «ربنا لك الحمد‏» کہے یا «ربنا ولك الحمد‏» واؤ کے ساتھ ہر دو طریقہ درست ہے ) ۔' WHERE id = 773;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا امام مالک رضی اللہ عنہ سے، انہوں نے نعیم بن عبداللہ مجمر سے، انہوں نے علی بن یحییٰ بن خلاد زرقی سے، انہوں نے اپنے باپ سے، انہوں نے رفاعہ بن رافع زرقی سے، انہوں نے کہا کہ ہم نبی کریم صلی اللہ علیہ وسلم کی اقتداء میں نماز پڑھ رہے تھے۔ جب آپ رکوع سے سر اٹھاتے تو «سمع الله لمن حمده» کہتے۔ ایک شخص نے پیچھے سے کہا «ربنا ولك الحمد،‏‏‏‏ حمدا كثيرا طيبا مباركا فيه» آپ صلی اللہ علیہ وسلم نے نماز سے فارغ ہو کر دریافت فرمایا کہ کس نے یہ کلمات کہے ہیں، اس شخص نے جواب دیا کہ میں نے۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے تیس سے زیادہ فرشتوں کو دیکھا کہ ان کلمات کو لکھنے میں وہ ایک دوسرے پر سبقت لے جانا چاہتے تھے۔' WHERE id = 783;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے عمرو بن دینار سے بیان کیا، انہوں نے طاؤس سے، انہوں نے ابن عباس رضی اللہ عنہما سے، آپ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم کو سات اعضاء پر سجدہ کا حکم دیا گیا، اس طرح کہ نہ بالوں کو اپنے سمیٹتے نہ کپڑے کو ( وہ سات اعضاء یہ ہیں ) پیشانی ( مع ناک ) دونوں ہاتھ، دونوں گھٹنے اور دونوں پاؤں۔' WHERE id = 793;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا کہ ہم سے حماد بن زید نے ثابت سے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے، انہوں نے فرمایا کہ میں نے جس طرح نبی کریم صلی اللہ علیہ وسلم کو نماز پڑھتے دیکھا تھا بالکل اسی طرح تم لوگوں کو نماز پڑھانے میں کسی قسم کی کوئی کمی نہیں چھوڑتا ہوں۔ ثابت نے بیان کیا کہ انس بن مالک رضی اللہ عنہ ایک ایسا عمل کرتے تھے جسے میں تمہیں کرتے نہیں دیکھتا۔ جب وہ رکوع سے سر اٹھاتے تو اتنی دیر تک کھڑے رہتے کہ دیکھنے والا سمجھتا کہ بھول گئے ہیں اور اسی طرح دونوں سجدوں کے درمیان اتنی دیر تک بیٹھتے رہتے کہ دیکھنے والا سمجھتا کہ بھول گئے ہیں۔' WHERE id = 804;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا کہ ہم سے اعمش نے شقیق بن سلمہ سے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے فرمایا کہ جب ہم نبی کریم صلی اللہ علیہ وسلم کے پیچھے نماز پڑھتے تو کہتے ( ترجمہ ) سلام ہو جبرائیل اور میکائیل پر سلام ہو فلاں اور فلاں پر ( اللہ پر سلام ) نبی کریم صلی اللہ علیہ وسلم ایک روز ہماری طرف متوجہ ہوئے اور فرمایا اللہ تو خود ”سلام“ ہے۔ ( تم اللہ کو کیا سلام کرتے ہو ) اس لیے جب تم میں سے کوئی نماز پڑھے تو یہ کہے «التحيات لله،‏‏‏‏ والصلوات والطيبات،‏‏‏‏ السلام عليك أيها النبي ورحمة الله وبركاته،‏‏‏‏ السلام علينا وعلى عباد الله الصالحين‏» تمام آداب بندگی، تمام عبادات اور تمام بہترین تعریفیں اللہ کے لیے ہیں۔ آپ پر سلام ہو اے نبی اور اللہ کی رحمتیں اور اس کی برکتیں ہم پر سلام اور اللہ کے تمام صالح بندوں پر سلام۔ جب تم یہ کہو گے تو تمہارا سلام آسمان و زمین میں جہاں کوئی اللہ کا نیک بندہ ہے اس کو پہنچ جائے گا۔ میں گواہی دیتا ہوں کہ اللہ کے سوا کوئی معبود نہیں اور گواہی دیتا ہوں کہ محمد اس کے بندے اور رسول ہیں۔' WHERE id = 814;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان ثوری نے عبدالملک بن عمیر سے بیان کیا، ان سے مغیرہ بن شعبہ کے کاتب وراد نے، انہوں نے بیان کیا کہ مجھ سے مغیرہ بن شعبہ رضی اللہ عنہ نے معاویہ رضی اللہ عنہ کو ایک خط میں لکھوایا کہ نبی کریم صلی اللہ علیہ وسلم ہر فرض نماز کے بعد یہ دعا پڑھتے تھے «لا إله إلا الله وحده لا شريك له،‏‏‏‏ ‏‏‏‏ له الملك،‏‏‏‏ ‏‏‏‏ وله الحمد،‏‏‏‏ ‏‏‏‏ وهو على كل شىء قدير،‏‏‏‏ ‏‏‏‏ اللهم لا مانع لما أعطيت،‏‏‏‏ ‏‏‏‏ ولا معطي لما منعت،‏‏‏‏ ‏‏‏‏ ولا ينفع ذا الجد منك الجد» اللہ کے سوا کوئی لائق عبادت نہیں۔ اس کا کوئی شریک نہیں۔ بادشاہت اس کی ہے اور تمام تعریف اسی کے لیے ہے۔ وہ ہر چیز پر قادر ہے۔ اے اللہ جسے تو دے اس سے روکنے والا کوئی نہیں اور جسے تو نہ دے اسے دینے والا کوئی نہیں اور کسی مالدار کو اس کی دولت و مال تیری بارگاہ میں کوئی نفع نہ پہنچا سکیں گے۔ شعبہ نے بھی عبدالملک سے اسی طرح روایت کی ہے۔ حسن نے فرمایا کہ ( حدیث میں لفظ ) «جد» کے معنی مال داری کے ہیں اور حکم، قاسم بن مخیمرہ سے وہ وراد کے واسطے سے اسی طرح روایت کرتے ہیں۔' WHERE id = 825;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، ان سے عبدالوارث بن سعید نے بیان کیا، ان سے عبد العزیز بن صہیب نے بیان کیا، کہ انس بن مالک رضی اللہ عنہ سے ایک شخص نے پوچھا کہ آپ نے نبی کریم صلی اللہ علیہ وسلم سے لہسن کے بارے میں کیا سنا ہے۔ انہوں نے بتایا کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص اس درخت کو کھائے وہ ہمارے قریب نہ آئے ہمارے ساتھ نماز نہ پڑھے۔' WHERE id = 836;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا کہ ہم سے عثمان بن عمر نے بیان کیا، انہوں نے کہا ہمیں یونس بن یزید نے زہری سے خبر دی، انہوں نے کہا کہ مجھے ہند بنت حارث نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا نے انہیں خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں عورتیں فرض نماز سے سلام پھیرنے کے فوراً بعد ( باہر آنے کے لیے ) اٹھ جاتی تھیں۔ رسول اللہ صلی اللہ علیہ وسلم اور مرد نماز کے بعد اپنی جگہ بیٹھے رہتے۔ جب تک اللہ کو منظور ہوتا۔ پھر جب رسول اللہ صلی اللہ علیہ وسلم اٹھتے تو دوسرے مرد بھی کھڑے ہو جاتے۔' WHERE id = 846;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد بن اسماء نے بیان کیا، انہوں نے کہا کہ ہم سے جویریہ بن اسماء نے امام مالک سے بیان کیا، ان سے زہری نے، ان سے سالم بن عبداللہ بن عمر رضی اللہ عنہما نے ان سے ابن عمر رضی اللہ عنہما نے کہ عمر بن خطاب رضی اللہ عنہ جمعہ کے دن کھڑے خطبہ دے رہے تھے کہ اتنے میں نبی کریم صلی اللہ علیہ وسلم کے اگلے صحابہ مہاجرین میں سے ایک بزرگ تشریف لائے ( یعنی عثمان رضی اللہ عنہ ) عمر رضی اللہ عنہ نے ان سے کہا بھلا یہ کون سا وقت ہے انہوں نے فرمایا کہ میں مشغول ہو گیا تھا اور گھر واپس آتے ہی اذان سنی، اس لیے میں وضو سے زیادہ اور کچھ ( غسل ) نہ کر سکا۔ عمر رضی اللہ عنہ نے فرمایا کہ وضو بھی اچھا ہے۔ حالانکہ آپ کو معلوم ہے کہ نبی کریم صلی اللہ علیہ وسلم غسل کے لیے فرماتے تھے۔' WHERE id = 858;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر عبداللہ نے بیان کیا، کہا کہ ہم سے عبدالوارث نے بیان کیا، کہا کہ ہم سے شعیب بن حبحاب نے بیان کیا، کہا کہ ہم سے انس رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں تم سے مسواک کے بارے میں بہت کچھ کہہ چکا ہوں۔' WHERE id = 868;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا کہ ہم سے شبابہ نے بیان کیا، کہا کہ ہم سے ورقاء بن عمرو نے بیان کیا، ان سے عمرو بن دینار نے، ان سے مجاہد نے، ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا عورتوں کو رات کے وقت مسجدوں میں آنے کی اجازت دے دیا کرو۔' WHERE id = 878;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی فلاس نے بیان کیا، کہا کہ ہم سے ابو قتیبہ بن قتیبہ نے بیان کیا، کہا کہ ہم سے علی بن مبارک نے یحییٰ بن ابی کثیر سے بیان کیا، ان سے عبداللہ بن ابی قتادہ نے (امام بخاری رحمہ اللہ کہتے ہیں کہ مجھے یقین ہے کہ) عبداللہ نے اپنے باپ ابوقتادہ سے روایت کی ہے، وہ نبی کریم صلی اللہ علیہ وسلم سے راوی ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا جب تک مجھے دیکھ نہ لو صف بندی کے لیے کھڑے نہ ہوا کرو اور آہستگی سے چلنا لازم کر لو۔' WHERE id = 888;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا کہ ہم سے ابن ابی ذئب نے بیان کیا، ان سے زہری نے، ان سے سالم نے، ان سے ان کے باپ (ابن عمر رضی اللہ عنہما) نے فرمایا کہ میں نے نبی کریم صلی الہ علیہ وسلم سے سنا۔ آپ صلی اللہ علیہ وسلم نے منبر پر خطبہ دیتے ہوئے فرمایا کہ جو جمعہ کے لیے آئے وہ پہلے غسل کر لیا کرے۔' WHERE id = 898;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے محمد بن عبدالرحمٰن بن ابی ذئب نے بیان کیا، ان سے زہری نے، ان سے ابوعبداللہ سلیمان اغر نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب جمعہ کا دن آتا ہے تو فرشتے جامع مسجد کے دروازے پر آنے والوں کے نام لکھتے ہیں، سب سے پہلے آنے والا اونٹ کی قربانی دینے والے کی طرح لکھا جاتا ہے۔ اس کے بعد آنے والا گائے کی قربانی دینے والے کی طرح پھر مینڈھے کی قربانی کا ثواب رہتا ہے۔ اس کے بعد مرغی کا، اس کے بعد انڈے کا۔ لیکن جب امام ( خطبہ دینے کے لیے ) باہر آ جاتا ہے تو یہ فرشتے اپنے دفاتر بند کر دیتے ہیں اور خطبہ سننے میں مشغول ہو جاتے ہیں۔' WHERE id = 908;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا کہ ہم سے عبد العزیز بن ابی حازم نے بیان کیا اپنے باپ سے اور ان سے سہل بن سعد نے یہی بیان کیا اور فرمایا کہ دوپہر کا سونا اور دوپہر کا کھانا جمعہ کی نماز کے بعد رکھتے تھے۔' WHERE id = 918;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، انہیں زبید بن حارث نے خبر دی، انہوں نے کہا کہ میں نے شعبی سے سنا، ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے عید کے دن خطبہ دیتے ہوئے فرمایا کہ پہلا کام جو ہم آج کے دن ( عید الاضحیٰ ) میں کرتے ہیں، یہ ہے کہ پہلے ہم نماز پڑھیں پھر واپس آ کر قربانی کریں۔ جس نے اس طرح کیا وہ ہمارے طریق پر چلا۔' WHERE id = 929;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے زبید نے بیان کیا، کہا کہ میں نے شعبی سے سنا، ان سے براء بن عازب نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہم اس دن پہلے نماز پڑھیں گے پھر خطبہ کے بعد واپس ہو کر قربانی کریں گے۔ جس نے اس طرح کیا اس نے ہماری سنت کے مطابق عمل کیا اور جس نے نماز سے پہلے قربانی کی تو اس کا ذبیحہ گوشت کا جانور ہے جسے وہ گھر والوں کے لیے لایا ہے، قربانی سے اس کا کوئی بھی تعلق نہیں۔ ایک انصاری رضی اللہ عنہ جن کا نام ابوبردہ بن نیار تھا بولے کہ یا رسول اللہ صلی اللہ علیہ وسلم میں نے تو ( نماز سے پہلے ہی ) قربانی کر دی لیکن میرے پاس ایک سال کی پٹھیا ہے جو دوندی ہوئی بکری سے بھی اچھی ہے۔ آپ نے صلی اللہ علیہ وسلم فرمایا کہ اچھا اسی کو بکری کے بدلہ میں قربانی کر لو اور تمہارے بعد یہ کسی اور کے لیے کافی نہ ہو گی۔' WHERE id = 940;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عباس نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان ثوری نے عبدالرحمٰن بن عابس سے بیان کیا، انہوں نے ابن عباس رضی اللہ عنہما سے سنا، انہوں نے فرمایا کہ میں نے عیدالفطر یا عید الاضحی کے دن نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھی۔ آپ صلی اللہ علیہ وسلم نے نماز پڑھنے کے بعد خطبہ دیا پھر عورتوں کی طرف آئے اور انہیں نصیحت فرمائی اور صدقہ کے لیے حکم فرمایا۔' WHERE id = 950;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے اسود بن قیس نے، ان سے جندب نے، انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے بقر عید کے دن نماز پڑھنے کے بعد خطبہ دیا پھر قربانی کی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے نماز سے پہلے ذبح کر لیا ہو تو اسے دوسرا جانور بدلہ میں قربانی کرنا چاہیے اور جس نے نماز سے پہلے ذبح نہ کیا ہو وہ اللہ کے نام پر ذبح کرے۔' WHERE id = 960;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا کہ مجھ سے میرے باپ نے بیان کیا، انہوں نے کہا کہ ہم سے اعمش نے بیان کیا، کہا کہ مجھ سے مسلم بن کیسان نے بیان کیا، ان سے مسروق نے، ان سے عائشہ رضی اللہ عنہا نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے رات کے ہر حصہ میں بھی وتر پڑھی ہے اور آخیر میں آپ صلی اللہ علیہ وسلم کا وتر صبح کے قریب پہنچا۔' WHERE id = 970;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا انہوں نے کہا کہ ہم سے مغیرہ بن عبدالرحمٰن نے بیان کیا، ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم جب سر مبارک آخری رکعت ( کے رکوع ) سے اٹھاتے تو یوں فرماتے «اللهم أنج عياش بن أبي ربيعة،‏‏‏‏ ‏‏‏‏ اللهم أنج سلمة بن هشام،‏‏‏‏ ‏‏‏‏ اللهم أنج الوليد بن الوليد،‏‏‏‏ ‏‏‏‏ اللهم أنج المستضعفين من المؤمنين،‏‏‏‏ ‏‏‏‏ اللهم اشدد وطأتك على مضر،‏‏‏‏ ‏‏‏‏ اللهم اجعلها سنين كسني يوسف» کہ یا اللہ! عیاش بن ابی ربیعہ کو نجات دے۔ یا اللہ! سلمہ بن ہشام کو نجات دے۔ یا اللہ! ولید بن ولید کو نجات دے۔ یا اللہ! بےبس ناتواں مسلمانوں کو نجات دے۔ یا اللہ! مضر کے کافروں کو سخت پکڑ۔ یا اللہ! ان کے سال یوسف علیہ السلام کے سے سال کر دے۔ اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا غفار کی قوم کو اللہ نے بخش دیا اور اسلم کی قوم کو اللہ نے سلامت رکھا۔ ابن ابی الزناد نے اپنے باپ سے صبح کی نماز میں یہی دعا نقل کی۔' WHERE id = 980;
UPDATE hadiths SET urdu = 'ہم سے حسن بن بشر نے بیان کیا، انہوں نے کہا کہ ہم سے معافی بن عمران نے بیان کیا کہ ان سے امام اوزاعی نے، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ایک شخص نے نبی کریم صلی اللہ علیہ وسلم سے ( قحط سے ) مال کی بربادی اور اہل و عیال کی بھوک کی شکایت کی۔ چنانچہ آپ صلی اللہ علیہ وسلم نے دعائے استسقاء کی۔ راوی نے اس موقع پر نہ چادر پلٹنے کا ذکر کیا اور نہ قبلہ کی طرف منہ کرنے کا۔' WHERE id = 991;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی نے بیان کیا، کہا کہ ہمیں عبدالوہاب ثقفی نے خبر دی، انہوں نے کہا کہ ہمیں یحییٰ بن سعید انصاری نے حدیث بیان کی، کہا کہ مجھے ابوبکر بن محمد بن عمرو بن حزم نے خبر دی کہ عباد بن تمیم نے انہیں خبر دی اور انہیں عبداللہ بن زید انصاری نے بتایا کہ نبی کریم صلی اللہ علیہ وسلم ( استسقاء کے لیے ) عیدگاہ کی طرف نکلے وہاں نماز پڑھنے کو جب آپ صلی اللہ علیہ وسلم دعا کرنے لگے یا راوی نے یہ کہا دعا کا ارادہ کیا تو قبلہ رو ہو کر چادر مبارک پلٹی۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) کہتے ہیں کہ اس حدیث کے راوی عبداللہ بن زید مازنی ہیں اور اس سے پہلے باب «الدعا فی الاستسقاء» میں جن کا ذکر گزرا اور وہ عبداللہ بن یزید ہیں کوفہ کے رہنے والے۔' WHERE id = 1001;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ایوب نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، انہوں نے صالح بن کیسان سے بیان کیا، ان سے عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے بیان کیا، ان سے زید بن خالد جہنی رضی اللہ عنہ نے بیان کیاکہ نبی کریم صلی اللہ علیہ وسلم نے حدیبیہ میں ہم کو صبح کی نماز پڑھائی۔ رات کو بارش ہو چکی تھی نماز کے بعد آپ صلی اللہ علیہ وسلم لوگوں کی طرف متوجہ ہوئے اور فرمایا معلوم ہے تمہارے رب نے کیا فیصلہ کیا ہے؟ لوگ بولے کہ اللہ تعالیٰ اور اس کے رسول خوب جانتے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پروردگار فرماتا ہے آج میرے دو طرح کے بندوں نے صبح کی۔ ایک مومن ہے ایک کافر۔ جس نے کہا اللہ کے فضل و رحم سے پانی پڑا وہ تو مجھ پر ایمان لایا اور ستاروں کا منکر ہوا اور جس نے کہا فلاں تارے کے فلاں جگہ آنے سے پانی پڑا اس نے میرا کفر کیا، تاروں پر ایمان لایا۔' WHERE id = 1011;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے یونس بن عبید نے، ان سے امام حسن بصری نے، ان سے ابوبکرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا سورج اور چاند دونوں اللہ تعالیٰ کی نشانیاں ہیں اور کسی کی موت و حیات سے ان میں گرہن نہیں لگتا بلکہ اللہ تعالیٰ اس کے ذریعہ اپنے بندوں کو ڈراتا ہے۔ عبدالوارث، شعبہ، خالد بن عبداللہ اور حماد بن سلمہ ان سب حافظوں نے یونس سے یہ جملہ کہ ”اللہ تعالیٰ ان کو گرہن کر کے اپنے بندوں کو ڈراتا ہے“ بیان نہیں کیا اور یونس کے ساتھ اس حدیث کو موسیٰ نے مبارک بن فضالہ سے، انہوں نے امام حسن بصری سے روایت کیا۔ اس میں یوں ہے کہ ابوبکرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے سن کر مجھ کو خبر دی کہ اللہ تعالیٰ ان کو گرہن کر کے اپنے بندوں کو ڈراتا ہے اور یونس کے ساتھ اس حدیث کو اشعث بن عبداللہ نے بھی امام حسن بصری سے روایت کیا۔' WHERE id = 1021;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا کہ ہم سے سعید بن عامر نے بیان کیا، ان سے شعبہ نے، ان سے یونس نے، ان سے امام حسن بصری نے اور ان سے ابوبکرہ رضی اللہ عنہ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم کے عہد مبارک میں سورج کو گرہن لگا تو آپ صلی اللہ علیہ وسلم نے دو رکعت نماز پڑھی تھی۔' WHERE id = 1033;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم اور معاذ بن فضالہ نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام بن ابی عبداللہ دستوائی نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے ابوسلمہ نے کہا کہ میں نے ابوہریرہ رضی اللہ عنہ کو سورۃ «إذا السماء انشقت‏» پڑھتے دیکھا۔ آپ نے اس میں سجدہ کیا میں نے کہا کہ اے ابوہریرہ! کیا میں نے آپ کو سجدہ کرتے ہوئے نہیں دیکھا ہے۔ آپ نے کہا کہ اگر میں نبی کریم صلی اللہ علیہ وسلم کو سجدہ کرتے نہ دیکھتا تو میں بھی نہ کرتا۔' WHERE id = 1044;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالواحد بن زیاد نے بیان کیا، ان سے اعمش نے، انہوں نے کہا کہ ہم سے ابراہیم نخعی نے بیان کیا، انہوں نے کہا کہ میں نے عبدالرحمٰن بن یزید سے سنا، وہ کہتے تھے کہ ہمیں عثمان بن عفان رضی اللہ عنہ نے منیٰ میں چار رکعت نماز پڑھائی تھی لیکن جب اس کا ذکر عبداللہ بن مسعود رضی اللہ عنہ سے کیا گیا تو انہوں نے کہا کہ «انا لله و انا اليه راجعون» ۔ پھر کہنے لگے میں نے تو نبی کریم صلی اللہ علیہ وسلم کے ساتھ منی ٰ میں دو رکعت نماز پڑھی ہے اور ابوبکر صدیق رضی اللہ عنہ کے ساتھ بھی میں نے دو رکعت ہی پڑھی ہیں اور عمر بن خطاب رضی اللہ عنہ کے ساتھ بھی دو رکعت ہی پڑھی تھی کاش میرے حصہ میں ان چار رکعتوں کے بجائے دو مقبول رکعتیں ہوتیں۔' WHERE id = 1054;
UPDATE hadiths SET urdu = 'ہم سے ابوالاعلیٰ بن حماد نے بیان کیا، انہوں نے کہا کہ ہم سے وہیب نے بیان کیا، انہوں نے کہا کہ ہم سے موسیٰ بن عقبہ نے بیان کیا، ان سے نافع نے بیان کیا، انہوں نے کہا کہ ابن عمر رضی اللہ عنہما نفل نماز سواری پر پڑھتے تھے۔ اسی طرح وتر بھی۔ اور فرماتے کہ نبی کریم صلی اللہ علیہ وسلم بھی ایسا کرتے تھے۔' WHERE id = 1064;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے خبر دی، انہیں زہری نے اور انہیں سالم بن عبداللہ بن عمر نے اپنے باپ عبداللہ بن عمر رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم اپنی اونٹنی کی پیٹھ پر خواہ اس کا منہ کسی طرف ہوتا نفل نماز سر کے اشاروں سے پڑھتے تھے۔ عبداللہ بن عمر رضی اللہ عنہما بھی اسی طرح کیا کرتے تھے۔' WHERE id = 1074;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، انہوں نے کہا ہمیں روح بن عبادہ نے خبر دی، انہوں نے کہا ہمیں حسین نے خبر دی، انہیں عبداللہ بن بریدہ نے، انہیں عمران بن حصین رضی اللہ عنہما نے کہ آپ نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا ( دوسری سند ) اور ہمیں اسحاق بن منصور نے خبر دی، کہا کہ ہمیں عبدالصمد نے خبر دی، کہا کہ میں نے اپنے باپ عبدالوارث سے سنا، کہا کہ ہم سے حسین نے بیان کیا اور ان سے ابن بریدہ نے کہا کہ مجھ سے عمران بن حصین رضی اللہ عنہما نے بیان کیا، وہ بواسیر کے مریض تھے انہوں نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے کسی آدمی کے بیٹھ کر نماز پڑھنے کے بارے میں پوچھا کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ افضل یہی ہے کہ کھڑے ہو کر پڑھے کیونکہ بیٹھ کر پڑھنے والے کو کھڑے ہو کر پڑھنے والے سے آدھا ثواب ملتا ہے اور لیٹے لیٹے پڑھنے والے کو بیٹھ کر پڑھنے والے سے آدھا ثواب ملتا ہے۔' WHERE id = 1084;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہمیں شعیب نے زہری سے خبر دی، کہا کہ مجھے زین العابدین علی بن حسین نے خبر دی، اور انہیں حسین بن علی رضی اللہ عنہما نے خبر دی کہ علی بن ابی طالب رضی اللہ عنہ نے انہیں خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ایک رات ان کے اور فاطمہ رضی اللہ عنہما کے پاس آئے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا تم لوگ ( تہجد کی ) نماز نہیں پڑھو گے؟ میں عرض کی کہ یا رسول اللہ! ہماری روحیں اللہ کے قبضہ میں ہیں، جب وہ چاہے گا ہمیں اٹھا دے گا۔ ہماری اس عرض پر آپ صلی اللہ علیہ وسلم واپس تشریف لے گئے۔ آپ صلی اللہ علیہ وسلم نے کوئی جواب نہیں دیا لیکن واپس جاتے ہوئے میں نے سنا کہ آپ صلی اللہ علیہ وسلم ران پر ہاتھ مار کر ( سورۃ الکہف کی یہ آیت پڑھ رہے تھے ) آدمی سب سے زیادہ جھگڑالو ہے «وكان الإنسان أكثر شىء جدلا‏» ۔' WHERE id = 1095;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہمیں شعیب نے زہری سے خبر دی، کہا کہ مجھے سالم بن عبداللہ نے خبر دی کہ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا ایک شخص نے دریافت کیا یا رسول اللہ صلی اللہ علیہ وسلم ! رات کی نماز کس طرح پڑھی جائے؟ آپ صلی اللہ علیہ وسلم نے فرمایا دو، دو رکعت اور جب طلوع صبح ہونے کا اندیشہ ہو تو ایک رکعت وتر پڑھ کر اپنی ساری نماز کو طاق بنا لے۔' WHERE id = 1106;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک رحمہ اللہ نے خبر دی، انہیں سعید بن ابوسعید مقبری نے خبر دی، انہیں ابوسلمہ بن عبدالرحمٰن نے خبر دی کہ ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا سے انہوں نے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم رمضان میں ( رات کو ) کتنی رکعتیں پڑھتے تھے۔ آپ نے جواب دیا کہ رسول اللہ صلی اللہ علیہ وسلم ( رات میں ) گیارہ رکعتوں سے زیادہ نہیں پڑھتے تھے۔ خواہ رمضان کا مہینہ ہوتا یا کوئی اور۔ پہلے آپ صلی اللہ علیہ وسلم چار رکعت پڑھتے۔ ان کی خوبی اور لمبائی کا کیا پوچھنا۔ پھر آپ صلی اللہ علیہ وسلم چار رکعت اور پڑھتے ان کی خوبی اور لمبائی کا کیا پوچھنا۔ پھر تین رکعتیں پڑھتے۔ عائشہ رضی اللہ عنہا نے فرمایا کہ میں نے عرض کیا یا رسول اللہ! آپ وتر پڑھنے سے پہلے ہی سو جاتے ہیں؟ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ عائشہ! میری آنکھیں سوتی ہیں لیکن میرا دل نہیں سوتا۔' WHERE id = 1116;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید نے بیان کیا، انہوں نے کہا کہ ہم سے سعید بن ابی ایوب نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوالاسود محمد بن عبدالرحمٰن نے بیان کیا، ان سے عروہ بن زبیر رضی اللہ عنہ نے اور ان سے عائشہ صدیقہ رضی اللہ عنہا نے، انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم فجر کی دو سنت رکعتیں پڑھنے کے بعد دائیں کروٹ پر لیٹ جاتے۔' WHERE id = 1127;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے عمرو بن دینار سے بیان کیا، انہوں نے کہا کہ میں نے ابوالشعثاء جابر بن عبداللہ سے سنا، انہوں نے بیان کیا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ آٹھ رکعت ایک ساتھ ( ظہر اور عصر ) اور سات رکعت ایک ساتھ ( مغرب اور عشاء ملا کر ) پڑھیں۔ ( بیچ میں سنت وغیرہ کچھ نہیں ) ابوالشعثاء سے میں نے کہا میرا خیال ہے کہ آپ صلی اللہ علیہ وسلم نے ظہر آخر وقت میں اور عصر اول وقت میں پڑھی ہو گی۔ اسی طرح مغرب آخر وقت میں پڑھی ہو گی اور عشاء اول وقت میں۔ ابوالشعثاء نے کہا کہ میرا بھی یہی خیال ہے۔' WHERE id = 1140;
UPDATE hadiths SET urdu = 'ہم سے عبدالاعلی بن حماد نے بیان کیا، کہا کہ ہم سے وہیب بن خالد نے بیان کیا، ان سے ایوب سختیانی اور عبیداللہ بن عمر نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے گھروں میں بھی کچھ نمازیں پڑھا کرو اور انہیں بالکل قبریں نہ بنا لو ( کہ جہاں نماز ہی نہ پڑھی جاتی ہو ) وہیب کے ساتھ اس حدیث کو عبدالوہاب ثقفی نے بھی ایوب سے روایت کیا ہے۔' WHERE id = 1151;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن نمیر نے بیان کیا، کہا کہ ہم سے محمد بن فضیل نے بیان کیا، کہا کہ ہم سے اعمش نے بیان کیا، ان سے ابراہیم نے، ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ ( پہلے ) نبی کریم صلی اللہ علیہ وسلم نماز پڑھتے ہوتے اور ہم سلام کرتے تو آپ صلی اللہ علیہ وسلم اس کا جواب دیتے تھے۔ جب ہم نجاشی کے یہاں سے واپس ہوئے تو ہم نے ( پہلے کی طرح نماز ہی میں ) سلام کیا۔ لیکن اس وقت آپ صلی اللہ علیہ وسلم نے جواب نہیں دیا بلکہ نماز سے فارغ ہو کر فرمایا کہ نماز میں آدمی کو فرصت کہاں۔' WHERE id = 1162;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا کہ ہم سے امام مالک رحمہ اللہ نے بیان کیا، ان سے ابوالنضر سالم بن ابی امیہ نے، ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے عائشہ رضی اللہ عنہا نے فرمایا کہ میں اپنا پاؤں نبی کریم صلی اللہ علیہ وسلم کے سامنے پھیلا لیتی تھی اور آپ صلی اللہ علیہ وسلم نماز پڑھتے ہوتے جب آپ صلی اللہ علیہ وسلم سجدہ کرنے لگتے تو آپ صلی اللہ علیہ وسلم مجھے ہاتھ لگاتے، میں پاؤں سمیٹ لیتی، پھر جب آپ صلی اللہ علیہ وسلم کھڑے ہو جاتے تو میں پھیلا لیتی۔' WHERE id = 1173;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نماز میں پہلو پر ہاتھ رکھنے سے منع کیا گیا تھا۔ ہشام اور ابوہلال محمد بن سلیم نے، ابن سیرین سے اس حدیث کو روایت کیا، وہ ابوہریرہ رضی اللہ عنہ سے اور وہ نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 1183;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا کہ ہم سے یزید بن ابراہیم نے بیان کیا، ان سے محمد بن سیرین نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا، کہ نبی کریم صلی اللہ علیہ وسلم نے تیسرے پہر کی دو نمازوں ( ظہر یا عصر ) میں سے کوئی نماز پڑھی۔ میرا غالب گمان یہ ہے کہ وہ عصر ہی کی نماز تھی۔ اس میں آپ صلی اللہ علیہ وسلم نے صرف دو ہی رکعت پر سلام پھیر دیا۔ پھر آپ صلی اللہ علیہ وسلم ایک درخت کے تنے سے جو مسجد کی اگلی صف میں تھا، ٹیک لگا کر کھڑے ہو گئے۔ آپ صلی اللہ علیہ وسلم اپنا ہاتھ اس پر رکھے ہوئے تھے۔ حاضرین میں ابوبکر اور عمر رضی اللہ عنہما بھی تھے لیکن انہیں بھی کچھ کہنے کی ہمت نہیں ہوئی۔ جو ( جلد باز قسم کے ) لوگ نماز پڑھتے ہی مسجد سے نکل جانے کے عادی تھے۔ وہ باہر جا چکے تھے۔ لوگوں نے کہا کیا نماز کی رکعتیں کم ہو گئیں۔ ایک شخص جنہیں نبی کریم صلی اللہ علیہ وسلم ذوالیدین کہتے تھے۔ وہ بولے یا رسول اللہ! آپ بھول گئے یا نماز میں کمی ہو گئی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا نہ میں بھولا ہوں اور نہ نماز کی رکعتیں کم ہوئیں۔ ذوالیدین بولے کہ نہیں آپ بھول گئے ہیں۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے دو رکعت اور پڑھی اور سلام پھیرا پھر تکبیر کہی اور معمول کے مطابق یا اس سے بھی طویل سجدہ کیا۔ جب سجدہ سے سر اٹھایا تو پھر تکبیر کہی اور پھر تکبیر کہہ کر سجدہ میں گئے۔ یہ سجدہ بھی معمول کی طرح یا اس سے طویل تھا۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے سر اٹھایا اور تکبیر کہی۔' WHERE id = 1194;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے اشعث بن ابی الثعثاء نے، انہوں نے کہا کہ میں نے معاویہ بن سوید مقرن سے سنا، وہ براء بن عازب رضی اللہ عنہ سے نقل کرتے تھے کہ ہمیں نبی کریم صلی اللہ علیہ وسلم نے سات کاموں کا حکم دیا اور سات کاموں سے روکا۔ ہمیں آپ صلی اللہ علیہ وسلم نے حکم دیا تھا جنازہ کے ساتھ چلنے، مریض کی مزاج پرسی، دعوت قبول کرنے، مظلوم کی مدد کرنے کا، قسم پوری کرنے کا، سلام کا جواب دینے کا، چھینک پر «يرحمک الله» کہنے کا اور آپ صلی اللہ علیہ وسلم نے ہمیں منع کیا تھا چاندی کے برتن ( استعمال میں لانے ) سے، سونے کی انگوٹھی پہننے سے، ریشم اور دیباج ( کے کپڑوں کے پہننے ) سے، قسی سے، استبرق سے۔' WHERE id = 1204;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ایوب سختیانی نے اور ان سے محمد بن سیرین نے، ان سے ام عطیہ انصاری رضی اللہ عنہا نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کی بیٹی ( زینب یا ام کلثوم رضی اللہ عنہما ) کی وفات ہوئی آپ صلی اللہ علیہ وسلم وہاں تشریف لائے اور فرمایا کہ تین یا پانچ مرتبہ غسل دے دو اور اگر مناسب سمجھو تو اس سے بھی زیادہ دے سکتی ہو۔ غسل کے پانی میں بیری کے پتے ملا لو اور آخر میں کافور یا ( یہ کہا کہ ) کچھ کافور کا استعمال کر لینا اور غسل سے فارغ ہونے پر مجھے خبر دے دینا۔ چنانچہ ہم نے جب غسل دے لیا تو آپ صلی اللہ علیہ وسلم کو خبر دیدی۔ آپ صلی اللہ علیہ وسلم نے ہمیں اپنا ازار دیا اور فرمایا کہ اسے ان کی قمیص بنا دو۔ آپ صلی اللہ علیہ وسلم کی مراد اپنے ازار سے تھی۔' WHERE id = 1216;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا کہ ہم سے حماد نے، ان سے ایوب نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ایک شخص میدان عرفہ میں ( احرام باندھے ہوئے ) کھڑا ہوا تھا کہ اپنی سواری سے گر پڑا اور سواری نے انہیں کچل دیا۔ یا ( «وقصته‏» کے بجائے یہ لفظ ) «أوقصته» کہا۔ نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے فرمایا کہ پانی اور بیری کے پتوں سے غسل دے کر دو کپڑوں میں انہیں کفن دو اور یہ بھی ہدایت فرمائی کہ انہیں خوشبو نہ لگاؤ اور نہ ان کا سر چھپاؤ۔ کیونکہ یہ قیامت کے دن لبیک کہتا ہوا اٹھے گا۔' WHERE id = 1227;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا ‘ کہا کہ ہم کو عبداللہ بن مبارک نے خبر دی ‘ کہا کہ ہم کو شعبہ نے خبر دی ‘ انہیں سعد بن ابراہیم نے ‘ انہیں ان کے باپ ابراہیم بن عبدالرحمٰن نے کہ عبدالرحمٰن بن عوف رضی اللہ عنہ کے سامنے کھانا حاضر کیا گیا۔ وہ روزہ سے تھے اس وقت انہوں نے فرمایا کہ ہائے! مصعب بن عمیر رضی اللہ عنہ شہید کئے گئے ‘ وہ مجھ سے بہتر تھے۔ لیکن ان کے کفن کے لیے صرف ایک چادر میسر آ سکی کہ اگر اس سے ان کا سر ڈھانکا جاتا تو پاؤں کھل جاتے اور پاؤں ڈھانکے جاتے تو سر کھل جاتا اور میں سمجھتا ہوں کہ انہوں نے یہ بھی فرمایا اور حمزہ رضی اللہ عنہ بھی ( اسی طرح ) شہید ہوئے وہ بھی مجھ سے اچھے تھے۔ پھر ان کے بعد دنیا کی کشادگی ہمارے لیے خوب ہوئی یا یہ فرمایا کہ دنیا ہمیں بہت دی گئی اور ہمیں تو اس کا ڈر لگتا ہے کہ کہیں ایسا نہ ہو کہ ہماری نیکیوں کا بدلہ اسی دنیا میں ہم کو مل گیا ہو پھر آپ اس طرح رونے لگے کہ کھانا بھی چھوڑ دیا۔' WHERE id = 1237;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن خلیل نے بیان کیا ‘ ان سے علی بن مسہر نے بیان کیا ‘ ان سے ابواسحاق شیبانی نے ‘ ان سے ابوبردہ نے اور ان سے ان کے والد ابوموسیٰ اشعری نے کہ جب عمر رضی اللہ کو زخمی کیا گیا تو صہیب رضی اللہ عنہ یہ کہتے ہوئے آئے ‘ ہائے میرے بھائی! اس پر عمر رضی اللہ عنہ نے فرمایا کہ کیا تجھ کو معلوم نہیں کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہے کہ مردے کو اس کے گھر والوں کے رونے سے عذاب کیا جاتا ہے۔' WHERE id = 1249;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا ‘ ان سے محمد بن فضیل نے بیان کیا ‘ ان سے عاصم احول نے اور ان سے انس رضی اللہ عنہ نے کہ جب قاریوں کی ایک جماعت شہید کر دی گئی تو رسول اللہ صلی اللہ علیہ وسلم ایک مہینہ تک قنوت پڑھتے رہے۔ میں نے نبی کریم صلی اللہ علیہ وسلم کو کبھی نہیں دیکھا کہ آپ صلی اللہ علیہ وسلم ان دنوں سے زیادہ کبھی غمگین رہے ہوں۔' WHERE id = 1259;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا ‘ انہوں نے کہا ہم سے ہشام دستوائی نے بیان کیا ‘ ان سے یحییٰ بن ابی کثیر نے، ان سے ابوسلمہ اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب تم لوگ جنازہ دیکھو تو کھڑے ہو جاؤ اور جو شخص جنازہ کے ساتھ چل رہا ہو وہ اس وقت تک نہ بیٹھے جب تک جنازہ رکھ نہ دیا جائے۔' WHERE id = 1269;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ کہا کہ ہم سے شعبہ نے ‘ ان سے شیبانی نے اور ان سے شعبی نے بیان کیا کہ مجھے اس صحابی نے خبر دی تھی جو نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک الگ تھلگ قبر پر سے گزرا۔ وہ کہتا تھا کہ آپ صلی اللہ علیہ وسلم نے ہماری امامت کی اور ہم نے آپ صلی اللہ علیہ وسلم کے پیچھے صفیں بنا لیں۔ ہم نے پوچھا کہ ابوعمرو ( یہ شعبی کی کنیت ہے ) یہ آپ سے بیان کرنے والے کون صحابی ہیں؟ فرمایا کہ عبداللہ بن عباس رضی اللہ عنہما۔' WHERE id = 1280;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا۔ کہا کہ ہم سے غندر (محمد بن جعفر) نے بیان کیا ‘ کہا کہ ہم سے شعبہ نے بیان کیا ‘ ان سے سعد بن ابراہیم نے اور ان سے طلحہ نے کہا کہ میں نے ابن عباس رضی اللہ عنہما کی اقتداء میں نماز ( جنازہ ) پڑھی ( دوسری سند ) ہم سے محمد بن کثیر نے بیان کیا ‘ کہا کہ ہمیں سفیان ثوری نے خبر دی ‘ انہیں سعد بن ابراہیم نے ‘ انہیں طلحہ بن عبداللہ بن عوف نے ‘ انہوں نے بتلایا کہ میں نے ابن عباس رضی اللہ عنہما کے پیچھے نماز جنازہ پڑھی تو آپ نے سورۃ فاتحہ ( ذرا پکار کر ) پڑھی۔ پھر فرمایا کہ تمہیں معلوم ہونا چاہیے کہ یہی طریقہ نبوی ہے۔' WHERE id = 1291;
UPDATE hadiths SET urdu = 'ہم سے سعید بن سلیمان نے بیان کیا ‘ انہوں نے کہا کہ ہم سے لیث نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ابن شہاب نے بیان کیا۔ ان سے عبدالرحمٰن بن کعب نے کہ جابر بن عبداللہ رضی اللہ عنہما نے انہیں خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نے احد کے دو دو شہیدوں کو دفن کرنے میں ایک ساتھ جمع فرمایا تھا۔' WHERE id = 1301;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا کہ ہم کو شعیب نے خبر دی ‘ انہوں نے بیان کیا کہ ابن شہاب ہر اس بچے کی جو وفات پا گیا ہو نماز جنازہ پڑھتے تھے۔ اگرچہ وہ حرام ہی کا بچہ کیوں نہ ہو کیونکہ اس کی پیدائش اسلام کی فطرت پر ہوئی۔ یعنی اس صورت میں جب کہ اس کے والدین مسلمان ہونے کے دعویدار ہوں۔ اگر صرف باپ مسلمان ہو اور ماں کا مذہب اسلام کے سوا کوئی اور ہو جب بھی بچہ کے رونے کی پیدائش کے وقت اگر آواز سنائی دیتی تو اس پر نماز پڑھی جاتی۔ لیکن اگر پیدائش کے وقت کوئی آواز نہ آتی تو اس کی نماز نہیں پڑھی جاتی تھی۔ بلکہ ایسے بچے کو کچا حمل گر جانے کے درجہ میں سمجھا جاتا تھا۔ کیونکہ ابوہریرہ رضی اللہ عنہ نے روایت کیا ہے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر بچہ فطرت ( اسلام ) پر پیدا ہوتا ہے۔ پھر اس کے ماں باپ اسے یہودی یا نصرانی یا مجوسی بنا دیتے ہیں جس طرح تم دیکھتے ہو کہ جانور صحیح سالم بچہ جنتا ہے۔ کیا تم نے کوئی کان کٹا ہوا بچہ بھی دیکھا ہے؟ پھر ابوہریرہ رضی اللہ عنہ نے اس آیت کو تلاوت کیا۔ «فطرة الله التي فطر الناس عليها‏‏‏» الآية‏ ”یہ اللہ کی فطرت ہے جس پر اس نے لوگوں کو پیدا کیا ہے۔“' WHERE id = 1312;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ کہا ہم سے یعقوب بن ابراہیم نے ‘ ان سے ان کے والد نے ‘ ان سے صالح نے ‘ ان سے نافع نے کہ ابن عمر رضی اللہ عنہما نے انہیں خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کنویں والوں ( جس میں بدر کے مشرک مقتولین کو ڈال دیا گیا تھا ) کے قریب آئے اور فرمایا تمہارے مالک نے جو تم سے سچا وعدہ کیا تھا اسے تم لوگوں نے پا لیا۔ لوگوں نے عرض کیا کہ آپ صلی اللہ علیہ وسلم مردوں کو خطاب کرتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم کچھ ان سے زیادہ سننے والے نہیں ہو البتہ وہ جواب نہیں دے سکتے۔' WHERE id = 1323;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا ‘ ان سے سعید بن ابی سعید نے بیان کیا ‘ ان سے ان کے باپ نے بیان کیا ‘ ان سے ابو سعید خدری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب جنازہ تیار ہو جاتا ہے پھر مرد اس کو اپنی گردنوں پر اٹھا لیتے ہیں تو اگر وہ مردہ نیک ہو تو کہتا ہے کہ ہاں آگے لیے چلو مجھے بڑھائے چلو اور اگر نیک نہیں ہوتا تو کہتا ہے۔ ہائے رے خرابی! میرا جنازہ کہاں لیے جا رہے ہو۔ اس آواز کو انسان کے سوا تمام اللہ کی مخلوق سنتی ہے۔ اگر کہیں انسان سن پائیں تو بیہوش ہو جائیں۔' WHERE id = 1333;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ابوعوانہ نے بیان کیا ‘ ان سے ہلال بن حمید نے ‘ ان سے عروہ نے اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے اس مرض کے موقع پر فرمایا تھا جس سے آپ صلی اللہ علیہ وسلم جانبر نہ ہو سکے تھے کہ اللہ تعالیٰ کی یہود و نصاریٰ پر لعنت ہو۔ انہوں نے اپنے انبیاء کی قبروں کو مساجد بنا لیا۔ اگر یہ ڈر نہ ہوتا تو آپ صلی اللہ علیہ وسلم کی قبر بھی کھلی رہنے دی جاتی۔ لیکن ڈر اس کا ہے کہ کہیں اسے بھی لوگ سجدہ گاہ نہ بنا لیں۔ اور ہلال سے روایت ہے کہ عروہ بن زبیر نے میری کنیت ( ابوعوانہ یعنی عوانہ کے والد ) رکھ دی تھی ورنہ میرے کوئی اولاد نہ تھی۔' WHERE id = 1343;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن نمیر نے بیان کیا ‘ کہا کہ مجھ سے میرے والد نے بیان کیا ‘ کہا کہ ہم سے اسماعیل بن خالد نے بیان کیا ‘ ان سے قیس بن ابی حازم نے بیان کیا کہ جریر بن عبداللہ رضی اللہ عنہ نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے نماز قائم کرنے ‘ زکوٰۃ دینے اور ہر مسلمان کے ساتھ خیر خواہی کرنے پر بیعت کی تھی۔' WHERE id = 1355;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا کہ ہم سے ابوعاصم نبیل نے بیان کیا ‘ کہا کہ ہمیں سعدان بن بشیر نے خبر دی ‘ کہا کہ ہم سے ابومجاہد سعد طائی نے بیان کیا ‘ کہا کہ ہم سے محل بن خلیفہ طائی نے بیان کیا ‘ کہا کہ میں نے عدی بن حاتم طائی رضی اللہ عنہ سے سنا ‘ انہوں نے کہا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں موجود تھا کہ دو شخص آئے ‘ ایک فقر و فاقہ کی شکایت لیے ہوئے تھا اور دوسرے کو راستوں کے غیر محفوظ ہونے کی شکایت تھی۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جہاں تک راستوں کے غیر محفوظ ہونے کا تعلق ہے تو بہت جلد ایسا زمانہ آنے والا ہے کہ جب ایک قافلہ مکہ سے کسی محافظ کے بغیر نکلے گا۔ ( اور اسے راستے میں کوئی خطرہ نہ ہو گا ) اور رہا فقر و فاقہ تو قیامت اس وقت تک نہیں آئے گی جب تک ( مال و دولت کی کثرت کی وجہ سے یہ حال نہ ہو جائے کہ ) ایک شخص اپنا صدقہ لے کر تلاش کرے لیکن کوئی اسے لینے والا نہ ملے۔ پھر اللہ تعالیٰ کے درمیان کوئی پردہ نہ ہو گا اور نہ ترجمانی کے لیے کوئی ترجمان ہو گا۔ پھر اللہ تعالیٰ اس سے پوچھے گا کہ کیا میں نے تجھے دنیا میں مال نہیں دیا تھا؟ وہ کہے گا کہ ہاں دیا تھا۔ پھر اللہ تعالیٰ پوچھے گا کہ کیا میں نے تیرے پاس پیغمبر نہیں بھیجا تھا؟ وہ کہے گا کہ ہاں بھیجا تھا۔ پھر وہ شخص اپنے دائیں طرف دیکھے گا تو آگ کے سوا اور کچھ نظر نہیں آئے گا پھر بائیں طرف دیکھے گا اور ادھر بھی آگ ہی آگ ہو گی۔ پس تمہیں جہنم سے ڈرنا چاہیے خواہ ایک کھجور کے ٹکڑے ہی ( کا صدقہ کر کے اس سے اپنا بچاؤ کر سکو ) اگر یہ بھی میسر نہ آ سکے تو اچھی بات ہی منہ سے نکالے۔' WHERE id = 1366;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا عبیداللہ عمری سے، انہوں نے کہا کہ مجھ سے خبیب بن عبدالرحمٰن نے حفص بن عاصم سے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا سات قسم کے آدمیوں کو اللہ تعالیٰ اپنے ( عرش کے ) سایہ میں رکھے گا جس دن اس کے سوا اور کوئی سایہ نہ ہو گا۔ انصاف کرنے والا حاکم ‘ وہ نوجوان جو اللہ تعالیٰ کی عبادت میں جوان ہوا ہو ‘ وہ شخص جس کا دل ہر وقت مسجد میں لگا رہے ‘ دو ایسے شخص جو اللہ کے لیے محبت رکھتے ہیں ‘ اسی پر وہ جمع ہوئے اور اسی پر جدا ہوئے ‘ ایسا شخص جسے کسی خوبصورت اور عزت دار عورت نے بلایا لیکن اس نے یہ جواب دیا کہ میں اللہ سے ڈرتا ہوں ‘ وہ انسان جو صدقہ کرے اور اسے اس درجہ چھپائے کہ بائیں ہاتھ کو بھی خبر نہ ہو کہ داہنے ہاتھ نے کیا خرچ کیا اور وہ شخص جو اللہ کو تنہائی میں یاد کرے اور اس کی آنکھیں آنسوؤں سے بہنے لگ جائیں۔' WHERE id = 1376;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا ‘ کہا کہ ہم سے جریر نے اعمش سے بیان کیا ‘ ان سے ابووائل نے ‘ انہوں نے حذیفہ بن یمان رضی اللہ عنہ سے کہ عمر بن خطاب رضی اللہ عنہ نے فرمایا کہ فتنہ سے متعلق رسول اللہ صلی اللہ علیہ وسلم کی حدیث آپ لوگوں میں کس کو یاد ہے؟ حذیفہ رضی اللہ عنہ نے بیان کیا کہ میں نے کہا میں اس طرح یاد رکھتا ہوں جس طرح نبی کریم صلی اللہ علیہ وسلم نے اس کو بیان فرمایا تھا۔ اس پر عمر رضی اللہ عنہ نے فرمایا کہ تمہیں اس کے بیان پر جرات ہے۔ اچھا تو نبی کریم صلی اللہ علیہ وسلم نے فتنوں کے بارے میں کیا فرمایا تھا؟ میں نے کہا کہ ( آپ صلی اللہ علیہ وسلم نے فرمایا تھا ) انسان کی آزمائش ( فتنہ ) اس کے خاندان ‘ اولاد اور پڑوسیوں میں ہوتی ہے اور نماز ‘ صدقہ اور اچھی باتوں کے لیے لوگوں کو حکم کرنا اور بری باتوں سے منع کرنا اس فتنے کا کفارہ بن جاتی ہیں۔ اعمش نے کہا ابووائل کبھی یوں کہتے تھے۔ نماز اور صدقہ اور اچھی باتوں کا حکم دینا بری بات سے روکنا ‘ یہ اس فتنے کو مٹا دینے والے نیک کام ہیں۔ پھر اس فتنے کے متعلق عمر رضی اللہ عنہ نے فرمایا کہ میری مراد اس فتنہ سے نہیں۔ میں اس فتنے کے بارے میں پوچھنا چاہتا ہوں جو سمندر کی طرح ٹھاٹھیں مارتا ہوا پھیلے گا۔ حذیفہ رضی اللہ عنہ نے بیان کیا ‘ میں نے کہا کہ امیرالمؤمنین آپ اس فتنے کی فکر نہ کیجئے آپ کے اور اس فتنہ کے درمیان ایک بند دروازہ ہے۔ عمر رضی اللہ عنہ نے پوچھا کہ وہ دروازہ توڑ دیا جائے گا یا صرف کھولا جائے گا۔ انہوں نے بتلایا نہیں بلکہ وہ دروازہ توڑ دیا جائے گا۔ اس پر عمر رضی اللہ عنہ نے فرمایا کہ جب دروازہ توڑ دیا جائے گا تو پھر کبھی بھی بند نہ ہو سکے گا ابووائل نے کہا کہ ہاں پھر ہم رعب کی وجہ سے حذیفہ رضی اللہ عنہ سے یہ نہ پوچھ سکے کہ وہ دروازہ کون ہے؟ اس لیے ہم نے مسروق سے کہا کہ تم پوچھو۔ انہوں نے کہا کہ مسروق رحمتہ اللہ علیہ نے پوچھا تو حذیفہ رضی اللہ عنہ نے فرمایا کہ دروازہ سے مراد خود عمر رضی اللہ عنہ ہی تھے۔ ہم نے پھر پوچھا تو کیا عمر رضی اللہ عنہ جانتے تھے کہ آپ کی مراد کون تھی؟ انہوں نے کہا ہاں جیسے دن کے بعد رات کے آنے کو جانتے ہیں اور یہ اس لیے کہ میں نے جو حدیث بیان کی وہ غلط نہیں تھی۔' WHERE id = 1387;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا ‘ کہا کہ ہم سے شعبہ نے بیان کیا ‘ کہا کہ ہم سے سعید بن ابی بردہ نے بیان کیا ‘ ان سے ان کے باپ ابوبردہ نے ان کے دادا ابوموسیٰ اشعری سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر مسلمان پر صدقہ کرنا ضروری ہے۔ لوگوں نے پوچھا اے اللہ کے نبی! اگر کسی کے پاس کچھ نہ ہو؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر اپنے ہاتھ سے کچھ کما کر خود کو بھی نفع پہنچائے اور صدقہ بھی کرے۔ لوگوں نے کہا اگر اس کی طاقت نہ ہو؟ فرمایا کہ پھر کسی حاجت مند فریادی کی مدد کرے۔ لوگوں نے کہا اگر اس کی بھی سکت نہ ہو۔ فرمایا پھر اچھی بات پر عمل کرے اور بری باتوں سے باز رہے۔ اس کا یہی صدقہ ہے۔' WHERE id = 1397;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے میرے باپ نے بیان کیا ‘ انہوں نے کہا مجھ سے ثمامہ نے بیان کیا ‘ ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے انہیں رسول اللہ صلی اللہ علیہ وسلم کے بیان کردہ احکام زکوٰۃ کے مطابق لکھا کہ زکوٰۃ میں بوڑھے، عیبی اور نر نہ لیے جائیں ‘ البتہ اگر صدقہ وصول کرنے والا مناسب سمجھے تو لے سکتا ہے۔' WHERE id = 1407;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا ‘ کہا کہ ہم سے عبدہ نے ‘ ان سے ہشام نے بیان کیا ‘ ان سے ان کے باپ نے ‘ ان سے زینب بنت ام سلمہ نے ‘ ان سے ام سلمہ نے ‘ انہوں نے کہا کہ میں نے عرض کیا ‘ یا رسول اللہ! اگر میں ابوسلمہ ( اپنے پہلے خاوند ) کے بیٹوں پر خرچ کروں تو درست ہے یا نہیں۔ کیونکہ وہ میری بھی اولاد ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں ان پر خرچ کر۔ تو جو کچھ بھی ان پر خرچ کرے گی اس کا ثواب تجھ کو ملے گا۔' WHERE id = 1418;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا ‘ کہا کہ مجھ سے امام مالک رحمہ اللہ نے ابوالزناد سے بیان کیا ‘ ان سے اعرج نے ‘ اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا مسکین وہ نہیں ہے جو لوگوں کا چکر کاٹتا پھرتا ہے تاکہ اسے دو ایک لقمہ یا دو ایک کھجور مل جائیں۔ بلکہ اصلی مسکین وہ ہے جس کے پاس اتنا مال نہیں کہ وہ اس کے ذریعہ سے بےپرواہ ہو جائے۔ اس حال میں بھی کسی کو معلوم نہیں کہ کوئی اسے صدقہ ہی دیدے اور نہ وہ خود ہاتھ پھیلانے کے لیے اٹھتا ہے۔' WHERE id = 1429;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا ‘ انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے محمد بن زیاد نے بیان کیا ‘ کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ حسن بن علی رضی اللہ عنہما نے زکوٰۃ کی کھجوروں کے ڈھیر سے ایک کھجور اٹھا کر اپنے منہ میں ڈال لی تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا۔ چھی چھی! نکالو اسے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا تمہیں معلوم نہیں کہ ہم لوگ صدقہ کا مال نہیں کھاتے۔' WHERE id = 1440;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا کہ ہم سے یحییٰ قطان نے بیان کیا ‘ ان سے شعبہ نے کہا کہ ہم سے قتادہ نے بیان کیا ‘ اور ان سے انس رضی اللہ عنہ نے کہ عرینہ کے کچھ لوگوں کو مدینہ کی آب و ہوا موافق نہیں آئی۔ رسول اللہ صلی اللہ علیہ وسلم نے انہیں اس کی اجازت دے دی کہ وہ زکوٰۃ کے اونٹوں میں جا کر ان کا دودھ اور پیشاب استعمال کریں ( کیونکہ وہ ایسے مرض میں مبتلا تھے جس کی دوا یہی تھی ) لیکن انہوں نے ( ان اونٹوں کے ) چرواہے کو مار ڈالا اور اونٹوں کو لے کر بھاگ نکلے۔ رسول اللہ صلی اللہ علیہ وسلم نے ان کے پیچھے آدمی دوڑائے آخر وہ لوگ پکڑ لائے گئے۔ آپ صلی اللہ علیہ وسلم نے ان کے ہاتھ اور پاؤں کٹوا دئیے اور ان کی آنکھوں میں گرم سلائیاں پھروا دیں پھر انہیں دھوپ میں ڈلوا دیا ( جس کی شدت کی وجہ سے ) وہ پتھر چبانے لگے تھے۔ اس روایت کی متابعت ابوقلابہ ثابت اور حمید نے انس رضی اللہ عنہ کے واسطہ سے کی ہے۔' WHERE id = 1450;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا ‘ انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ایوب نے بیان کیا ‘ ان سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے صدقہ فطر یا یہ کہا کہ صدقہ رمضان مرد، عورت، آزاد اور غلام ( سب پر ) ایک صاع کھجور یا ایک صاع جَو فرض قرار دیا تھا۔ پھر لوگوں نے آدھا صاع گیہوں اس کے برابر قرار دے لیا۔ لیکن ابن عمر رضی اللہ عنہما کھجور دیا کرتے تھے۔ ایک مرتبہ مدینہ میں کھجور کا قحط پڑا تو آپ نے جو صدقہ میں نکالا۔ ابن عمر رضی اللہ عنہما چھوٹے بڑے سب کی طرف سے یہاں تک کہ میرے بیٹوں کی طرف سے بھی صدقہ فطر نکالتے تھے۔ ابن عمر رضی اللہ عنہما صدقہ فطر ہر فقیر کو جو اسے قبول کرتا، دے دیا کرتے تھے۔ اور لوگ صدقہ فطر ایک یا دو دن پہلے ہی دے دیا کرتے تھے۔ امام بخاری رحمہ اللہ نے کہا میرے بیٹوں سے نافع کے بیٹے مراد ہیں۔ امام بخاری رحمہ اللہ نے کہا وہ عید سے پہلے جو صدقہ دے دیتے تھے تو اکٹھا ہونے کے لیے نہ فقیروں کے لیے ( پھر وہ جمع کر کے فقراء میں تقسیم کر دیا جاتا ) ۔' WHERE id = 1460;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے سیارابوالحکم نے بیان کیا، کہا کہ میں نے ابو حزم سے سنا، انہوں نے بیان کیا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا کہ آپ صلی اللہ علیہ وسلم نے فرمایا جس شخص نے اللہ کے لیے اس شان کے ساتھ حج کیا کہ نہ کوئی فحش بات ہوئی اور نہ کوئی گناہ تو وہ اس دن کی طرح واپس ہو گا جیسے اس کی ماں نے اسے جنا تھا۔' WHERE id = 1470;
UPDATE hadiths SET urdu = 'ہم سے علی بن مسلم نے بیان کیا، کہا کہ ہم سے عبداللہ بن نمیر نے بیان کیا، کہا کہ ہم سے عبیداللہ عمری نے نافع سے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ جب یہ دو شہر ( بصرہ اور کوفہ ) فتح ہوئے تو لوگ عمر رضی اللہ عنہ کے پاس آئے اور کہا کہ یا امیرالمؤمنین رسول اللہ صلی اللہ علیہ وسلم نے نجد کے لوگوں کے لیے احرام باندھنے کی جگہ قرن المنازل قرار دی ہے اور ہمارا راستہ ادھر سے نہیں ہے، اگر ہم قرن کی طرف جائیں تو ہمارے لیے بڑی دشواری ہو گی۔ اس پر عمر رضی اللہ عنہ نے فرمایا کہ پھر تم لوگ اپنے راستے میں اس کے برابر کوئی جگہ تجویز کر لو۔ چنانچہ ان کے لیے ذات عرق کی تعیین کر دی۔' WHERE id = 1480;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر مقدمی نے بیان کیا، کہا کہ ہم سے فضیل بن سلیمان نے بیان کیا، کہا کہ ہم سے موسیٰ بن عقبہ نے بیان کیا، کہا کہ مجھے کریب نے خبر دی اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ حجتہ الوداع میں ظہر اور عصر کے درمیان ہفتہ کے دن نبی کریم صلی اللہ علیہ وسلم کنگھا کرنے اور تیل لگانے اور ازار اور رداء پہننے کے بعد اپنے صحابہ کے ساتھ مدینہ سے نکلے۔ آپ صلی اللہ علیہ وسلم نے اس وقت زعفران میں رنگے ہوئے ایسے کپڑے کے سوا جس کا رنگ بدن پر لگتا ہو کسی قسم کی چادر یا تہبند پہننے سے منع نہیں کیا۔ دن میں آپ صلی اللہ علیہ وسلم ذوالحلیفہ پہنچ گئے ( اور رات وہیں گزاری ) پھر آپ صلی اللہ علیہ وسلم سوار ہوئے اور بیداء سے آپ صلی اللہ علیہ وسلم نے اور آپ صلی اللہ علیہ وسلم کے ساتھیوں نے لبیک کہا اور احرام باندھا اور اپنے اونٹوں کو ہار پہنایا۔ ذی قعدہ کے مہینے میں اب پانچ دن رہ گئے تھے پھر جب آپ صلی اللہ علیہ وسلم مکہ پہنچے تو ذی الحجہ کے چار دن گزر چکے تھے۔ آپ صلی اللہ علیہ وسلم نے بیت اللہ کا طواف کیا اور صفا اور مروہ کی سعی کی، آپ صلی اللہ علیہ وسلم ابھی حلال نہیں ہوئے کیونکہ قربانی کے جانور آپ صلی اللہ علیہ وسلم کے ساتھ تھے اور آپ صلی اللہ علیہ وسلم نے ان کی گردن میں ہار ڈال دیا تھا۔ آپ صلی اللہ علیہ وسلم حجون پہاڑ کے نزدیک مکہ کے بالائی حصہ میں اترے۔ حج کا احرام اب بھی باقی تھا۔ بیت اللہ کے طواف کے بعد پھر آپ صلی اللہ علیہ وسلم وہاں اس وقت تک تشریف نہیں لے گئے جب تک میدان عرفات سے واپس نہ ہو لیے۔ آپ صلی اللہ علیہ وسلم نے اپنے ساتھیوں کو حکم دیا تھا کہ وہ بیت اللہ کا طواف کریں اور صفا و مروہ کے درمیان سعی کریں، پھر اپنے سروں کے بال ترشوا کر حلال ہو جائیں۔ یہ فرمان ان لوگوں کے لیے تھا جن کے ساتھ قربانی کے جانور نہیں تھے۔ اگر کسی کے ساتھ اس کی بیوی تھی تو وہ اس سے ہمبستر ہو سکتا تھا۔ اسی طرح خوشبودار اور ( سلے ہوئے ) کپڑے کا استعمال بھی اس کے لیے جائز تھا۔' WHERE id = 1492;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا کہ ہم سے ابن عدی نے بیان کیا، ان سے عبداللہ بن عون نے ان سے مجاہد نے بیان کیا، کہا کہ ہم عبداللہ بن عباس رضی اللہ عنہما کی خدمت میں حاضر تھے۔ لوگوں نے دجال کا ذکر کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہے کہ اس کی دونوں آنکھوں کے درمیان کافر لکھا ہوا ہو گا۔ تو ابن عباس رضی اللہ عنہما نے فرمایا کہ میں نے تو یہ نہیں سنا۔ ہاں آپ صلی اللہ علیہ وسلم نے یہ فرمایا تھا کہ گویا میں موسیٰ علیہ السلام کو دیکھ رہا ہوں کہ جب آپ نالے میں اترے تو لبیک کہہ رہے ہیں۔' WHERE id = 1502;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا کہ ہم سے محمد بن جعفر غندر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے قیس بن مسلم نے، ان سے طارق بن شہاب نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ( حجتہ الوداع کے موقع پر یمن سے ) حاضر ہوا تو آپ صلی اللہ علیہ وسلم نے ( مجھ کو عمرہ کے بعد ) احرام کھول دینے کا حکم دیا۔' WHERE id = 1512;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، ان سے معن بن عیسیٰ نے بیان کیا، ان سے امام مالک رحمہ اللہ نے بیان کیا، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم مکہ میں بلند گھاٹی ( یعنی جنت المعلیٰ ) کی طرف سے داخل ہوتے اور نکلتے ”ثنیہ سفلیٰ“ کی طرف سے یعنی نیچے کی گھاٹی ( باب شبیکہ ) کی طرف سے۔' WHERE id = 1522;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے بیان کیا، ان سے ان کے والد نے اور ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے فرمایا، اگر تمہاری قوم کا زمانہ کفر سے ابھی تازہ نہ ہوتا تو میں خانہ کعبہ کو توڑ کر اسے ابراہیم علیہ السلام کی بنیاد پر بناتا کیونکہ قریش نے اس میں کمی کر دی ہے۔ اس میں ایک دروازہ اور اس دروازے کے مقابل رکھتا۔ ابومعاویہ نے کہا ہم سے ہشام نے بیان کیا۔ حدیث میں «خلف» سے دروازہ مراد ہے۔' WHERE id = 1532;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی فلاس نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، کہا کہ ہم سے عبیداللہ بن اخنس نے بیان کیا، کہا کہ مجھ سے ابن ابی ملیکہ نے بیان کیا، ان سے عبداللہ بن عباس رضی اللہ عنہما نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”گویا میری نظروں کے سامنے وہ پتلی ٹانگوں والا سیاہ آدمی ہے جو خانہ کعبہ کے ایک ایک پتھر کو اکھاڑ پھینکے گا۔“' WHERE id = 1542;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا کہ ہمیں محمد بن جعفر نے خبر دی، کہا کہ مجھے زید بن اسلم نے خبر دی، انہیں ان کے والد نے کہ عمر بن خطاب رضی اللہ عنہ نے حجر اسود کو خطاب کر کے فرمایا ”بخدا مجھے خوب معلوم ہے کہ تو صرف ایک پتھر ہے جو نہ کوئی نفع پہنچا سکتا ہے نہ نقصان اور اگر میں نے رسول اللہ صلی اللہ علیہ وسلم کو تجھے بوسہ دیتے نہ دیکھا ہوتا تو میں کبھی بوسہ نہ دیتا۔“ اس کے بعد آپ نے بوسہ دیا۔ پھر فرمایا ”اور اب ہمیں رمل کی بھی کیا ضرورت ہے۔ ہم نے اس کے ذریعہ مشرکوں کو اپنی قوت دکھائی تھی تو اللہ نے ان کو تباہ کر دیا۔“ پھر فرمایا ”جو عمل رسول اللہ صلی اللہ علیہ وسلم نے کیا ہے اسے اب چھوڑنا بھی ہم پسند نہیں کرتے۔“' WHERE id = 1552;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا کہ ہم سے انس بن عیاض نے بیان کیا، ان سے عبیداللہ عمری نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم جب بیت اللہ کا پہلا طواف ( یعنی طواف قدوم ) کرتے تو اس کے تین چکروں میں آپ صلی اللہ علیہ وسلم دوڑ کر چلتے اور چار میں معمول کے موافق چلتے پھر جب صفا اور مروہ کی سعی کرتے تو ”بطن مسیل“ ( وادی ) میں دوڑ کر چلتے۔' WHERE id = 1563;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا کہ ہم سے ابوضمرہ نے بیان کیا، کہا کہ ہم سے موسیٰ بن عقبہ نے بیان کیا، ان سے نافع نے کہ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا، میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے۔ آپ صلی اللہ علیہ وسلم سورج طلوع ہوتے اور غروب ہوتے وقت نماز پڑھنے سے روکتے تھے۔' WHERE id = 1574;
UPDATE hadiths SET urdu = 'ہم سے احمد بن عیسیٰ نے بیان کیا، انہوں نے کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا کہ مجھے عمرو بن حارث نے خبر دی، انہیں محمد بن عبدالرحمٰن بن نوفل قرشی نے، انہوں نے عروہ بن زبیر سے پوچھا تھا، عروہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے جیسا کہ معلوم ہے حج کیا تھا۔ مجھے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے اس کے متعلق خبر دی کہ جب آپ مکہ معظمہ آئے تو سب سے پہلا کام یہ کیا کہ آپ نے وضو کیا، پھر کعبہ کا طواف کیا۔ یہ آپ کا عمرہ نہیں تھا۔ اس کے بعد ابوبکر رضی اللہ عنہ نے حج کیا اور آپ نے بھی سب سے پہلے کعبہ کا طواف کیا جب کہ یہ آپ کا بھی عمرہ نہیں تھا۔ عمر رضی اللہ عنہ نے بھی اسی طرح کیا۔ پھر عثمان رضی اللہ عنہ نے حج کیا میں نے دیکھا کہ سب سے پہلے آپ نے بھی کعبہ کا طواف کیا۔ آپ کا بھی یہ عمرہ نہیں تھا۔ پھر معاویہ اور عبداللہ بن عمر رضی اللہ عنہم کا زمانہ آیا۔ پھر میں نے اپنے والد زبیر بن عوام رضی اللہ عنہ کے ساتھ بھی حج کیا۔ یہ ( سارے اکابر ) پہلے کعبہ ہی کے طواف سے شروع کرتے تھے جب کہ یہ عمرہ نہیں ہوتا تھا۔ اس کے بعد مہاجرین و انصار کو بھی میں نے دیکھا کہ وہ بھی اسی طرح کرتے رہے اور ان کا بھی یہ عمرہ نہیں ہوتا تھا۔ آخری ذات جسے میں نے اس طرح کرتے دیکھا، وہ عبداللہ بن عمر رضی اللہ عنہما کی تھی۔ انہوں نے بھی عمرہ نہیں کیا تھا۔ ابن عمر رضی اللہ عنہما ابھی موجود ہیں لیکن ان سے لوگ اس کے متعلق پوچھتے نہیں۔ اسی طرح جو حضرات گزر گئے، ان کا بھی مکہ میں داخل ہوتے ہی سب سے پہلا قدم طواف کے لے اٹھتا تھا۔ پھر یہ بھی احرام نہیں کھولتے تھے۔ میں نے اپنی والدہ ( اسماء بنت ابی بکر رضی اللہ عنہما ) اور خالہ ( عائشہ صدیقہ رضی اللہ عنہا ) کو بھی دیکھا کہ جب وہ آتیں تو سب سے پہلے طواف کرتیں اور یہ اس کے بعد احرام نہیں کھولتی تھیں۔' WHERE id = 1585;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا کہ ہم سے اسحاق ازرق نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے عبدالعزیز بن رفیع کے واسطے سے بیان کیا، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم نے ظہر اور عصر کی نماز آٹھویں ذی الحجہ میں کہاں پڑھی تھی؟ اگر آپ کو نبی کریم صلی اللہ علیہ وسلم سے یاد ہے تو مجھے بتائیے۔ انہوں نے جواب دیا کہ منیٰ میں۔ میں نے پوچھا کہ بارہویں تاریخ کو عصر کہاں پڑھی تھی؟ فرمایا کہ محصب میں۔ پھر انہوں نے فرمایا کہ جس طرح تمہارے حکام کرتے ہیں اسی طرح تم بھی کرو۔' WHERE id = 1595;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں سالم بن عبداللہ نے کہ عبدالملک بن مروان (خلیفہ) نے حجاج کو لکھا کہ حج کے کاموں میں عبداللہ بن عمر رضی اللہ عنہما کی اقتداء کرے۔ جب عرفہ کا دن آیا تو عبداللہ بن عمر رضی اللہ عنہما آئے میں بھی آپ کے ساتھ تھا، سورج ڈھل چکا تھا، آپ نے حجاج کے ڈیرے کے پاس آ کر بلند آواز سے کہا حجاج کہاں ہے؟ حجاج باہر نکلا تو ابن عمر رضی اللہ عنہما نے فرمایا چل جلدی کر وقت ہو گیا۔ حجاج نے کہا ابھی سے؟ ابن عمر رضی اللہ عنہما نے فرمایا کہ ہاں۔ حجاج بولا کہ پھر تھوڑی مہلت دے دیجئیے، میں ابھی غسل کر کے آتا ہوں۔ پھر عبداللہ بن عمر رضی اللہ عنہما ( اپنی سواری سے ) اتر گئے۔ حجاج باہر نکلا اور میرے اور میرے والد ( ابن عمر ) کے بیچ میں چلنے لگا، میں نے اس سے کہا کہ آج اگر سنت پر عمل کی خواہش ہے تو خطبہ مختصر پڑھ اور وقوف میں جلدی کر۔ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ سالم سچ کہتا ہے۔' WHERE id = 1605;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا، کہا کہ ہم سے زہیر نے بیان کیا، کہا کہ ہم سے ابواسحٰق عمرو بن عبداللہ نے بیان کیا، کہا کہ میں نے عبدالرحمٰن بن یزید سے سنا کہ عبداللہ بن مسعود رضی اللہ عنہ نے حج کیا، آپ کے ساتھ تقریباً عشاء کی اذان کے وقت ہم مزدلفہ میں بھی آئے، آپ نے ایک شخص کو حکم دیا اس نے اذان اور تکبیر کہی اور آپ نے مغرب کی نماز پڑھی، پھر دو رکعت ( سنت ) اور پڑھی اور شام کا کھانا منگوا کر کھایا۔ میرا خیال ہے ( راوی حدیث زہیر کا ) کہ پھر آپ نے حکم دیا اور اس شخص نے اذان دی اور تکبیر کہی عمرو ( راوی حدیث ) نے کہا میں یہی سمجھتا ہوں کہ شک زہیر ( عمرو کے شیخ ) کو تھا، اس کے بعد عشاء کی نماز دو رکعت پڑھی۔ جب صبح صادق ہوئی تو آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم اس نماز ( فجر ) کو اس مقام اور اس دن کے سوا اور کبھی اس وقت ( طلوع فجر ہوتے ہی ) نہیں پڑھتے تھے، عبداللہ بن مسعود رضی اللہ عنہ نے یہ بھی فرمایا کہ یہ صرف دو نمازیں ( آج کے دن ) اپنے معمولی وقت سے ہٹا دی جاتی ہیں۔ جب لوگ مزدلفہ آتے ہیں تو مغرب کی نماز ( عشاء کے ساتھ ملا کر ) پڑھی جاتی ہے اور فجر کی نماز طلوع فجر کے ساتھ ہی۔ انہوں نے فرمایا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اسی طرح کرتے دیکھا تھا۔' WHERE id = 1616;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم ضحاک بن مخلد نے بیان کیا، انہیں ابن جریج نے خبر دی، انہیں عطاء نے، انہیں ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے ( مزدلفہ سے لوٹتے وقت ) فضل ( بن عباس رضی اللہ عنہما ) کو اپنے پیچھے سوار کرایا تھا۔ فضل رضی اللہ عنہ نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم رمی جمرہ تک برابر لبیک پکارتے رہے۔' WHERE id = 1626;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، انہوں نے کہا ہم سے افلح بن حمید نے بیان کیا، ان سے قاسم نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کی ہدی کے قلادے خود بٹے تھے، پھر آپ صلی اللہ علیہ وسلم نے انہیں اشعار کیا اور ہار پہنایا، یا میں نے ہار پہنایا، پھر آپ صلی اللہ علیہ وسلم نے بیت اللہ کے لیے انہیں بھیج دیا اور خود مدینہ میں ٹھہر گئے لیکن کوئی بھی ایسی چیز آپ صلی اللہ علیہ وسلم کے لیے حرام نہیں ہوئی جو آپ صلی اللہ علیہ وسلم کے لیے حلال تھی۔' WHERE id = 1638;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں یحییٰ بن سعید نے، ان سے عمرہ بنت عبدالرحمٰن نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے سنا، انہوں نے بتلایا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ( حج کے لیے ) نکلے تو ذی قعدہ میں سے پانچ دن باقی رہے تھے ہم صرف حج کا ارادہ لے کر نکلے تھے، جب ہم مکہ کے قریب پہنچے تو رسول اللہ صلی اللہ علیہ وسلم نے حکم دیا کہ جن لوگوں کے ساتھ قربانی نہ ہو وہ جب طواف کر لیں اور صفا و مروہ کی سعی بھی کر لیں تو حلال ہو جائیں گے، عائشہ رضی اللہ عنہا نے کہا کہ قربانی کے دن ہمارے گھر گائے کا گوشت لایا گیا تو میں نے کہا کہ یہ کیا ہے؟ ( لانے والے نے بتلایا ) کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیویوں کی طرف سے یہ قربانی کی ہے، یحییٰ نے کہا کہ میں نے عمرہ کی یہ حدیث قاسم سے بیان کی انہوں نے کہا عمرہ نے یہ حدیث ٹھیک ٹھیک بیان کیا ہے۔' WHERE id = 1648;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعیدقطان نے، ان سے ابن جریج نے، ان سے عطاء نے، انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے فرمایا کہ ہم اپنی قربانی کا گوشت منیٰ کے بعد تین دن سے زیادہ نہیں کھاتے تھے، پھر نبی کریم صلی اللہ علیہ وسلم نے ہمیں اجازت دے دی اور فرمایا کہ کھاؤ بھی اور توشہ کے طور پر ساتھ بھی لے جاؤ، چنانچہ ہم نے کھایا اور ساتھ بھی لائے۔ ابن جریج نے کہا کہ میں نے عطاء سے پوچھا کیا جابر رضی اللہ عنہ نے یہ بھی کہا تھا کہ یہاں تک کہ ہم مدینہ پہنچ گئے، انہوں نے کہا نہیں ایسا نہیں فرمایا۔' WHERE id = 1658;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد بن اسماء نے بیان کیا، کہا ہم سے جویریہ بن اسماء نے، ان سے نافع نے کہ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا نبی کریم صلی اللہ علیہ وسلم اور آپ صلی اللہ علیہ وسلم کے بہت سے اصحاب نے سر منڈوایا تھا لیکن بعض نے کتروایا بھی تھا۔' WHERE id = 1668;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا مجھ سے یحییٰ بن سعید نے بیان کیا، ان سے فضل بن غزوان نے بیان کیا، ان سے عکرمہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ دسویں تاریخ کو رسول اللہ صلی اللہ علیہ وسلم نے منیٰ میں خطبہ دیا، خطبہ میں آپ صلی اللہ علیہ وسلم نے پوچھا لوگو! آج کون سا دن ہے؟ لوگ بولے یہ حرمت کا دن ہے، آپ صلی اللہ علیہ وسلم نے پھر پوچھا اور یہ شہر کون سا ہے؟ لوگوں نے کہا یہ حرمت کا شہر ہے، آپ صلی اللہ علیہ وسلم نے پوچھا یہ مہینہ کون سا ہے؟ لوگوں نے کہا یہ حرمت کا مہینہ ہے، پھر آپ صلی اللہ علیہ وسلم نے فرمایا بس تمہارا خون تمہارے مال اور تمہاری عزت ایک دوسرے پر اسی طرح حرام ہے جیسے اس دن کی حرمت، اس شہر اور اس مہینہ کی حرمت ہے، اس کلمہ کو آپ صلی اللہ علیہ وسلم نے کئی بار دہرایا اور پھر آسمان کی طرف سر اٹھا کر کہا اے اللہ! کیا میں نے ( تیرا پیغام ) پہنچا دیا اے اللہ! کیا میں نے پہنچا دیا۔ عبداللہ بن عباس رضی اللہ عنہما نے بتلایا کہ اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے نبی کریم صلی اللہ علیہ وسلم کی یہ وصیت اپنی تمام امت کے لیے ہے، لہٰذا حاضر ( اور جاننے والے ) غائب ( اور ناواقف لوگوں کو اللہ کا پیغام ) پہنچا دیں۔ آپ صلی اللہ علیہ وسلم نے پھر فرمایا دیکھو میرے بعد ایک دوسرے کی گردن مار کر کافر نہ بن جانا۔' WHERE id = 1678;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے حکم بن عتبہ نے بیان کیا، ان سے ابراہیم نخعی نے، ان سے عبدالرحمٰن بن یزید نے کہ انہوں نے عبداللہ بن مسعود رضی اللہ عنہ کے ساتھ حج کیا انہوں نے دیکھا جمرہ عقبہ کی سات کنکریوں کے ساتھ رمی کے وقت آپ نے بیت اللہ کو تو اپنی بائیں طرف اور منی کو دائیں طرف کر لیا پھر فرمایا کہ یہی ان کا بھی مقام تھا جن پر سورۃ البقرہ نازل ہوئی تھی یعنی نبی کریم صلی اللہ علیہ وسلم ۔' WHERE id = 1688;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی نے بیان کیا، کہا ہم سے اسحٰق بن یوسف نے بیان کیا، ان سے سفیان ثوری نے بیان کیا، ان سے عبدالعزیز بن رفیع نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے پوچھا، مجھے وہ حدیث بتائے جو آپ کو رسول اللہ صلی اللہ علیہ وسلم سے یاد ہو کہ انہوں نے آٹھویں ذی الحجہ کے دن ظہر کی نماز کہاں پڑھی تھی، انہوں نے کہا منیٰ میں، میں نے پوچھا اور روانگی کے دن عصر کہاں پڑھی تھی انہوں نے فرمایا کہ ابطح میں اور تم اسی طرح کرو جس طرح تمہارے حاکم لوگ کرتے ہوں۔ ( تاکہ فتنہ واقع نہ ہو ) ۔' WHERE id = 1700;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، کہا ہم کو ابن جریج نے خبر دی، کہا کہ مجھے عطاء بن ابی رباح نے خبر دی، ان سے عروہ بن زبیر رضی اللہ عنہ نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے پوچھا تو آپ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے رجب میں کوئی عمرہ نہیں کیا تھا۔' WHERE id = 1712;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ان سے یزید بن زریع نے بیان کیا، ان سے ابن عون نے بیان کیا، ان سے قاسم بن محمد نے اور دوسری (روایت میں) ابن عون، ابراہیم سے روایت کرتے ہیں اور وہ اسود سے، انہوں نے بیان کیا کہ عائشہ رضی اللہ عنہا نے کہا: یا رسول اللہ! لوگ تو دو نسک ( حج اور عمرہ ) کر کے واپس ہو رہے ہیں اور میں نے صرف ایک نسک ( حج ) کیا ہے؟ اس پر ان سے کہا گیا کہ پھر انتظار کریں اور جب پاک ہو جائیں تو تنعیم جا کر وہاں سے ( عمرہ کا ) احرام باندھیں، پھر ہم سے فلاں جگہ آ ملیں اور یہ کہ اس عمرہ کا ثواب تمہارے خرچ اور محنت کے مطابق ملے گا۔' WHERE id = 1722;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ( سفر سے ) رات کو گھر نہیں پہنچتے تھے یا صبح کے وقت پہنچ جاتے یا دوپہر بعد ( زوال سے لے کر غروب آفتاب تک کسی بھی وقت تشریف لاتے ) ۔' WHERE id = 1733;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا کہ ہم کو یونس نے خبر دی، ان سے زہری نے کہا کہ مجھے سالم نے خبر دی، کہا کہ ابن عمر رضی اللہ عنہما فرمایا کرتے تھے کیا تمہارے لیے رسول اللہ صلی اللہ علیہ وسلم کی سنت کافی نہیں ہے کہ اگر کسی کو حج سے روک دیا جائے، ہو سکے تو وہ بیت اللہ کا طواف کر لے اور صفا اور مروہ کی سعی، پھر وہ ہر چیز سے حلال ہو جائے، یہاں تک کہ وہ دوسرے سال حج کر لے پھر قربانی کرے، اگر قربانی نہ ملے تو روزہ رکھے، عبداللہ سے روایت ہے کہ ہمیں معمر نے خبر دی، ان سے زہری نے بیان کیا کہ مجھ سے سالم نے بیان کیا، ان سے ابن عمر رضی اللہ عنہما نے اسی پہلی روایت کی طرح بیان کیا۔' WHERE id = 1743;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے منصور نے، ان سے ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جس نے اس گھر کا حج کیا اور نہ شہوت کی فحش باتیں کیں، نہ گناہ کیا تو وہ اس دن کی طرح واپس ہو گا جس دن اس کی ماں نے اسے جنا تھا۔' WHERE id = 1753;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے میرے والد نے بیان کیا، ان سے اعمش نے بیان کیا، کہا کہ مجھ سے ابراہیم نے اسود سے بیان کیا اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ منیٰ کے غار میں تھے کہ آپ صلی اللہ علیہ وسلم پر سورۃ والمرسلات نازل ہونی شروع ہوئی۔ پھر آپ صلی اللہ علیہ وسلم اس کی تلاوت کرنے لگے اور میں آپ کی زبان سے اسے سیکھنے لگا، ابھی آپ صلی اللہ علیہ وسلم نے تلاوت ختم بھی نہیں کی تھی کہ ہم پر ایک سانپ گرا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اسے مار ڈالو چنانچہ ہم اس کی طرف لپکے لیکن وہ بھاگ گیا۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس طرح سے تم اس کے شر سے بچ گئے وہ بھی تمہارے شر سے بچ کر چلا گیا۔ ( ابوعبداللہ امام بخاری رحمہ اللہ نے کہا کہ اس حدیث سے میرا مقصد صرف یہ ہے کہ منیٰ حرم میں داخل ہے اور صحابہ نے حرم میں سانپ مارنے میں کوئی حرج نہیں سمجھا تھا ) ۔' WHERE id = 1763;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں زید بن اسلم نے، انہیں ابراہیم بن عبداللہ بن حنین نے، انہیں ان کے والد نے کہ عبداللہ بن عباس اور مسور بن مخرمہ رضی اللہ عنہم کا مقام ابواء میں ( ایک مسئلہ پر ) اختلاف ہوا۔ عبداللہ بن عباس رضی اللہ عنہما نے مجھے ابوایوب رضی اللہ عنہ کے یہاں ( مسئلہ پوچھنے کے لیے ) بھیجا، میں جب ان کی خدمت میں پہنچا تو وہ کنوئیں کے دو لکڑیوں کے بیچ غسل کر رہے تھے، ایک کپڑے سے انہوں نے پردہ کر رکھا تھا میں نے پہنچ کر سلام کیا تو انہوں نے دریافت فرمایا کہ کون ہو؟ میں نے عرض کی کہ میں عبداللہ بن حنین ہوں، آپ رضی اللہ عنہ کی خدمت میں مجھے عبداللہ بن عباس رضی اللہ عنہما نے بھیجا ہے یہ دریافت کرنے کے لیے کہ احرام کی حالت میں رسول اللہ صلی اللہ علیہ وسلم سر مبارک کس طرح دھوتے تھے۔ یہ سن کر انہوں نے کپڑے پر ( جس سے پردہ تھا ) ہاتھ رکھ کر اسے نیچے کیا۔ اب آپ کا سر دکھائی دے رہا تھا، جو شخص ان کے بدن پر پانی ڈال رہا تھا، اس سے انہوں نے پانی ڈالنے کے لیے کہا۔ اس نے ان کے سر پر پانی ڈالا، پھر انہوں نے اپنے سر کو دونوں ہاتھ سے ہلایا اور دونوں ہاتھ آگے لے گئے اور پھر پیچھے لائے فرمایا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو ( احرام کی حالت میں ) اسی طرح کرتے دیکھا تھا۔' WHERE id = 1773;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے بیان کیا، ان سے سعید بن جبیر نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کے ساتھ عرفات میں ٹھہرا ہوا تھا کہ اپنی اونٹنی سے گر پڑا اور اس نے اس کی گردن توڑ دی، تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے پانی اور بیری سے غسل دے کر دو کپڑوں ( احرام والوں ہی میں ) کفنا دو لیکن خوشبو نہ لگانا، نہ سر چھپانا اور نہ حنوط لگانا کیونکہ اللہ تعالیٰ قیامت میں اسے لبیک پکارتے ہوئے اٹھائے گا۔' WHERE id = 1783;
UPDATE hadiths SET urdu = 'امام بخاری رحمہ اللہ نے کہا کہ مجھ سے احمد بن محمد نے کہا کہ ان سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے، ان سے ان کے داد (ابراہیم بن عبدالرحمٰن بن عوف رضی اللہ عنہ) نے کہ عمر رضی اللہ عنہ نے اپنے آخری حج کے موقع پر نبی کریم صلی اللہ علیہ وسلم کی بیویوں کو حج کی اجازت دی تھی اور ان کے ساتھ عثمان بن عفان اور عبدالرحمٰن بن عوف رضی اللہ عنہما کو بھیجا تھا۔' WHERE id = 1793;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، ان سے سفیان ثوری نے، ان سے اعمش نے، ان سے ان کے والد یزید بن شریک نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ میرے پاس کتاب اللہ اور نبی کریم صلی اللہ علیہ وسلم کے اس صحیفہ کے سوا جو نبی کریم صلی اللہ علیہ وسلم کے حوالہ سے ہے اور کوئی چیز ( شرعی احکام سے متعلق ) لکھی ہوئی صورت میں نہیں ہے۔ اس صحیفہ میں یہ بھی لکھا ہوا ہے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا مدینہ عائر پہاڑی سے لے کر فلاں مقام تک حرم ہے، جس نے اس حد میں کوئی بدعت نکالی یا کسی بدعتی کو پناہ دی تو اس پر اللہ اور تمام ملائکہ اور انسانوں کی لعنت ہے، نہ اس کی کوئی فرض عبادت مقبول ہے نہ نفل اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمام مسلمانوں میں سے کسی کا بھی عہد کافی ہے اس لیے اگر کسی مسلمان کی ( دی ہوئی امان میں دوسرے مسلمان نے ) بدعہدی کی تو اس پر اللہ تعالیٰ اور تمام ملائکہ اور انسانوں کی لعنت ہے۔ نہ اس کی کوئی فرض عبادت مقبول ہے نہ نفل، اور جو کوئی اپنے مالک کو چھوڑ کر اس کی اجازت کے بغیر کسی دوسرے کو مالک بنائے، اس پر اللہ اور تمام ملائکہ اور انسانوں کی لعنت ہے، نہ اس کی کوئی فرض عبادت مقبول ہے نہ نفل۔' WHERE id = 1803;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھے سے امام مالک نے بیان کیا، ان سے نعیم بن عبداللہ المجمر نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مدینہ کے راستوں پر فرشتے ہیں نہ اس میں طاعون آ سکتا ہے نہ دجال۔' WHERE id = 1813;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے خالد بن یزید نے، ان سے سعید بن ابی ہلال نے، ان سے زید بن اسلم نے، ان سے ان کے والد نے اور ان سے عمر رضی اللہ عنہ نے جو فرمایا کرتے تھے اے اللہ! مجھے اپنے راستے میں شہادت عطا کر اور میری موت اپنے رسول صلی اللہ علیہ وسلم کے شہر میں مقدر کر دے۔ ابن زریع نے روح بن قاسم سے، انہوں نے زید بن اسلم سے، انہوں نے اپنی والدہ سے، انہوں نے حفصہ بنت عمر رضی اللہ عنہما سے بیان کیا کہ میں نے عمر رضی اللہ عنہ سے اسی طرح سنا تھا، ہشام نے بیان کیا، ان سے زید نے، ان سے ان کے والد نے، ان سے حفصہ رضی اللہ عنہا نے کہ میں نے عمر رضی اللہ عنہ سے سنا پھر یہی حدیث روایت کی۔' WHERE id = 1823;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے بیان کیا کہ مجھے سالم نے خبر دی کہ ابن عمر رضی اللہ عنہما نے کہا میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب رمضان کا چاند دیکھو تو روزہ شروع کر دو اور جب شوال کا چاند دیکھو تو روزہ افطار کر دو اور اگر ابر ہو تو اندازہ سے کام کرو۔ ( یعنی تیس روزے پورے کر لو ) اور بعض نے لیث سے بیان کیا کہ مجھ سے عقیل اور یونس نے بیان کیا کہ ”رمضان کا چاند“ مراد ہے۔' WHERE id = 1833;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے ابن جریج نے بیان کیا، ان سے یحییٰ بن عبداللہ بن صیفی نے، ان سے عکرمہ بن عبدالرحمٰن نے اور ان سے ام سلمہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم اپنی ازواج سے ایک مہینہ تک جدا رہے پھر انتیس دن پورے ہو گئے تو صبح کے وقت یا شام کے وقت آپ صلی اللہ علیہ وسلم ان کے پاس تشریف لے گئے اس پر کسی نے کہا آپ نے تو عہد کیا تھا کہ آپ صلی اللہ علیہ وسلم ایک مہینہ تک ان کے یہاں تشریف نہیں لے جائیں گے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مہینہ انتیس دن کا بھی ہوتا ہے۔' WHERE id = 1843;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے جویریہ نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے ”صوم وصال“ رکھا تو صحابہ رضی اللہ عنہم نے بھی رکھا لیکن صحابہ رضی اللہ عنہم کے لیے دشواری ہو گئی۔ اس لیے آپ صلی اللہ علیہ وسلم نے اس سے منع فرما دیا، صحابہ رضی اللہ عنہم نے اس پر عرض کی کہ آپ صلی اللہ علیہ وسلم صوم وصال رکھتے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا میں تمہاری طرح نہیں ہوں۔ میں تو برابر کھلایا اور پلایا جاتا ہوں۔' WHERE id = 1854;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہوں نے بیان کیا کہ مجھے حمید بن عبدالرحمٰن نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں تھے کہ ایک شخص نے حاضر ہو کر کہا کہ یا رسول اللہ! میں تو تباہ ہو گیا، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کیا بات ہوئی؟ اس نے کہا کہ میں نے روزہ کی حالت میں اپنی بیوی سے جماع کر لیا ہے، اس پر رسول اللہ صلی اللہ علیہ وسلم نے دریافت فرمایا کیا تمہارے پاس کوئی غلام ہے جسے تم آزاد کر سکو؟ اس نے کہا نہیں، پھر آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کیا پے در پے دو مہینے کے روزے رکھ سکتے ہو؟ اس نے عرض کی نہیں، پھر آپ صلی اللہ علیہ وسلم نے پوچھا کیا تم کو ساٹھ مسکینوں کو کھانا کھلانے کی طاقت ہے؟ اس نے اس کا جواب بھی انکار میں دیا، راوی نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم تھوڑی دیر کے لیے ٹھہر گئے، ہم بھی اپنی اسی حالت میں بیٹھے ہوئے تھے کہ آپ صلی اللہ علیہ وسلم کی خدمت میں ایک بڑا تھیلا ( عرق نامی ) پیش کیا گیا جس میں کھجوریں تھیں۔ عرق تھیلے کو کہتے ہیں ( جسے کھجور کی چھال سے بناتے ہیں ) نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ سائل کہاں ہے؟ اس نے کہا کہ میں حاضر ہوں، آپ صلی اللہ علیہ وسلم نے فرمایا کے اسے لے لو اور صدقہ کر دو، اس شخص نے کہا یا رسول اللہ! کیا میں اپنے سے زیادہ محتاج پر صدقہ کر دوں، بخدا ان دونوں پتھریلے میدانوں کے درمیان کوئی بھی گھرانہ میرے گھر سے زیادہ محتاج نہیں ہے، اس پر نبی کریم صلی اللہ علیہ وسلم اس طرح ہنس پڑے کہ آپ کے آگے کے دانت دیکھے جا سکے۔ پھر آپ صلی اللہ علیہ وسلم نے ارشاد فرمایا کہ اچھا جا اپنے گھر والوں ہی کو کھلا دے۔' WHERE id = 1866;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے محمد بن عبدالرحمٰن انصاری نے بیان کیا، کہا کہ میں نے محمد بن عمرو بن حسن بن علی رضی اللہ عنہ سے سنا اور انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم ایک سفر ( غزوہ فتح ) میں تھے آپ صلی اللہ علیہ وسلم نے دیکھا کہ ایک شخص پر لوگوں نے سایہ کر رکھا ہے، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا بات ہے؟ لوگوں نے کہا کہ ایک روزہ دار ہے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ سفر میں رو زہ رکھنا اچھا کام نہیں ہے۔' WHERE id = 1876;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا کہ ہم سے ابوبکر بن عیاش نے بیان کیا، ان سے سلیمان شیبانی نے اور ان سے ابن ابی اوفی رضی اللہ عنہ نے کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھا۔ آپ صلی اللہ علیہ وسلم روزے سے تھے، جب شام ہوئی تو آپ صلی اللہ علیہ وسلم نے ایک شخص سے فرمایا کہ ( اونٹ سے ) اتر کر میرے لیے ستو گھول، اس نے کہا: یا رسول اللہ! اگر شام ہونے کا کچھ اور انتظار فرمائیں تو بہتر ہو، آپ صلی اللہ علیہ وسلم نے فرمایا، اتر کر میرے لیے ستو گھول ( وقت ہو گیا ہے ) جب تم یہ دیکھ لو کہ رات ادھر مشرق سے آ گئی تو روزہ دار کے روزہ کھولنے کا وقت ہو گیا۔' WHERE id = 1888;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے جعفر بن عون نے بیان کیا، ان سے ابوالعمیس عتبہ بن عبداللہ نے بیان کیا، ان سے عون بن ابی حجیفہ نے اور ان سے ان کے والد (وہب بن عبداللہ رضی اللہ عنہ) نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے سلمان اور ابوالدرداء رضی اللہ عنہ میں ( ہجرت کے بعد ) بھائی چارہ کرایا تھا۔ ایک مرتبہ سلمان رضی اللہ عنہ، ابودرداء رضی اللہ عنہ سے ملاقات کے لیے گئے۔ تو ( ان کی عورت ) ام الدرداء رضی اللہ عنہا کو بہت پراگندہ حال میں دیکھا۔ ان سے پوچھا کہ یہ حالت کیوں بنا رکھی ہے؟ ام الدرداء رضی اللہ عنہا نے جواب دیا کہ تمہارے بھائی ابوالدرداء رضی اللہ عنہ ہیں جن کو دنیا کی کوئی حاجت ہی نہیں ہے پھر ابوالدرداء رضی اللہ عنہ بھی آ گئے اور ان کے سامنے کھانا حاضر کیا اور کہا کہ کھانا کھاؤ، انہوں نے کہا کہ میں تو روزے سے ہوں، اس پر سلمان رضی اللہ عنہ نے فرمایا کہ میں بھی اس وقت تک کھانا نہیں کھاؤں گا جب تک تم خود بھی شریک نہ ہو گے۔ راوی نے بیان کیا کہ پھر وہ کھانے میں شریک ہو گئے ( اور روزہ توڑ دیا ) رات ہوئی تو ابوالدرداء رضی اللہ عنہ عبادت کے لیے اٹھے اور اس مرتبہ بھی سلمان رضی اللہ عنہ نے فرمایا کہ ابھی سو جاؤ۔ پھر جب رات کا آخری حصہ ہوا تو سلمان رضی اللہ عنہ نے فرمایا کہ اچھا اب اٹھ جاؤ۔ چنانچہ دونوں نے نماز پڑھی۔ اس کے بعد سلمان رضی اللہ عنہ نے فرمایا کہ تمہارے رب کا بھی تم پر حق ہے۔ جان کا بھی تم پر حق ہے اور تمہاری بیوی کا بھی تم پر حق ہے، اس لیے ہر حق والے کے حق کو ادا کرنا چاہئے، پھر آپ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ صلی اللہ علیہ وسلم سے اس کا تذکرہ کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ سلمان نے سچ کہا۔' WHERE id = 1898;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے مغیرہ نے بیان کیا کہ میں نے مجاہد سے سنا اور انہوں نے عبداللہ بن عمرو رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، مہینہ میں صرف تین دن کے روزے رکھا کر۔ انہوں نے کہا کہ مجھ میں اس سے بھی زیادہ کی طاقت ہے۔ اسی طرح وہ برابر کہتے رہے ( کہ مجھ میں اس سے بھی زیادہ کی طاقت ہے ) یہاں تک کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ایک دن روزہ رکھو اور ایک دن کا روزہ چھوڑ دیا کر۔ آپ صلی اللہ علیہ وسلم نے ان سے یہ بھی فرمایا کہ مہینہ میں ایک قرآن مجید ختم کیا کر۔ انہوں نے اس پر بھی کہا کہ میں اس سے زیادہ کی طاقت رکھتا ہوں۔ اور برابر یہی کہتے رہے۔ یہاں تک کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تین دن میں ( ایک قرآن ختم کیا کر ) ۔' WHERE id = 1908;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ نے بیان کیا، ان سے امام مالک رحمہ اللہ نے بیان کیا کہ مجھ سے سالم نے بیان کیا، کہا کہ مجھ سے ام فضل رضی اللہ عنہا کے مولی عمیر نے بیان کیا اور ان سے ام فضل رضی اللہ عنہا نے بیان کیا۔ (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور ہم سے عبداللہ بن یوسف نے بیان کیا، انہیں امام مالک رحمہ اللہ نے خبر دی، انہیں عمر بن عبداللہ کے غلام ابونضر نے، انہیں عبداللہ بن عباس رضی اللہ عنہما کے غلام عمیر نے اور انہیں ام فضل بنت حارث رضی اللہ عنہا نے کہ ان کے یہاں کچھ لوگ عرفات کے دن نبی کریم صلی اللہ علیہ وسلم کے روزہ کے بارے میں جھگڑ رہے تھے۔ بعض نے کہا کہ آپ صلی اللہ علیہ وسلم روزہ سے ہیں۔ اور بعض نے کہا کہ روزہ سے نہیں ہیں۔ اس پر ام فضل رضی اللہ عنہا نے آپ کی خدمت میں دودھ کا ایک پیالہ بھیجا ( تاکہ حقیقت ظاہر ہو جائے ) آپ اپنے اونٹ پر سوار تھے، آپ نے دودھ پی لیا۔' WHERE id = 1918;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا کہ ہم سے امام مالک رحمہ اللہ نے بیان کیا، ان سے ہشام بن عروہ نے اور ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ عاشوراء کے دن زمانہ جاہلیت میں قریش روزہ رکھا کرتے تھے اور رسول اللہ صلی اللہ علیہ وسلم بھی رکھتے۔ پھر جب آپ صلی اللہ علیہ وسلم مدینہ تشریف لائے تو آپ صلی اللہ علیہ وسلم نے یہاں بھی عاشورہ کے دن روزہ رکھا اور اس کا لوگوں کو بھی حکم دیا۔ لیکن رمضان کی فرضیت کے بعد آپ نے اس کو چھوڑ دیا اور فرمایا کہ اب جس کا جی چاہے اس دن روزہ رکھے اور جس کا چاہے نہ رکھے۔' WHERE id = 1930;
UPDATE hadiths SET urdu = 'اور ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں عروہ نے خبر دی اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ایک مرتبہ ( رمضان کی ) نصف شب میں مسجد تشریف لے گئے اور وہاں تراویح کی نماز پڑھی۔ کچھ صحابہ رضی اللہ عنہم بھی آپ کے ساتھ نماز میں شریک ہو گئے۔ صبح ہوئی تو انہوں نے اس کا چرچا کیا۔ چنانچہ دوسری رات میں لوگ پہلے سے بھی زیادہ جمع ہو گئے اور آپ صلی اللہ علیہ وسلم کے ساتھ نماز پڑھی۔ دوسری صبح کو اور زیادہ چرچا ہوا اور تیسری رات اس سے بھی زیادہ لوگ جمع ہو گئے۔ آپ نے ( اس رات بھی ) نماز پڑھی اور لوگوں نے آپ صلی اللہ علیہ وسلم کی اقتداء کی۔ چوتھی رات کو یہ عالم تھا کہ مسجد میں نماز پڑھنے آنے والوں کے لیے جگہ بھی باقی نہیں رہی تھی۔ ( لیکن اس رات آپ برآمد ہی نہیں ہوئے ) بلکہ صبح کی نماز کے لیے باہر تشریف لائے۔ جب نماز پڑھ لی تو لوگوں کی طرف متوجہ ہو کر شہادت کے بعد فرمایا۔ امابعد! تمہارے یہاں جمع ہونے کا مجھے علم تھا، لیکن مجھے خوف اس کا ہوا کہ کہیں یہ نماز تم پر فرض نہ کر دی جائے اور پھر تم اس کی ادائیگی سے عاجز ہو جاؤ، چنانچہ جب نبی کریم صلی اللہ علیہ وسلم کی وفات ہوئی تو یہی کیفیت قائم رہی۔' WHERE id = 1940;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا، کہا کہ ہم سے عبدالواحد بن زیاد نے بیان کیا، ان سے عاصم بن سلیمان نے بیان کیا، ان سے ابومجلز اور عکرمہ نے، ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا شب قدر رمضان کے ( آخری ) عشرہ میں پڑتی ہے۔ جب نو راتیں گزر جائیں یا سات باقی رہ جائیں۔ آپ صلی اللہ علیہ وسلم کی مراد شب قدر سے تھی۔ عبدالوہاب نے ایوب اور خالد سے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ شب قدر کو چوبیس تاریخ ( کی رات ) میں تلاش کرو۔' WHERE id = 1950;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے خبر دی، انہیں یحییٰ بن سعید نے، انہیں عمرہ بنت عبدالرحمٰن نے اور انہیں ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے اعتکاف کا ارادہ کیا۔ جب آپ صلی اللہ علیہ وسلم اس جگہ تشریف لائے ( یعنی مسجد میں ) جہاں آپ صلی اللہ علیہ وسلم نے اعتکاف کا ارادہ کیا تھا۔ تو وہاں کئی خیمے موجود تھے۔ عائشہ رضی اللہ عنہا کا بھی، حفصہ رضی اللہ عنہا کا بھی اور زینب رضی اللہ عنہا کا بھی، اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کیا تم یہ سمجھتے ہو کہ انہوں نے ثواب کی نیت سے ایسا کیا ہے، پھر آپ صلی اللہ علیہ وسلم واپس تشریف لے گئے اور اعتکاف نہیں کیا بلکہ شوال کے عشرہ میں اعتکاف کیا۔' WHERE id = 1961;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی شبیہ نے بیان کیا، کہا کہ ہم سے ابوبکر بن عیاش نے بیان کیا، ان سے ابوحصین عثمان بن عاصم نے، ان سے ابوصالح سمان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ہر سال رمضان میں دس دن کا اعتکاف کیا کرتے تھے۔ لیکن جس سال آپ صلی اللہ علیہ وسلم کا انتقال ہوا، اس سال آپ صلی اللہ علیہ وسلم نے بیس دن کا اعتکاف کیا تھا۔' WHERE id = 1971;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ مجھے عبداللہ بن ابی سفر نے خبر دی، انہیں شعبی نے، ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے «معراض» ( تیر کے شکار ) کے متعلق پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر اس کے دھار کی طرف سے لگے تو کھا۔ اگر چوڑائی سے لگے تو مت کھا۔ کیونکہ وہ مردار ہے، میں نے عرض کیا یا رسول اللہ! میں اپنا کتا ( شکار کے لیے ) چھوڑتا ہوں اور بسم اللہ پڑھ لیتا ہوں، پھر اس کے ساتھ مجھے ایک ایسا کتا اور ملتا ہے جس پر میں نے بسم اللہ نہیں پڑھی ہے۔ میں یہ فیصلہ نہیں کر پاتا کہ دونوں میں کون سے کتے نے شکار پکڑا۔ آپ صلی اللہ علیہ وسلم نے فرمایا، ایسے شکار کا گوشت نہ کھا۔ کیونکہ تو نے بسم اللہ تو اپنے کتے کے لیے پڑھی ہے۔ دوسرے کے لیے تو نہیں پڑھی۔' WHERE id = 1981;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن جعفر نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالرزاق نے بیان کیا، ان سے معمر نے بیان کیا، ان سے ہمام نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اگر عورت اپنے شوہر کی کمائی اس کی اجازت کے بغیر بھی ( اللہ کے راستے میں ) خرچ کرتی ہے تو اسے آدھا ثواب ملتا ہے۔' WHERE id = 1992;
UPDATE hadiths SET urdu = 'ہم سے علی بن عیاش نے بیان کیا، کہا کہ ہم سے ابوغسان محمد بن مطرف نے بیان کیا، کہا کہ مجھ سے محمد بن منکدر نے بیان کیا، اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اللہ تعالیٰ ایسے شخص پر رحم کرے جو بیچتے وقت اور خریدتے وقت اور تقاضا کرتے وقت فیاضی اور نرمی سے کام لیتا ہے۔' WHERE id = 2002;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے عون بن ابی جحیفہ نے بیان کیا کہ میں نے اپنے والد کو ایک پچھنا لگانے والا غلام خریدتے دیکھا۔ میں نے یہ دیکھ کر ان سے اس کے متعلق پوچھا تو انہوں نے جواب دیا کہ نبی کریم صلی اللہ علیہ وسلم نے کتے کی قیمت لینے اور خون کی قیمت لینے سے منع فرمایا ہے، آپ نے گودنے والی اور گدوانے والی کو ( گودنا لگوانے سے ) سود لینے والے اور سود دینے والے کو ( سود لینے یا دینے سے ) منع فرمایا اور تصویر بنانے والے پر لعنت بھیجی۔' WHERE id = 2012;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن عیسیٰ نے بیان کیا، کہا کہ ہم سے ابومعاویہ نے بیان کیا، کہا کہ ہم سے اعمش نے بیان کیا، ان سے ابراہیم نخعی نے، ان سے اسود بن یزید نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک یہودی سے کچھ غلہ ادھار خریدا۔ اور اپنی زرہ اس کے پاس گروی رکھوائی۔' WHERE id = 2022;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے عبدالوارث نے، ان سے ابوالتیاح نے، اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اے بنو نجار! اپنے باغ کی قیمت مقرر کر دو۔ ( آپ صلی اللہ علیہ وسلم نے اس جگہ کو مسجد کے لیے خریدنا چاہتے تھے ) اس باغ میں کچھ حصہ تو ویرانہ اور کچھ حصے میں کھجور کے درخت تھے۔' WHERE id = 2032;
UPDATE hadiths SET urdu = 'ابوعبداللہ (امام بخاری رحمہ اللہ) نے کہا کہ لیث بن سعد نے بیان کیا کہ مجھ سے عبدالرحمٰن بن خالد نے بیان کیا، ان سے ابن شہاب نے، ان سے سالم بن عبداللہ نے، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا، کہ میں نے امیرالمؤمنین عثمان رضی اللہ عنہ کو اپنی وادی قریٰ کی زمین، ان کی خیبر کی زمین کے بدلے میں بیچی تھی۔ پھر جب ہم نے بیع کر لی تو میں الٹے پاؤں ان کے گھر سے اس خیال سے باہر نکل گیا کہ کہیں وہ بیع فسخ نہ کر دیں۔ کیونکہ شریعت کا قاعدہ یہ تھا کہ بیچنے اور خریدنے والے کو ( بیع توڑنے کا ) اختیار اس وقت تک رہتا ہے جب تک وہ ایک دوسرے سے جدا نہ ہو جائیں۔ عبداللہ رضی اللہ عنہ نے کہا کہ جب ہماری خرید و فروخت پوری ہو گئی اور میں نے غور کیا تو معلوم ہوا کہ میں نے عثمان رضی اللہ عنہ کو نقصان پہنچایا ہے کیونکہ ( اس تبادلہ کے نتیجے میں، میں نے ان کی پہلی زمین سے ) انہیں تین دن کے سفر کی دوری پر ثمود کی زمین کی طرف دھکیل دیا تھا اور انہوں نے مجھے ( میری مسافت کم کر کے ) مدینہ سے صرف تین دن کے سفر کی دوری پر لا چھوڑا تھا۔' WHERE id = 2042;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے وہیب نے بیان کیا، کہا کہ ہم سے عمرو بن یحییٰ نے بیان کیا، ان سے عباد بن تمیم انصاری نے اور ان سے عبداللہ بن زید رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ابراہیم علیہ السلام نے مکہ کو حرام قرار دیا۔ اور اس کے لیے دعا فرمائی۔ میں بھی مدینہ کو اسی طرح حرام قرار دیتا ہوں جس طرح ابراہیم علیہ السلام نے مکہ کو حرام قرار دیا تھا۔ اور اس کے لیے، اس کے مد اور صاع ( غلہ ناپنے کے دو پیمانے ) کی برکت کے لیے اس طرح دعا کرتا ہوں جس طرح ابراہیم علیہ السلام نے مکہ کے لیے دعا کی تھی۔' WHERE id = 2054;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا کہ ہم سے سفیان نے بیان کیا، ان سے زہری نے بیان کیا، ان سے سعید بن مسیب نے بیان کیا، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اس سے منع فرمایا کہ کوئی شہری کسی دیہاتی کا مال و اسباب بیچے اور یہ کہ کوئی ( سامان خریدنے کی نیت کے بغیر دوسرے اصل خریداروں سے ) بڑھ کر بولی نہ دے۔ اسی طرح کوئی شخص اپنے بھائی کے سودے میں مداخلت نہ کرے۔ کوئی شخص ( کسی عورت کو ) دوسرے کے پیغام نکاح ہوتے ہوئے اپنا پیغام نہ بھیجے۔ اور کوئی عورت اپنی کسی دینی بہن کو اس نیت سے طلاق نہ دلوائے کہ اس کے حصہ کو خود حاصل کر لے۔' WHERE id = 2065;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ابوالزناد نے، انہیں اعرج نے، اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ( تجارتی ) قافلوں کی پیشوائی ( ان کا سامان شہر پہنچے سے پہلے ہی خرید لینے کی غرض سے ) نہ کرو۔ ایک شخص کسی دوسرے کی بیع پر بیع نہ کرے اور کوئی «نجش» ( دھوکہ فریب ) نہ کرے اور کوئی شہری، بدوی کا مال نہ بیچے اور بکری کے تھن میں دودھ نہ روکے۔ لیکن اگر کوئی اس ( آخری ) صورت میں جانور خرید لے تو اسے دوہنے کے بعد دونوں طرح کے اختیارات ہیں۔ اگر وہ اس بیع پر راضی ہے تو جانور کو روک سکتا ہے اور اگر وہ راضی نہیں تو ایک صاع کھجور اس کے ساتھ دے کر اسے واپس کر دے۔' WHERE id = 2075;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے عبدالوہاب نے بیان کیا، ان سے عبیداللہ عمری نے بیان کیا، ان سے سعید بن ابی سعید نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ( تجارتی قافلوں سے ) آگے بڑھ کر ملنے سے منع فرمایا ہے اور بستی والوں کو باہر والوں کا مال بیچنے سے بھی منع فرمایا۔' WHERE id = 2086;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، اور انہیں مالک بن اوس رضی اللہ عنہ نے خبر دی کہ انہیں سو اشرفیاں بدلنی تھیں۔ ( انہوں نے بیان کیا کہ ) پھر مجھے طلحہ بن عبیداللہ رضی اللہ عنہما نے بلایا۔ اور ہم نے ( اپنے معاملہ کی ) بات چیت کی۔ اور ان سے میرا معاملہ طے ہو گیا۔ وہ سونے ( اشرفیوں ) کو اپنے ہاتھ میں لے کر الٹنے پلٹنے لگے اور کہنے لگے کہ ذرا میرے خزانچی کو غابہ سے آ لینے دو۔ عمر رضی اللہ عنہ بھی ہماری باتیں سن رہے تھے، آپ نے فرمایا: اللہ کی قسم! جب تک تم طلحہ سے روپیہ لے نہ لو، ان سے جدا نہ ہونا کیونکہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہے کہ سونا سونے کے بدلہ میں اگر نقد نہ ہو تو سود ہو جاتا ہے۔ گیہوں، گیہوں کے بدلے میں اگر نقد نہ ہو تو سود ہو جاتا ہے۔ جَو، جَو کے بدلہ میں اگر نقد نہ ہو تو سود ہو جاتا ہے اور کھجور، کھجور کے بدلہ میں اگر نقد نہ ہو تو سود ہو جاتی ہے۔' WHERE id = 2097;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، انہوں نے کہا کہ میں نے امام مالک سے سنا، ان سے عبیداللہ بن ربیع نے پوچھا کہ کیا آپ سے داؤد نے سفیان سے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے یہ حدیث بیان کی تھی کہ نبی کریم صلی اللہ علیہ وسلم نے پانچ وسق یا اس سے کم میں بیع عریہ کی اجازت دے دی ہے؟ تو انہوں نے کہا کہ ہاں' WHERE id = 2110;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن حفص بن غیاث نے بیان کیا، کہا کہ مجھ سے میرے باپ نے بیان کیا، ان سے اعمش نے بیان کیا، کہا کہ ہم نے ابراہیم کے سامنے قرض میں گروی رکھنے کا ذکر کیا تو انہوں نے کہا کہ اس میں کوئی حرج نہیں ہے۔ پھر ہم سے اسود کے واسطہ سے بیان کیا کہ ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مقررہ مدت کے قرض پر ایک یہودی سے غلہ خریدا اور اپنی زرہ اس کے یہاں گروی رکھی تھی۔' WHERE id = 2120;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، کہا ہم سے ابن نمیر نے بیان کیا، کہا کہ ہمیں ہشام نے خبر دی (دوسری سند) اور مجھ سے محمد نے بیان کیا کہا کہ میں نے عثمان بن فرقد سے سنا، انہوں نے کہا کہ میں نے ہشام بن عروہ سے سنا، وہ اپنے باپ سے بیان کرتے تھے کہ انہوں نے عائشہ رضی اللہ عنہا سے سنا، وہ فرماتی تھیں کہ ( قرآن کی آیت ) «ومن كان غنيا فليستعفف ومن كان فقيرا فليأكل بالمعروف‏» جو شخص مالدار ہو وہ ( اپنی زیر پرورش یتیم کا مال ہضم کرنے سے ) اپنے کو بچائے۔ اور جو فقیر ہو وہ نیک نیتی کے ساتھ اس میں سے کھا لے۔“ یہ آیت یتیموں کے ان سر پرستوں کے متعلق نازل ہوئی تھی جو ان کی اور ان کے مال کی نگرانی اور دیکھ بھال کرتے ہوں کہ اگر وہ فقیر ہیں تو ( اس خدمت کے عوض ) نیک نیتی کے ساتھ اس میں سے کھا سکتے ہیں۔' WHERE id = 2131;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے، ان سے ابن مسیب نے اور انہوں نے ابوہریرہ رضی اللہ عنہ کو یہ فرماتے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اس ذات کی قسم جس کے ہاتھ میں میری جان ہے، وہ زمانہ آنے والا ہے جب ابن مریم ( عیسیٰ علیہ السلام ) تم میں ایک عادل اور منصف حاکم کی حیثیت سے اتریں گے۔ وہ صلیب کو توڑ ڈالیں گے، سوروں کو مار ڈالیں گے اور جزیہ کو ختم کر دیں گے۔ اس وقت مال کی اتنی زیادتی ہو گی کہ کوئی لینے والا نہ رہے گا۔' WHERE id = 2142;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ مجھے لیث نے خبر دی، انہیں سعید نے، انہیں ان کے والد نے، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سے میں نے خود سنا ہے کہ جب کوئی باندی زنا کرائے اور وہ ثابت ہو جائے تو اس پر حد زنا جاری کی جائے، البتہ اسے لعنت ملامت نہ کی جائے۔ پھر اگر وہ زنا کرائے تو اس پر اس مرتبہ بھی حد جاری کی جائے، لیکن کسی قسم کی لعنت ملامت نہ کی جائے۔ تیسری مرتبہ بھی اگر زنا کرے اور زنا ثابت ہو جائے تو اسے بیچ ڈالے خواہ بال کی ایک رسی کے بدلے ہی کیوں نہ ہو۔' WHERE id = 2153;
UPDATE hadiths SET urdu = 'ہم سے محمد بن محبوب نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، ان سے اعمش نے بیان کیا، انہوں نے کہا کہ ہم نے ابراہیم نخعی کے سامنے بیع سلم میں گروی رکھنے کا ذکر کیا تو انہوں نے کہا ہم سے اسود نے بیان کیا، اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک یہودی سے ایک مقررہ مدت کے لیے غلہ خریدا اور اس کے پاس اپنی لوہے کی زرہ گروی رکھ دی تھی۔' WHERE id = 2170;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، انہوں نے کہا کہ ہم سے عقیل نے کہ ابن شہاب نے بیان کیا کہ مجھے عروہ بن زبیر نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی بیوی عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ نے بنو دیل کے ایک ماہر راہبر سے مزدوری طے کر لی تھی۔ وہ شخص کفار قریش کے دین پر تھا۔ ان دونوں حضرات نے اپنی دونوں اونٹنیاں اس کے حوالے کر دی تھیں اور کہہ دیا تھا کہ تین راتوں کے بعد صبح سویرے ہی سواروں کے ساتھ غار ثور پر آ جائے۔' WHERE id = 2181;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے بیان کیا، ان سے ابوالمتوکل نے بیان کیا، اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے کچھ صحابہ رضی اللہ عنہم سفر میں تھے۔ دوران سفر میں وہ عرب کے ایک قبیلہ پر اترے۔ صحابہ نے چاہا کہ قبیلہ والے انہیں اپنا مہمان بنا لیں، لیکن انہوں نے مہمانی نہیں کی، بلکہ صاف انکار کر دیا۔ اتفاق سے اسی قبیلہ کے سردار کو سانپ نے ڈس لیا، قبیلہ والوں نے ہر طرح کی کوشش کر ڈالی، لیکن ان کا سردار اچھا نہ ہوا۔ ان کے کسی آدمی نے کہا کہ چلو ان لوگوں سے بھی پوچھیں جو یہاں آ کر اترے ہیں۔ ممکن ہے کوئی دم جھاڑنے کی چیز ان کے پاس ہو۔ چنانچہ قبیلہ والے ان کے پاس آئے اور کہا کہ بھائیو! ہمارے سردار کو سانپ نے ڈس لیا ہے۔ اس کے لیے ہم نے ہر قسم کی کوشش کر ڈالی لیکن کچھ فائدہ نہ ہوا۔ کیا تمہارے پاس کوئی چیز دم کرنے کی ہے؟ ایک صحابی نے کہا کہ قسم اللہ کی میں اسے جھاڑ دوں گا لیکن ہم نے تم سے میزبانی کے لیے کہا تھا اور تم نے اس سے انکار کر دیا۔ اس لیے اب میں بھی اجرت کے بغیر نہیں جھاڑ سکتا، آخر بکریوں کے ایک گلے پر ان کا معاملہ طے ہوا۔ وہ صحابی وہاں گئے اور «الحمد لله رب العالمين» پڑھ پڑھ کر دم کیا۔ ایسا معلوم ہوا جیسے کسی کی رسی کھول دی گئی ہو۔ وہ سردار اٹھ کر چلنے لگا، تکلیف و درد کا نام و نشان بھی باقی نہیں تھا۔ بیان کیا کہ پھر انہوں نے طے شدہ اجرت صحابہ کو ادا کر دی۔ کسی نے کہا کہ اسے تقسیم کر لو، لیکن جنہوں نے جھاڑا تھا، وہ بولے کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر پہلے ہم آپ صلی اللہ علیہ وسلم سے اس کا ذکر کر لیں۔ اس کے بعد دیکھیں گے کہ آپ صلی اللہ علیہ وسلم کیا حکم دیتے ہیں۔ چنانچہ سب حضرات رسول اللہ صلی اللہ علیہ وسلم خدمت میں حاضر ہوئے اور آپ صلی اللہ علیہ وسلم سے اس کا ذکر کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا یہ تم کو کیسے معلوم ہوا کہ سورۃ فاتحہ بھی ایک رقیہ ہے؟ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم نے ٹھیک کیا۔ اسے تقسیم کر لو اور ایک میرا حصہ بھی لگاؤ۔ یہ فرما کر رسول اللہ صلی اللہ علیہ وسلم ہنس پڑے۔ شعبہ نے کہا کہ ابوالبشر نے ہم سے بیان کیا، انہوں نے ابوالمتوکل سے ایسا ہی سنا۔' WHERE id = 2192;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا، ان سے ابن ذکوان نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، مالدار کی طرف سے ( قرض ادا کرنے میں ) ٹال مٹول کرنا ظلم ہے۔ اور اگر کسی کا قرض کسی مالدار کے حوالہ کیا جائے تو وہ اسے قبول کرے۔' WHERE id = 2203;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کے پاس جب کسی ایسی میت کو لایا جاتا جس پر کسی کا قرض ہوتا تو آپ صلی اللہ علیہ وسلم فرماتے کہ کیا اس نے اپنے قرض کے ادا کرنے کے لیے بھی کچھ چھوڑا ہے؟ پھر اگر کوئی آپ کو بتا دیتا کہ ہاں اتنا مال ہے جس سے قرض ادا ہو سکتا ہے۔ تو آپ صلی اللہ علیہ وسلم اس کی نماز پڑھاتے ورنہ آپ صلی اللہ علیہ وسلم مسلمانوں ہی سے فرما دیتے کہ اپنے ساتھی کی نماز پڑھ لو۔ پھر جب اللہ تعالیٰ نے آپ صلی اللہ علیہ وسلم پر فتح کے دروازے کھول دیئے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں مسلمانوں کا خود ان کی ذات سے بھی زیادہ مستحق ہوں۔ اس لیے اب جو بھی مسلمان وفات پا جائے اور وہ مقروض رہا ہو تو اس کا قرض ادا کرنا میرے ذمے ہے اور جو مسلمان مال چھوڑ جائے وہ اس کے وارثوں کا حق ہے۔' WHERE id = 2213;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، ان سے یحییٰ بن صالح نے بیان کیا، ان سے معاویہ بن سلام نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، کہ میں نے عقبہ بن عبدالغافر سے سنا اور انہوں نے ابو سعید خدری رضی اللہ عنہ سے، انہوں نے بیان کیا کہ بلال رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں برنی کھجور ( کھجور کی ایک عمدہ قسم ) لے کر آئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا یہ کہاں سے لائے ہو؟ انہوں نے کہا ہمارے پاس خراب کھجور تھی، اس کے دو صاع اس کے ایک صاع کے بدلے میں دے کر ہم اسے لائے ہیں۔ تاکہ ہم یہ آپ کو کھلائیں آپ صلی اللہ علیہ وسلم نے فرمایا توبہ توبہ یہ تو سود ہے بالکل سود۔ ایسا نہ کیا کر البتہ ( اچھی کھجور ) خریدنے کا ارادہ ہو تو ( خراب ) کھجور بیچ کر ( اس کی قیمت سے ) عمدہ خریدا کر۔' WHERE id = 2225;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے سعد بن ابراہیم نے انہوں نے ابوسلمہ سے سنا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ( بنی اسرائیل میں سے ) ایک شخص بیل پر سوار ہو کر جا رہا تھا کہ اس بیل نے اس کی طرف دیکھا اور اس سوار سے کہا کہ میں اس کے لیے نہیں پیدا ہوا ہوں۔ میری پیدائش تو کھیت جوتنے کے لیے ہوئی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں اس پر ایمان لایا اور ابوبکر اور عمر بھی ایمان لائے۔ اور ایک دفعہ ایک بھیڑئیے نے ایک بکری پکڑ لی تھی تو گڈریے نے اس کا پیچھا کیا۔ بھیڑیا بولا! آج تو تو اسے بچاتا ہے۔ جس دن ( مدینہ اجاڑ ہو گا ) درندے ہی درندے رہ جائیں گے۔ اس دن میرے سوا کون بکریوں کا چرانے والا ہو گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں اس پر ایمان لایا اور ابوبکر اور عمر بھی۔ ابوسلمہ نے کہا کہ ابوبکر اور عمر رضی اللہ عنہما اس مجلس میں موجود نہیں تھے۔' WHERE id = 2236;
UPDATE hadiths SET urdu = 'ہم سے صدقہ نے بیان کیا، کہا کہ ہم کو عبدالرحمٰن بن مہدی نے خبر دی، انہیں امام مالک نے، انہیں زید بن اسلم نے، ان سے ان کے والد نے بیان کیا کہ ہم سے صدقہ نے بیان کیا ، کہا کہ ہم کو عبدالرحمٰن بن مہدی نے خبر دی ، انہیں امام مالک نے ، انہیں زید بن اسلم نے ، ان سے ان کے والد نے بیان کیا کہ عمر ؓ نے فرمایا ، اگر مجھے بعد میں آنے والے مسلمانوں کا خیال نہ ہوتا تو جتنے شہر بھی فتح کرتا ، انہیں فتح کرنے والوں میں تقسیم کرتا جاتا ، بالکل اسی طرح جس طرح نبی کریم ﷺ نے خیبر کی زمین تقسیم فرما دی تھی ۔ … حدیث متعلقہ ابواب: مفتوحہ شہر کی غازیوں میں تقسیم کی سنت ۔' WHERE id = 2246;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا کہا کہ ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے، آپ نے فرمایا کہ لوگ کہتے ہیں ابوہریرہ بہت حدیث بیان کرتے ہیں۔ حالانکہ مجھے بھی اللہ سے ملنا ہے ( میں غلط بیانی کیسے کر سکتا ہوں ) یہ لوگ یہ بھی کہتے ہیں کہ مہاجرین اور انصار آخر اس کی طرح کیوں احادیث بیان نہیں کرتے؟ بات یہ ہے کہ میرے بھائی مہاجرین بازاروں میں خرید و فروخت میں مشغول رہا کرتے اور میرے بھائی انصار کو ان کی جائیداد ( کھیت اور باغات وغیرہ ) مشغول رکھا کرتی تھی۔ صرف میں ایک مسکین آدمی تھا۔ پیٹ بھر لینے کے بعد میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت ہی میں برابر حاضر رہا کرتا۔ جب یہ سب حضرات غیر حاضر رہتے تو میں حاضر ہوتا۔ اس لیے جن احادیث کو یہ یاد نہیں کر سکتے تھے، میں انہیں یاد رکھتا تھا، اور ایک دن نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ تم میں سے جو شخص بھی اپنے کپڑے کو میری اس تقریر کے ختم ہونے تک پھیلائے رکھے پھر ( تقریر ختم ہونے پر ) اسے اپنے سینے سے لگا لے تو وہ میری احادیث کو کبھی نہیں بھولے گا۔ میں نے اپنی کملی کو پھیلا دیا۔ جس کے سوا میرا بدن پر اور کوئی کپڑا نہیں تھا۔ جب نبی کریم صلی اللہ علیہ وسلم نے اپنی تقریر ختم فرمائی تو میں نے وہ چادر اپنے سینے سے لگا لی۔ اس ذات کی قسم جس نے آپ کو حق کے ساتھ نبی بنا کر مبعوث کیا، پھر آج تک میں آپ صلی اللہ علیہ وسلم کے اسی ارشاد کی وجہ سے ( آپ صلی اللہ علیہ وسلم کی کوئی حدیث نہیں بھولا ) اللہ گواہ ہے کہ اگر قرآن کی دو آیتیں نہ ہوتیں تو میں تم سے کوئی حدیث کبھی بیان نہ کرتا آیت «إن الذين يكتمون ما أنزلنا من البينات‏» سے اللہ تعالیٰ کے ارشاد «الرحيم‏» تک۔ ( جس میں ) اس دین کے چھپانے والے پر، جسے اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم کے ذریعہ دنیا میں بھیجا ہے، سخت لعنت کی گئی ہے۔' WHERE id = 2259;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا کہ ہم سے نافع بن عمر نے بیان کیا، ان سے ابن ابی ملکیہ نے اور ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک دفعہ سورج گرہن کی نماز پڑھی پھر فرمایا ( ابھی ابھی ) دوزخ مجھ سے اتنی قریب آ گئی تھی کہ میں نے چونک کر کہا۔ اے رب! کیا میں بھی انہیں میں سے ہوں۔ اتنے میں دوزخ میں میری نظر ایک عورت پر پڑی۔ ( اسماء رضی اللہ عنہا نے بیان کیا ) مجھے یاد ہے کہ ( نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ ) اس عورت کو ایک بلی نوچ رہی تھی۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ اس پر اس عذاب کی کیا وجہ ہے؟ آپ کے ساتھ والے فرشتوں نے کہا کہ اس عورت نے اس بلی کو اتنی دیر تک باندھے رکھا کہ وہ بھوک کے مارے مر گئی۔' WHERE id = 2271;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب، ان سے عبدالرحمٰن بن عوف رضی اللہ عنہ کے غلام ابوعبید نے، اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اگر کوئی شخص لکڑیوں کا گٹھا اپنی پیٹھ پر ( بیچنے کے لیے ) لیے پھرے تو وہ اس سے اچھا ہے کہ کسی کے سامنے ہاتھ پھیلائے۔ پھر خواہ اسے کچھ دے یا نہ دے۔' WHERE id = 2281;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، ان سے عبدالواحد نے بیان کیا، ان سے اعمش نے بیان کیا، انہوں نے بیان کیا کہ ابراہیم کی خدمت میں ہم نے بیع سلم میں رہن کا ذکر کیا، تو انہوں نے بیان کیا کہ مجھ سے اسود نے بیان کیا اور ان سے عائشہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک یہودی سے غلہ ایک خاص مدت ( کے قرض پر ) خریدا، اور اپنی لوہے کی زرہ اس کے پاس رہن رکھ دی۔' WHERE id = 2292;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے کہا کہ ہم سے انس نے بیان کیا، ان سے ہشام نے، ان سے وہب بن کیسان نے اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے خبر دی کہ جب ان کے والد شہید ہوئے تو ایک یہودی کا تیس وسق قرض اپنے اوپر چھوڑ گئے۔ جابر رضی اللہ عنہ نے اس سے مہلت مانگی، لیکن وہ نہیں مانا۔ پھر جابر رضی اللہ عنہ آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تاکہ آپ صلی اللہ علیہ وسلم اس یہودی ( ابوشحم ) سے ( مہلت دینے کی ) سفارش کریں۔ رسول اللہ صلی اللہ علیہ وسلم تشریف لائے اور یہودی سے یہ فرمایا کہ جابر رضی اللہ عنہ کے باغ کے پھل ( جو بھی ہوں ) اس قرض کے بدلے میں لے لے۔ جو ان کے والد کے اوپر اس کا ہے، اس نے اس سے بھی انکار کیا۔ اب رسول اللہ صلی اللہ علیہ وسلم باغ میں داخل ہوئے اور اس میں چلتے رہے پھر جابر رضی اللہ عنہ سے آپ صلی اللہ علیہ وسلم نے فرمایا کہ باغ کا پھل توڑ کے اس کا قرض ادا کرو۔ جب رسول اللہ صلی اللہ علیہ وسلم واپس تشریف لائے تو انہوں نے باغ کی کھجوریں توڑیں اور یہودی کا تیس وسق ادا کر دیا۔ سترہ وسق اس میں سے بچ بھی رہا۔ جابر رضی اللہ عنہ آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تاکہ آپ کو بھی یہ اطلاع دیں۔ آپ صلی اللہ علیہ وسلم اس وقت عصر کی نماز پڑھ رہے تھے۔ جب آپ صلی اللہ علیہ وسلم فارغ ہوئے تو انہوں نے آپ صلی اللہ علیہ وسلم کو اطلاع دی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی خبر ابن خطاب کو بھی کر دو۔ چنانچہ جابر رضی اللہ عنہ عمر رضی اللہ عنہ کے یہاں گئے۔ عمر رضی اللہ عنہ نے فرمایا، میں تو اسی وقت سمجھ گیا تھا جب رسول اللہ صلی اللہ علیہ وسلم باغ میں چل رہے تھے کہ اس میں ضرور برکت ہو گئی۔' WHERE id = 2302;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شبیہ نے بیان کیا، ان سے جریر نے بیان کیا، ان سے منصور نے، ان سے شعبی نے، ان سے مغیرہ بن شعبہ کے غلام وراد نے اور ان سے مغیرہ بن شعبہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اللہ تعالیٰ نے تم پر ماں ( اور باپ ) کی نافرمانی لڑکیوں کو زندہ دفن کرنا، ( واجب حقوق کی ) ادائیگی نہ کرنا اور ( دوسروں کا مال ناجائز طریقہ پر ) دبا لینا حرام قرار دیا ہے۔ اور فضول بکواس کرنے اور کثرت سے سوال کرنے اور مال ضائع کرنے کو مکروہ قرار دیا ہے۔' WHERE id = 2313;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے محمد بن عدی نے بیان کیا، ان سے شعبہ نے، ان سے سعد بن ابراہیم نے، ان سے حمید بن عبدالرحمٰن نے، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، میں نے تو یہ ارادہ کر لیا تھا کہ نماز کی جماعت قائم کرنے کا حکم دے کر خود ان لوگوں کے گھروں میں جاؤں جو جماعت میں حاضر نہیں ہوتے اور ان کے گھر کو جلا دوں۔' WHERE id = 2324;
UPDATE hadiths SET urdu = 'اور لیث بن سعد نے بیان کیا کہ مجھ سے جعفر بن ربیعہ نے بیان کیا، ان سے عبدالرحمٰن بن ہرمز نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے بنی اسرائیل کے ایک مرد کا ذکر کیا۔ پھر پوری حدیث بیان کی ( جو اس سے پہلے گزر چکی ہے ) کہ ( قرض دینے والا ) باہر یہ دیکھنے کے لیے نکلا کہ ممکن ہے کوئی جہاز اس کا روپیہ لے کر آیا ہو۔ ( دریا کے کنارے پر جب وہ پہنچا ) تو اسے ایک لکڑی ملی جسے اس نے اپنے گھر کے ایندھن کے لیے اٹھا لیا۔ لیکن جب اسے چیرا تو اس میں روپیہ اور خط پایا۔' WHERE id = 2334;
UPDATE hadiths SET urdu = 'ہم سے اسحٰق بن ابراہیم نے بیان کیا، انہوں نے کہا کہ ہم کو معاذ بن ہشام نے خبر دی، انہوں نے کہا کہ ہم سے ان کے باپ نے بیان کیا، ان سے قتادہ نے، ان سے ابوالمتوکل ناجی نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، جب مومنوں کو دوزخ سے نجات مل جائے گی تو انہیں ایک پل پر جو جنت اور دوزخ کے درمیان ہو گا روک لیا جائے گا اور وہیں ان کے مظالم کا بدلہ دے دیا جائے گا۔ جو وہ دنیا میں باہم کرتے تھے۔ پھر جب پاک صاف ہو جائیں گے تو انہیں جنت میں داخلہ کی اجازت دی جائے گی۔ اس ذات کی قسم! جس کے ہاتھ میں محمد کی جان ہے، ان میں سے ہر شخص اپنے جنت کے گھر کو اپنے دنیا کے گھر سے بھی بہتر طور پر پہچانے گا۔ یونس بن محمد نے بیان کیا کہ ہم سے شیبان نے بیان کیا، ان سے قتادہ نے اور ان سے ابوالمتوکل نے بیان کیا۔' WHERE id = 2345;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو ہشام بن عروہ نے خبر دی، انہیں ان کے باپ نے، اور ان سے عائشہ رضی اللہ عنہا نے ( قرآن مجید کی آیت ) «وإن امرأة خافت من بعلها نشوزا أو إعراضا‏» ”اگر کوئی عورت اپنے شوہر کی طرف سے نفرت یا اس کے منہ پھیرنے کا خوف رکھتی ہو“ کے بارے میں فرمایا کہ کسی شخص کی بیوی ہے لیکن شوہر اس کے پاس زیادہ آتا جاتا نہیں بلکہ اسے جدا کرنا چاہتا ہے اس پر اس کی بیوی کہتی ہے کہ میں اپنا حق تمہیں معاف کرتی ہوں۔ اسی بارے میں یہ آیت نازل ہوئی۔' WHERE id = 2355;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، ان سے عروہ نے بیان کیا، اور ان سے عائشہ رضی اللہ عنہا نے کہ عتبہ بن ربیعہ کی بیٹی ہند رضی اللہ عنہا حاضر خدمت ہوئیں اور عرض کیا، یا رسول اللہ! ابوسفیان ( جو ان کے شوہر ہیں وہ ) بخیل ہیں۔ تو کیا اس میں کوئی حرج ہے اگر میں ان کے مال میں سے لے کر اپنے بال بچوں کو کھلایا کروں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم دستور کے مطابق ان کے مال سے لے کر کھلاؤ تو اس میں کوئی حرج نہیں۔' WHERE id = 2365;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ابوعقیل نے بیان کیا، ان سے ابوالمتوکل ناجی نے بیان کیا کہ میں جابر بن عبداللہ رضی اللہ عنہما کی خدمت میں حاضر ہوا تو انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم مسجد میں تشریف رکھتے تھے۔ اس لیے میں بھی مسجد کے اندر چلا گیا۔ البتہ اونٹ بلاط کے ایک کنارے پر باندھ دیا۔ آپ صلی اللہ علیہ وسلم سے میں نے عرض کیا کہ یا رسول اللہ! آپ کا اونٹ حاضر ہے۔ آپ صلی اللہ علیہ وسلم باہر تشریف لائے اور اونٹ کے چاروں طرف ٹہلنے لگے۔ پھر فرمایا کہ قیمت بھی لے اور اونٹ بھی لے جا۔' WHERE id = 2375;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید نے بیان کیا، انہوں نے کہا ہم سے سعید بن ابی ایوب نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوالاسود نے بیان کیا، ان سے عکرمہ نے اور ان سے عبداللہ بن عمرو رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص اپنے مال کی حفاظت کرتے ہوئے قتل کر دیا گیا وہ شہید ہے۔' WHERE id = 2385;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے جبلہ نے بیان کیا کہ ہمارا قیام مدینہ میں تھا اور ہم پر قحط کا دور دورہ ہوا۔ عبداللہ بن زبیر رضی اللہ عنہما ہمیں کھجور کھانے کے لیے دیتے تھے اور عبداللہ بن عمر رضی اللہ عنہما گزرتے ہوئے یہ کہہ کر جایا کرتے تھے کہ دو دو کھجور ایک ساتھ ملا کر نہ کھانا کیونکہ نبی کریم صلی اللہ علیہ وسلم نے اپنے دوسرے ساتھی کی اجازت کے بغیر ایسا کرنے سے منع فرمایا ہے۔' WHERE id = 2395;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، ان سے قتادہ نے، ان سے نضر بن انس نے، ان سے بشیر بن نہیک نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جس نے کسی ( ساجھے کے ) غلام کا اپنا حصہ آزاد کر دیا تو اگر اس کے پاس مال ہے تو پورا غلام آزاد ہو جائے گا۔ ورنہ باقی حصوں کو آزاد کرانے کے لیے اس سے محنت مزدوری کرائی جائے۔ لیکن اس سلسلے میں اس پر کوئی دباو نہ ڈالا جائے۔' WHERE id = 2407;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے، ان سے ان کے والد نے، ان سے ابومرواح نے اور ان سے ابوذر غفاری رضی اللہ عنہ نے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کہ کون سا عمل افضل ہے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ پر ایمان لانا اور اس کی راہ میں جہاد کرنا۔ میں نے پوچھا اور کس طرح کا غلام آزاد کرنا افضل ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا، جو سب سے زیادہ قیمتی ہو اور مالک کی نظر میں جو بہت زیادہ پسندیدہ ہو۔ میں نے عرض کیا کہ اگر مجھ سے یہ نہ ہو سکا؟ آپ صلی اللہ علیہ وسلم نے فرمایا، کہ پھر کسی مسلمان کاریگر کی مدد کر یا کسی بے ہنر کی۔ انہوں نے کہا کہ اگر میں یہ بھی نہ کر سکا؟ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر لوگوں کو اپنے شر سے محفوظ کر دے کہ یہ بھی ایک صدقہ ہے جسے تم خود اپنے اوپر کرو گے۔' WHERE id = 2419;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا ہم سے مسعر نے بیان کیا، ان سے قتادہ نے، ان سے زرارہ بن اوفی نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ نے میری امت کے دلوں میں پیدا ہونے والے وسوسوں کو معاف کر دیا ہے جب تک وہ انہیں عمل یا زبان پر نہ لائیں۔“' WHERE id = 2429;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، انہیں ان کے والد نے خبر دی کہ حکیم بن حزام رضی اللہ عنہ نے اپنے کفر کے زمانے میں سو غلام آزاد کیے تھے اور سو اونٹ لوگوں کی سواری کے لیے دیے تھے۔ پھر جب اسلام لائے تو سو اونٹ لوگوں کی سواری کے لیے دیے اور سو غلام آزاد کیے۔ پھر انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا۔ یا رسول اللہ! بعض ان نیک اعمال کے متعلق آپ کا کیا خیال ہے جنہیں میں بہ نیت ثواب کفر کے زمانہ میں کیا کرتا تھا ( ہشام بن عروہ نے کہا کہ ) «أتحنث بها» کے معنی «أتبرر بها» کے ہیں ) انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے اس پر فرمایا ”جو نیکیاں تم پہلے کر چکے ہو وہ سب قائم رہیں گی۔“' WHERE id = 2439;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے کہا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب غلام اپنے آقا کی خیر خواہی کرے اور اپنے رب کی عبادت تمام حسن و خوبی کے ساتھ بجا لائے تو اسے دوگنا ثواب ملتا ہے۔“' WHERE id = 2450;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی نافع سے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ام المؤمنین سیدہ عائشہ رضی اللہ عنہا نے ایک باندی خرید کر اسے آزاد کرنا چاہا، اس باندی کے مالکوں نے کہا کہ اس شرط پر ہم معاملہ کر سکتے ہیں کہ ولاء ہمارے ساتھ قائم رہے۔ رسول اللہ صلی اللہ علیہ وسلم نے عائشہ رضی اللہ عنہا سے فرمایا کہ ان کی اس شرط کی وجہ سے تم نہ رکو، ولاء تو اسی کی ہوتی ہے جو آزاد کرے۔' WHERE id = 2461;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ہشام بن زید بن انس بن مالک نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ مرالظہران نامی جگہ میں ہم نے ایک خرگوش کا پیچھا کیا۔ لوگ ( اس کے پیچھے ) دوڑے اور اسے تھکا دیا اور میں نے قریب پہنچ کر اسے پکڑ لیا۔ پھر ابوطلحہ رضی اللہ عنہ کے ہاں لایا۔ انہوں نے اسے ذبح کیا اور اس کے پیچھے کا یا دونوں رانوں کا گوشت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بھیجا۔ ( شعبہ نے بعد میں یقین کے ساتھ ) کہا کہ دونوں رانیں انہوں نے بھیجی تھیں، اس میں کوئی شک نہیں۔ رسول اللہ صلی اللہ علیہ وسلم نے اسے قبول فرمایا تھا میں نے پوچھا اور اس میں سے آپ صلی اللہ علیہ وسلم نے کچھ تناول بھی فرمایا؟ انہوں نے بیان کیا کہ ہاں! کچھ تناول فرمایا تھا۔ اس کے بعد پھر انہوں نے کہا کہ آپ نے وہ ہدیہ قبول فرما لیا تھا۔' WHERE id = 2471;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، ان سے عزرہ بن ثابت انصاری نے بیان کیا، کہا کہ مجھ سے ثمامہ بن عبداللہ نے بیان کیا، عزرہ نے کہا کہ میں ثمامہ بن عبداللہ کی خدمت میں حاضر ہوا تو انہوں نے مجھے خوشبو عنایت فرمائی اور بیان کیا کہ انس رضی اللہ عنہ خوشبو کو واپس نہیں کرتے تھے۔ ثمامہ نے کہا کہ انس رضی اللہ عنہ کا گمان تھا کہ نبی کریم صلی اللہ علیہ وسلم خوشبو کو واپس نہیں فرمایا کرتے تھے۔' WHERE id = 2481;
UPDATE hadiths SET urdu = 'اور بکر بن مضر نے عمرو بن حارث سے، انہوں نے بکیر سے، انہوں نے ابن عباس رضی اللہ عنہما کے غلام کریب سے ( بیان کیا کہ ) نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ میمونہ رضی اللہ عنہا نے اپنی ایک لونڈی آزاد کی تو رسول اللہ صلی اللہ علیہ وسلم نے ان سے فرمایا ”اگر وہ تمہارے ننھیال والوں کو دی جاتی تو تمہیں زیادہ ثواب ملتا۔“' WHERE id = 2492;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا محارب بن دثار سے اور انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، آپ فرماتے تھے کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو سفر میں ایک اونٹ بیچا تھا۔ جب ہم مدینہ پہنچے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ مسجد میں جا کر دو رکعت نماز پڑھ، پھر آپ صلی اللہ علیہ وسلم نے وزن کیا۔ شعبہ نے بیان کیا، میرا خیال ہے کہ ( جابر رضی اللہ عنہ نے کہا ) میرے لیے وزن کیا ( آپ صلی اللہ علیہ وسلم کے حکم سے بلال رضی اللہ عنہ نے ) اور ( اس پلڑے کو جس میں سکہ تھا ) جھکا دیا۔ ( تاکہ مجھے زیادہ ملے ) اس میں سے کچھ تھوڑا سا میرے پاس جب سے محفوظ تھا۔ لیکن شام والے ( اموی لشکر ) یوم حرہ کے موقع پر مجھ سے چھین کر لے گئے۔' WHERE id = 2502;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، کہا ہم سے خالد بن حارث نے بیان کیا، ان سے شعبہ نے، ان سے ہشام بن زید نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ایک یہودی عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں زہر ملا ہوا بکری کا گوشت لائی، آپ صلی اللہ علیہ وسلم نے اس میں سے کچھ کھایا ( لیکن فوراً ہی فرمایا کہ اس میں زہر پڑا ہوا ہے ) پھر جب اسے لایا گیا ( اور اس نے زہر ڈالنے کا اقرار بھی کر لیا ) تو کہا گیا کہ کیوں نہ اسے قتل کر دیا جائے۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ اس زہر کا اثر میں نے ہمیشہ نبی کریم صلی اللہ علیہ وسلم کے تالو میں محسوس کیا۔' WHERE id = 2513;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا قتادہ سے کہ میں نے انس رضی اللہ عنہ سے سنا۔ آپ نے بیان کیا کہ مدینے پر ( دشمن کے حملے کا ) خوف تھا۔ اس لیے نبی کریم صلی اللہ علیہ وسلم نے ابوطلحہ رضی اللہ عنہ سے ایک گھوڑا جس کا نام مندوب تھا مستعار لیا، پھر آپ صلی اللہ علیہ وسلم اس پر سوار ہوئے ( صحابہ بھی ساتھ تھے ) پھر جب واپس ہوئے تو فرمایا، ہمیں تو کوئی خطرہ کی چیز نظر نہ آئی، البتہ یہ گھوڑا سمندر کی طرح ( تیز دوڑتا ) پایا۔' WHERE id = 2523;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے عبداللہ بن عمر نمیری نے بیان کیا، کہا ہم سے ثوبان نے بیان کیا اور لیث بن سعد نے بیان کیا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، انہیں عروہ، ابن مسیب، علقمہ بن وقاص اور عبیداللہ نے عائشہ رضی اللہ عنہا کی حدیث کے متعلق خبر دی اور ان کی باہم ایک کی بات دوسرے کی بات کی تصدیق کرتی ہے کہ جب ان پر تہمت لگانے والوں نے تہمت لگائی تو رسول اللہ صلی اللہ علیہ وسلم نے علی اور اسامہ رضی اللہ عنہما کو اپنی بیوی ( عائشہ رضی اللہ عنہا ) کو اپنے سے جدا کرنے کے متعلق مشورہ کرنے کے لیے بلایا، کیونکہ آپ صلی اللہ علیہ وسلم پر اب تک ( اس سلسلے میں ) وحی نہیں آئی تھی۔ اسامہ رضی اللہ عنہ نے تو یہ کہا کہ آپ کی زوجہ مطہرہ ( عائشہ رضی اللہ عنہا ) میں ہم سوائے خیر کے اور کچھ نہیں جانتے۔ اور بریرہ رضی اللہ عنہا ( ان کی خادمہ ) نے کہا کہ میں کوئی ایسی چیز نہیں جانتی جس سے ان پر عیب لگایا جا سکے۔ اتنی بات ضرور ہے کہ وہ نوعمر لڑکی ہیں کہ آٹا گوندھتی اور پھر جا کے سو رہتی ہے اور بکری آ کر اسے کھا لیتی ہے۔ رسول اللہ صلی اللہ علیہ وسلم نے ( تہمت کے جھوٹ ثابت ہونے کے بعد ) فرمایا کہ ایسے شخص کی طرف سے کون عذر خواہی کرے گا جو میری بیوی کے بارے میں بھی مجھے اذیت پہنچاتا ہے۔ قسم اللہ کی! میں نے اپنے گھر میں خیر کے سوا اور کچھ نہیں دیکھا اور لوگ ایسے شخص کا نام لیتے ہیں جس کے متعلق بھی مجھے خیر کے سوا اور کچھ معلوم نہیں۔' WHERE id = 2533;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی، انہیں اشعث بن ابوشعثاء نے، انہیں ان کے والد نے، انہیں مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ( گھر میں ) تشریف لائے تو میرے یہاں ایک صاحب ( ان کے رضاعی بھائی ) بیٹھے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، عائشہ! یہ کون ہے؟ میں نے عرض کیا کہ یہ میرا رضاعی بھائی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا عائشہ! ذرا دیکھ بھال کر لو، کون تمہارا رضاعی بھائی ہے۔ کیونکہ رضاعت وہی معتبر ہے جو کم سنی میں ہو۔ محمد بن کثیر کے ساتھ اس حدیث کو عبدالرحمٰن بن مہدی نے سفیان ثوری سے روایت کیا ہے۔' WHERE id = 2543;
UPDATE hadiths SET urdu = 'ہم سے زیاد بن یحییٰ نے بیان کیا، کہا ہم سے حاتم بن وردان نے بیان کیا، کہا ہم سے ایوب نے بیان کیا، عبداللہ بن ابی ملیکہ سے اور ان سے مسور بن مخرمہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے ہاں چند قبائیں آئیں تو مجھ سے میرے باپ مخرمہ رضی اللہ عنہ نے کہا کہ میرے ساتھ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں چلو۔ ممکن ہے آپ صلی اللہ علیہ وسلم ان میں سے کوئی مجھے بھی عنایت فرمائیں۔ میرے والد ( نبی کریم صلی اللہ علیہ وسلم کے گھر پہنچ کر ) دروازے پر کھڑے ہو گئے اور باتیں کرنے لگے۔ آپ صلی اللہ علیہ وسلم نے ان کی آواز پہچان لی اور باہر تشریف لائے، آپ صلی اللہ علیہ وسلم کے پاس ایک قباء بھی تھی، آپ صلی اللہ علیہ وسلم اس کی خوبیاں بیان کرنے لگے، اور فرمایا ”میں نے یہ تمہارے ہی لیے الگ کر رکھی تھی، میں نے یہ تمہارے ہی لیے الگ کر رکھی تھی۔“' WHERE id = 2553;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے نافع بن عمر نے بیان کیا، ان سے ابن ابی ملیکہ نے بیان کیا کہ ابن عباس رضی اللہ عنہما نے لکھا تھا ”نبی کریم صلی اللہ علیہ وسلم نے مدعیٰ علیہ کے لیے قسم کھانے کا فیصلہ کیا تھا۔“' WHERE id = 2563;
UPDATE hadiths SET urdu = 'ہم سے ابرہیم بن حمزہ نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے، ان سے عبیداللہ بن عبداللہ نے کہ عبداللہ بن عباس رضی اللہ عنہما نے انہیں خبر دی، انہوں نے بیان کیا کہ انہیں ابوسفیان رضی اللہ عنہ نے خبر دی کہ ہرقل نے ان سے کہا تھا کہ میں نے تم سے پوچھا تھا کہ وہ ( محمد صلی اللہ علیہ وسلم ) تمہیں کس بات کا حکم دیتے ہیں تو تم نے بتایا کہ وہ تمہیں نماز، سچائی، عفت، عہد کے پورا کرنے اور امانت کے ادا کرنے کا حکم دیتے ہیں۔ اور یہ نبی کی صفات ہیں۔' WHERE id = 2574;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے معتمر نے بیان کیا، کہا کہ میں نے اپنے باپ سے سنا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے عرض کیا گیا، اگر آپ عبداللہ بن ابی ( منافق ) کے یہاں تشریف لے چلتے تو بہتر تھا۔ آپ صلی اللہ علیہ وسلم اس کے یہاں ایک گدھے پر سوار ہو کر تشریف لے گئے۔ صحابہ رضوان اللہ علیہم پیدل آپ صلی اللہ علیہ وسلم کے ہمراہ تھے۔ جدھر سے آپ صلی اللہ علیہ وسلم گزر رہے تھے وہ شور زمین تھی۔ جب نبی کریم صلی اللہ علیہ وسلم اس کے یہاں پہنچے تو وہ کہنے لگا ذرا آپ دور ہی رہئیے آپ کے گدھے کی بو نے میرا دماغ پریشان کر دیا ہے۔ اس پر ایک انصاری صحابی بولے کہ اللہ کی قسم! رسول اللہ صلی اللہ علیہ وسلم کا گدھا تجھ سے زیادہ خوشبودار ہے۔ عبداللہ ( منافق ) کی طرف سے اس کی قوم کا ایک شخص اس صحابی کی اس بات پر غصہ ہو گیا اور دونوں نے ایک دوسرے کو برا بھلا کہا۔ پھر دونوں طرف سے دونوں کے حمایتی مشتعل ہو گئے اور ہاتھا پائی، چھڑی اور جوتے تک نوبت پہنچ گئی۔ ہمیں معلوم ہوا ہے کہ یہ آیت اسی موقع پر نازل ہوئی تھی۔ «وإن طائفتان من المؤمنين اقتتلوا فأصلحوا بينهما‏» ”اگر مسلمانوں کے دو گروہ آپس میں لڑ پڑیں تو ان میں صلح کرا دو۔“' WHERE id = 2584;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے بشر نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے بشیر بن یسار نے اور ان سے سہل بن ابی حثمہ رضی اللہ عنہ نے بیان کیا کہ عبداللہ بن سہل اور محیصہ بن مسعود بن زید رضی اللہ عنہما خیبر گئے۔ خیبر کے یہودیوں سے مسلمانوں کی ان دنوں صلح تھی۔' WHERE id = 2594;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے سفیان نے بیان کیا، ان سے زیاد بن علاقہ نے بیان کیا کہ میں نے جریر رضی اللہ عنہ سے سنا، آپ بیان کرتے تھے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے بیعت کی تو آپ صلی اللہ علیہ وسلم نے مجھ سے ہر مسلمان کے ساتھ خیر خواہی کرنے کی شرط پر بیعت کی تھی۔' WHERE id = 2605;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے عبدالواحد بن ایمن مکی نے بیان کیا، ان سے ان کے باپ نے بیان کیا کہ میں عائشہ رضی اللہ عنہا کی خدمت میں حاضر ہوا تو آپ نے بتلایا کہ بریرہ رضی اللہ عنہ میرے یہاں آئیں، انہوں نے کتابت کا معاملہ کر لیا تھا۔ مجھ سے کہنے لگیں کہ اے ام المؤمنین! مجھے آپ خرید لیں، کیونکہ میرے مالک مجھے بیچنے پر آمادہ ہیں، پھر آپ مجھے آزاد کر دینا۔ عائشہ رضی اللہ عنہا نے فرمایا کہ ہاں ( میں ایسا کر لوں گی ) لیکن بریرہ رضی اللہ عنہا نے پھر کہا کہ میرے مالک مجھے اسی وقت بیچیں گے جب وہ ولاء کی شرط اپنے لیے لگا لیں۔ اس پر عائشہ رضی اللہ عنہا نے فرمایا کہ پھر مجھے ضرورت نہیں ہے۔ جب نبی کریم صلی اللہ علیہ وسلم نے سنا، یا آپ صلی اللہ علیہ وسلم کو معلوم ہوا ( راوی کو شبہ تھا ) تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ بریرہ ( رضی اللہ عنہا ) کا کیا معاملہ ہے؟ تم انہیں خرید کر آزاد کر دو، وہ لوگ جو چاہیں شرط لگا لیں۔ عائشہ رضی اللہ عنہا نے کہا کہ میں نے بریرہ کو خرید کر آزاد کر دیا اور اس کے مالک نے ولاء کی شرط اپنے لیے محفوظ رکھی۔ آپ صلی اللہ علیہ وسلم نے یہی فرمایا کہ ولاء اسی کی ہوتی ہے جو آزاد کرے ( دوسرے ) جو چاہیں شرط لگاتے رہیں۔' WHERE id = 2616;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا کہ ہم سے محمد بن عبداللہ انصاری نے بیان کیا ‘ ان سے ابن عون نے ‘ کہا کہ مجھے نافع نے خبر دی ‘ انہیں ابن عمر رضی اللہ عنہما نے کہ عمر بن خطاب رضی اللہ عنہ کو خیبر میں ایک قطعہ زمین ملی تو آپ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں مشورہ کیلئے حاضر ہوئے اور عرض کیا یا رسول اللہ! مجھے خیبر میں ایک زمین کا ٹکڑا ملا ہے اس سے بہتر مال مجھے اب تک کبھی نہیں ملا تھا ‘ آپ اس کے متعلق کیا حکم فرماتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر جی چاہے تو اصل زمین اپنے ملکیت میں باقی رکھ اور پیداوار صدقہ کر دے۔ ابن عمر رضی اللہ عنہما نے بیان کیا کہ پھر عمر رضی اللہ عنہ نے اس کو اس شرط کے ساتھ صدقہ کر دیا کہ نہ اسے بیچا جائے گا نہ اس کا ہبہ کیا جائے گا اور نہ اس میں وراثت چلے گی۔ اسے آپ نے محتاجوں کے لیے ‘ رشتہ داروں کے لیے اور غلام آزاد کرانے کے لیے ‘ اللہ کے دین کی تبلیغ اور اشاعت کے لیے اور مہمانوں کیلئے صدقہ ( وقف ) کر دیا اور یہ کہ اس کا متولی اگر دستور کے مطابق اس میں سے اپنی ضرورت کے مطابق وصول کر لے یا کسی محتاج کو دے تو اس پر کوئی الزام نہیں۔ ابن عون نے بیان کیا کہ جب میں نے اس حدیث کا ذکر ابن سیرین سے کیا تو انہوں نے فرمایا کہ ( متولی ) اس میں سے مال جمع کرنے کا ارادہ نہ رکھتا ہو۔' WHERE id = 2626;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا ورقاء سے ‘ انہوں نے ابن ابی نجیح سے ‘ ان سے عطاء نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ شروع اسلام میں ( میراث کا ) مال اولاد کو ملتا تھا اور والدین کے لیے وصیت ضروری تھی لیکن اللہ تعالیٰ نے جس طرح چاہا اس حکم کو منسوخ کر دیا پھر لڑکے کا حصہ دو لڑکیوں کے برابر قرار دیا اور والدین میں سے ہر ایک کا چھٹا حصہ اور بیوی کا ( اولاد کی موجودگی میں ) آٹھواں حصہ اور ( اولاد کے نہ ہونے کی صورت میں ) چوتھا حصہ قرار دیا۔ اسی طرح شوہر کا ( اولاد نہ ہونے کی صورت میں ) آدھا ( اولاد ہونے کی صورت میں ) چوتھائی حصہ قرار دیا۔' WHERE id = 2636;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا ‘ کہا ہم سے لیث نے بیان کیا ‘ ان سے عقیل نے ‘ ان سے ابن شہاب نے کہا کہ مجھے عبدالرحمٰن بن عبداللہ بن کعب نے خبر دی اور ان سے عبداللہ بن کعب نے بیان کیا کہ میں نے کعب بن مالک رضی اللہ عنہ سے سنا ‘ وہ بیان کرتے تھے کہ میں نے عرض کیا یا رسول اللہ! میری توبہ ( غزوہ تبوک میں نہ جانے کی ) قبول ہونے کا شکرانہ یہ ہے کہ میں اپنا مال اللہ اور اس کے رسول کے راستے میں دیدوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر اپنے مال کا ایک حصہ اپنے پاس ہی باقی رکھو تو تمہارے حق میں یہ بہتر ہے۔ میں نے عرض کیا کہ پھر میں اپنا خیبر کا حصہ اپنے پاس محفوظ رکھتا ہوں۔' WHERE id = 2646;
UPDATE hadiths SET urdu = 'اور امام بخاری رحمہ اللہ نے کہا کہ ہم سے سلیمان بن حرب نے بیان کیا ‘ ان سے حماد بن اسامہ نے بیان کیا ‘ ان سے ایوب نے ‘ ان سے نافع نے بیان کیا کہ ابن عمر رضی اللہ عنہما کو کوئی وصی بناتا تو وہ کبھی انکار نہ کرتے۔ ابن سیرین تابعی رحمہ اللہ کا محبوب مشغلہ یہ تھا کہ یتیم کے مال و جائیداد کے سلسلے میں ان کے خیر خواہوں اور ولیوں کو جمع کرتے تاکہ ان کے لیے کوئی اچھی صورت پیدا کرنے کے لیے غور کریں۔ طاؤس تابعی رحمہ اللہ سے جب یتیموں کے بارے میں کوئی سوال کیا جاتا تو آپ یہ آیت پڑھتے کہ «والله يعلم المفسد من المصلح‏» ”اور اللہ فساد پیدا کرنے والے اور سنوارنے والے کو خوب جانتا ہے۔“ عطاء رحمہ اللہ نے یتیموں کے بارے میں کہا خواہ وہ معمولی قسم کے لوگوں میں ہوں یا بڑے درجے کے ‘ اس کا ولی اس کے حصہ میں سے جیسے اس کے لائق ہو، ویسا اس پر خرچ کرے۔' WHERE id = 2656;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ‘ ان سے ایوب سختیانی نے ‘ ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ عمر رضی اللہ عنہ نے اپنے وقف میں یہ شرط لگائی تھی کہ اس کا متولی اس میں سے کھا سکتا ہے اور اپنے دوست کو کھلا سکتا ہے لیکن وہ دولت نہ جوڑے۔' WHERE id = 2666;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم کو شعیب نے خبر دی ‘ ان سے زہری نے بیان کیا کہ مجھے سعید بن مسیب نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ‘ آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ اللہ کے راستے میں جہاد کرنے والے کی مثال۔۔۔۔ اور اللہ تعالیٰ اس شخص کو خوب جانتا ہے جو ( خلوص دل کے ساتھ صرف اللہ تعالیٰ کی رضا کیلئے ) اللہ کے راستے میں جہاد کرتا ہے۔۔۔۔ اس شخص کی سی ہے جو رات میں برابر نماز پڑھتا رہے اور دن میں برابر روزے رکھتا رہے اور اللہ تعالیٰ نے اپنے راستے میں جہاد کرنے والے کیلئے اس کی ذمہ داری لے لی ہے کہ اگر اسے شہادت دے گا تو اسے بے حساب و کتاب جنت میں داخل کرے گا یا پھر زندہ و سلامت ( گھر ) ثواب اور مال غنیمت کے ساتھ واپس کرے گا۔' WHERE id = 2676;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر حوضی نے بیان کیا ‘ کہا ہم سے ہمام نے ان سے اسحاق نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے بنو سلیم کے ( 70 ) ستر آدمی ( جو قاری تھے ) بنو عامر کے یہاں بھیجے۔ جب یہ سب حضرات ( بئرمعونہ پر ) پہنچے تو میرے ماموں حرام بن ملحان رضی اللہ عنہ نے کہا میں ( بنو سلیم کے یہاں ) آگے جاتا ہوں اگر مجھے انہوں نے اس بات کا امن دے دیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی باتیں ان تک پہنچاؤں تو۔ بہتر ورنہ تم لوگ میرے قریب تو ہو ہی۔ چنانچہ وہ ان کے یہاں گئے اور انہوں نے امن بھی دے دیا۔ ابھی وہ قبیلہ کے لوگوں کو رسول اللہ صلی اللہ علیہ وسلم کی باتیں سنا ہی رہے تھے کہ قبیلہ والوں نے اپنے ایک آدمی ( عامر بن طفیل ) کو اشارہ کیا اور اس نے آپ رضی اللہ عنہ کے جسم پر برچھا پیوست کر دیا جو آرپار ہو گیا۔ اس وقت ان کی زبان سے نکلا اللہ اکبر میں کامیاب ہو گیا کعبہ کے رب کی قسم! اس کے بعد قبیلہ والے حرام رضی اللہ عنہ کے دوسرے ساتھیوں کی طرف ( جو ستر کی تعداد میں تھے ) بڑھے اور سب کو قتل کر دیا۔ البتہ ایک صاحب جو لنگڑے تھے ‘ پہاڑ پر چڑھ گئے۔ ہمام ( راوی حدیث ) نے بیان کیا میں سمجھتا ہوں کہ ایک اور ان کے ساتھ ( پہاڑ پر چڑھے تھے ) ( عمر بن امیہ ضمری ) اس کے بعد جبرائیل علیہ السلام نے نبی کریم صلی اللہ علیہ وسلم کو خبر دی کہ آپ کے ساتھی اللہ تعالیٰ سے جا ملے ہیں پس اللہ خود بھی ان سے خوش ہے اور انہیں بھی خوش کر دیا ہے۔ اس کے بعد ہم ( قرآن کی دوسری آیتوں کے ساتھ یہ آیت بھی ) پڑھتے تھے ( ترجمہ ) ہماری قوم کے لوگوں کو یہ پیغام پہنچا دو کہ ہم اپنے رب سے آ ملے ہیں ‘ پس ہمارا رب خود بھی خوش ہے اور ہمیں بھی خوش کر دیا ہے۔ اس کے بعد یہ آیت منسوخ ہو گئی ‘ نبی کریم صلی اللہ علیہ وسلم نے چالیس دن تک صبح کی نماز میں قبیلہ رعل ‘ ذکوان ‘ بنی لحیان اور بنی عصیہ کے لیے بددعا کی تھی جنہوں نے اللہ اور اس کے رسول صلی اللہ علیہ وسلم کی نافرمانی کی تھی۔' WHERE id = 2688;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا ‘ کہا ہم کو عبدالوہاب ثقفی نے خبر دی ‘ کہا ہم سے خالد نے بیان کیا عکرمہ سے کہ ابن عباس رضی اللہ عنہما نے ان سے اور ( اپنے صاحبزادے ) علی بن عبداللہ سے فرمایا تم دونوں ابو سعید خدری رضی اللہ عنہ کی خدمت میں جاؤ اور ان سے احادیث نبوی سنو۔ چنانچہ ہم حاضر ہوئے ‘ اس وقت ابوسعید رضی اللہ عنہ اپنے ( رضاعی ) بھائی کے ساتھ باغ میں تھے اور باغ کو پانی دے رہے تھے ‘ جب آپ نے ہمیں دیکھا تو ( ہمارے پاس ) تشریف لائے اور ( چادر اوڑھ کر ) گوٹ مار کر بیٹھ گئے ‘ اس کے بعد بیان فرمایا ہم مسجد نبوی کی اینٹیں ( ہجرت نبوی کے بعد تعمیر مسجد کیلئے ) ایک ایک کر کے ڈھو رہے تھے لیکن عمار رضی اللہ عنہ دو دو اینٹیں لا رہے تھے ‘ اتنے میں نبی کریم صلی اللہ علیہ وسلم ادھر سے گزرے اور ان کے سر سے غبار کو صاف کیا پھر فرمایا افسوس! عمار کو ایک باغی جماعت مارے گی ‘ یہ تو انہیں اللہ کی ( اطاعت کی ) طرف دعوت دے رہا ہو گا لیکن وہ اسے جہنم کی طرف بلا رہے ہوں گے۔' WHERE id = 2698;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے ابوعوانہ نے بیان کیا ‘ کہا ہم سے عبدالمالک بن عمیر نے بیان کیا ‘ انہوں نے عمرو بن میمون اودی سے سنا ‘ انہوں نے بیان کیا کہ سعد بن ابی وقاص رضی اللہ عنہ اپنے بچوں کو یہ کلمات دعائیہ اس طرح سکھاتے تھے جیسے معلم بچوں کو لکھنا سکھاتا ہے اور فرماتے تھے «اللهم إني أعوذ بك من الجبن،‏‏‏‏ ‏‏‏‏ وأعوذ بك أن أرد إلى أرذل العمر،‏‏‏‏ ‏‏‏‏ وأعوذ بك من فتنة الدنيا،‏‏‏‏ ‏‏‏‏ وأعوذ بك من عذاب القبر» ”اے اللہ! بزدلی سے میں تیری پناہ مانگتا ہوں ‘ اس سے تیری پناہ مانگتا ہوں کہ عمر کے سب سے ذلیل حصے ( بڑھاپے ) میں پہنچا دیا جاؤں اور تیری پناہ مانگتا ہوں میں دنیا کے فتنوں سے اور تیری پناہ مانگتا ہوں قبر کے عذاب سے۔“ پھر میں نے یہ حدیث جب مصعب بن سعد سے بیان کی تو انہوں نے بھی اس کی تصدیق کی۔' WHERE id = 2708;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا ‘ کہا ہم سے ابراہیم بن سعد زہری نے بیان کیا ‘ کہا کہ مجھ سے صالح بن کیسان نے بیان کیا ابن شہاب سے ‘ انہوں نے سہل بن سعد زہری رضی اللہ عنہ سے ‘ انہوں نے بیان کیا کہ میں مروان بن حکم ( خلیفہ اور اس وقت کے امیر مدینہ ) کو مسجد نبوی میں بیٹھے ہوئے دیکھا تو ان کے قریب گیا اور پہلو میں بیٹھ گیا اور پھر انہوں نے ہمیں خبر دی کہ زید بن ثابت انصاری رضی اللہ عنہ نے انہیں خبر دی تھی کہ رسول اللہ صلی اللہ علیہ وسلم نے ان سے آیت لکھوائی «لا يستوي القاعدون من المؤمنين والمجاهدون في سبيل الله» انہوں نے بیان کیا پھر عبداللہ ابن مکتوم رضی اللہ عنہ آئے۔ آپ صلی اللہ علیہ وسلم اس وقت مجھ سے آیت مذکورہ لکھوا رہے تھے، انہوں نے کہا یا رسول اللہ! اگر مجھ میں جہاد کی طاقت ہوتی تو میں جہاد میں شریک ہوتا۔ وہ نابینا تھے ‘ اس پر اللہ تبارک تعالیٰ نے اپنے رسول صلی اللہ علیہ وسلم پر وحی نازل کی۔ اس وقت آپ صلی اللہ علیہ وسلم کی ران میری ران پر تھی میں نے آپ پر وحی کی شدت کی وجہ سے آپ صلی اللہ علیہ وسلم کی ران کا اتنا بوجھ محسوس کیا کہ مجھے ڈر ہو گیا کہ کہیں میری ران پھٹ نہ جائے۔ اس کے بعد وہ کیفیت آپ صلی اللہ علیہ وسلم سے ختم ہو گئی اور اللہ عزوجل نے فقط «غير أولي الضرر‏» نازل فرمایا۔' WHERE id = 2718;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا ‘ کہا کہ ہم سے فلیح نے بیان کیا ‘ ان سے ہلال نے بیان کیا ‘ ان سے عطاء بن یسار نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم منبر پر تشریف لائے اور فرمایا میرے بعد تم پر دنیا کی جو برکتیں کھول دی جائیں گی ‘ میں تمہارے بارے میں ان سے ڈر رہا ہوں کہ ( کہیں تم ان میں مبتلا نہ ہو جاؤ ) اس کے بعد آپ صلی اللہ علیہ وسلم نے دنیا کی رنگینیوں کا ذکر فرمایا۔ پہلے دنیا کی برکات کا ذکر کیا پھر اس کی رنگینیوں کو بیان فرمایا ‘ اتنے میں ایک صحابی کھڑے ہوئے اور عرض کیا یا رسول اللہ! کیا بھلائی، برائی پیدا کر دے گی۔ آپ صلی اللہ علیہ وسلم اس پر تھوڑی دیر کے لیے خاموش ہو گئے۔ ہم نے سمجھا کہ آپ صلی اللہ علیہ وسلم پر وحی نازل ہو رہی ہے۔ سب لوگ خاموش ہو گئے جیسے ان کے سروں پر پرندے ہوں۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے چہرہ مبارک سے پسینہ صاف کیا اور دریافت فرمایا سوال کرنے والا کہاں ہے؟ کیا یہ بھی ( مال اور دنیا کی برکات ) خیر ہے؟ تین مرتبہ آپ صلی اللہ علیہ وسلم نے یہی جملہ دہرایا پھر فرمایا دیکھو بہار کے موسم میں جب ہری گھاس پیدا ہوتی ہے ‘ وہ جانور کو مار ڈالتی ہے یا مرنے کے قریب کر دیتی ہے مگر وہ جانور بچ جاتا ہے جو ہری ہری دوب چرتا ہے ‘ کوکھیں بھرتے ہی سورج کے سامنے جا کھڑا ہوتا ہے۔ لید ‘ گوبر ‘ پیشاب کرتا ہے پھر اس کے ہضم ہو جانے کے بعد اور چرتا ہے ‘ اسی طرح یہ مال بھی ہرا بھرا اور شیریں ہے اور مسلمان کا وہ مال کتنا عمدہ ہے جسے اس نے حلال طریقوں سے جمع کیا ہو اور پھر اسے اللہ کے راستے میں ( جہاد کے لیے ) یتیموں کے لیے مسکینوں کے لیے وقف کر دیا ہو لیکن جو شخص ناجائز طریقوں سے جمع کرتا ہے تو وہ ایک ایسا کھانے والا ہے جو کبھی آسودہ نہیں ہوتا اور وہ مال قیامت کے دن اس کے خلاف گواہ بن کر آئے گا۔' WHERE id = 2728;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے زکریا نے بیان کیا، کہا ہم سے عامر نے، کہا ہم سے عروہ بارقی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”خیر و برکت قیامت تک گھوڑے کی پیشانی کے ساتھ بندھی رہے گی یعنی آخرت میں ثواب اور دنیا میں مال غنیمت ملتا رہے گا۔“' WHERE id = 2738;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو شعبہ نے خبر دی، انہیں قتادہ نے اور انہوں نے انس بن مالک رضی اللہ عنہ سے سنا کہ مدینہ میں ( ایک رات ) کچھ خوف اور گھبراہٹ ہوئی تو نبی کریم صلی اللہ علیہ وسلم نے ابوطلحہ رضی اللہ عنہ کا ایک گھوڑا مانگ لیا۔ اس گھوڑے کا نام ”مندوب“ تھا۔ آپ صلی اللہ علیہ وسلم اس پر سوار ہوئے اور واپس آ کر فرمایا کہ خوف کی تو کوئی بات ہم نے نہیں دیکھی البتہ یہ گھوڑا کیا ہے دریا ہے!۔' WHERE id = 2748;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے زہیر بن معاویہ نے بیان کیا، ان سے حمید نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی ایک اونٹنی تھی جس کا نام عضباء تھا۔ کوئی اونٹنی اس سے آگے نہیں بڑھتی تھی یا حمید نے یوں کہا وہ پیچھے رہ جانے کے قریب نہ ہوتی پھر ایک دیہاتی ایک نوجوان ایک قوی اونٹ پر سوار ہو کر آیا اور آپ صلی اللہ علیہ وسلم کی اونٹنی سے ان کا اونٹ آگے نکل گیا۔ مسلمانوں پر یہ بڑا شاق گزرا لیکن جب نبی کریم صلی اللہ علیہ وسلم کو اس کا علم ہوا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ برحق ہے کہ دنیا میں جو چیز بھی بلند ہوتی ہے ( کبھی کبھی ) اسے وہ گراتا بھی ہے۔ موسیٰ نے حماد سے اس کی روایت طول کے ساتھ کی ہے، حماد نے ثابت سے، انہوں نے انس رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 2758;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے یزید بن عبداللہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ ابوعامر رضی اللہ عنہ کے گھٹنے میں تیر لگا تو میں ان کے پاس پہنچا۔ انہوں نے فرمایا کہ اس تیر کو کھینچ کر نکال لو میں نے کھینچ لیا تو اس سے خون بہنے لگا پھر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ صلی اللہ علیہ وسلم کو اس حادثہ کی اطلاع دی تو آپ صلی اللہ علیہ وسلم نے ( ان کے لیے ) دعا فرمائی «اللهم اغفر لعبيد أبي عامر» اے اللہ! عبید ابوعامر کی مغفرت فرما۔' WHERE id = 2769;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے محمد بن طلحہ نے بیان کیا، ان سے مصعب ابن سعد نے بیان کیا کہ سعد بن ابی وقاص رضی اللہ عنہ کا خیال تھا کہ انہیں دوسرے بہت سے صحابہ پر ( اپنی مالداری اور بہادری کی وجہ سے ) فضیلت حاصل ہے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ صرف اپنے کمزور معذور لوگوں کی دعاؤں کے نتیجہ میں اللہ کی طرف سے مدد پہنچائے جاتے ہو اور ان ہی کی دعاؤں سے رزق دئیے جاتے ہیں۔' WHERE id = 2780;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سب سے زیادہ خوبصورت اور سب سے زیادہ بہادر تھے۔ ایک رات مدینہ پر ( ایک آواز سن کر ) بڑا خوف چھا گیا تھا، سب لوگ اس آواز کی طرف بڑھے لیکن نبی کریم صلی اللہ علیہ وسلم سب سے آگے تھے اور آپ صلی اللہ علیہ وسلم نے ہی واقعہ کی تحقیق کی۔ آپ صلی اللہ علیہ وسلم ابوطلحہ رضی اللہ عنہ کے ایک گھوڑے پر سوار تھے جس کی پشت ننگی تھی۔ آپ صلی اللہ علیہ وسلم کی گردن سے تلوار لٹک رہی تھی اور آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ ڈرو مت۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہم نے تو گھوڑے کو سمندر کی طرح تیز پایا ہے یا یہ فرمایا کہ گھوڑا جیسے سمندر ہے۔' WHERE id = 2791;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ابوالضحیٰ، مسلم نے، جو صبیح کے صاحبزاے ہیں، ان سے مسروق نے بیان کیا اور ان سے مغیرہ بن شعبہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم قضائے حاجت کے لیے تشریف لے گئے۔ جب آپ صلی اللہ علیہ وسلم واپس ہوئے تو میں پانی لے کر خدمت میں حاضر ہوا، آپ صلی اللہ علیہ وسلم شامی جبہ پہنے ہوئے تھے۔ پھر آپ صلی اللہ علیہ وسلم نے کلی کی اور ناک میں پانی ڈالا اور اپنے چہرہ پاک کو دھویا۔ اس کے بعد ( ہاتھ دھونے کے لیے ) آستین چڑھانے کی کوشش کی لیکن آستین تنگ تھی اس لیے ہاتھوں کو نیچے سے نکالا پھر انہیں دھویا اور سر کا مسح کیا اور دونوں موزوں ہر دو کا بھی مسح کیا۔' WHERE id = 2801;
UPDATE hadiths SET urdu = 'ہم سے سعید بن محمد نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا مجھ سے میرے باپ ابراہیم بن سعد نے بیان کیا، ان سے صالح بن کیسان نے، ان سے اعرج نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک قائم نہیں ہو گی جب تک تم ترکوں سے جنگ نہ کر لو گے، جن کی آنکھیں چھوٹی ہوں گی، چہرے سرخ ہوں گے، ناک موٹی پھیلی ہوئی ہو گی، ان کے چہرے ایسے ہوں گے جیسے تہ بند چمڑا لگی ہوئی ہوتی ہے اور قیامت اس وقت تک قائم نہ ہو گی جب تک تم ایک ایسی قوم سے جنگ نہ کر لو گے جن کے جوتے بال کے بنے ہوئے ہوں گے۔“' WHERE id = 2811;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا، کہا ہم کو شعبہ نے خبر دی قتادہ سے، انہوں نے کہا کہ میں نے انس رضی اللہ عنہ سے سنا کہ آپ بیان کرتے تھے کہ جب نبی کریم صلی اللہ علیہ وسلم نے شاہ روم کو خط لکھنے کا ارادہ کیا تو آپ صلی اللہ علیہ وسلم سے کہا گیا کہ وہ لوگ کوئی خط اس وقت تک قبول نہیں کرتے جب تک وہ سربمہر نہ ہو، چنانچہ آپ صلی اللہ علیہ وسلم نے ایک چاندی کی انگوٹھی بنوائی۔ گویا دست مبارک پر اس کی سفیدی میری نظروں کے سامنے ہے۔ اس انگوٹھی پر ”محمد رسول اللہ“ کھدا ہوا تھا۔' WHERE id = 2821;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم سے ہشام نے بیان کیا، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں عبدالرحمٰن بن کعب بن مالک نے اور انہیں ان کے والد کعب بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم غزوہ تبوک کے لیے جمعرات کے دن نکلے تھے۔ آپ صلی اللہ علیہ وسلم جمعرات کے دن سفر کرنا پسند فرماتے تھے۔' WHERE id = 2832;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا۔ کہا ہم سے شعبہ نے بیان کیا، ان سے حمید نے بیان کیا اور انہوں نے انس رضی اللہ عنہ سے سنا۔ آپ بیان کرتے تھے کہ انصار خندق کھودتے ہوئے ( غزوہ خندق کے موقع پر ) کہتے تھے «نحن الذين بايعوا محمدا على الجهاد ما حيينا أبدا» ”ہم وہ لوگ ہیں جنہوں نے محمد ( صلی اللہ علیہ وسلم ) سے جہاد پر بیعت کی ہے ہمیشہ کے لیے، جب تک ہمارے جسم میں جان ہے۔“' WHERE id = 2842;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے حاتم بن اسماعیل نے بیان کیا، ان سے یزید بن ابی عبید نے اور ان سے سلمہ بن اکوع رضی اللہ عنہ نے بیان کیا کہ غزوہ خیبر کے موقع پر علی رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نہیں آئے تھے۔ ان کی آنکھوں میں تکلیف تھی۔ پھر انہوں نے کہا کہ کیا میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ جہاد میں شریک نہ ہوں گا؟ چنانچہ وہ نکلے اور آپ صلی اللہ علیہ وسلم سے جا ملے۔ اس رات کی شام کو جس کی صبح کو خیبر فتح ہوا ہے آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں اسلامی پرچم اس شخص کو دوں گا یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) کل اسلامی پرچم اس شخص کے ہاتھ میں ہو گا جسے اللہ اور اس کے رسول اپنا محبوب رکھتے ہیں۔ یا آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ جو اللہ اور اس کے رسول سے محبت رکھتا ہے۔ اور اللہ اس شخص کے ہاتھ پر فتح فرمائے گا۔ پھر علی رضی اللہ عنہ بھی آ گئے۔ حالانکہ ان کے آنے کی ہمیں کوئی امید نہ تھی۔ ( کیونکہ وہ آشوب چشم میں مبتلا تھے ) لوگوں نے کہا کہ یہ علی رضی اللہ عنہ بھی آ گئے اور آپ صلی اللہ علیہ وسلم نے جھنڈا انہیں کو دیا۔ اور اللہ نے انہیں کے ہاتھ پر فتح فرمائی۔' WHERE id = 2854;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ابن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے عمرو بن اوس نے اور ان سے عبدالرحمٰن بن ابی بکر صدیق رضی اللہ عنہما نے بیان کیا کہ مجھے نبی کریم صلی اللہ علیہ وسلم نے حکم دیا تھا کہ اپنی سواری پر اپنے پیچھے عائشہ رضی اللہ عنہا کو بٹھا کر لے جاؤں اور تنعیم سے ( احرام باندھ کر ) انہیں عمرہ کرا لاؤں۔' WHERE id = 2864;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ مجھ سے عبدالعزیز بن ابی سلمہ نے بیان کیا، ان سے صالح بن کیسان نے، ان سے سالم بن عبداللہ نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم حج یا عمرہ سے واپس ہوتے جہاں تک میں سمجھتا ہوں یوں کہا جب آپ صلی اللہ علیہ وسلم جہاد سے لوٹتے، تو جب بھی آپ کسی بلندی پر چڑھتے یا ( نشیب سے ) کنکریلے میدان میں آتے تو تین مرتبہ «الله اكبر» کہتے۔ پھر فرماتے «لا إله إلا الله،‏‏‏‏ وحده لا شريك له،‏‏‏‏ له الملك،‏‏‏‏ وله الحمد،‏‏‏‏ وهو على كل شىء قدير،‏‏‏‏ آيبون تائبون عابدون ساجدون لربنا حامدون،‏‏‏‏ صدق الله وعده،‏‏‏‏ ونصر عبده،‏‏‏‏ وهزم الأحزاب وحده‏ ‏‏.‏» ”اللہ کے سوا اور کوئی معبود نہیں وہ ایک ہے۔ اس کا کوئی شریک نہیں۔ ملک اس کا ہے اور تمام تعریفیں اسی کے لیے ہیں اور وہ ہر کام پر قدرت رکھتا ہے۔ ہم واپس ہو رہے ہیں توبہ کرتے ہوئے، عبادت کرتے ہوئے۔ اپنے رب کی بارگاہ میں سجدہ ریز ہوتے اور اس کی حمد پڑھتے ہوئے، اللہ نے اپنا وعدہ سچ کر دکھایا اور اپنے بندے کی مدد کی اور تنہا ( کفار کی ) تمام جماعتوں کو شکست دے دی۔“ صالح نے کہا کہ میں نے سالم بن عبداللہ سے پوچھا کیا عبداللہ بن عمر رضی اللہ عنہما نے لفظ «آيبون» کے بعد «إن شاء الله» نہیں کہا تھا تو انہوں نے بتایا کہ نہیں۔' WHERE id = 2874;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے امام مالک رحمہ اللہ نے خبر دی ‘ انہیں عبداللہ بن ابی بکر نے ‘ انہیں عباد بن تمیم نے اور انہیں ابوبشیر انصاری رضی اللہ عنہ نے کہ وہ ایک سفر میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے۔ عبداللہ ( عبداللہ بن ابی بکر بن حزم راوی حدیث ) نے کہا کہ میرا خیال ہے ابوبشیر نے کہا کہ لوگ اپنی خواب گاہوں میں تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنا ایک قاصد ( زید بن حارثہ رضی اللہ عنہ ) یہ اعلان کرنے کے لیے بھیجا کہ جس شخص کے اونٹ کی گردن میں تانت کا گنڈا ہو یا یوں فرمایا کہ گنڈا ( ہار ) ہو وہ اسے کاٹ ڈالے۔' WHERE id = 2884;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا ‘ کہا کہ میں نے ابواسامہ سے پوچھا، کیا عبیداللہ نے آپ سے یہ حدیث بیان کی ہے کہ ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ ایک عورت رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں کسی غزوے میں مقتول پائی گئی تو نبی کریم صلی اللہ علیہ وسلم نے عورتوں اور بچوں کے قتل سے منع فرمایا ( تو انہوں نے اس کا اقرار کیا ) ۔' WHERE id = 2894;
UPDATE hadiths SET urdu = 'ہم سے ابوبکر بن اصرم نے بیان کیا ‘ انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی ‘ انہوں نے کہا ہم کو معمر نے خبر دی ‘ انہیں ہمام بن منبہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”لڑائی کیا ہے؟ ایک چال ہے۔“' WHERE id = 2906;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا ‘ کہا ہم کو یزید بن ابی عبید نے خبر دی ‘ انہیں سلمہ بن اکوع رضی اللہ عنہ نے خبر دی ‘ انہوں نے بیان کیا کہ میں مدینہ منورہ سے غابہ ( شام کے راستے میں ایک مقام ) جا رہا تھا ‘ غابہ کی پہاڑی پر ابھی میں پہنچا تھا کہ عبدالرحمٰن بن عوف رضی اللہ عنہ کا ایک غلام ( رباح ) مجھے ملا۔ میں نے کہا ‘ کیا بات پیش آئی؟ کہنے لگا کہ رسول اللہ صلی اللہ علیہ وسلم کی دودہیل اونٹنیاں ( دودھ دینے والیاں ) چھین لی گئیں ہیں۔ میں نے پوچھا کس نے چھینا ہے؟ بتایا کہ قبیلہ غطفان اور قبیلہ فزارہ کے لوگوں نے۔ پھر میں نے تین مرتبہ بہت زور سے چیخ کر ”یا صباحاہ ‘ یا صباحاہ“ کہا۔ اتنی زور سے کہ مدینہ کے چاروں طرف میری آواز پہنچ گئی۔ اس کے بعد میں بہت تیزی کے ساتھ آگے بڑھا ‘ اور ڈاکوؤں کو جا لیا ‘ اونٹنیاں ان کے ساتھ تھیں ‘ میں نے ان پر تیر برسانا شروع کر دیا ‘ اور کہنے لگا ‘ میں اکوع کا بیٹا سلمہ ہوں اور آج کا دن کمینوں کی ہلاکت کا دن ہے۔ آخر اونٹنیاں میں نے ان سے چھڑا لیں ‘ ابھی وہ لوگ پانی نہ پینے پائے تھے اور انہیں ہانک کر واپس لا رہا تھا کہ اتنے میں رسول اللہ صلی اللہ علیہ وسلم بھی مجھ کو مل گئے۔ میں نے عرض کیا: یا رسول اللہ! ڈاکو پیاسے ہیں اور میں نے مارے تیروں کے پانی بھی نہیں پینے دیا۔ اس لیے ان کے پیچھے کچھ لوگوں کو بھیج دیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا ‘ اے ابن الاکوع! تو ان پر غالب ہو چکا اب جانے دے ‘ درگزر کر وہ تو اپنی قوم میں پہنچ گئے جہاں ان کی مہمانی ہو رہی ہے۔' WHERE id = 2917;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا ‘ کہا ہم سے ابو عمیس عتبہ بن عبداللہ نے بیان کیا ‘ ان سے ایاس بن سلمہ بن اکوع رضی اللہ عنہ نے ‘ ان سے ان کے باپ (سلمہ رضی اللہ عنہ) نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس سفر میں مشرکوں کا ایک جاسوس آیا۔ ( آپ صلی اللہ علیہ وسلم غزوہ ہوازن کے لیے تشریف لے جا رہے تھے ) وہ جاسوس صحابہ کی جماعت میں بیٹھا ‘ باتیں کیں ‘ پھر وہ واپس چلا گیا ‘ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے تلاش کر کے مار ڈالو۔ چنانچہ اسے ( سلمہ بن اکوع رضی اللہ عنہ نے ) قتل کر دیا ‘ اور آپ صلی اللہ علیہ وسلم نے اس کے ہتھیار اور اوزار قتل کرنے والے کو دلوا دئیے۔' WHERE id = 2927;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم کو شعیب نے خبر دی، انہیں زہری نے (دوسری سند) مجھ سے محمود بن غیلان نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا ‘ انہیں معمر نے خبر دی ‘ انہیں زہری نے ‘ انہیں ابن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک غزوہ میں موجود تھے۔ آپ صلی اللہ علیہ وسلم نے ایک شخص کے متعلق جو اپنے کو مسلمان کہتا تھا ‘ فرمایا کہ یہ شخص دوزخ والوں میں سے ہے۔ جب جنگ شروع ہوئی تو وہ شخص ( مسلمانوں کی طرف ) بڑی بہادری کے ساتھ لڑا اور وہ زخمی بھی ہو گیا۔ صحابہ نے عرض کیا ‘ یا رسول اللہ! جس کے متعلق آپ نے فرمایا تھا کہ وہ دوزخ میں جائے گا۔ آج تو وہ بڑی بے جگری کے ساتھ لڑا ہے اور ( زخمی ہو کر ) مر بھی گیا ہے۔ آپ صلی اللہ علیہ وسلم نے اب بھی وہی جواب دیا کہ جہنم میں گیا۔ ابوہریرہ رضی اللہ عنہ نے بیان کیا ‘ کہ ممکن تھا کہ بعض لوگوں کے دل میں کچھ شبہ پیدا ہو جاتا۔ لیکن ابھی لوگ اسی غور و فکر میں تھے کہ کسی نے بتایا کہ ابھی وہ مرا نہیں ہے۔ البتہ زخم کاری ہے۔ پھر جب رات آئی تو اس نے زخموں کی تاب نہ لا کر خودکشی کر لی۔ جب آپ صلی اللہ علیہ وسلم کو اس کی خبر دی گئی تو آپ صلی اللہ علیہ وسلم نے فرمایا: اللہ اکبر! میں گواہی دیتا ہوں کہ میں اللہ کا بندہ اور اس کا رسول ہوں۔ پھر آپ صلی اللہ علیہ وسلم نے بلال رضی اللہ عنہ کو حکم دیا ‘ اور انہوں نے لوگوں میں اعلان کر دیا کہ مسلمان کے سوا جنت میں کوئی اور داخل نہیں ہو گا اور اللہ تعالیٰ کبھی اپنے دین کی امداد کسی فاجر شخص سے بھی کرا لیتا ہے۔' WHERE id = 2937;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا ‘ کہا کہ ہم سے غندر نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے محمد بن زیاد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ حسن بن علی رضی اللہ عنہما نے صدقہ کی کھجور میں سے ( جو بیت المال میں آئی تھی ) ایک کھجور اٹھا لی اور اپنے منہ کے قریب لے گئے۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے انہیں فارسی زبان کا یہ لفظ کہہ کر روک دیا کہ «كخ كخ» کیا تمہیں معلوم نہیں کہ ہم صدقہ نہیں کھایا کرتے ہیں۔' WHERE id = 2947;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے جویریہ نے بیان کیا ‘ ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ جب رسول اللہ صلی اللہ علیہ وسلم ( جہاد سے ) واپس ہوتے تو تین بار اللہ اکبر کہتے ‘ اور یہ دعا پڑھتے «آيبون إن شاء الله تائبون عابدون حامدون لربنا ساجدون،‏‏‏‏ صدق الله وعده،‏‏‏‏ ونصر عبده،‏‏‏‏ وهزم الأحزاب وحده» ”ان شاءاللہ ہم اللہ کی طرف لوٹنے والے ہیں۔ ہم توبہ کرنے والے ہیں۔ اپنے رب کی عبادت کرنے والے ہیں۔ اس کی تعریف کرنے والے اور اس کے لیے سجدہ کرنے والے ہیں۔ اللہ نے اپنا وعدہ سچا کر دکھایا ‘ اپنے بندے کی مدد کی ‘ اور کافروں کے لشکر کو اسی اکیلے نے شکست دے دی۔“' WHERE id = 2958;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا ہم کو امام مالک بن انس نے بیان کیا ‘ انہیں ابوالزناد نے بیان کیا ‘ انہیں اعرج نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا ہم کو امام مالک بن انس نے بیان کیا ‘ انہیں ابوالزناد نے بیان کیا ‘ انہیں اعرج نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ' WHERE id = 2969;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ انصاری نے بیان کیا ‘ کہا کہ مجھ سے میرے والد عبداللہ نے بیان کیا ‘ ان سے ثمامہ نے اور ان سے انس رضی اللہ عنہ نے کہ جب ابوبکر رضی اللہ عنہ خلیفہ ہوئے تو انہوں نے ان کو ( یعنی انس رضی اللہ عنہ کو ) بحرین ( عامل بنا کر ) بھیجا اور ایک پروانہ لکھ کر ان کو دیا اور اس پر نبی کریم صلی اللہ علیہ وسلم کی انگوٹھی کی مہر لگائی، مہر مبارک پر تین سطریں کندہ تھیں ‘ ایک سطر میں ”محمد“ دوسری میں ”رسول“ تیسری میں ”اللہ“ کندہ تھا۔' WHERE id = 2979;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا ‘ کہا ہم سے عبداللہ بن مبارک نے ‘ انہیں یونس نے، انہیں زہری نے ‘ انہیں حمید بن عبدالرحمٰن نے ‘ انہوں نے معاویہ رضی اللہ عنہ سے سنا ‘ آپ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس کے ساتھ اللہ تعالیٰ بھلائی چاہتا ہے اسے دین کی سمجھ دے دیتا ہے۔ اور دینے والا تو اللہ ہی ہے میں تو صرف تقسیم کرنے والا ہوں اور اپنے دشمنوں کے مقابلے میں یہ امت ( مسلمہ ) ہمیشہ غالب رہے گی۔ تاآنکہ اللہ کا حکم ( قیامت ) آ جائے اور اس وقت بھی وہ غالب ہی ہوں گے۔“' WHERE id = 2989;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا ‘ کہا ہم سے غندر نے بیان کیا ‘ کہا ہم سے شعبہ نے ‘ ان سے عمرو بن مرہ نے بیان کیا ‘ انہوں نے ابووائل سے سنا ‘ انہوں نے بیان کیا کہ ہم سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ ایک اعرابی ( لاحق بن ضمیرہ باہلی ) نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا ایک شخص ہے جو غنیمت حاصل کرنے کے لیے جہاد میں شریک ہوا ‘ ایک شخص ہے جو اس لیے شرکت کرتا ہے کہ اس کی بہادری کے چرچے زبانوں پر آ جائیں ‘ ایک شخص اس لیے لڑتا ہے کہ اس کی دھاک بیٹھ جائے ‘ تو ان میں سے اللہ کے راستے میں کون سا ہو گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص جنگ میں شرکت اس لیے کرے تاکہ اللہ کا کلمہ ( دین ) ہی بلند رہے۔ فقط وہی اللہ کے راستے میں ہے۔' WHERE id = 2999;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے قرۃ بن خالد نے بیان کیا، کہا ہم سے عمرو بن دینار نے بیان کیا اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم مقام جعرانہ میں غنیمت تقسیم کر رہے تھے کہ ایک شخص ذوالخویصرہ نے آپ سے کہا، انصاف سے کام لیجئے، آپ صلی اللہ علیہ وسلم نے فرمایا ”اگر میں بھی انصاف سے کام نہ لوں تو بدبخت ہوا۔“' WHERE id = 3010;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، انہوں نے کہا کہ ہم سے صالح بن کیسان نے، ان سے ابن شہاب نے بیان کیا کہ مجھے عمر بن محمد بن جبیر بن مطعم نے خبر دی کہ میرے باپ محمد بن جبیر نے کہا اور انہیں جبیر بن مطعم رضی اللہ عنہ نے خبر دی کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے۔ آپ کے ساتھ اور بھی صحابہ تھے۔ حنین کے جہاد سے واپسی ہو رہی تھی۔ راستے میں کچھ بدو آپ صلی اللہ علیہ وسلم سے لپٹ گئے ( لوٹ کا مال ) آپ سے مانگتے تھے۔ وہ آپ سے ایسا لپٹے کہ آپ صلی اللہ علیہ وسلم کو ایک ببول کے درخت کی طرف دھکیل لے گئے۔ آپ کی چادر اس میں اٹک کر رہ گئی۔ اس وقت آپ ٹھہر گئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا ” ( بھائیو ) میری چادر تو دے دو۔ اگر میرے پاس ان کانٹے دار درختوں کی تعداد میں اونٹ ہوتے تو وہ بھی تم میں تقسیم کر دیتا۔ تم مجھے بخیل، جھوٹا اور بزدل ہرگز نہیں پاؤ گے۔“' WHERE id = 3020;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے ابوجمرہ نے بیان کیا، کہا کہ میں نے جویریہ بن قدامہ تمیمی سے سنا، انہوں نے بیان کیا کہ میں نے عمر بن خطاب رضی اللہ عنہ سے سنا تھا، ( جب وہ زخمی ہوئے ) آپ سے ہم نے عرض کیا تھا کہ ہمیں کوئی وصیت کیجئے! تو آپ نے فرمایا کہ میں تمہیں اللہ تعالیٰ کے عہد کی ( جو تم نے ذمیوں سے کیا ہے ) وصیت کرتا ہوں ( کہ اس کی حفاظت میں کوتاہی نہ کرنا ) کیونکہ وہ تمہارے نبی کا ذمہ ہے اور تمہارے گھر والوں کی روزی ہے ( کہ جزیہ کے روپیہ سے تمہارے بال بچوں کی گزران ہوتی ہے ) ۔' WHERE id = 3032;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے بشر بن مفضل نے، کہا ہم سے یحییٰ بن سعید انصاری نے، ان سے بشیر بن یسار نے اور ان سے سہل بن ابی حثمہ نے بیان کیا کہ عبداللہ بن سہل اور محیصہ بن مسعود بن زید رضی اللہ عنہما خیبر گئے۔ ان دنوں ( خیبر کے یہودیوں سے مسلمانوں کی ) صلح تھی۔ پھر دونوں حضرات ( خیبر پہنچ کر اپنے اپنے کام کے لیے ) جدا ہو گئے۔ اس کے بعد محیصہ رضی اللہ عنہ عبداللہ بن سہل رضی اللہ عنہ کے پاس آئے تو کیا دیکھتے ہیں کہ وہ خون میں لوٹ رہے ہیں۔ کسی نے ان کو قتل کر ڈالا، خیر محیصہ رضی اللہ عنہ نے عبداللہ رضی اللہ عنہ کو دفن کر دیا۔ پھر مدینہ آئے، اس کے بعد عبدالرحمٰن بن سہل ( عبداللہ رضی اللہ عنہ کے بھائی ) اور مسعود کے دونوں صاحبزادے محیصہ اور حویصہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے، گفتگو عبدالرحمٰن رضی اللہ عنہ نے شروع کی، تو آپ صلی اللہ علیہ وسلم نے فرمایا، کہ جو تم لوگوں میں عمر میں بڑے ہوں وہ بات کریں۔ عبدالرحمٰن سب سے کم عمر تھے، وہ چپ ہو گئے۔ اور محیصہ اور حویصہ نے بات شروع کی۔ آپ نے دریافت کیا، کیا تم لوگ اس پر قسم کھا سکتے ہو، کہ جس شخص کو تم قاتل کہہ رہے ہو اس پر تمہارا حق ثابت ہو سکے۔ ان لوگوں نے عرض کیا کہ ہم ایک ایسے معاملے میں کس طرح قسم کھا سکتے ہیں جس کو ہم نے خود اپنی آنکھوں سے نہ دیکھا ہو۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر کیا یہود تمہارے دعوے سے اپنی برات اپنی طرف سے پچاس قسمیں کھا کر کے کر دیں؟ ان لوگوں نے عرض کیا کہ کفار کی قسموں کا ہم کس طرح اعتبار کر سکتے ہیں۔ چنانچہ آپ صلی اللہ علیہ وسلم نے خود اپنے پاس سے ان کو دیت ادا کر دی۔' WHERE id = 3042;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے حاتم نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے باپ نے اور ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ قریش سے جس زمانہ میں رسول اللہ صلی اللہ علیہ وسلم نے ( حدیبیہ کی ) صلح کی تھی، اسی مدت میں میری والدہ ( قتیلہ ) اپنے باپ ( حارث بن مدرک ) کو ساتھ لے کر میرے پاس آئیں، وہ اسلام میں داخل نہیں ہوئی تھیں۔ ( عروہ نے بیان کیا کہ ) اسماء رضی اللہ عنہا نے اس بارے میں آپ صلی اللہ علیہ وسلم سے پوچھا کہ یا رسول اللہ! میری والدہ آئی ہوئی ہیں اور مجھ سے رغبت کے ساتھ ملنا چاہتی ہیں، تو کیا میں ان کے ساتھ صلہ رحمی کروں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں! ان کے ساتھ صلہ رحمی کر۔' WHERE id = 3052;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم کو اسماعیل بن علیہ نے خبر دی، انہیں علی بن مبارک نے کہا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے محمد بن ابراہیم بن حارث نے، ان سے ابوسلمہ بن عبدالرحمٰن نے ان کا ایک دوسرے صاحب سے ایک زمین کے بارے میں جھگڑا تھا۔ وہ عائشہ رضی اللہ عنہا کی خدمت میں حاضر ہوئے اور ان سے واقعہ بیان کیا۔ انہوں نے ( جواب میں ) فرمایا: ابوسلمہ! کسی کی زمین ( کے ناحق لینے ) سے بچو، کیونکہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہے کہ اگر ایک بالشت کے برابر بھی کسی نے ( زمین کے بارے میں ) ظلم کیا تو ( قیامت کے دن ) ساتھ زمینوں کا طوق اسے پہنایا جائے گا۔' WHERE id = 3063;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حکم نے، ان سے مجاہد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” «بالصبا» باد صبا ( مشرقی ہوا ) کے ذریعہ میری مدد کی گئی اور قوم عاد «دبور‏ ‏‏» ( مغربی ہوا ) سے ہلاک کر دی گئی تھی۔“' WHERE id = 3073;
UPDATE hadiths SET urdu = 'ہم سے فروہ بن ابی المغراء نے بیان کیا، کہا ہم سے علی بن مسہر نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے باپ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ حارث بن ہشام رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کہ وحی آپ کے پاس کس طرح آتی ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کئی طرح سے آتی ہے۔ کبھی فرشتہ کے ذریعہ آتی ہے تو وہ گھنٹی بجنے کی آواز کی طرح نازل ہوتی ہے۔ جب وحی ختم ہو جاتی ہے تو جو کچھ فرشتے نے نازل کیا ہوتا ہے، میں اسے پوری طرح یاد کر چکا ہوتا ہوں۔ وحی اترنے کی یہ صورت میرے لیے بہت دشوار ہوتی ہے۔ کبھی فرشتہ میرے سامنے ایک مرد کی صورت میں آ جاتا ہے وہ مجھ سے باتیں کرتا ہے اور جو کچھ کہہ جاتا ہے میں اسے پوری طرح یاد کر لیتا ہوں۔' WHERE id = 3083;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں عبیداللہ بن عبداللہ نے، اور انہوں نے ابن عباس رضی اللہ عنہما سے سنا، وہ کہتے تھے کہ میں نے ابوطلحہ رضی اللہ عنہ سے سنا، وہ کہتے تھے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”فرشتے اس گھر میں داخل نہیں ہوتے جس میں کتے ہوں اور اس میں بھی نہیں جس میں جاندار کی تصویر ہو۔“' WHERE id = 3093;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن یوسف نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے زکریا بن ابی زائدہ نے بیان کیا، ان سے سعید بن الاشوع نے، ان سے شعبی نے اور ان سے مسروق نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے پوچھا ( ان کے اس کہنے پر کہ نبی کریم صلی اللہ علیہ وسلم نے اللہ تعالیٰ کو دیکھا نہیں تھا ) پھر اللہ تعالیٰ کے اس ارشاد «ثم دنا فتدلى * فكان قاب قوسين أو أدنى‏» کے بارے میں آپ کا کیا خیال ہے؟ انہوں نے کہا کہ یہ آیت تو جبرائیل علیہ السلام کے بارے میں ہے، وہ انسانی شکل میں نبی کریم صلی اللہ علیہ وسلم کے پاس آیا کرتے تھے اور اس مرتبہ اپنی اس شکل میں آئے جو اصلی تھی اور انہوں نے تمام آسمان کے کناروں کو ڈھانپ لیا تھا۔' WHERE id = 3103;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں ہمام بن منبہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جنت میں داخل ہونے والے سب سے پہلے گروہ کے چہرے ایسے روشن ہوں گے جیسے چودہویں کا چاند روشن ہوتا ہے۔ نہ اس میں تھوکیں گے نہ ان کی ناک سے کوئی آلائش آئے گی اور نہ پیشاب، پاخانہ کریں گے۔ ان کے برتن سونے کے ہوں گے۔ کنگھے سونے چاندی کے ہوں گے۔ انگیٹھیوں کا ایندھن عود کا ہو گا۔ پسینہ مشک جیسا خوشبودار ہو گا اور ہر شخص کی دو بیویاں ہوں گی۔ جن کا حسن ایسا ہو گا کہ پنڈلیوں کا گودا گوشت کے اوپر سے دکھائی دے گا۔ نہ جنتیوں میں آپس میں کوئی اختلاف ہو گا اور نہ بغض و عناد، ان کے دل ایک ہوں گے اور وہ صبح و شام اللہ پاک کی تسبیح و تہلیل میں مشغول رہا کریں گے۔“' WHERE id = 3113;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم سے محمد بن مطرف نے بیان کیا، کہا کہ مجھ سے ابوحازم نے بیان کیا، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جنت کے آٹھ دروازے ہیں۔ ان میں ایک دروازے کا نام ریان ہے۔ جس سے داخل ہونے والے صرف روزے دار ہوں گے۔“' WHERE id = 3124;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے، ان سے ابووائل نے بیان کیا کہ اسامہ بن زید رضی اللہ عنہما سے کسی نے کہا کہ اگر آپ فلاں صاحب ( عثمان رضی اللہ عنہ ) کے یہاں جا کر ان سے گفتگو کرو تو اچھا ہے ( تاکہ وہ یہ فساد دبانے کی تدبیر کریں ) انہوں نے کہا کیا تم لوگ یہ سمجھتے ہو کہ میں ان سے تم کو سنا کر ( تمہارے سامنے ہی ) بات کرتا ہوں، میں تنہائی میں ان سے گفتگو کرتا ہوں اس طرح پر کہ فساد کا دروازہ نہیں کھولتا، میں یہ بھی نہیں چاہتا کہ سب سے پہلے میں فساد کا دروازہ کھولوں اور میں آپ صلی اللہ علیہ وسلم سے ایک حدیث سننے کے بعد یہ بھی نہیں کہتا کہ جو شخص میرے اوپر سردار ہو وہ سب لوگوں میں بہتر ہے۔ لوگوں نے پوچھا کہ آپ نے نبی کریم صلی اللہ علیہ وسلم سے جو حدیث سنی ہے وہ کیا ہے؟ اسامہ رضی اللہ عنہ نے کہا نبی کریم صلی اللہ علیہ وسلم کو میں نے یہ فرماتے سنا تھا کہ قیامت کے دن ایک شخص کو لایا جائے گا اور جہنم میں ڈال دیا جائے گا۔ آگ میں اس کی آنتیں باہر نکل آئیں گی اور وہ شخص اس طرح چکر لگانے لگے گا جیسے گدھا اپنی چکی پر گردش کیا کرتا ہے۔ جہنم میں ڈالے جانے والے اس کے قریب آ کر جمع ہو جائیں گے اور اس سے کہیں گے، اے فلاں! آج یہ تمہاری کیا حالت ہے؟ کیا تم ہمیں اچھے کام کرنے کے لیے نہیں کہتے تھے، اور کیا تم برے کاموں سے ہمیں منع نہیں کیا کرتے تھے؟ وہ شخص کہے گا جی ہاں، میں تمہیں تو اچھے کاموں کا حکم دیتا تھا لیکن خود نہیں کرتا تھا۔ برے کاموں سے تمہیں منع بھی کرتا تھا، لیکن میں اسے خود کیا کرتا تھا۔ اس حدیث کو غندر نے بھی شعبہ سے، انہوں نے اعمش سے روایت کیا ہے۔' WHERE id = 3134;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے عبداللہ بن دینار نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا کہ آپ مشرق کی طرف اشارہ کر کے فرما رہے تھے کہ ہاں! فتنہ اسی طرف سے نکلے گا جہاں سے شیطان کے سر کا کونا نکلتا ہے۔' WHERE id = 3145;
UPDATE hadiths SET urdu = 'ہم سے عاصم بن علی نے بیان کیا، کہا ہم سے ابن وہب نے بیان کیا، ان سے سعید مقبری نے، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جمائی شیطان کی طرف سے ہے۔ پس جب کسی کو جمائی آئے تو جہاں تک ہو سکے اسے روکے۔ کیونکہ جب کوئی ( جمائی لیتے ہوئے ) ”ہاہا“ کرتا ہے تو شیطان اس پر ہنستا ہے۔“' WHERE id = 3155;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں ابوالزناد نے خبر دی، انہیں اعرج نے خبر دی، اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کفر کی چوٹی مشرق میں ہے اور فخر اور تکبر کرنا گھوڑے والوں، اونٹ والوں اور زمینداروں میں ہوتا ہے جو ( عموماً ) گاؤں کے رہنے والے ہوتے ہیں اور بکری والوں میں دل جمعی ہوتی ہے۔“' WHERE id = 3166;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں عبداللہ بن دینار نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”پانچ جانور ایسے ہیں جنہیں اگر کوئی شخص حالت احرام میں بھی مار ڈالے تو اس پر کوئی گناہ نہیں۔ بچھو، چوہا، کاٹ لینے والا کتا، کوا اور چیل۔“' WHERE id = 3178;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے سلیمان نے بیان کیا، کہا کہ مجھے یزید بن خصیفہ نے خبر دی، کہا کہ مجھے سائب بن یزید نے خبر دی، انہوں نے سفیان بن ابی زہیر شنوی رضی اللہ عنہ سے سنا، انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم نے فرمایا ”جس نے کوئی کتا پالا، نہ تو پالنے والے کا مقصد کھیت کی حفاظت ہے اور نہ مویشیوں کی، تو روزانہ اس کے نیک عمل میں سے ایک قیراط ( ثواب ) کی کمی ہو جاتی ہے۔“ سائب نے پوچھا، کیا تم نے خود یہ حدیث رسول اللہ صلی اللہ علیہ وسلم سے سنی تھی؟ انہوں نے کہا، ہاں! اس قبلہ کے رب کی قسم ( میں نے خود اس حدیث کو رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے ) ۔' WHERE id = 3188;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے اعمش نے بیان کیا، کہا کہ مجھ سے عبداللہ بن مرہ نے بیان کیا، ان سے مسروق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب بھی کوئی انسان ظلم سے قتل کیا جاتا ہے تو آدم علیہ السلام کے سب سے پہلے بیٹے ( قابیل ) کے نامہ اعمال میں بھی اس قتل کا گناہ لکھا جاتا ہے۔ کیونکہ قتل ناحق کی بنا سب سے پہلے اسی نے قائم کی تھی۔“' WHERE id = 3198;
UPDATE hadiths SET urdu = 'ہم سے خالد بن یزید نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحاق نے ان سے اسود نے کہا کہ میں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ آیت «فهل من مدكر‏» کی تلاوت فرما رہے تھے۔' WHERE id = 3208;
UPDATE hadiths SET urdu = 'ہم سے بیان بن عمرو نے بیان کیا، کہا ہم سے نضر نے بیان کیا، کہا ہم کو ابن عون نے خبر دی، انہیں مجاہد نے اور انہوں نے ابن عباس رضی اللہ عنہما سے سنا آپ کے سامنے لوگ دجال کا تذکرہ کر رہے تھے کہ اس کی پیشانی پر لکھا ہوا ہو گا ”کافر“ یا ( یوں لکھا ہوا ہو گا ) ”ک ف ر“ ابن عباس رضی اللہ عنہما نے کہا کہ نبی کریم صلی اللہ علیہ وسلم سے میں نے یہ حدیث نہیں سنی تھی۔ البتہ آپ صلی اللہ علیہ وسلم نے ایک مرتبہ یہ حدیث بیان فرمائی کہ ابراہیم علیہ السلام ( کی شکل و وضع معلوم کرنے ) کے لیے تم اپنے صاحب کو دیکھ سکتے ہو اور موسیٰ علیہ السلام کا بدن گٹھا ہوا، گندم گوں، ایک سرخ اونٹ پر سوار تھے۔ جس کی نکیل کھجور کی چھال کی تھی۔ جیسے میں انہیں اس وقت بھی دیکھ رہا ہوں کہ وہ اللہ کی بڑائی بیان کرتے ہوئے وادی میں اتر رہے ہیں۔' WHERE id = 3218;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے مطلب کے آزاد کردہ غلام عمرو بن ابی عمرو نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے احد پہاڑ کو دیکھ کر فرمایا کہ یہ پہاڑ ہم سے محبت رکھتا ہے اور ہم اس سے محبت رکھتے ہیں۔ اے اللہ! ابراہیم علیہ السلام نے مکہ مکرمہ کو حرمت والا شہر قرار دیا تھا اور میں مدینہ کے دو پتھریلے علاقے کے درمیانی علاقے کے حصے کو حرمت والا قرار دیتا ہوں۔ اس حدیث کو عبداللہ بن زید رضی اللہ عنہ نے بھی نبی کریم صلی اللہ علیہ وسلم سے روایت کیا ہے۔' WHERE id = 3229;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ کہا ہم سے ہشام بن عروہ نے بیان کیا ‘ ان سے ان کے والد نے اور ان سے عبداللہ بن زمعہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ( خطبہ کے دوران ) آپ صلی اللہ علیہ وسلم نے قوم کا ذکر کیا جنہوں نے اونٹنی کو ذبح کر دیا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ( اللہ کی قسم بھیجی ہوئی ) اس ( اونٹنی ) کو ذبح کرنے والا قوم کا ایک بہت ہی باعزت آدمی ( قیدار نامی ) تھا ‘ جیسے ہمارے زمانے میں ابوزمعہ ( اسود بن مطلب ) ہے۔' WHERE id = 3239;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد بن اسماء ابن اخی جویریہ نے بیان کیا ‘ انہوں نے کہا ہم سے جویریہ بن اسماء نے بیان کیا ‘ ان سے مالک نے بیان کیا ‘ ان سے زہری نے بیان کیا ‘ ان کو سعید بن مسیب اور ابوعبیدہ نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ لوط علیہ السلام پر رحم فرمائے کہ وہ زبردست رکن ( یعنی اللہ تعالیٰ ) کی پناہ لیتے تھے اور اگر میں اتنی مدت تک قید رہتا جتنی یوسف علیہ السلام رہے تھے اور پھر میرے پاس ( بادشاہ کا آدمی ) بلانے کے لیے آتا تو میں فوراً اس کے ساتھ چلا جاتا۔“' WHERE id = 3249;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد جعفی نے بیان کیا ‘ کہا ہم سے عبدالرزاق نے بیان کیا ‘ کہا ہم کو معمر نے خبر دی ‘ انہیں ہمام نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر بنی اسرائیل نہ ہوتے ( سلویٰ کا گوشت جمع کر کے نہ رکھتے ) تو گوشت کبھی نہ سڑتا۔ اور اگر حوا نہ ہوتیں ( یعنی آدم علیہ السلام سے دغا نہ کرتیں ) تو کوئی عورت اپنے شوہر کی خیانت کبھی نہ کرتی۔“' WHERE id = 3260;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا ‘ کہا ہم سے ابراہیم بن سعد نے بیان کیا ‘ ان سے ابن شہاب نے ‘ ان سے حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”موسیٰ اور آدم علیہم السلام نے آپس میں بحث کی۔ موسیٰ علیہ السلام نے ان سے کہا کہ آپ آدم ہیں جنہیں ان کی لغزش نے جنت سے نکالا۔ آدم علیہ السلام بولے اور آپ موسیٰ علیہ السلام ہیں کہ جنہیں اللہ تعالیٰ نے اپنی رسالت اور اپنے کلام سے نوازا ‘ پھر بھی آپ مجھے ایک ایسے معاملے پر ملامت کرتے ہیں جو اللہ تعالیٰ نے میری پیدائش سے بھی پہلے مقدر کر دیا۔“ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”چنانچہ آدم علیہ السلام، موسیٰ علیہ السلام پر غالب آ گئے۔ رسول اللہ صلی اللہ علیہ وسلم نے یہ جملہ دو مرتبہ فرمایا۔' WHERE id = 3270;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے سہل بن یوسف نے بیان کیا، کہا میں نے عوام سے سنا، ان سے مجاہد نے بیان کیا کہ میں نے عباس رضی اللہ عنہ سے پوچھا، کیا میں سورۃ ص میں سجدہ کیا کروں؟ تو انہوں نے آیت «ومن ذريته داود وسليمان‏» تلاوت کی «فبهداهم اقتده‏» تک نیز انہوں نے کہا کہ تمہارے نبی کریم صلی اللہ علیہ وسلم ان لوگوں میں سے تھے جنہیں انبیاء علیہم السلام کی اقتداء کا حکم تھا۔' WHERE id = 3281;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن ابی رجاء نے بیان کیا، کہا ہم سے نضر نے بیان کیا، ان سے ہشام، کہا کہ مجھے میرے والد نے خبر دی، کہا کہ میں نے عبداللہ بن جعفر سے سنا، کہا کہ میں نے علی رضی اللہ عنہ سے سنا، آپ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ مریم بنت عمران ( اپنے زمانہ میں ) سب سے بہترین خاتون تھیں اور اس امت کی سب سے بہترین خاتون خدیجہ ہیں ( رضی اللہ عنہا ) ۔' WHERE id = 3291;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں ہمام نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”عیسیٰ ابن مریم علیہما السلام نے ایک شخص کو چوری کرتے ہوئے دیکھا پھر اس سے دریافت فرمایا: تو نے چوری کی ہے؟ اس نے کہا ہرگز نہیں، اس ذات کی قسم جس کے سوا اور کوئی معبود نہیں۔ عیسیٰ علیہ السلام نے فرمایا کہ میں اللہ پر ایمان لایا اور میری آنکھوں کو دھوکا ہوا۔“' WHERE id = 3302;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، انہوں نے کہا کہ ہم سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تمہارا زمانہ پچھلی امتوں کے مقابلے میں ایسا ہے جیسے عصر سے مغرب تک کا وقت ہے، تمہاری مثال یہود و نصاریٰ کے ساتھ ایسی ہے جیسے کسی شخص نے کچھ مزدور لیے اور کہا کہ میرا کام آدھے دن تک کون ایک ایک قیراط کی اجرت پر کرے گا؟ یہود نے آدھے دن تک ایک ایک قیراط کی مزدوری پر کام کرنا طے کر لیا۔ پھر اس شخص نے کہا کہ آدھے دن سے عصر کی نماز تک میرا کام کون شخص ایک ایک قیراط کی مزدوری پر کرے گا۔ اب نصاریٰ ایک ایک قیراط کی مزدوری پر آدھے دن سے عصر کے وقت تک مزدوری کرنے پر تیار ہو گئے۔ پھر اس شخص نے کہا کہ عصر کی نماز سے سورج ڈوبنے تک دو دو قیراط پر کون شخص میرا کام کرے گا؟ تمہیں معلوم ہونا چاہئے کہ وہ تمہیں ہو جو دو دو قیراط کی مزدوری پر عصر سے سورج ڈوبنے تک کام کرو گے۔ تم آگاہ رہو کہ تمہاری مزدوری دگنی ہے۔ یہود و نصاریٰ اس فیصلہ پر غصہ ہو گئے اور کہنے لگے کہ کام تو ہم زیادہ کریں اور مزدوری ہمیں کو کم ملے۔ اللہ تعالیٰ نے ان سے فرمایا کیا میں نے تمہیں تمہارا حق دینے میں کوئی کمی کی ہے؟ انہوں نے کہا کہ نہیں۔ اللہ تعالیٰ نے فرمایا کہ پھر یہ میرا فضل ہے، میں جسے چاہوں زیادہ دوں۔' WHERE id = 3314;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے ابوسلمہ نے بیان کیا، اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”گزشتہ امتوں میں محدث لوگ ہوا کرتے تھے اور اگر میری امت میں کوئی ایسا ہے تو وہ عمر بن خطاب ہیں۔“' WHERE id = 3324;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا کہا، ہم سے ابوعوانہ نے ان سے عبدالملک بن عمیر نے، ان سے ربعی بن حراش نے بیان کیا کہ عقبہ بن عمرو ابومسعود انصاری نے حذیفہ رضی اللہ عنہ سے کہا کہ نے نبی کریم صلی اللہ علیہ وسلم سے جو حدیثیں سنی ہیں وہ آپ ہم سے کیوں بیان نہیں کرتے؟ حذیفہ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ کہتے سنا تھا کہ ایک شخص کی موت کا وقت جب قریب ہوا اور وہ زندگی سے بالکل ناامید ہو گیا تو اپنے گھر والوں کو وصیت کی کہ جب میری موت ہو جائے تو پہلے میرے لیے بہت سی لکڑیاں جمع کرنا اور اس سے آگ جلانا۔ جب آگ میرے جسم کو خاکستر بنا چکے اور صرف ہڈیاں باقی رہ جائیں تو ہڈیوں کو پیس لینا اور کسی سخت گرمی کے دن میں یا ( یوں فرمایا کہ ) سخت ہوا کے دن مجھ کو ہوا میں اڑا دینا۔ لیکن اللہ تعالیٰ نے اسے جمع کیا اور پوچھا کہ تو نے ایسا کیوں کیا تھا؟ اس نے کہا کہ تیرے ہی ڈر سے۔ آخر اللہ تعالیٰ نے اس کو بخش دیا۔ عقبہ رضی اللہ عنہ نے کہا کہ میں نے بھی آپ صلی اللہ علیہ وسلم کو فرماتے ہوئے یہ حدیث سنی ہے۔ ہم سے موسیٰ نے بیان کیا کہا ہم سے ابوعوانہ نے بیان کیا کہا ہم سے عبدالملک نے بیان کیا اور کہا کہ اس روایت میں «في يوم راح» ہے ( سوا شک کے ) اس کے معنی بھی کسی تیز ہوا کے دن کے ہیں۔' WHERE id = 3334;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے عبیداللہ نے بیان کیا، ان سے سعید بن ابی سعید نے بیان کیا، ان سے ان کے باپ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ایک مرتبہ پوچھا گیا: یا رسول اللہ! سب سے زیادہ شریف کون ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”جو سب سے زیادہ پرہیزگار ہو۔“ صحابہ نے عرض کیا کہ ہمارا سوال اس کے بارے میں نہیں ہے، اس پر آپ صلی اللہ علیہ وسلم نے فرمایا ”پھر ( نسب کی رو سے ) اللہ کے نبی یوسف علیہ السلام سب سے زیادہ شریف تھے۔“' WHERE id = 3344;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا اور ان سے سعد بن ابراہیم نے (دوسری سند) یعقوب بن ابراہیم نے کہا کہ ہمارے والد نے ہم سے بیان کیا اور ان سے ان کے والد نے، کہا مجھ سے عبدالرحمٰن بن ہرمزالاعرج نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قریش، انصار، جہینہ، مزینہ، اسلم، اشجع اور غفار ان سب قبیلوں کے لوگ میرے خیرخواہ ہیں اور ان کا بھی اللہ اور اس کے رسول کے سوا کوئی حمایتی نہیں ہے۔“' WHERE id = 3356;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو عبدالوہاب ثقفی نے خبر دی، انہیں ایوب نے، انہیں محمد نے، انہیں ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے بیان کیا کہ ”قبیلہ اسلم کو اللہ تعالیٰ نے سلامت رکھا اور قبیلہ غفار کی اللہ تعالیٰ نے مغفرت فرما دی۔“' WHERE id = 3366;
UPDATE hadiths SET urdu = 'ہم سے ابولنعمان نے بیان کیا، انہوں نے کہا ہم سے ابوعوانہ نے بیان کیا، ان سے بشر نے، ان سے سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ اگر تم کو عرب کی جہالت معلوم کرنا اچھا لگے تو سورۃ الانعام میں ایک سو تیس آیتوں کے بعد یہ آیتیں پڑھ لو «قد خسر الذين قتلوا أولادهم سفها بغير علم‏» ”یقیناً وہ لوگ تباہ ہوئے جنہوں نے اپنی اولاد کو نادانی سے مار ڈالا۔“ سے لے کر «قد ضلوا وما كانوا مهتدين‏» ”وہ گمراہ ہیں، راہ پانے والے نہیں۔“ تک۔' WHERE id = 3376;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے عبداللہ بن دینار نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میری اور مجھ سے پہلے کے تمام انبیاء کی مثال ایسی ہے جیسے ایک شخص نے ایک گھر بنایا اور اس میں ہر طرح کی زینت پیدا کی لیکن ایک کونے میں ایک اینٹ کی جگہ چھوٹ گئی۔ اب تمام لوگ آتے ہیں اور مکان کو چاروں طرف سے گھوم کر دیکھتے ہیں اور تعجب میں پڑ جاتے ہیں لیکن یہ بھی کہتے جاتے ہیں کہ یہاں پر ایک اینٹ کیوں نہ رکھی گئی؟ تو میں ہی وہ اینٹ ہوں اور میں خاتم النبیین ہوں۔“' WHERE id = 3386;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن رجاء نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحٰق نے، ان سے وہب نے، ان سے ابوجحیفہ سوائی رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا۔ آپ صلی اللہ علیہ وسلم کے نچلے ہونٹ مبارک کے نیچے ٹھوڑی کے کچھ بال سفید تھے۔' WHERE id = 3396;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم سے ابن جریج نے بیان کیا، کہا کہ مجھے ابن شہاب نے خبر دی، انہیں عروہ نے اور انہیں عائشہ رضی اللہ عنہا نے ایک مرتبہ رسول اللہ صلی اللہ علیہ وسلم ان کے یہاں بہت ہی خوش خوش داخل ہوئے، خوشی اور مسرت سے پیشانی کی لکیریں چمک رہی تھیں۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا ”عائشہ! تم نے سنا نہیں مجزز مدلجی نے زید و اسامہ کے صرف قدم دیکھ کر کیا بات کہی؟ اس نے کہا کہ ایک کے پاؤں دوسرے کے پاؤں سے ملتے ہوئے نظر آتے ہیں۔“' WHERE id = 3406;
UPDATE hadiths SET urdu = 'ہم سے عبدالاعلی بن حماد نے بیان کیا، انہوں نے کہا ہم سے یزید بن زریع نے بیان کیا، انہوں نے کہا ہم سے سعید نے بیان کیا، انہوں نے قتادہ سے، انہوں نے انس بن مالک رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم دعا استسقاء کے سوا اور کسی دعا میں ( زیادہ اونچا ) ہاتھ نہیں اٹھاتے تھے۔ اس دعا میں آپ صلی اللہ علیہ وسلم اتنا اونچا ہاتھ اٹھاتے کہ بغل مبارک کی سفیدی دکھائی دیتی تھی۔' WHERE id = 3417;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحٰق نے، ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ صلح حدیبیہ کے دن ہم چودہ سو کی تعداد میں تھے۔ حدیبیہ ایک کنویں کا نام ہے ہم نے اس سے اتنا پانی کھینچا کہ اس میں ایک قطرہ بھی باقی نہ رہا ( جب رسول اللہ صلی اللہ علیہ وسلم کو اس کی خبر ہوئی تو آپ تشریف لائے ) اور کنویں کے کنارے بیٹھ کر پانی کی دعا کی اور اس پانی سے کلی کی اور کلی کا پانی کنویں میں ڈال دیا۔ ابھی تھوڑی دیر بھی نہیں ہوئی تھی کہ کنواں پھر پانی سے بھر گیا۔ ہم بھی اس سے خوب سیر ہوئے اور ہمارے اونٹ بھی سیراب ہو گئے یا پانی پی کر لوٹے۔' WHERE id = 3428;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک نہیں قائم ہو گی جب تک تم ایک ایسی قوم کے ساتھ جنگ نہ کر لو جن کے جوتے بال کے ہوں اور جب تک تم ترکوں سے جنگ نہ کر لو، جن کی آنکھیں چھوٹی ہوں گی، چہرے سرخ ہوں گے، ناک چھوٹی اور چپٹی ہو گی، چہرے ایسے ہوں گے جیسے تہ بہ تہ ڈھال ہوتی ہے۔“' WHERE id = 3438;
UPDATE hadiths SET urdu = 'اور زہری سے روایت ہے، ان سے ہند بنت الحارث نے بیان کیا کہ ام سلمہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم بیدار ہوئے تو فرمایا ”سبحان اللہ! کیسے کیسے خزانے اترے ہیں ( جو مسلمانوں کو ملیں گے ) اور کیا کیا فتنے و فساد اترے ہیں۔“' WHERE id = 3449;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی انہیں اعمش نے، انہیں خیثمہ نے، ان سے سوید بن غفلہ نے بیان کیا کہ علی رضی اللہ عنہ نے کہا، جب تم سے کوئی بات رسول اللہ صلی اللہ علیہ وسلم کے حوالہ سے میں بیان کروں تو یہ سمجھو کہ میرے لیے آسمان سے گر جانا اس سے بہتر ہے کہ میں آپ صلی اللہ علیہ وسلم پر کوئی جھوٹ باندھوں البتہ جب میں اپنی طرف سے کوئی بات تم سے کہوں تو لڑائی تو تدبیر اور فریب ہی کا نام ہے ( اس میں کوئی بات بنا کر کہوں تو ممکن ہے ) ۔ دیکھو میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرماتے تھے کہ آخر زمانہ میں کچھ لوگ ایسے پیدا ہوں گے جو چھوٹے چھوٹے دانتوں والے، کم عقل اور بیوقوف ہوں گے۔ باتیں وہ کہیں گے جو دنیا کی بہترین بات ہو گی۔ لیکن اسلام سے اس طرح صاف نکل چکے ہوں گے جیسے تیر جانور کے پار نکل جاتا ہے۔ ان کا ایمان ان کے حلق سے نیچے نہیں اترے گا، تم انہیں جہاں بھی پاؤ قتل کر دو، کیونکہ ان کے قتل سے قاتل کو قیامت کے دن ثواب ملے گا۔' WHERE id = 3460;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابی بشر نے، ان سے سعید بن جبیر نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ عمر بن خطاب ابن عباس رضی اللہ عنہما کو اپنے پاس بٹھاتے تھے۔ اس پر عبدالرحمٰن بن عوف رضی اللہ عنہ نے عمر رضی اللہ عنہ سے شکایت کی کہ ان جیسے تو ہمارے لڑکے بھی ہیں۔ لیکن عمر رضی اللہ عنہ نے جواب دیا کہ یہ محض ان کے علم کی وجہ سے ہے۔ پھر عمر رضی اللہ عنہ نے عبداللہ بن عباس رضی اللہ عنہما سے آیت «إذا جاء نصر الله والفتح‏» کے متعلق پوچھا تو انہوں نے جواب دیا کہ یہ رسول اللہ صلی اللہ علیہ وسلم کی وفات تھی جس کی خبر اللہ تعالیٰ نے آپ کو دی عمر رضی اللہ عنہ نے فرمایا جو تم نے سمجھا ہے میں بھی وہی سمجھتا ہوں۔' WHERE id = 3473;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے یونس بن یزید نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے خلیفہ بن خیاط نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، ان سے سعید نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ مکہ والوں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا تھا کہ انہیں کوئی معجزہ دکھائیں تو آپ صلی اللہ علیہ وسلم نے شق قمر کا معجزہ یعنی چاند کا پھٹ جانا ان کو دکھایا۔' WHERE id = 3483;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا اور انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ ہم سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ایک زمانہ آئے گا کہ اہل اسلام کی جماعتیں جہاد کریں گی تو ان سے پوچھا جائے گا کہ کیا تمہارے ساتھ رسول اللہ صلی اللہ علیہ وسلم کا کوئی صحابی بھی ہے؟ وہ کہیں گے کہ ہاں ہیں۔ تب ان کی فتح ہو گی۔ پھر ایک ایسا زمانہ آئے گا کہ مسلمانوں کی جماعتیں جہاد کریں گی اور اس موقع پر یہ پوچھا جائے گا کہ یہاں رسول اللہ صلی اللہ علیہ وسلم کے صحابی کی صحبت اٹھانے والے ( تابعی ) بھی موجود ہیں؟ جواب ہو گا کہ ہاں ہیں اور ان کے ذریعہ فتح کی دعا مانگی جائے گی، اس کے بعد ایک زمانہ ایسا آئے گا کہ مسلمانوں کی جماعتیں جہاد کریں گی اور اس وقت سوال اٹھے گا کہ کیا یہاں کوئی بزرگ ایسے ہیں جو رسول اللہ صلی اللہ علیہ وسلم کے صحابہ کے شاگردوں میں سے کسی بزرگ کی صحبت میں رہے ہوں؟ جواب ہو گا کہ ہاں ہیں، تو ان کے ذریعہ فتح کی دعا مانگی جائے گی پھر ان کی فتح ہو گی۔' WHERE id = 3494;
UPDATE hadiths SET urdu = 'ہم سے حمیدی اور محمد بن عبداللہ نے بیان کیا، کہا کہ ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے، ان سے محمد بن جبیر بن مطعم نے اور ان سے ان کے والد نے بیان کیا کہ ایک عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آئی تو آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ پھر آنا۔ اس نے کہا: اگر میں آؤں اور آپ کو نہ پاؤں تو؟ گویا وہ وفات کی طرف اشارہ کر رہی تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تم مجھے نہ پا سکو تو ابوبکر کے پاس چلی آنا۔' WHERE id = 3504;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، ہم سے شعبہ نے بیان کیا، ان سے اعمش نے بیان کیا، کہا میں نے ذکوان سے سنا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے اصحاب کو برا بھلا مت کہو۔ اگر کوئی شخص احد پہاڑ کے برابر بھی سونا ( اللہ کی راہ میں ) خرچ کر ڈالے تو ان کے ایک مد غلہ کے برابر بھی نہیں ہو سکتا اور نہ ان کے آدھے مد کے برابر۔“ شعبہ کے ساتھ اس حدیث کو جریر، عبداللہ بن داود، ابومعاویہ اور محاضر نے بھی اعمش سے روایت کیا ہے۔' WHERE id = 3516;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ بن مدینی نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا ان سے صالح نے، ان سے ابن شہاب نے، کہا مجھ کو عبدالحمید بن عبدالرحمٰن نے خبر دی، انہیں محمد بن سعد بن ابی وقاص نے خبر دی اور ان سے ان کے والد (سعد بن ابی وقاص رضی اللہ عنہ) نے بیان کیا (دوسری سند) اور مجھ سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے، ان سے عبدالحمید بن عبدالرحمٰن بن زید نے، ان سے محمد بن سعد بن ابی وقاص نے اور ان سے ان کے والد نے بیان کیا کہ عمر رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم سے اندر آنے کی اجازت چاہی۔ اس وقت آپ کے پاس قریش کی چند عورتیں ( امہات المؤمنین میں سے ) بیٹھی باتیں کر رہی تھیں اور آپ کی آواز پر اپنی آواز اونچی کرتے ہوئے آپ سے نان و نفقہ میں زیادتی کا مطالبہ کر رہی تھیں۔ جوں ہی عمر رضی اللہ عنہ نے اجازت چاہی تو وہ تمام کھڑی ہو کر پردے کے پیچھے جلدی سے بھاگ کھڑی ہوئیں۔ آخر آپ صلی اللہ علیہ وسلم نے اجازت دی اور وہ داخل ہوئے تو آپ صلی اللہ علیہ وسلم مسکرا رہے تھے۔ عمر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! اللہ تعالیٰ آپ صلی اللہ علیہ وسلم کو ہمیشہ خوش رکھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا: مجھے ان عورتوں پر ہنسی آ رہی ہے جو ابھی میرے پاس بیٹھی ہوئی تھیں، لیکن تمہاری آواز سنتے ہی سب پردے کے پیچھے بھاگ گئیں۔ عمر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! ڈرنا تو انہیں آپ سے چاہیے تھا۔ پھر انہوں نے ( عورتوں سے ) کہا اے اپنی جانوں کی دشمنو! تم مجھ سے تو ڈرتی ہو اور نبی کریم صلی اللہ علیہ وسلم سے نہیں ڈرتیں، عورتوں نے کہا کہ ہاں، آپ ٹھیک کہتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم کے مقابلے میں آپ کہیں زیادہ سخت ہیں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا: اے ابن خطاب! اس ذات کی قسم جس کے ہاتھ میں میری جان ہے، اگر شیطان تمہیں کسی راستے پر چلتا دیکھتا ہے تو اسے چھوڑ کر وہ کسی دوسرے راستے پر چل پڑتا ہے۔' WHERE id = 3526;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا کہ مجھ سے عثمان بن غیاث نے بیان کیا، کہا کہ مجھ سے ابوعثمان نہدی نے بیان کیا، اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ میں مدینہ کے ایک باغ ( بئراریس ) میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھا کہ ایک صاحب نے آ کر دروازہ کھلوایا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان کے لیے دروازہ کھول دو اور انہیں جنت کی بشارت سنا دو، میں نے دروازہ کھولا تو ابوبکر رضی اللہ عنہ تھے۔ میں نے انہیں نبی کریم صلی اللہ علیہ وسلم کے فرمانے کے مطابق جنت کی خوشخبری سنائی تو انہوں نے اس پر اللہ کی حمد کی، پھر ایک اور صاحب آئے اور دروازہ کھلوایا۔ نبی کریم صلی اللہ علیہ وسلم نے اس موقع پر بھی یہی فرمایا کہ دروازہ ان کے لیے کھول دو اور انہیں جنت کی بشارت سنا دو، میں نے دروازہ کھولا تو عمر رضی اللہ عنہ تھے، انہیں بھی جب نبی کریم صلی اللہ علیہ وسلم کے ارشاد کی اطلاع سنائی تو انہوں نے بھی اللہ تعالیٰ کی حمد و ثنا بیان کی۔ پھر ایک تیسرے اور صاحب نے دروازہ کھلوایا۔ ان کے لیے بھی نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دروازہ کھول دو اور انہیں جنت کی بشارت سنا دو ان مصائب اور آزمائشوں کے بعد جن سے انہیں ( دنیا میں ) واسطہ پڑے گا۔ وہ عثمان رضی اللہ عنہ تھے۔ جب میں نے ان کو نبی کریم صلی اللہ علیہ وسلم کے ارشاد کی اطلاع دی تو انہوں نے اللہ کی حمد و ثنا کے بعد فرمایا کہ اللہ تعالیٰ ہی مدد کرنے والا ہے۔' WHERE id = 3536;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ان کے والد نے کہ ایک شخص سہل بن سعد رضی اللہ عنہ کے یہاں آیا اور کہا کہ یہ فلاں شخص اس کا اشارہ امیر مدینہ ( مروان بن حکم ) کی طرف تھا، برسر منبر علی رضی اللہ عنہ کو برا بھلا کہتا ہے، ابوحازم نے بیان کیا کہ سہل بن سعد رضی اللہ عنہ نے پوچھا کیا کہتا ہے؟ اس نے بتایا کہ انہیں ”ابوتراب“ کہتا ہے، اس پر سہل ہنسنے لگے اور فرمایا کہ اللہ کی قسم! یہ نام تو ان کا رسول اللہ صلی اللہ علیہ وسلم نے رکھا تھا اور خود علی رضی اللہ عنہ کو اس نام سے زیادہ اپنے لیے اور کوئی نام پسند نہیں تھا۔ یہ سن کر میں نے اس حدیث کے جاننے کے لیے سہل رضی اللہ عنہ سے خواہش ظاہر کی اور عرض کیا: اے ابوعباس! یہ واقعہ کس طرح سے ہے؟ انہوں نے بیان کیا کہ ایک مرتبہ علی رضی اللہ عنہ فاطمہ رضی اللہ عنہا کے یہاں آئے اور پھر باہر آ کر مسجد میں لیٹ رہے، پھر آپ صلی اللہ علیہ وسلم نے ( فاطمہ رضی اللہ عنہا سے ) دریافت فرمایا، تمہارے چچا کے بیٹے کہاں ہیں؟ انہوں نے بتایا کہ مسجد میں ہیں۔ آپ صلی اللہ علیہ وسلم مسجد میں تشریف لائے، دیکھا تو ان کی چادر پیٹھ سے نیچے گر گئی ہے اور ان کی کمر پر اچھی طرح سے خاک لگ چکی ہے۔ آپ صلی اللہ علیہ وسلم مٹی ان کی کمر سے صاف فرمانے لگے اور بولے، اٹھو اے ابوتراب اٹھو! ( دو مرتبہ آپ صلی اللہ علیہ وسلم نے فرمایا ) ۔' WHERE id = 3546;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اپنی صاحبزادی فاطمہ رضی اللہ عنہا کو اپنے اس مرض کے موقع پر بلایا جس میں آپ کی وفات ہوئی، پھر آہستہ سے کوئی بات کہی تو وہ رونے لگیں، پھر آپ صلی اللہ علیہ وسلم نے انہیں بلایا اور آہستہ سے کوئی بات کہی تو وہ ہنسنے لگیں، عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر میں نے ان سے اس کے متعلق پوچھا۔' WHERE id = 3557;
UPDATE hadiths SET urdu = 'ہم سے ہاشم نے بیان کیا، کہا ہم سے عمرو بن عون نے بیان کیا، کہا ہم سے خالد بن عبداللہ نے بیان کیا، ان سے اسماعیل نے، ان سے قیس نے بیان کیا کہ میں نے سعد بن ابی وقاص رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ عرب میں سب سے پہلے اللہ کے راستے میں، میں نے تیر اندازی کی تھی ( ابتداء اسلام میں ) ہم نبی کریم صلی اللہ علیہ وسلم ، کے ساتھ اس طرح غزوات میں شرکت کرتے تھے کہ ہمارے پاس درخت کے پتوں کے سوا کھانے کے لیے کچھ بھی نہ ہوتا تھا، اس سے ہمیں اونٹ اور بکریوں کی طرح اجابت ہوتی تھی۔ یعنی ملی ہوئی نہیں ہوتی تھی۔ لیکن اب بنی اسد کا یہ حال ہے کہ اسلامی احکام پر عمل میں میرے اندر عیب نکالتے ہیں ( اگر ) ایسا ہو تو میں بالکل محروم اور بے نصیب ہی رہا اور میرے سب کام برباد ہو گئے۔ ہوا یہ تھا کہ بنی اسد نے عمر رضی اللہ عنہ سے سعد رضی اللہ عنہ کی چغلی کھائی تھی۔ یہ کہا تھا کہ وہ اچھی طرح نماز بھی نہیں پڑھتے۔' WHERE id = 3568;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے مغیرہ نے، ان سے ابراہیم نے، ان سے علقمہ نے بیان کیا کہ میں جب شام آیا تو میں نے دو رکعت نماز پڑھ کر یہ دعا کی کہ اے اللہ! مجھے کوئی نیک ساتھی عطا فرما۔ پھر میں ایک قوم کے پاس آیا اور ان کی مجلس میں بیٹھ گیا، تھوڑی ہی دیر بعد ایک بزرگ آئے اور میرے پاس بیٹھ گئے۔ میں نے پوچھا یہ کون بزرگ ہیں؟ لوگوں نے بتایا کہ یہ ابودرداء رضی اللہ عنہ ہیں۔ اس پر میں نے عرض کیا کہ میں نے اللہ تعالیٰ سے دعا کی تھی کہ کوئی نیک ساتھی مجھے عطا فرما، تو اللہ تعالیٰ نے آپ کو مجھے عنایت فرمایا۔ انہوں نے دریافت کیا، تمہارا وطن کہاں ہے؟ میں نے عرض کیا کوفہ ہے۔ انہوں نے کہا کیا تمہارے یہاں «ابن أم عبد صاحب النعلين والوساد والمطهرة» ( یعنی عبداللہ بن مسعود رضی اللہ عنہ ) نہیں ہیں؟ کیا تمہارے یہاں وہ نہیں ہیں جنہیں اللہ تعالیٰ اپنے نبی کریم صلی اللہ علیہ وسلم کی زبانی شیطان سے پناہ دے چکا ہے کہ وہ انہیں کبھی غلط راستے پر نہیں لے جا سکتا۔ ( مراد عمار رضی اللہ عنہ سے تھی ) کیا تم میں وہ نہیں ہیں جو رسول اللہ صلی اللہ علیہ وسلم کے بتائے ہوئے بہت سے بھیدوں کے حامل ہیں جنہیں ان کے سوا اور کوئی نہیں جانتا۔ ( یعنی حذیفہ رضی اللہ عنہ ) اس کے بعد انہوں نے دریافت فرمایا: عبداللہ رضی اللہ عنہ آیت «والليل إذا يغشى‏» کی تلاوت کس طرح کرتے ہیں؟ میں نے انہیں پڑھ کر سنائی کہ «والليل إذا يغشى * والنهار إذا تجلى * والذكر والأنثى‏» اس پر انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے خود اپنی زبان مبارک سے مجھے بھی اسی طرح یاد کرایا تھا۔' WHERE id = 3580;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام بن یوسف نے خبر دی، انہیں معمر نے، انہیں زہری نے اور انہیں انس رضی اللہ عنہ نے، اور عبدالرزاق نے بیان کیا کہ ہمیں معمر نے خبر دی، انہیں زہری نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ حسن بن علی رضی اللہ عنہما سے زیادہ اور کوئی شخص نبی کریم صلی اللہ علیہ وسلم سے زیادہ مشابہ نہیں تھا۔' WHERE id = 3590;
UPDATE hadiths SET urdu = 'کہا ہم سے حسن بن بشیر نے بیان کیا، ان سے عثمان بن اسود نے اور ان سے ابن ابی ملیکہ نے بیان کیا کہ معاویہ رضی اللہ عنہ نے عشاء کے بعد وتر کی نماز صرف ایک رکعت پڑھی وہیں ابن عباس رضی اللہ عنہما کے مولیٰ ( کریب ) بھی موجود تھے، جب وہ ابن عباس رضی اللہ عنہما کی خدمت میں حاضر ہوئے تو ( امیر معاویہ رضی اللہ عنہ کی ایک رکعت وتر کا ذکر کیا ) اس پر انہوں نے کہا: کوئی حرج نہیں ہے، انہوں نے رسول اللہ صلی اللہ علیہ وسلم کی صحبت اٹھائی ہے۔' WHERE id = 3602;
UPDATE hadiths SET urdu = 'مجھ سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے کہ رسول اللہ صلی اللہ علیہ وسلم اپنے مرض الوفات میں بھی ازواج مطہرات کی باری کی پابندی فرماتے رہے البتہ یہ دریافت فرماتے رہے کہ کل مجھے کس کے یہاں ٹھہرنا ہے؟ کیونکہ آپ عائشہ رضی اللہ عنہا کی باری کے خواہاں تھے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ جب میرے یہاں قیام کا دن آیا تو آپ کو سکون ہوا۔' WHERE id = 3612;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عبدالرحمٰن بن عبداللہ بن جبیر نے کہا اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایمان کی نشانی انصار سے محبت رکھنا ہے اور نفاق کی نشانی انصار سے بغض رکھنا ہے۔“' WHERE id = 3622;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے یحییٰ بن سعید نے، انہوں نے انس رضی اللہ عنہ سے سنا جب وہ انس رضی اللہ عنہ کے ساتھ خلیفہ ولید بن عبدالملک کے یہاں جانے کے لیے نکلے۔ نبی کریم صلی اللہ علیہ وسلم نے انصار کو بلایا تاکہ بحرین کا ملک بطور جاگیر انہیں عطا فرما دیں۔ انصار نے کہا جب تک آپ ہمارے بھائی مہاجرین کو بھی اسی جیسی جاگیر نہ عطا فرمائیں ہم اسے قبول نہیں کریں گے۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”دیکھو جب آج تم قبول نہیں کرتے ہو تو پھر میرے بعد بھی صبر کرنا یہاں تک کہ مجھ سے آ ملو، کیونکہ میرے بعد قریب ہی تمہاری حق تلفی ہونے والی ہے۔“' WHERE id = 3632;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے سعد بن ابراہیم نے، ان سے ابوامامہ بن سہل بن حنیف نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ایک قوم ( یہود بنی قریظہ ) نے سعد بن معاذ رضی اللہ عنہ کو ثالث مان کر ہتھیار ڈال دیئے تو انہیں بلانے کے لیے آدمی بھیجا گیا اور وہ گدھے پر سوار ہو کر آئے۔ جب اس جگہ کے قریب پہنچے جسے ( نبی کریم صلی اللہ علیہ وسلم نے ایام جنگ میں ) نماز پڑھنے کے لیے منتخب کیا ہوا تھا تو نبی کریم صلی اللہ علیہ وسلم نے صحابہ سے فرمایا کہ اپنے سب سے بہتر شخص کے لیے یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا ) اپنے سردار کو لینے کے لیے کھڑے ہو جاؤ۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا: اے سعد! انہوں نے تم کو ثالث مان کر ہتھیار ڈال دیئے ہیں۔ سعد رضی اللہ عنہ نے کہا پھر میرا فیصلہ یہ ہے کہ ان کے جو لوگ جنگ کرنے والے ہیں انہیں قتل کر دیا جائے اور ان کی عورتوں، بچوں کو جنگی قیدی بنا لیا جائے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تم نے اللہ کے فیصلے کے مطابق فیصلہ کیا یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) فرشتے کے حکم کے مطابق فیصلہ کیا ہے۔' WHERE id = 3642;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے، ان سے سعید بن ابی بردہ نے اور ان سے ان کے والد نے کہ میں مدینہ منورہ حاضر ہوا تو میں نے عبداللہ بن سلام رضی اللہ عنہ سے ملاقات کی، انہوں نے کہا، آؤ تمہیں میں ستو اور کھجور کھلاؤں گا اور تم ایک ( باعظمت ) مکان میں داخل ہو گے ( کہ رسول صلی اللہ علیہ وسلم بھی اس میں تشریف لے گئے تھے ) پھر آپ صلی اللہ علیہ وسلم نے فرمایا تمہارا قیام ایک ایسے ملک میں ہے جہاں سودی معاملات بہت عام ہیں اگر تمہارا کسی شخص پر کوئی حق ہو اور پھر وہ تمہیں ایک تنکے یا جَو کے ایک دانے یا ایک گھاس کے برابر بھی ہدیہ دے تو اسے قبول نہ کرنا کیونکہ وہ بھی سود ہے۔ نضر، ابوداؤد اور وہب نے ( اپنی روایتوں میں ) «البيت‏.‏» ( گھر ) کا ذکر نہیں کیا۔' WHERE id = 3652;
UPDATE hadiths SET urdu = 'مجھ سے اسماعیل بن خلیل نے بیان کیا، کہا ہم سے سلمہ بن رجاء نے، انہیں ہشام بن عروہ نے، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ احد کی لڑائی میں جب مشرکین ہار چکے تو ابلیس نے چلا کر کہا: اے اللہ کے بندو! پیچھے والوں کو ( قتل کرو ) چنانچہ آگے کے مسلمان پیچھے والوں پر پل پڑے اور انہیں قتل کرنا شروع کر دیا۔ حذیفہ رضی اللہ عنہ نے جو دیکھا تو ان کے والد ( یمان رضی اللہ عنہ ) بھی وہیں موجود تھے انہوں نے پکار کر کہا: اے اللہ کے بندو یہ تو میرے والد ہیں میرے والد! عائشہ رضی اللہ عنہا نے بیان کیا: اللہ کی قسم! اس وقت تک لوگ وہاں سے نہیں ہٹے جب تک انہیں قتل نہ کر لیا۔ حذیفہ رضی اللہ عنہ نے صرف اتنا کہا اللہ تمہاری مغفرت کرے۔ ( ہشام نے بیان کیا کہ ) اللہ کی قسم! حذیفہ رضی اللہ عنہ برابر یہ کلمہ دعائیہ کہتے رہے ( کہ اللہ ان کے والد پر حملہ کرنے والوں کو بخشے جو کہ محض غلط فہمی کی وجہ سے یہ حرکت کر بیٹھے ) یہ دعا مرتے دم تک کرتے رہے۔' WHERE id = 3662;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے اور ان سے قیس بن ابی حازم نے بیان کیا کہ ابوبکر رضی اللہ عنہ قبیلہ احمس کی ایک عورت سے ملے ان کا نام زینب بنت مہاجر تھا۔ آپ نے دیکھا کہ وہ بات ہی نہیں کرتیں دریافت فرمایا کیا بات ہے یہ بات کیوں نہیں کرتیں؟ لوگوں نے بتایا کہ مکمل خاموشی کے ساتھ حج کرنے کی منت مانی ہے۔ ابوبکر رضی اللہ عنہ نے ان سے فرمایا: اجی بات کرو اس طرح حج کرنا تو جاہلیت کی رسم ہے، چنانچہ اس نے بات کی اور پوچھا آپ کون ہیں؟ ابوبکر رضی اللہ عنہ نے کہا کہ میں مہاجرین کا ایک آدمی ہوں۔ انہوں نے پوچھا کہ مہاجرین کے کس قبیلہ سے ہیں؟ آپ نے فرمایا کہ قریش سے، انہوں نے پوچھا قریش کے کس خاندان سے؟ ابوبکر رضی اللہ عنہ نے اس پر فرمایا تم بہت پوچھنے والی عورت ہو، میں ابوبکر ہوں۔ اس کے بعد انہوں نے پوچھا جاہلیت کے بعد اللہ تعالیٰ نے جو ہمیں یہ دین حق عطا فرمایا ہے اس پر ہم ( مسلمان ) کب تک قائم رہ سکیں گے؟ آپ نے فرمایا اس پر تمہارا قیام اس وقت تک رہے گا جب تک تمہارے امام حاکم سیدھے رہیں گے۔ اس خاتون نے پوچھا امام سے کیا مراد ہے؟ آپ نے فرمایا: کیا تمہاری قوم میں سردار اور اشراف لوگ نہیں ہیں جو اگر لوگوں کو کوئی حکم دیں تو وہ اس کی اطاعت کریں؟ اس نے کہا کہ کیوں نہیں ہیں۔ ابوبکر رضی اللہ عنہ نے کہا کہ امام سے یہی مراد ہیں۔' WHERE id = 3672;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا ہم سے مہدی نے بیان کیا انہوں نے کہا کہ غیلان بن جریر نے بیان کیا کہ ہم انس بن مالک رضی اللہ عنہ کی خدمت میں حاضر ہوتے تھے۔ وہ ہم سے انصار کے متعلق بیان فرمایا کرتے تھے اور مجھ سے فرماتے کہ تمہاری قوم نے فلاں موقع پر یہ کارنامہ انجام دیا، فلاں موقع پر یہ کارنامہ انجام دیا۔' WHERE id = 3682;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے، ان سے ابواسحاق نے، ان سے عمرو بن میمون نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ( نماز پڑھتے ہوئے ) سجدہ کی حالت میں تھے، قریش کے کچھ لوگ وہیں اردگرد موجود تھے۔ اتنے میں عقبہ بن ابی معیط اونٹ کی اوجھڑی بچہ دان لایا اور نبی کریم صلی اللہ علیہ وسلم کی پیٹھ مبارک پر اسے ڈال دیا۔ اس کی وجہ سے آپ صلی اللہ علیہ وسلم نے اپنا سر نہیں اٹھایا پھر فاطمہ رضی اللہ عنہا آئیں اور گندگی کو پیٹھ مبارک سے ہٹایا اور جس نے ایسا کیا تھا اسے بددعا دیں۔ نبی کریم صلی اللہ علیہ وسلم نے بھی ان کے حق میں بددعا کی کہ اے اللہ! قریش کی اس جماعت کو پکڑ لے۔ ابوجہل بن ہشام، عتبہ بن ربیعہ، شیبہ بن ربیعہ اور امیہ بن خلف یا ( امیہ کے بجائے آپ نے بددعا ) ابی بن خلف ( کے حق میں فرمائی ) شبہ راوی حدیث شعبہ کو تھا۔ عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ پھر میں نے دیکھا کہ بدر کی لڑائی میں یہ سب لوگ قتل کر دئیے گئے اور ایک کنویں میں انہیں ڈال دیا گیا تھا سوائے امیہ یا ابی کے کہ اس کا ہر ایک جوڑ الگ الگ ہو گیا تھا اس لیے کنویں میں نہیں ڈالا جا سکا۔' WHERE id = 3692;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا مجھ سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھ سے عمر بن محمد نے بیان کیا، کہا مجھ کو میرے دادا زید بن عبداللہ بن عمرو نے خبر دی، ان سے ان کے والد عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ عمر رضی اللہ عنہ ( اسلام لانے کے بعد قریش سے ) ڈرے ہوئے گھر میں بیٹھے ہوئے تھے کہ ابوعمرو عاص بن وائل سہمی اندر آیا، ایک دھاری دار چادر اور ریشمی کرتہ پہنے ہوئے تھا۔ وہ قبیلہ بنو سہم سے تھا جو زمانہ جاہلیت میں ہمارے حلیف تھے۔ عاص نے عمر رضی اللہ عنہ سے کہا کیا بات ہے؟ عمر رضی اللہ عنہ نے کہا کہ تمہاری قوم بنو سہم والے کہتے ہیں کہ اگر میں مسلمان ہوا تو وہ مجھ کو مار ڈالیں گے۔ عاص نے کہا ”تمہیں کوئی نقصان نہیں پہنچا سکتا“ جب عاص نے یہ کلمہ کہہ دیا تو عمر رضی اللہ عنہ نے کہا کہ پھر میں بھی اپنے کو امان میں سمجھتا ہوں۔ اس کے بعد عاص باہر نکلا تو دیکھا کہ میدان لوگوں سے بھر گیا ہے۔ عاص نے پوچھا کدھر کا رخ ہے؟ لوگوں نے کہا ہم ابن خطاب کی خبر لینے جاتے ہیں جو بےدین ہو گیا ہے۔ عاص نے کہا اسے کوئی نقصان نہیں پہنچا سکتا، یہ سنتے ہی لوگ لوٹ گئے۔' WHERE id = 3702;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے کہا ہم سے اسحاق بن سعید سعیدی نے بیان کیا۔ ان سے ان کے والد سعید بن عمرو بن سعید بن عاص نے، ان سے ام خالد بنت خالد رضی اللہ عنہا نے بیان کیا کہ میں جب حبشہ سے آئی تو بہت کم عمر تھی۔ مجھے رسول اللہ صلی اللہ علیہ وسلم نے ایک دھاری دار چادر عنایت فرمائی اور پھر آپ نے اس کی دھاریوں پر اپنا ہاتھ پھیر کر فرمایا «سناه،‏‏‏‏‏‏‏‏ سناه‏ ‏‏.‏» ۔ حمیدی نے بیان کیا کہ «سناه،‏‏‏‏‏‏‏‏ سناه‏ ‏‏.‏» حبشی زبان کا لفظ ہے یعنی اچھا اچھا۔' WHERE id = 3712;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا ہم سے عبدالرزق نے بیان کیا، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں سعید بن مسیب نے اور انہیں ان کے والد مسیب بن حزن صحابی رضی اللہ عنہ نے کہ جب ابوطالب کی وفات کا وقت قریب ہوا تو نبی کریم صلی اللہ علیہ وسلم ان کے پاس تشریف لے گئے۔ اس وقت وہاں ابوجہل بھی بیٹھا ہوا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”چچا! کلمہ لا الہٰ الا اللہ ایک مرتبہ کہہ دو، اللہ کی بارگاہ میں ( آپ کی بخشش کے لیے ) ایک یہی دلیل میرے ہاتھ آ جائے گی۔“ اس پر ابوجہل اور عبداللہ بن ابی امیہ نے کہا: اے ابوطالب! کیا عبدالمطلب کے دین سے تم پھر جاؤ گے! یہ دونوں ان ہی پر زور دیتے رہے اور آخری کلمہ جو ان کی زبان سے نکلا، وہ یہ تھا کہ میں عبدالمطلب کے دین پر قائم ہوں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں ان کے لیے اس وقت تک مغفرت طلب کرتا رہوں گا جب تک مجھے اس سے منع نہ کر دیا جائے گا۔ چنانچہ ( سورۃ براۃ میں ) یہ آیت نازل ہوئی «ما كان للنبي والذين آمنوا أن يستغفروا للمشركين ولو كانوا أولي قربى من بعد ما تبين لهم أنهم أصحاب الجحيم‏» ”نبی کے لیے اور مسلمانوں کے لیے مناسب نہیں ہے کہ مشرکین کے لیے دعا مغفرت کریں خواہ وہ ان کے ناطے والے ہی کیوں نہ ہوں جب کہ ان کے سامنے یہ بات واضح ہو گئی کہ وہ دوزخی ہیں۔“ اور سورۃ قصص میں یہ آیت نازل ہوئی «إنك لا تهدي من أحببت‏» ”بیشک جسے آپ چاہیں ہدایت نہیں کر سکتے۔“' WHERE id = 3722;
UPDATE hadiths SET urdu = 'مجھ سے فروہ بن ابی المغراء نے بیان کیا، کہا ہم سے علی بن مسہر نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے میرا نکاح جب ہوا تو میری عمر چھ سال کی تھی، پھر ہم مدینہ ( ہجرت کر کے ) آئے اور بنی حارث بن خزرج کے یہاں قیام کیا۔ یہاں آ کر مجھے بخار چڑھا اور اس کی وجہ سے میرے بال گرنے لگے۔ پھر مونڈھوں تک خوب بال ہو گئے پھر ایک دن میری والدہ ام رومان رضی اللہ عنہا آئیں۔ اس وقت میں اپنی چند سہیلیوں کے ساتھ جھولا جھول رہی تھی انہوں نے مجھے پکارا تو میں حاضر ہو گئی۔ مجھے کچھ معلوم نہیں تھا کہ میرے ساتھ ان کا کیا ارادہ ہے۔ آخر انہوں نے میرا ہاتھ پکڑ کر گھر کے دروازہ کے پاس کھڑا کر دیا اور میرا سانس پھولا جا رہا تھا۔ تھوڑی دیر میں جب مجھے کچھ سکون ہوا تو انہوں نے تھوڑا سا پانی لے کر میرے منہ اور سر پر پھیرا۔ پھر گھر کے اندر مجھے لے گئیں۔ وہاں انصار کی چند عورتیں موجود تھیں، جنہوں نے مجھے دیکھ کر دعا دی کہ خیر و برکت اور اچھا نصیب لے کر آئی ہو۔ میری ماں نے مجھے انہیں کے حوالہ کر دیا اور انہوں نے میری آرائش کی۔ اس کے بعد دن چڑھے اچانک رسول اللہ صلی اللہ علیہ وسلم میرے پاس تشریف لائے اور انہوں نے مجھے آپ کے سپرد کر دیا میری عمر اس وقت نو سال تھی۔' WHERE id = 3732;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے مالک نے بیان کیا، ان سے عمر بن عبیداللہ کے مولیٰ ابوالنضر نے، ان سے عبید یعنی ابن حنین نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم منبر پر بیٹھے، فرمایا ”اپنے ایک نیک بندے کو اللہ تعالیٰ نے اختیار دیا کہ دنیا کی نعمتوں میں سے جو وہ چاہے اسے اپنے لیے پسند کر لے یا جو اللہ تعالیٰ کے یہاں ہے ( آخرت میں ) اسے پسند کر لے۔ اس بندے نے اللہ تعالیٰ کے ہاں ملنے والی چیز کو پسند کر لیا۔“ اس پر ابوبکر رضی اللہ عنہ رونے لگے اور عرض کیا ہمارے ماں باپ آپ پر فدا ہوں۔ ( ابوسعید رضی اللہ عنہ کہتے ہیں ) ہمیں ابوبکر رضی اللہ عنہ کے اس رونے پر حیرت ہوئی، بعض لوگوں نے کہا اس بزرگ کو دیکھئیے نبی کریم صلی اللہ علیہ وسلم تو ایک بندے کے متعلق خبر دے رہے ہیں جسے اللہ تعالیٰ نے دنیا کی نعمتوں اور جو اللہ کے پاس ہے اس میں سے کسی کے پسند کرنے کا اختیار دیا تھا اور یہ کہہ رہے ہیں کہ ہمارے ماں باپ آپ پر فدا ہوں۔ لیکن رسول اللہ صلی اللہ علیہ وسلم ہی کو ان دو چیزوں میں سے ایک کا اختیار دیا گیا اور ابوبکر رضی اللہ عنہ ہم میں سب سے زیادہ اس بات سے واقف تھے اور رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ لوگوں میں سب سے زیادہ اپنی صحبت اور مال کے ذریعہ مجھ پر احسان کرنے والے ابوبکر ہیں۔ اگر میں اپنی امت میں سے کسی کو اپنا خلیل بنا سکتا تو ابوبکر رضی اللہ عنہ کو بناتا البتہ اسلامی رشتہ ان کے ساتھ کافی ہے۔ مسجد میں کوئی دروازہ اب کھلا ہوا باقی نہ رکھا جائے سوائے ابوبکر کے گھر کی طرف کھلنے والے دروازے کے۔' WHERE id = 3742;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ان سے یحییٰ بن سعید قطان نے بیان کیا، ان سے اعمش نے، انہوں نے شقیق بن سلمہ سے سنا، کہا کہ ہم سے خباب رضی اللہ عنہ نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہجرت کی تو ہمارا مقصد صرف اللہ کی رضا تھی اور اللہ تعالیٰ ہمیں اس کا اجر بھی ضرور دے گا۔ پس ہم میں سے بعض تو پہلے ہی اس دنیا سے اٹھ گئے۔ اور یہاں اپنا کوئی بدلہ انہوں نے نہیں پایا۔ مصعب بن عمیر رضی اللہ عنہ بھی انہیں میں سے ہیں۔ احد کی لڑائی میں انہوں نے شہادت پائی۔ اور ان کے کفن کے لیے ہمارے پاس ایک کمبل کے سوا اور کچھ نہیں تھا۔ اور وہ بھی ایسا کہ اگر اس سے ہم ان کا سر چھپاتے تو ان کے پاؤں کھل جاتے۔ اور اگر پاؤں چھپاتے تو سر کھلا رہ جاتا۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے حکم دیا کہ ان کا سر چھپا دیا جائے اور پاؤں کو اذخر گھاس سے چھپا دیا جائے۔ اور ہم میں بعض وہ ہیں جنہوں نے اپنے عمل کا پھل اس دنیا میں پختہ کر لیا۔ اور اب وہ اس کو خوب چن رہے ہیں۔' WHERE id = 3752;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ ہمیں ابواسحاق نے خبر دی، انہوں نے براء بن عازب رضی اللہ عنہما سے سنا، انہوں نے یوں بیان کیا کہ سب سے پہلے ( ہجرت کر کے ) ہمارے یہاں مصعب بن عمیر رضی اللہ عنہ اور ابن ام مکتوم رضی اللہ عنہ آئے پھر عمار بن یاسر رضی اللہ عنہما اور بلال رضی اللہ عنہ آئے۔' WHERE id = 3762;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا ہم سے عبدالعزیز بن ابوحازم نے بیان کیا، ان سے ان کے والد سلمہ بن دینار نے، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ تاریخ کا شمار نبی کریم صلی اللہ علیہ وسلم کی نبوت کے سال سے ہوا اور نہ آپ کی وفات کے سال سے بلکہ اس کا شمار مدینہ کی ہجرت کے سال سے ہوا۔' WHERE id = 3772;
UPDATE hadiths SET urdu = 'مجھ سے حسن بن شقیق نے بیان کیا، کہا ہم سے معتمر نے بیان کیا کہ میرے والد سلیمان بن طرخان نے بیان کیا (دوسری سند) اور ہم سے ابوعثمان نہدی نے بیان کیا کہا میں نے سنا سلمان فارسی رضی اللہ عنہ سے کہ ان کو کچھ اوپر دس آدمیوں نے ایک مالک سے ان کو دس سے زائد آدمیوں نے لیا، ایک مالک نے دوسرے مالک سے خریدا۔' WHERE id = 3783;
UPDATE hadiths SET urdu = '(دوسری سند) امام بخاری رحمہ اللہ فرماتے ہیں اور مجھ سے محمود بن غیلان نے بیان کیا کہا، ہم سے وہب بن جریر نے بیان کیا، ان سے شعبہ نے، ان سے ابواسحاق نے اور ان سے براء رضی اللہ عنہ نے بیان کیا کہ بدر کی لڑائی میں مجھے اور عبداللہ بن عمر رضی اللہ عنہما کو نابالغ قرار دے دیا گیا تھا اور اس لڑائی میں مہاجرین کی تعداد ساٹھ سے کچھ زیادہ تھی اور انصار دو سو چالیسں سے کچھ زیادہ تھے۔' WHERE id = 3793;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، کہ ہم سے سفیان ثوری نے بیان کیا، ان سے ابوہاشم نے، ان سے ابومجلز نے، ان سے قیس بن عباد نے اور ان سے ابوذر رضی اللہ عنہ نے بیان کیا آیت کریمہ «هذان خصمان اختصموا في ربهم‏» ”یہ دو فریق ہیں جنہوں نے اللہ کے بارے میں مقابلہ کیا“ قریش کے چھ شخصوں کے بارے میں نازل ہوئی تھی ( تین مسلمانوں کی طرف کے یعنی علی، حمزہ اور عبیدہ بن حارث رضی اللہ عنہم اور ( تین کفار کی طرف کے یعنی ) شیبہ بن ربیعہ، عتبہ بن ربیعہ اور ولید بن عتبہ۔' WHERE id = 3804;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا، کہا انہوں نے روح بن عبادہ سے سنا، کہا ہم سے سعید بن ابی عروبہ نے بیان کیا، ان سے قتادہ نے بیان کیا کہ انس بن مالک رضی اللہ عنہ نے کہا، ہم سے ابوطلحہ رضی اللہ عنہ نے بیان کیا کہ بدر کی لڑائی میں رسول اللہ صلی اللہ علیہ وسلم کے حکم سے قریش کے چوبیس مقتول سردار بدر کے ایک بہت ہی اندھیرے اور گندے کنویں میں پھینک دئیے گئے۔ عادت مبارکہ تھی کہ جب دشمن پر غالب ہوتے تو میدان جنگ میں تین دن تک قیام فرماتے جنگ بدر کے خاتمہ کے تیسرے دن آپ کے حکم سے آپ کی سوای پر کجاوہ باندھا گیا اور آپ روانہ ہوئے آپ کے اصحاب بھی آپ کے ساتھ تھے صحابہ نے کہا، غالباً آپ کسی ضرورت کے لیے تشریف لے جا رہے ہیں آخر آپ اس کنویں کے کنارے آ کر کھڑے ہو گئے اور کفار قریش کے مقتولین سرداروں کے نام ان کے باپ کے نام کے ساتھ لے کر آپ انہیں آواز دینے لگے کہ اے فلاں بن فلاں! اے فلاں بن فلاں! کیا آج تمہارے لیے یہ بات بہتر نہیں تھی کہ تم نے دنیا میں اللہ اور اس کے رسول کی اطاعت کی ہوتی؟ بیشک ہم سے ہمارے رب نے جو وعدہ کیا تھا وہ ہمیں پوری طرح حاصل ہو گیا تو کیا تمہارے رب کا تمہارے متعلق جو وعدہ ( عذاب کا ) تھا وہ بھی تمہیں پوری طرح مل گیا؟ ابوطلحہ رضی اللہ عنہ نے بیان کیا کہ اس پر عمر رضی اللہ عنہ بول پڑے: یا رسول اللہ! آپ ان لاشوں سے کیوں خطاب فرما رہے ہیں؟ جن میں کوئی جان نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اس ذات کی قسم جس کے ہاتھ میں میری جان ہے، جو کچھ میں کہہ رہا ہوں تم لوگ ان سے زیادہ اسے نہیں سن رہے ہو۔“ قتادہ نے بیان کیا کہ اللہ تعالیٰ نے انہیں زندہ کر دیا تھا ( اس وقت ) تاکہ نبی کریم صلی اللہ علیہ وسلم انہیں اپنی بات سنا دیں ان کی توبیخ ‘ ذلت ‘ نامرادی اور حسرت و ندامت کے لیے۔' WHERE id = 3814;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، ہم سے لیث نے بیان کیا، ان سے یحییٰ نے ان سے نافع نے کہ ابن عمر رضی اللہ عنہما نے جمعہ کے دن ذکر کیا کہ سعید بن زید بن عمرو بن نفیل رضی اللہ عنہما جو بدری صحابی تھے، بیمار ہیں۔ دن چڑھ چکا تھا، ابن عمر رضی اللہ عنہما سوار ہو کر ان کے پاس تشریف لے گئے۔ اتنے میں جمعہ کا وقت قریب ہو گیا اور وہ جمعہ کی نماز ( مجبوراً ) نہ پڑھ سکے۔' WHERE id = 3826;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، انہیں ابن شہاب زہری نے خبر دی، انہیں عروہ بن زبیر رضی اللہ عنہما نے، انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے کہ ابوحذیفہ رضی اللہ عنہ جو رسول اللہ صلی اللہ علیہ وسلم کے ساتھ بدر کی لڑائی میں شریک ہونے والوں میں تھے، نے سالم رضی اللہ عنہ کو اپنا منہ بولا بیٹا بنایا تھا اور اپنی بھتیجی ہند بنت ولید بن عتبہ سے شادی کرا دی تھی۔ سالم رضی اللہ عنہ ایک انصاری خاتون کے غلام تھے۔ جیسے نبی کریم صلی اللہ علیہ وسلم نے زید بن حارثہ رضی اللہ عنہ کو اپنا منہ بولا بیٹا بنا لیا تھا۔ جاہلیت میں یہ دستور تھا کہ اگر کوئی شخص کسی کو اپنا منہ بولا بیٹا بنا لیتا تو لوگ اسی کی طرف اسے منسوب کر کے پکارتے اور منہ بولا بیٹا اس کی میراث کا بھی وارث ہوتا۔ یہاں تک کہ اللہ تعالیٰ نے یہ آیت نازل کی «ادعوهم لآبائهم‏» ”انہیں ان کے باپوں کی طرف منسوب کر کے پکارو۔“ تو سہلہ رضی اللہ عنہا نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں۔ پھر تفصیل سے راوی نے حدیث بیان کی۔' WHERE id = 3836;
UPDATE hadiths SET urdu = 'ہم سے احمد نے بیان کیا جو صالح کے بیٹے ہیں، کہا ہم سے عنبسہ ابن خالد نے بیان کیا، ان سے یونس بن یزید نے بیان کیا اور ان سے ابن شہاب نے بیان کیا کہ پھر میں نے حصین بن محمد انصاری سے جو بنی سالم کے شریف لوگوں میں سے تھے، محمود بن ربیع کی حدیث کے متعلق پوچھا جس کی روایت انہوں نے عتبان بن مالک رضی اللہ عنہ سے کی تھی تو انہوں نے بھی اس کی تصدیق کی۔' WHERE id = 3846;
UPDATE hadiths SET urdu = 'اور لیث نے یحییٰ بن سعید انصاری سے بیان کیا، انہوں نے کہا کہ ہم سے سعید بن مسیب نے بیان کیا کہ پہلا فساد جب برپا ہوا یعنی عثمان رضی اللہ عنہ کی شہادت کا تو اس نے اصحاب بدر میں سے کسی کو باقی نہیں چھوڑا۔ پھر جب دوسرا فساد برپا ہوا یعنی حرہ کا، تو اس نے اصحاب حدیبیہ میں سے کسی کو باقی نہیں چھوڑا۔ پھر تیسرا فساد برپا ہوا تو وہ اس وقت تک نہیں گیا جب تک لوگوں میں کچھ بھی خوبی یا عقل باقی تھی۔' WHERE id = 3858;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن نصر نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن آدم نے بیان کیا، ان سے یحییٰ بن ابی زائدہ نے، انہوں نے اپنے والد زکریا بن ابی زائدہ سے، ان سے ابواسحاق سبیعی نے بیان کیا، ان سے براء بن عازب رضی اللہ عنہما نے بیان کیا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے چند آدمیوں کو ابورافع کے پاس بھیجا ( منجملہ ان کے ) عبداللہ بن عتیک رات کو اس گھر میں گھسے، وہ سو رہا تھا۔ اسے قتل کیا۔' WHERE id = 3870;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہیں خارجہ بن زید بن ثابت نے خبر دی انہوں نے زید بن ثابت رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ جب ہم قرآن مجید کو لکھنے لگے تو مجھے سورۃ الاحزاب کی ایک آیت ( لکھی ہوئی ) نہیں ملی۔ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اس کی تلاوت کرتے بارہا سنا تھا۔ پھر جب ہم نے اس کی تلاش کی تو وہ آیت خزیمہ بن ثابت انصاری رضی اللہ عنہ کے پاس ہمیں ملی ( آیت یہ تھی ) «من المؤمنين رجال صدقوا ما عاهدوا الله عليه فمنهم من قضى نحبه ومنهم من ينتظر» پھر ہم نے اس آیت کو اس کی سورت میں قرآن مجید میں ملا دیا۔' WHERE id = 3880;
UPDATE hadiths SET urdu = 'ہم سے بسرہ بن صفوان نے بیان کیا، کہا ہم سے ابراہیم نے بیان کیا، ان سے ان کے والد نے، ان سے عبداللہ بن شداد نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ سعد بن مالک کے سوا میں نے اور کسی کے لیے نبی کریم صلی اللہ علیہ وسلم کو اپنے والدین کا ایک ساتھ ذکر کرتے نہیں سنا، میں نے خود سنا کہ احد کے دن آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ سعد! خوب تیر برساؤ۔ میرے ماں باپ تم پر قربان ہوں۔' WHERE id = 3890;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا کہ ثعلبہ بن ابی مالک نے بیان کیا کہ عمر بن خطاب رضی اللہ عنہ نے مدینہ کی خواتین میں چادریں تقسیم کروائیں۔ ایک عمدہ قسم کی چادر باقی بچ گئی تو ایک صاحب نے جو وہیں موجود تھے، عرض کیا: یا امیرالمؤمنین! یہ چادر رسول اللہ صلی اللہ علیہ وسلم کی نواسی کو دے دیجئیے جو آپ کے نکاح میں ہیں۔ ان کا اشارہ ام کلثوم بنت علی رضی اللہ عنہا کی طرف تھا۔ لیکن عمر رضی اللہ عنہ بولے کہ ام سلیط رضی اللہ عنہا ان سے زیادہ مستحق ہیں۔ ام سلیط رضی اللہ عنہا کا تعلق قبیلہ انصار سے تھا اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے بیعت کی تھی۔ عمر رضی اللہ عنہ نے کہا کہ غزوہ احد میں وہ ہمارے لیے پانی کی مشک بھربھر کر لاتی تھیں۔' WHERE id = 3901;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے شقیق نے اور ان سے خباب رضی اللہ عنہ نے بیان کیا کہ ہم نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ ہجرت کی اور ہمارا مقصد اس سے صرف اللہ تعالیٰ کی رضا مندی حاصل کرنا تھا۔ ضروری تھا کہ اللہ تعالیٰ ہمیں اس پر ثواب دیتا۔ ہم میں سے بعض لوگ تو وہ تھے جو اللہ سے جا ملے اور ( دنیا میں ) انہوں نے اپنا کوئی ثواب نہیں دیکھا۔ مصعب بن عمیر رضی اللہ عنہ بھی انہیں میں سے تھے۔ غزوہ احد میں انہوں نے شہادت پائی اور ایک چادر کے سوا اور کوئی چیز انہوں نے نہیں چھوڑی۔ اس چادر سے ( کفن دیتے وقت ) جب ہم ان کا سر چھپاتے تو پاؤں کھل جاتے اور پاؤں چھپاتے تو سر کھل جاتا تھا۔ آپ صلی اللہ علیہ وسلم نے ہم سے فرمایا ” «غطوا بها رأسه،‏‏‏‏ واجعلوا على رجليه الإذخر» چادر سے سر چھپا دو اور پاؤں پر اذخر گھاس رکھ دو۔“ یا آپ صلی اللہ علیہ وسلم نے یوں فرمایا ” «ألقوا على رجليه من الإذخر» یعنی ان کے پیروں پر اذخر گھاس ڈال دو۔“ ( دونوں جملوں کا مطلب ایک ہی ہے ) اور ہم میں بعض وہ ہیں جنہیں ان کے اس عمل کا پھل ( اسی دنیا میں ) دے دیا گیا اور وہ اس سے خوب فائدہ اٹھا رہے ہیں۔' WHERE id = 3911;
UPDATE hadiths SET urdu = 'مجھ سے حبان نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، ان کو معمر نے خبر دی، انہوں نے کہا کہ مجھ سے ثمامہ بن عبداللہ بن انس نے بیان کیا اور انہوں نے انس بن مالک رضی اللہ عنہ سے سنا وہ بیان کرتے تھے کہ جب حرام بن ملحان کو جو ان کے ماموں تھے بئرمعونہ کے موقع پر زخمی کیا گیا تو زخم پر سے خون کو ہاتھ میں لے کر انہوں نے اپنے چہرہ اور سر پر لگا لیا اور کہا کعبہ کے رب کی قسم! میری مراد حاصل ہو گئی۔' WHERE id = 3921;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن علی فلاس نے بیان کیا، کہا ہم سے ابوعاصم ضحاک بن مخلد نے بیان کیا، کہا ہم کو حنظلہ بن ابی سفیان نے خبر دی، کہا ہم کو سعید بن میناء نے خبر دی، کہا میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ جب خندق کھودی جا رہی تھی تو میں نے معلوم کیا کہ نبی کریم صلی اللہ علیہ وسلم انتہائی بھوک میں مبتلا ہیں۔ میں فوراً اپنی بیوی کے پاس آیا اور کہا کیا تمہارے پاس کوئی کھانے کی چیز ہے؟ میرا خیال ہے کہ نبی کریم صلی اللہ علیہ وسلم انتہائی بھوکے ہیں۔ میری بیوی ایک تھیلا نکال کر لائیں جس میں ایک صاع جَو تھے۔ گھر میں ہمارا ایک بکری کا بچہ بھی بندھا ہوا تھا۔ میں نے بکری کے بچے کو ذبح کیا اور میری بیوی نے جَو کو چکی میں پیسا۔ جب میں ذبح سے فارغ ہوا تو وہ بھی جَو پیس چکی تھیں۔ میں نے گوشت کی بوٹیاں کر کے ہانڈی میں رکھ دیا اور نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ میری بیوی نے پہلے ہی تنبیہ کر دی تھی کہ نبی کریم صلی اللہ علیہ وسلم اور آپ کے صحابہ کے سامنے مجھے شرمندہ نہ کرنا۔ چنانچہ میں نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر آپ کے کان میں یہ عرض کیا کہ یا رسول اللہ! ہم نے ایک چھوٹا سا بچہ ذبح کر لیا ہے اور ایک صاع جَو پیس لیے ہیں جو ہمارے پاس تھے۔ اس لیے آپ دو ایک صحابہ کو ساتھ لے کر تشریف لے چلیں۔ آپ صلی اللہ علیہ وسلم نے بہت بلند آواز سے فرمایا کہ اے اہل خندق! جابر ( رضی اللہ عنہ ) نے تمہارے لیے کھانا تیار کروایا ہے۔ بس اب سارا کام چھوڑ دو اور جلدی چلے چلو۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب تک میں آ نہ جاؤں ہانڈی چولھے پر سے نہ اتارنا اور تب آٹے کی روٹی پکانی شروع کرنا۔ میں اپنے گھر آیا۔ ادھر آپ صلی اللہ علیہ وسلم بھی صحابہ کو ساتھ لے کر روانہ ہوئے۔ میں اپنی بیوی کے پاس آیا تو وہ مجھے برا بھلا کہنے لگیں۔ میں نے کہا کہ تم نے جو کچھ مجھ سے کہا تھا میں نے نبی کریم صلی اللہ علیہ وسلم کے سامنے عرض کر دیا تھا۔ آخر میری بیوی نے گندھا ہوا آٹا نکالا اور آپ صلی اللہ علیہ وسلم نے اس میں اپنے لعاب دہن کی آمیزش کر دی اور برکت کی دعا کی۔ ہانڈی میں بھی آپ نے لعاب کی آمیزش کی اور برکت کی دعا کی۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ اب روٹی پکانے والی کو بلاؤ۔ وہ میرے سامنے روٹی پکائے اور گوشت ہانڈی سے نکالے لیکن چولھے سے ہانڈی نہ اتارنا۔ صحابہ کی تعداد ہزار کے قریب تھی۔ میں اللہ تعالیٰ کی قسم کھاتا ہوں کہ اتنے ہی کھانے کو سب نے ( شکم سیر ہو کر ) کھایا اور کھانا بچ بھی گیا۔ جب تمام لوگ واپس ہو گئے تو ہماری ہانڈی اسی طرح ابل رہی تھی جس طرح شروع میں تھی اور آٹے کی روٹیاں برابر پکائی جا رہی تھیں۔' WHERE id = 3931;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا ‘ کہا ہم سے ہشام بن حسان نے بیان کیا ‘ ان سے یحییٰ بن ابی کثیر نے ‘ ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے جابر رضی اللہ عنہ نے کہ عمر بن خطاب رضی اللہ عنہ غزوہ خندق کے موقع پر سورج غروب ہونے کے بعد ( لڑ کر ) واپس ہوئے۔ وہ کفار قریش کو برا بھلا کہہ رہے تھے۔ انہوں نے عرض کیا: یا رسول اللہ! سورج غروب ہونے کو ہے اور میں عصر کی نماز اب تک نہیں پڑھ سکا۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کی قسم! نماز تو میں بھی نہ پڑھ سکا۔ آخر ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ وادی بطحان میں اترے۔ آپ صلی اللہ علیہ وسلم نے نماز کے لیے وضو کیا۔ ہم نے بھی وضو کیا ‘ پھر عصر کی نماز سورج غروب ہونے کے بعد پڑھی اور اس کے بعد مغرب کی نماز پڑھی۔' WHERE id = 3941;
UPDATE hadiths SET urdu = 'ہم سے زکریا بن یحییٰ نے بیان کیا ‘ کہا ہم سے عبداللہ بن نمیر نے بیان کیا ‘ ان سے ہشام بن عروہ نے بیان کیا ‘ ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ غزوہ خندق کے موقع پر سعد رضی اللہ عنہ زخمی ہو گئے تھے۔ قریش کے ایک کافر شخص ‘ حسان بن عرفہ نامی نے ان پر تیر چلایا تھا اور وہ ان کے بازو کی رگ میں آ کے لگا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے مسجد میں ایک خیمہ لگا دیا تھا تاکہ قریب سے ان کی عیادت کرتے رہیں۔ پھر جب آپ غزوہ خندق سے واپس ہوئے اور ہتھیار رکھ کر غسل کیا تو جبرائیل علیہ السلام آپ کے پاس آئے۔ وہ اپنے سر سے غبار جھاڑ رہے تھے۔ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہا آپ نے ہتھیار رکھ دیئے۔ اللہ کی قسم! ابھی میں نے ہتھیار نہیں اتارے ہیں۔ آپ کو ان پر فوج کشی کرنی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کن پر؟ تو انہوں نے بنو قریظہ کی طرف اشارہ کیا۔ آپ صلی اللہ علیہ وسلم بنو قریظہ تک پہنچے ( اور انہوں نے اسلامی لشکر کے پندرہ دن کے سخت محاصرہ کے بعد ) سعد بن معاذ رضی اللہ عنہ کو ثالث مان کر ہتھیار ڈال دیئے۔ آپ صلی اللہ علیہ وسلم نے سعد رضی اللہ عنہ کو فیصلہ کا اختیار دیا۔ سعد رضی اللہ عنہ نے کہا کہ میں ان کے بارے میں فیصلہ کرتا ہوں کہ جتنے لوگ ان کے جنگ کرنے کے قابل ہیں وہ قتل کر دیئے جائیں ‘ ان کی عورتیں اور بچے قید کر لیے جائیں اور ان کا مال تقسیم کر لیا جائے۔ ہشام نے بیان کیا کہ پھر مجھے میرے والد نے عائشہ رضی اللہ عنہا سے خبر دی کہ سعد رضی اللہ عنہ نے یہ دعا کی تھی ”اے اللہ! تو خوب جانتا ہے کہ اس سے زیادہ مجھے کوئی چیز عزیز نہیں کہ میں تیرے راستے میں اس قوم سے جہاد کروں جس نے تیرے رسول کو جھٹلایا اور انہیں ان کے وطن سے نکالا لیکن اب ایسا معلوم ہوتا ہے کہ تو نے ہماری اور ان کی لڑائی اب ختم کر دی ہے۔ لیکن اگر قریش سے ہماری لڑائی کا کوئی بھی سلسلہ ابھی باقی ہو تو مجھے اس کے لیے زندہ رکھنا۔ یہاں تک کہ میں تیرے راستے میں ان سے جہاد کروں اور اگر لڑائی کے سلسلے کو تو نے ختم ہی کر دیا ہے تو میرے زخموں کو پھر سے ہرا کر دے اور اسی میں میری موت واقع کر دے۔ اس دعا کے بعد سینے پر ان کا زخم پھر سے تازہ ہو گیا۔ مسجد میں قبیلہ بنو غفار کے کچھ صحابہ کا بھی ایک خیمہ تھا۔ خون ان کی طرف بہہ کر آیا تو وہ گھبرائے اور انہوں نے کہا: اے خیمہ والو! تمہاری طرف سے یہ خون ہماری طرف بہہ کر آ رہا ہے؟ دیکھا تو سعد رضی اللہ عنہ کے زخم سے خون بہہ رہا تھا ‘ ان کی وفات اسی میں ہوئی۔' WHERE id = 3951;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم کو شعیب نے خبر دی ‘ ان سے زہری نے بیان کیا ‘ کہا کہ مجھے سالم نے خبر دی اور ان سے ابن عمر رضی اللہ عنہما نے کہ میں نجد کی طرف نبی کریم صلی اللہ علیہ وسلم کے ساتھ غزوہ کے لیے گیا تھا۔ وہاں ہم دشمن کے آمنے سامنے ہوئے اور ان کے مقابلے میں صف بندی کی۔' WHERE id = 3961;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا کہ ہشام بن یوسف نے اپنی یاد سے مجھے حدیث لکھوائی۔ انہوں نے بیان کیا کہ ہمیں معمر نے خبر دی ‘ ان سے زہری نے بیان کیا ‘ کہا کہ مجھ سے خلیفہ ولید بن عبدالملک نے پوچھا ‘ کیا تم کو معلوم ہے کہ علی رضی اللہ عنہ بھی عائشہ رضی اللہ عنہا پر تہمت لگانے والوں میں تھے؟ میں نے کہا کہ نہیں ‘ البتہ تمہاری قوم ( قریش ) کے دو آدمیوں ابوسلمہ بن عبدالرحمٰن اور ابوبکر بن عبدالرحمٰن بن حارث نے مجھے خبر دی کہ عائشہ رضی اللہ عنہا نے ان سے کہا کہ علی رضی اللہ عنہ ان کے معاملے میں خاموش تھے۔ پھر لوگوں نے ہشام بن یوسف ( یا زہری ) سے دوبارہ پوچھا۔ انہوں نے یہی کہا «مسلما» اس میں شک نہ کیا «مسيئا» کا لفظ نہیں کہا اور «عليه» کا لفظ زیاوہ کیا ( یعنی زہری نے ولید کو اور کچھ جواب نہیں دیا اور پرانے نسخہ میں «مسلما» کا لفظ تھا ) ۔' WHERE id = 3971;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن عیسیٰ نے بیان کیا ‘ کہا ہم سے محمد بن فضیل نے ‘ کہا ہم سے حصین بن عبدالرحمٰن نے ‘ ان سے سالم بن ابی الجعد نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ غزوہ حدیبیہ کے موقع پر سارا ہی لشکر پیاسا ہو چکا تھا۔ رسول اللہ صلی اللہ علیہ وسلم کے سامنے ایک چھاگل تھا ‘ اس کے پانی سے آپ نے وضو کیا۔ پھر صحابہ آپ کی خدمت میں حاضر ہوئے تو آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا بات ہے؟ صحابہ بولے کہ یا رسول اللہ! ہمارے پاس اب پانی نہیں رہا ‘ نہ وضو کرنے کے لیے اور نہ پینے کے لیے۔ سوا اس پانی کے جو آپ کے برتن میں موجود ہے۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے اپنا ہاتھ اس برتن میں رکھا اور پانی آپ کی انگلیوں کے درمیان سے چشمے کی طرح پھوٹ پھوٹ کر ابلنے لگا۔ راوی نے بیان کیا کہ پھر ہم نے پانی پیا بھی اور وضو بھی کیا۔ ( سالم کہتے ہیں کہ ) میں نے جابر رضی اللہ عنہ سے پوچھا کہ آپ لوگ کتنی تعداد میں تھے؟ انہوں نے بتلایا کہ اگر ہم ایک لاکھ بھی ہوتے تو بھی وہ پانی کافی ہو جاتا۔ ویسے اس وقت ہماری تعداد پندرہ سو تھی۔' WHERE id = 3981;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے عمرو بن مرہ نے ‘ انہوں نے کہا کہ میں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے سنا ‘ وہ بیعت رضوان میں شریک تھے۔ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں جب کوئی صدقہ لے کر حاضر ہوتا تو آپ دعا کرتے کہ اے اللہ! اس پر اپنی رحمت نازل فرما۔ چنانچہ میرے والد بھی اپنا صدقہ لے کر حاضر ہوئے تو آپ صلی اللہ علیہ وسلم نے دعا کی کہ اے اللہ! آل ابی اوفی رضی اللہ عنہ پر اپنی رحمت نازل فرما۔' WHERE id = 3993;
UPDATE hadiths SET urdu = 'ہم سے محمد بن حاتم بن زریع نے بیان کیا ‘ کہا ہم سے شاذان (اسود بن عامر) نے ‘ ان سے شعبہ نے ‘ ان سے ابوحمزہ نے بیان کیا کہ انہوں نے عائذ بن عمرو رضی اللہ عنہ سے پوچھا: وہ نبی کریم صلی اللہ علیہ وسلم کے صحابی تھے اور بیعت رضوان میں شریک تھے کہ کیا وتر کی نماز ( ایک رکعت اور پڑھ کر ) توڑی جا سکتی ہے؟ انہوں نے کہا کہ اگر شروع رات میں تو نے وتر پڑھ لیا ہو تو آخر رات میں نہ پڑھو۔' WHERE id = 4003;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ‘ ان سے ایوب سختیانی نے ‘ ان سے مجاہد نے ‘ ان سے ابن ابی لیلیٰ نے ‘ ان سے کعب بن عجرہ رضی اللہ عنہ نے بیان کیا کہ وہ عمرہ حدیبیہ کے موقع پر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو جوئیں ان کے چہرے پر گر رہی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ یہ جوئیں جو تمہارے سر سے گر رہی ہیں ‘ تکلیف دے رہی ہیں؟ انہوں نے عرض کیا: جی ہاں! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر سر منڈوا لو اور تین دن روزہ رکھ لو یا چھ مسکینوں کا کھانا کھلا دو یا پھر کوئی قربانی کر ڈالو۔ ( سر منڈوانے کا فدیہ ہو گا ) ایوب سختیانی نے بیان کیا کہ مجھے معلوم نہیں کہ ان تینوں امور میں سے پہلے نبی کریم صلی اللہ علیہ وسلم نے کون سی بات ارشاد فرمائی تھی۔' WHERE id = 4015;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ‘ ان سے ثابت نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے صبح کی نماز خیبر کے قریب پہنچ کر ادا کی ‘ ابھی اندھیرا تھا پھر فرمایا ‘ اللہ کی ذات سب سے بلند و برتر ہے۔ خیبر برباد ہوا ‘ یقیناً جب ہم کسی قوم کے میدان میں اتر جاتے ہیں تو ڈرائے لوگوں کی صبح بری ہو جاتی ہے۔ پھر یہودی گلیوں میں ڈرتے ہوئے نکلے۔ آخر نبی کریم صلی اللہ علیہ وسلم نے ان کے جنگ کرنے والے لوگوں کو قتل کرا دیا اور عورتوں اور بچوں کو قید کر لیا۔ قیدیوں میں ام المؤمنین صفیہ رضی اللہ عنہا بھی تھیں جو دحیہ کلبی رضی اللہ عنہ کے حصہ میں آئی تھیں۔ پھر وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آ گئیں۔ چنانچہ آپ نے ان سے نکاح کر لیا اور مہر میں انہیں آزاد کر دیا۔ عبدالعزیز بن صہیب نے ثابت سے پوچھا: ابو محمد! کیا تم نے یہ پوچھا تھا کہ نبی کریم صلی اللہ علیہ وسلم نے صفیہ رضی اللہ عنہا کو مہر کیا دیا تھا؟ ثابت رضی اللہ عنہ نے اثبات میں سر ہلایا۔' WHERE id = 4025;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ انہوں نے کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا ‘ ان سے ابوحازم نے بیان کیا ‘ انہوں نے کہا کہ مجھے سہل بن سعد رضی اللہ عنہ نے خبر دی کہ غزوہ خیبر میں رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ کل میں جھنڈا ایک ایسے شخص کو دوں گا جس کے ہاتھوں پر اللہ تعالیٰ فتح عطا فرمائے گا اور جو اللہ اور اس کے رسول سے محبت رکھتا ہے اور اللہ اور اس کے رسول بھی اسے عزیز رکھتے ہیں۔ راوی نے بیان کیا کہ وہ رات سب کی اس فکر میں گزر گئی کہ دیکھیں ‘ نبی کریم صلی اللہ علیہ وسلم عَلم کسے عطا فرماتے ہیں۔ صبح ہوئی تو سب خدمت نبوی میں حاضر ہوئے اور اس امید کے ساتھ کہ عَلم انہیں کو ملے لیکن نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ علی بن ابی طالب کہاں ہیں؟ عرض کیا گیا کہ یا رسول اللہ! وہ تو آنکھوں کی تکلیف میں مبتلا ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں بلا لاؤ۔ جب وہ لائے گئے تو آپ صلی اللہ علیہ وسلم نے اپنا تھوک ان کی آنکھوں میں لگایا اور ان کے لیے دعا کی۔ اس دعا کی برکت سے ان کی آنکھیں اتنی اچھی ہو گئیں جیسے پہلے کوئی بیماری ہی نہیں تھی۔ علی رضی اللہ عنہ نے عَلم سنبھال کر عرض کیا: یا رسول اللہ! میں ان سے اس وقت تک جنگ کروں گا جب تک وہ ہمارے ہی جیسے نہ ہو جائیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یوں ہی چلتے رہو ‘ ان کے میدان میں اتر کر پہلے انہیں اسلام کی دعوت دو اور بتاؤ کہ اللہ کا ان پر کیا حق ہے۔ اللہ کی قسم! اگر تمہارے ذریعہ ایک شخص کو بھی ہدایت مل جائے تو یہ تمہارے لیے سرخ اونٹوں سے بہتر ہے۔' WHERE id = 4035;
UPDATE hadiths SET urdu = 'ہم سے سعید بن سلیمان نے بیان کیا ‘ کہا ہم سے عباد نے بیان کیا ‘ ان سے شیبانی نے بیان کیا اور انہوں نے ابن ابی اوفی رضی اللہ عنہما سے سنا کہ غزوہ خیبر میں ایک موقع پر ہم بہت بھوکے تھے ‘ ادھر ہانڈیوں میں ابال آ رہا تھا ( گدھے کا گوشت پکایا جا رہا تھا ) اور کچھ پک بھی گئیں تھیں کہ نبی کریم صلی اللہ علیہ وسلم کے منادی نے اعلان کیا کہ گدھے کے گوشت کا ایک ذرہ بھی نہ کھاؤ اور اسے پھینک دو۔ ابن ابی اوفی رضی اللہ عنہما نے بیان کیا کہ پھر بعض لوگوں نے کہا کہ آپ صلی اللہ علیہ وسلم نے اس کی ممانعت اس لیے کی ہے کہ ابھی اس میں سے خمس نہیں نکالا گیا تھا اور بعض لوگوں کا خیال تھا کہ آپ نے اس کی واقعی ممانعت ( ہمیشہ کے لیے ) کر دی ہے ‘ کیونکہ یہ گندگی کھاتا ہے۔' WHERE id = 4045;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا ‘ انہوں نے کہا ہم سے معاویہ بن عمرو نے بیان کیا ‘ انہوں نے کہا ہم سے ابواسحاق نے بیان کیا ‘ ان سے امام مالک بن انس نے بیان کیا ‘ ان سے ثور نے بیان کیا ‘ انہوں نے کہا کہ مجھ سے ابن مطیع کے مولیٰ سالم نے بیان کیا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ جب خیبر فتح ہوا تو مال غنیمت میں سونا اور چاندی نہیں ملا تھا بلکہ گائے ‘ اونٹ ‘ سامان اور باغات ملے تھے پھر ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ وادی القریٰ کی طرف لوٹے۔ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک مدعم نامی غلام تھا جو بنی ضباب کے ایک صحابی نے آپ کو ہدیہ میں دیا تھا۔ وہ نبی کریم صلی اللہ علیہ وسلم کا کجاوہ اتار رہا تھا کہ کسی نامعلوم سمت سے ایک تیر آ کر ان کے لگا۔ لوگوں نے کہا مبارک ہو: شہادت! لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہرگز نہیں ‘ اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے جو چادر اس نے خیبر میں تقسیم سے پہلے مال غنیمت میں سے چرائی تھی وہ اس پر آگ کا شعلہ بن کر بھڑک رہی ہے۔ یہ سن کر ایک دوسرے صحابی ایک یا دو تسمے لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ یہ میں نے اٹھا لیے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ بھی جہنم کا تسمہ بنتا۔' WHERE id = 4057;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے یحییٰ بن سعید نے بیان کیا ‘ کہا ہم سے سفیان ثوری نے بیان کیا ‘ ان سے عبداللہ بن دینار نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ایک جماعت کا امیر رسول اللہ صلی اللہ علیہ وسلم نے اسامہ بن زید رضی اللہ عنہما کو بنایا۔ ان کی امارت پر بعض لوگوں کو اعتراض ہوا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ آج تم کو اس کی امارت پر اعتراض ہے تم ہی کچھ دن پہلے اس کے باپ کی امارت پر اعتراض کر چکے ہو۔ حالانکہ اللہ کی قسم وہ امارت کے مستحق و اہل تھے۔ اس کے علاوہ وہ مجھے سب سے زیادہ عزیز تھے جس طرح یہ اسامہ رضی اللہ عنہ ان کے بعد مجھے سب سے زیادہ عزیز ہے۔' WHERE id = 4070;
UPDATE hadiths SET urdu = 'ہم سے احمد بن واقد نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ‘ ان سے ایوب سختیانی نے ‘ ان سے حمید بن ہلال نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے زید ‘ جعفر اور عبداللہ بن رواحہ رضی اللہ عنہم کی شہادت کی خبر اس وقت صحابہ رضی اللہ عنہم کو دے دی تھی جب ابھی ان کے متعلق کوئی خبر نہیں آئی تھی۔ آپ صلی اللہ علیہ وسلم فرماتے جا رہے تھے کہ اب زید جھنڈا اٹھائے ہوئے ہیں ‘ اب وہ شہید کر دیئے گئے ‘ اب جعفر نے جھنڈا اٹھا لیا ‘ وہ بھی شہید کر دیئے گئے۔ اب ابن رواحہ نے جھنڈا اٹھا لیا ‘ وہ بھی شہید کر دیئے گئے۔ نبی کریم صلی اللہ علیہ وسلم کی آنکھوں سے آنسو جاری تھے۔ آخر اللہ کی تلواروں میں سے ایک تلوار خالد بن ولید نے جھنڈا اپنے ہاتھ میں لے لیا اور اللہ نے ان کے ہاتھ پر فتح عنایت فرمائی۔' WHERE id = 4081;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم الضحاک بن مخلد نے بیان کیا ‘ کہا ہم سے یزید بن ابی عبید نے بیان کیا ‘ ان سے سلمہ بن اکوع رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ سات غزووں میں شریک رہا ہوں اور میں نے ابن حارثہ ( یعنی اسامہ رضی اللہ عنہ ) کے ساتھ بھی غزوہ کیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں ہم پر امیر بنایا تھا۔' WHERE id = 4091;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ انہوں نے کہا ہم سے شعیب نے بیان کیا ‘ انہوں نے کہا ہم سے ابوالزناد نے بیان کیا ‘ ان سے عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ان شاءاللہ ہماری قیام گاہ اگر اللہ تعالیٰ نے فتح عنایت فرمائی تو خیف بنی کنانہ میں ہو گی۔ جہاں قریش نے کفر کی حمایت کے لیے قسم کھائی تھی۔“' WHERE id = 4102;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا ‘ کہا ہم سے ابوعوانہ نے بیان کیا ‘ ان سے ابوبشر نے ‘ ان سے سعید بن جبیر نے ‘ ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ عمر رضی اللہ عنہ مجھے اپنی مجلس میں اس وقت بھی بلا لیتے جب وہاں بدر کی جنگ میں شریک ہونے والے بزرگ صحابہ رضی اللہ عنہم بیٹھے ہوتے۔ اس پر بعض لوگ کہنے لگے اس جوان کو آپ ہماری مجلس میں کیوں بلاتے ہیں؟ اس کے جیسے تو ہمارے بچے بھی ہیں۔ اس پر عمر رضی اللہ عنہ نے کہا وہ تو ان لوگوں میں سے ہے جن کا علم و فضل تم جانتے ہو۔ انہوں نے بیان کیا کہ پھر ان بزرگ صحابیوں کو ایک دن عمر رضی اللہ عنہ نے بلایا اور مجھے بھی بلایا۔ بیان کیا کہ میں سمجھتا تھا کہ مجھے اس دن آپ نے اس لیے بلایا تھا تاکہ آپ میرا علم بتا سکیں۔ پھر آپ نے دریافت کیا «إذا جاء نصر الله والفتح * ورأيت الناس يدخلون‏» ‘ ختم سورت تک ‘ کے متعلق تم لوگوں کا کیا خیال ہے؟ کسی نے کہا کہ ہمیں اس آیت میں حکم دیا گیا ہے کہ ہم اللہ کی حمد بیان کریں اور اس سے استغفار کریں کہ اس نے ہماری مدد کی اور ہمیں فتح عنایت فرمائی۔ بعض نے کہا کہ ہمیں اس کے متعلق کچھ معلوم نہیں ہے اور بعض نے کوئی جواب نہیں دیا پھر انہوں نے مجھ سے دریافت کیا: ابن عباس! کیا تمہارا بھی یہی خیال ہے؟ میں نے جواب دیا کہ نہیں ‘ پوچھا ‘ پھر تم کیا کہتے ہو؟ میں نے کہا کہ اس میں رسول اللہ صلی اللہ علیہ وسلم کی وفات کی طرف اشارہ ہے کہ جب اللہ تعالیٰ کی مدد اور فتح حاصل ہو گئی۔ یعنی فتح مکہ تو یہ آپ صلی اللہ علیہ وسلم کی وفات کی نشانی ہے۔ اس لیے آپ اپنے رب کی حمد اور تسبیح اور اس کی مغفرت طلب کریں کہ وہ توبہ قبول کرنے والا ہے۔ عمر رضی اللہ عنہ نے کہا کہ جو کچھ تم نے کہا وہی میں بھی سمجھتا ہوں۔' WHERE id = 4112;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا کہ ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے خبر دی، انہیں زہری نے، کہا کہ مجھے عروہ بن زبیر نے خبر دی کہ غزوہ فتح ( مکہ ) کے موقع پر ایک عورت نے نبی کریم صلی اللہ علیہ وسلم کے عہد میں چوری کر لی تھی۔ اس عورت کی قوم گھبرائی ہوئی اسامہ بن زید رضی اللہ عنہما کے پاس آئی تاکہ وہ نبی کریم صلی اللہ علیہ وسلم سے اس کی سفارش کر دیں ( کہ اس کا ہاتھ چوری کے جرم میں نہ کاٹا جائے ) ۔ عروہ نے بیان کیا کہ جب اسامہ رضی اللہ عنہ نے اس کے بارے میں نبی کریم صلی اللہ علیہ وسلم سے گفتگو کی تو آپ صلی اللہ علیہ وسلم کے چہرے کا رنگ بدل گیا اور آپ صلی اللہ علیہ وسلم نے فرمایا! تم مجھ سے اللہ کی قائم کی ہوئی ایک حد کے بارے میں سفارش کرنے آئے ہو۔ اسامہ رضی اللہ عنہ نے عرض کیا: میرے لیے دعا مغفرت کیجئے، یا رسول اللہ! پھر دوپہر بعد نبی کریم صلی اللہ علیہ وسلم نے صحابہ رضی اللہ عنہم کو خطاب کیا، اللہ تعالیٰ کی اس کے شان کے مطابق تعریف کرنے کے بعد فرمایا: امابعد! تم میں سے پہلے لوگ اس لیے ہلاک ہو گئے کہ اگر ان میں سے کوئی معزز شخص چوری کرتا تو اسے چھوڑ دیتے لیکن اگر کوئی کمزور چوری کر لیتا تو اس پر حد قائم کرتے اور اس ذات کی قسم جس کے ہاتھ میں محمد صلی اللہ علیہ وسلم کی جان ہے اگر فاطمہ بنت محمد بھی چوری کر لے تو میں اس کا ہاتھ کاٹوں گا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے اس عورت کے لیے حکم دیا اور ان کا ہاتھ کاٹ دیا گیا۔ پھر اس عورت نے صدق دل سے توبہ کر لی اور شادی بھی کر لی۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ بعد میں وہ میرے یہاں آتی تھیں۔ ان کو اور کوئی ضرورت ہوتی تو میں رسول اللہ صلی اللہ علیہ وسلم کے سامنے پیش کر دیتی۔' WHERE id = 4122;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے، ان سے نافع نے کہ عمر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! (دوسری سند) اور مجھ سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں معمر نے خبر دی، انہیں ایوب نے، انہیں نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ جب ہم غزوہ حنین سے واپس ہو رہے تھے تو عمر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے اپنی ایک نذر کے متعلق پوچھا جو انہوں نے زمانہ جاہلیت میں اعتکاف کی مانی تھی اور نبی کریم صلی اللہ علیہ وسلم نے انہیں اسے پوری کرنے کا حکم دیا اور بعض ( احمد بن عبدہ ضبی ) نے حماد سے بیان کیا، ان سے ایوب نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے۔ اور اس روایت کو جریر بن حازم اور حماد بن سلمہ نے ایوب سے بیان کیا، ان سے نافع نے، ان سے ابن عمر رضی اللہ عنہما نے، نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 4135;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابوالتیاح نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ فتح مکہ کے زمانے میں نبی کریم صلی اللہ علیہ وسلم نے قریش میں ( حنین کی ) غنیمت کی تقسیم کر دی۔ انصار رضی اللہ عنہم اس سے رنجیدہ ہوئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کیا تم اس پر راضی نہیں ہو کہ دوسرے لوگ دنیا اپنے ساتھ لے جائیں اور تم اپنے ساتھ رسول اللہ صلی اللہ علیہ وسلم کو لے جاؤ۔ انصار نے عرض کیا کہ ہم اس پر خوش ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ لوگ دوسرے کسی وادی یا گھاٹی میں رہیں تو میں انصار کی وادی یا گھاٹی میں رہوں گا۔' WHERE id = 4146;
UPDATE hadiths SET urdu = 'ہم سے عباس بن ولید نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، ان سے ایوب بن عائذ نے، ان سے قیس بن مسلم نے بیان کیا، کہا میں نے طارق بن شہاب سے سنا، انہوں نے کہا کہ مجھ سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہا کہ مجھے رسول اللہ صلی اللہ علیہ وسلم نے میری قوم کے وطن ( یمن ) میں بھیجا۔ پھر میں آیا تو نبی کریم صلی اللہ علیہ وسلم ( مکہ کی ) وادی ابطح میں پڑاؤ کئے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا: عبداللہ بن قیس! تم نے حج کا احرام باندھا لیا؟ میں نے عرض کیا: جی ہاں یا رسول اللہ! آپ نے دریافت فرمایا کہ کلمات احرام کس طرح کہے؟ بیان کیا کہ میں نے عرض کیا ( کہ یوں کلمات ادا کئے ہیں ) ”اے اللہ میں حاضر ہوں، اور جس طرح آپ صلی اللہ علیہ وسلم نے احرام باندھا ہے، میں نے بھی اسی طرح باندھا ہے۔“ فرمایا تم اپنے ساتھ قربانی کا جانور بھی لائے ہو؟ میں نے کہا کہ کوئی جانور تو میں اپنے ساتھ نہیں لایا۔ فرمایا تم پھر پہلے بیت اللہ کا طواف اور صفا اور مروہ کی سعی کر لو۔ ان رکنوں کی ادائیگی کے بعد حلال ہو جانا۔ میں نے اسی طرح کیا اور بنو قیس کی خاتون نے میرے سر میں کنگھا کیا اور اسی قاعدے پر ہم اس وقت تک چلتے رہے جب تک عمر رضی اللہ عنہ خلیفہ ہوئے ( اسی کو حج تمتع کہتے ہیں اور یہ بھی سنت ہے ) ۔' WHERE id = 4158;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن شاہین نے بیان کیا، کہا ہم کو خالد بن عبداللہ نے خبر دی، انہیں خالد حذاء نے، انہیں ابوعثمان نہدی رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے عمرو بن العاص رضی اللہ عنہ کو غزوہ ذات السلاسل کے لیے امیر لشکر بنا کر بھیجا۔ عمرو بن العاص رضی اللہ عنہ نے بیان کیا کہ ( غزوہ سے واپس آ کر ) میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ سے پوچھا کہ آپ کو سب سے زیادہ عزیز کون شخص ہے؟ فرمایا کہ عائشہ، میں نے پوچھا اور مردوں میں؟ فرمایا کہ اس کے والد، میں نے پوچھا، اس کے بعد کون؟ فرمایا کہ عمر۔ اس طرح آپ نے کئی آدمیوں کے نام لیے بس میں خاموش ہو گیا کہ کہیں آپ مجھے سب سے بعد میں نہ کر دیں۔' WHERE id = 4169;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو ابوعامر عقدی نے خبر دی، کہا ہم سے قرہ بن خالد نے بیان کیا، ان سے ابوحمزہ نے کہ میں نے ابن عباس رضی اللہ عنہما سے پوچھا کہ میرے پاس ایک گھڑا ہے جس میں میرے لیے نبیذ یعنی کھجور کا شربت بنایا جاتا ہے۔ میں وہ میٹھے رہنے تک پیا کرتا ہوں۔ بعض وقت بہت پی لیتا ہوں اور لوگوں کے پاس دیر تک بیٹھا رہتا ہوں تو ڈرتا ہوں کہ کہیں فضیحت نہ ہو۔ ( لوگ کہنے لگیں کہ یہ نشہ باز ہے ) اس پر ابن عباس رضی اللہ عنہما نے کہا کہ قبیلہ عبدالقیس کا وفد نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھے آئے نہ ذلیل ہوئے، نہ شرمندہ ( خوشی سے مسلمان ہو گئے نہ ہوتے تو ذلت اور شرمندگی حاصل ہوتی ) انہوں نے عرض کیا: یا رسول اللہ! ہمارے اور آپ کے درمیان میں مشرکین کے قبائل پڑتے ہیں۔ اس لیے ہم آپ کی خدمت میں صرف حرمت والے مہینے ہی میں حاضر ہو سکتے ہیں۔ آپ صلی اللہ علیہ وسلم ہمیں وہ احکام و ہدایات سنا دیں کہ اگر ہم ان پر عمل کرتے رہیں تو جنت میں داخل ہوں اور جو لوگ ہمارے ساتھ نہیں آ سکے ہیں انہیں بھی وہ ہدایات پہنچا دیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہیں چار چیزوں کا حکم دیتا ہوں اور چار چیزوں سے روکتا ہوں۔ میں تمہیں حکم دیتا ہوں اللہ پر ایمان لانے کا، تمہیں معلوم ہے اللہ پر ایمان لانا کسے کہتے ہیں؟ اس کی گواہی دینا کہ اللہ کے سوا کوئی معبود نہیں، نماز قائم کرنے کا، زکٰوۃ دینے کا، رمضان کے روزے رکھنے اور مال غنیمت میں سے پانچواں حصہ ( بیت المال کو ) ادا کرنے کا حکم دیتا ہوں اور میں تمہیں چار چیزوں سے روکتا ہوں یعنی کدو کے تونبے میں اور کریدی ہوئی لکڑی کے برتن میں اور سبز لاکھی برتن میں اور روغنی برتن میں نبیذ بھگونے سے منع کرتا ہوں۔' WHERE id = 4179;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے خالد نے، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہر امت میں امین ( امانتدار ) ہوتے ہیں اور اس امت کے امین ابوعبیدہ بن الجراح ہیں۔“' WHERE id = 4190;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عبداللہ بن ذکوان نے بیان کیا، ان سے عبدالرحمٰن اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ طفیل بن عمرو رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ قبیلہ دوس تو تباہ ہوا۔ اس نے نافرمانی اور انکار کیا ( اسلام قبول نہیں کیا ) آپ اللہ سے ان کے لیے دعا کیجئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے اللہ! قبیلہ دوس کو ہدایت دے اور انہیں میرے یہاں لے آ۔“' WHERE id = 4200;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا، کہا ہم سے زہیر بن معاویہ نے بیان کیا، کہا ہم سے ابواسحاق سبیعی نے بیان کیا، کہا کہ مجھ سے زید بن ارقم رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے انیس غزوے کئے اور ہجرت کے بعد صرف ایک حج کیا۔ اس حج کے بعد پھر آپ صلی اللہ علیہ وسلم نے کوئی حج نہیں کیا۔ یہ حج، حجۃ الوداع تھا۔ ابواسحاق نے بیان کیا کہ دوسرا حج آپ صلی اللہ علیہ وسلم نے ( ہجرت سے پہلے ) مکہ میں کیا تھا۔' WHERE id = 4211;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے یحییٰ بن سعید نے، ان سے عدی بن ثابت نے اور ان سے عبداللہ بن یزید خطمی نے اور انہیں ابوایوب رضی اللہ عنہ نے خبر دی کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ حجۃ الوداع کے موقع پر مغرب اور عشاء ملا کر ایک ساتھ پڑھی تھیں۔' WHERE id = 4221;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن رباح نے بیان کیا، انہوں نے کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، ان سے ان کے والد (ابراہیم بن سعد) نے بیان کیا، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے بیان کیا، انہیں عبیداللہ بن عبداللہ نے خبر دی اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے ( شاہ فارس ) کسریٰ کے پاس اپنا خط عبداللہ بن حذافہ سہمی رضی اللہ عنہ کو دے کر بھیجا اور انہیں حکم دیا کہ یہ خط بحرین کے گورنر کو دے دیں ( جو کسریٰ کا عالم تھا ) کسریٰ نے جب آپ کا خط مبارک پڑھا تو اس کے ٹکڑے ٹکڑے کر دئیے۔ میرا خیال ہے کہ ابن مسیب نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے ان کے لیے بددعا کی کہ وہ بھی ٹکڑے ٹکڑے ہو جائیں۔' WHERE id = 4231;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے شعبہ نے، ان سے سعد بن ابراہیم نے، ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اپنے مرض الموت میں باربار فرماتے تھے۔ ” ( «اللهم» ) «الرفيق الأعلى» اے اللہ! مجھے میرے رفقاء ( انبیاء اور صدیقین ) میں پہنچا دے ( جو اعلیٰ علیین میں رہتے ہیں ) ۔“' WHERE id = 4242;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، انہوں نے کہا کہ مجھ سے لیث نے بیان کیا، انہوں نے کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہوں نے کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ پیر کے دن مسلمان فجر کی نماز پڑھ رہے تھے اور ابوبکر رضی اللہ عنہ نماز پڑھا رہے تھے کہ اچانک نبی کریم صلی اللہ علیہ وسلم نظر آئے۔ آپ ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا کے حجرہ کا پردہ اٹھا کر صحابہ رضی اللہ عنہم کو دیکھ رہے تھے۔ صحابہ رضی للہ عنہم نماز میں صف باندھے کھڑے ہوئے تھے۔ نبی کریم صلی اللہ علیہ وسلم دیکھ کر ہنس پڑے۔ ابوبکر رضی اللہ عنہ پیچھے ہٹنے لگے تاکہ صف میں آ جائیں۔ آپ نے سمجھا کہ نبی کریم صلی اللہ علیہ وسلم نماز کے لیے تشریف لانا چاہتے ہیں۔ انس رضی اللہ عنہ نے بیان کیا، قریب تھا کہ مسلمان اس خوشی کی وجہ سے جو نبی کریم صلی اللہ علیہ وسلم کو دیکھ کر انہیں ہوئی تھی کہ وہ اپنی نماز توڑنے ہی کو تھے لیکن آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ سے اشارہ کیا کہ نماز پوری کر لو، پھر آپ حجرہ کے اندر تشریف لے گئے اور پردہ ڈال لیا۔' WHERE id = 4253;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کی وفات ہوئی تو آپ کی عمر تریسٹھ سال کی تھی۔ ابن شہاب نے کہا کہ مجھے سعید بن مسیب نے بھی اسی طرح خبر دی تھی۔' WHERE id = 4266;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے (دوسری سند) اور مجھ سے خلیفہ بن خیاط نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مومنین قیامت کے دن پریشان ہو کر جمع ہوں گے اور ( آپس میں ) کہیں گے، بہتر یہ تھا کہ اپنے رب کے حضور میں آج کسی کو ہم اپنا سفارشی بناتے۔ چنانچہ سب لوگ آدم علیہ السلام کی خدمت میں حاضر ہونگے اور عرض کریں گے کہ آپ انسانوں کے باپ ہیں۔ اللہ تعالیٰ نے آپ کو اپنے ہاتھ سے بنایا۔ آپ کے لیے فرشتوں کو سجدہ کا حکم دیا اور آپ کو ہر چیز کے نام سکھائے۔ آپ ہمارے لیے اپنے رب کے حضور میں سفارش کر دیں تاکہ آج کی مصیبت سے ہمیں نجات ملے۔ آدم علیہ السلام کہیں گے، میں اس کے لائق نہیں ہوں، وہ اپنی لغزش کو یاد کریں گے اور ان کو پروردگار کے حضور میں جانے سے شرم آئے گی۔ کہیں گے کہ تم لوگ نوح علیہ السلام کے پاس جاؤ۔ وہ سب سے پہلے نبی ہیں جنہیں اللہ تعالیٰ نے ( میرے بعد ) زمین والوں کی طرف مبعوث کیا تھا۔ سب لوگ نوح علیہ السلام کی خدمت میں حاضر ہوں گے۔ وہ بھی کہیں گے کہ میں اس قابل نہیں اور وہ اپنے رب سے اپنے سوال کو یاد کریں گے جس کے متعلق انہیں کوئی علم نہیں تھا۔ ان کو بھی شرم آئے گی اور کہیں گے کہ اللہ کے خلیل علیہ السلام کے پاس جاؤ۔ لوگ ان کی خدمت میں حاضر ہوں گے لیکن وہ بھی یہی کہیں گے کہ میں اس قابل نہیں، موسیٰ علیہ السلام کے پاس جاؤ، ان سے اللہ تعالیٰ نے کلام فرمایا تھا اور تورات دی تھی۔ لوگ ان کے پاس آئیں گے لیکن وہ بھی عذر کر دیں گے کہ مجھ میں اس کی جرات نہیں۔ ان کو بغیر کسی حق کے ایک شخص کو قتل کرنا یاد آ جائے گا اور اپنے رب کے حضور میں جاتے ہوئے شرم دامن گیر ہو گی۔ کہیں گے تم عیسیٰ علیہ السلام کے پاس جاؤ، وہ اللہ کے بندے اور اس کے رسول، اس کا کلمہ اور اس کی روح ہیں لیکن عیسیٰ علیہ السلام بھی یہی کہیں گے کہ مجھ میں اس کی ہمت نہیں، تم محمد صلی اللہ علیہ وسلم کے پاس جاؤ، وہ اللہ کے مقبول بندے ہیں اور اللہ نے ان کے تمام اگلے اور پچھلے گناہ معاف کر دئیے ہیں۔ چنانچہ لوگ میرے پاس آئیں گے، میں ان کے ساتھ جاؤں گا اور اپنے رب سے اجازت چاہوں گا۔ مجھے اجازت مل جائے گی، پھر میں اپنے رب کو دیکھتے ہی سجدہ میں گر پڑوں گا اور جب تک اللہ چاہے گا میں سجدہ میں رہوں گا، پھر مجھ سے کہا جائے گا کہ اپنا سر اٹھاؤ اور جو چاہو مانگو، تمہیں دیا جائے گا، جو چاہو کہو تمہاری بات سنی جائے گی۔ شفاعت کرو، تمہاری شفاعت قبول کی جائے گی۔ میں اپنا سر اٹھاؤں گا اور اللہ کی وہ حمد بیان کروں گا جو مجھے اس کی طرف سے سکھائی گئی ہو گی۔ اس کے بعد شفاعت کروں گا اور میرے لیے ایک حد مقرر کر دی جائے گی۔ میں انہیں جنت میں داخل کراؤں گا چوتھی مرتبہ جب میں واپس آؤں گا تو عرض کروں گا کہ جہنم میں ان لوگوں کے سوا اور کوئی اب باقی نہیں رہا جنہیں قرآن نے ہمیشہ کے لیے جہنم میں رہنا ضروری قرار دے دیا ہے۔ ابوعبداللہ امام بخاری رحمہ اللہ نے کہا کہ قرآن کی رو سے دوزخ میں قید رہنے سے مراد وہ لوگ ہیں جن کے لیے «خالدين فيها‏» کہا گیا ہے۔ کہ وہ ہمیشہ دوزخ میں رہیں گے۔' WHERE id = 4276;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا میں نے زہیر سے سنا، انہوں نے ابواسحاق سے اور انہوں نے براء بن عازب رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے بیت المقدس کی طرف رخ کر کے سولہ یا سترہ مہینے تک نماز پڑھی لیکن آپ چاہتے تھے کہ آپ کا قبلہ بیت اللہ ( کعبہ ) ہو جائے ( آخر ایک دن اللہ کے حکم سے ) آپ نے عصر کی نماز ( بیت اللہ کی طرف رخ کر کے ) پڑھی اور آپ کے ساتھ بہت سے صحابہ رضی اللہ عنہم نے بھی پڑھی۔ جن صحابہ نے یہ نماز آپ کے ساتھ پڑھی تھی، ان میں سے ایک صحابی مدینہ کی ایک مسجد کے قریب سے گزرے۔ اس مسجد میں لوگ رکوع میں تھے، انہوں نے اس پر کہا کہ میں اللہ کا نام لے کر گواہی دیتا ہوں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ مکہ کی طرف منہ کر کے نماز پڑھی ہے، تمام نمازی اسی حالت میں بیت اللہ کی طرف پھر گئے۔ اس کے بعد لوگوں نے کہا کہ جو لوگ کعبہ کے قبلہ ہونے سے پہلے انتقال کر گئے، ان کے متعلق ہم کیا کہیں۔ ( ان کی نمازیں قبول ہوئیں یا نہیں؟ ) اس پر یہ آیت نازل ہوئی «وما كان الله ليضيع إيمانكم إن الله بالناس لرءوف رحيم‏» ”اللہ ایسا نہیں کہ تمہاری عبادات کو ضائع کرے، بیشک اللہ اپنے بندوں پر بہت بڑا مہربان اور بڑا رحیم ہے۔“' WHERE id = 4286;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عاصم بن سلیمان نے بیان کیا اور انہوں نے انس بن مالک رضی اللہ عنہ سے صفا اور مروہ کے متعلق پوچھا۔ انہوں نے بتایا کہ اسے ہم جاہلیت کے کاموں میں سے سمجھتے تھے۔ جب اسلام آیا تو ہم ان کی سعی سے رک گئے، اس پر اللہ تعالیٰ نے یہ آیت نازل کی «إن الصفا والمروة» سے ارشاد «أن يطوف بهما‏» تک۔ یعنی بیشک صفا اور مروہ اللہ کی نشانیوں میں سے ہیں۔ پس ان کی سعی کرنے میں حج اور عمرہ کے دوران کوئی گناہ نہیں ہے۔' WHERE id = 4296;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن ولید نے بیان کیا، کہا ہم سے عبدالاعلیٰ نے بیان کیا، ان سے عبیداللہ نے بیان کیا، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ انھوں نے یوں قرآت کی «فدية» بغیر تنوین «طَعام مساكين‏» بتلایا کہ یہ آیت منسوخ ہے۔' WHERE id = 4306;
UPDATE hadiths SET urdu = 'مجھ سے محمد نے بیان کیا، کہا کہ مجھے ابن عیینہ نے خبر دی، انہیں عمرو نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ عکاظ، مجنہ اور ذوالمجاز زمانہ جاہلیت کے بازار ( میلے ) تھے، اس لیے ( اسلام کے بعد ) موسم حج میں صحابہ رضی اللہ عنہم نے وہاں کاروبار کو برا سمجھا تو آیت نازل ہوئی «ليس عليكم جناح أن تبتغوا فضلا من ربكم‏» کہ ”تمہیں اس بارے میں کوئی حرج نہیں کہ تم اپنے پروردگار کے یہاں سے تلاش معاش کرو۔“ یعنی موسم حج میں تجارت کے لیے مذکورہ منڈیوں میں جاؤ۔' WHERE id = 4317;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے یزید بن ہارون نے بیان کیا، ان سے ہشام بن حسان نے بیان کیا، ان سے محمد بن سیرین نے، ان سے عبیدہ نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ ( دوسری سند ) امام بخاری نے کہا کہ مجھ سے عبدالرحمٰن بن بشیر بن حکم نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ہشام بن حسان نے، کہا کہ مجھ سے محمد بن سیرین نے بیان کیا، ان سے عبیدہ بن عمرو نے اور ان سے علی رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے غزوہ خندق کے موقع پر فرمایا تھا، ان کفار نے ہمیں درمیانی نماز نہیں پڑھنے دی، یہاں تک کہ سورج غروب ہو گیا، اللہ ان کی قبروں اور گھروں کو یا ان کے پیٹوں کو آگ سے بھر دے۔ قبروں اور گھروں یا پیٹوں کے لفظوں میں شک یحییٰ بن سعید راوی کی طرف سے ہے۔' WHERE id = 4329;
UPDATE hadiths SET urdu = 'اور ہم سے محمد بن یوسف فریابی نے بیان کیا، ان سے سفیان ثوری نے، ان سے منصور اور اعمش نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب سورۃ البقرہ کی آخری آیات نازل ہوئی تو رسول اللہ صلی اللہ علیہ وسلم کھڑے ہوئے اور ہمیں پڑھ کر سنایا پھر شراب کی تجارت حرام کر دی۔' WHERE id = 4339;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ نے بیان کیا، کہا ہم سے انصاری نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے ثمامہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ پھر ابوطلحہ نے وہ باغ حسان اور ابی رضی اللہ عنہما کو دے دیا تھا۔ میں ان دونوں سے ان کا زیادہ قریبی تھا لیکن مجھے نہیں دیا۔' WHERE id = 4350;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن منیر نے بیان کیا، انہوں نے ابوالنضر ہاشم بن قاسم سے سنا، کہا ہم سے عبدالرحمٰن بن عبداللہ بن دینار نے بیان کیا، ان سے ان کے والد نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جسے اللہ تعالیٰ نے مال دیا اور پھر اس نے اس کی زکٰوۃ نہیں ادا کی تو ( آخرت میں ) اس کا مال نہایت زہریلے سانپ بن کر جس کی آنکھوں کے اوپر دو نقطے ہوں گے۔ اس کی گردن میں طوق کی طرح پہنا دیا جائے گا۔ پھر وہ سانپ اس کے دونوں جبڑوں کو پکڑ کر کہے گا کہ میں ہی تیرا مال ہوں، میں ہی تیرا خزانہ ہوں، پھر آپ نے اس آیت کی تلاوت «ولا يحسبن الذين يبخلون بما آتاهم الله من فضله‏» کی ”اور جو لوگ کہ اس مال میں بخل کرتے ہیں جو اللہ نے انہیں اپنے فضل سے دے رکھا ہے، وہ یہ نہ سمجھیں کہ یہ مال ان کے حق میں بہتر ہے۔“ آخر تک۔' WHERE id = 4360;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو عبداللہ بن نمیر نے خبر دی، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے اللہ تعالیٰ کے ارشاد «ومن كان غنيا فليستعفف ومن كان فقيرا فليأكل بالمعروف‏» ”بلکہ جو شخص خوشحال ہو وہ اپنے کو بالکل روکے رکھے۔ البتہ جو شخص نادار ہو وہ واجبی طور پر کھا سکتا ہے۔“ کے بارے میں فرمایا کہ یہ آیت یتیم کے بارے میں اتری ہے کہ اگر ولی نادار ہو تو یتیم کی پرورش اور دیکھ بھال کی اجرت میں وہ واجبی طور پر ( یتیم کے مال میں سے کچھ ) کھا سکتا ہے ( بشرطیکہ نیت میں فساد نہ ہو ) ۔' WHERE id = 4370;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے اور ان سے عروہ بن زبیر نے بیان کیا کہ زبیر رضی اللہ عنہ کا ایک انصاری صحابی سے مقام حرہ کی ایک نالی کے بارے میں جھگڑا ہو گیا ( کہ اس سے کون اپنے باغ کو پہلے سینچنے کا حق رکھتا ہے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ زبیر! پہلے تم اپنے باغ سینچ لو پھر اپنے پڑوسی کو جلد پانی دے دینا۔ اس پر اس انصاری صحابی نے کہا: یا رسول اللہ! اس لیے کہ یہ آپ کے پھوپھی زاد بھائی ہیں؟ یہ سن کر نبی کریم صلی اللہ علیہ وسلم کے چہرہ مبارک کا رنگ بدل گیا اور آپ صلی اللہ علیہ وسلم نے فرمایا: زبیر! اپنے باغ کو سینچو اور پانی اس وقت تک روکے رکھو کہ منڈیر تک بھر جائے، پھر اپنے پڑوسی کے لیے اسے چھوڑو۔ ( پہلے نبی کریم صلی اللہ علیہ وسلم نے انصاری کے ساتھ اپنے فیصلے میں رعایت رکھی تھی ) لیکن اس مرتبہ آپ صلی اللہ علیہ وسلم نے زبیر رضی اللہ عنہ کو صاف طور پر ان کا پورا حق دے دیا کیونکہ انصاری نے ایسی بات کہی تھی۔ جس سے آپ کا غصہ ہونا قدرتی تھا۔ آپ صلی اللہ علیہ وسلم نے اپنے پہلے فیصلہ میں دونوں کے لیے رعایت رکھی تھی۔ زبیر رضی اللہ عنہ نے بیان کیا کہ میرا خیال ہے، یہ آیات اسی سلسلے میں نازل ہوئی تھیں «فلا وربك لا يؤمنون حتى يحكموك فيما شجر بينهم‏» ”تیرے پروردگار کی قسم ہے کہ یہ لوگ ایماندار نہ ہوں گے جب تک یہ اس جھگڑے میں جو ان کے آپس میں ہوں آپ کو حکم نہ بنا لیں اور آپ کے فیصلے کو کھلے دل کے ساتھ برضا و رغبت تسلیم کرنے کے لیے تیار نہ ہوں۔“' WHERE id = 4380;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، انہیں ابن جریج نے خبر دی (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے اسحاق بن منصور نے بیان کیا، کہا ہم کو عبدالرزاق نے خبر دی، کہا ہم کو ابن جریج نے خبر دی، کہا ہم کو عبدالکریم جرزی نے خبر دی، انہیں عبداللہ بن حارث کے غلام مقسم نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے خبر دی کہ «لا يستوي القاعدون من المؤمنين‏» سے اشارہ ہے ان لوگوں کی طرف جو بدر میں شریک تھے اور جنہوں نے بلا کسی عذر کے بدر کی لڑائی میں شرکت نہیں کی تھی، وہ دونوں برابر نہیں ہو سکتے۔' WHERE id = 4390;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے اور انہوں نے براء بن عازب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ سب سے آخر میں جو سورت نازل ہوئی وہ سورۃ برات ہے اور ( احکام میراث کے سلسلے میں ) سب سے آخر میں جو آیت نازل ہوئی وہ «يستفتونك قل الله یفتیکم فى الکلالة» ہے۔' WHERE id = 4400;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عون نے بیان کیا، کہا ہم سے خالد بن عبداللہ طحان نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، ان سے قیس بن ابی حازم نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہو کر جہاد کیا کرتے تھے اور ہمارے ساتھ ہماری بیویاں نہیں ہوتی تھیں۔ اس پر ہم نے عرض کیا کہ ہم اپنے آپ کو خصی کیوں نہ کر لیں۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے ہمیں اس سے روک دیا اور اس کے بعد ہمیں اس کی اجازت دی کہ ہم کسی عورت سے کپڑے ( یا کسی بھی چیز ) کے بدلے میں نکاح کر سکتے ہیں۔ پھر عبداللہ رضی اللہ عنہ نے یہ آیت پڑھی «يا أيها الذين آمنوا لا تحرموا طيبات ما أحل الله لكم» ”اے ایمان والو! اپنے اوپر ان پاکیزہ چیزوں کو حرام نہ کرو جو اللہ نے تمہارے لیے جائز کی ہیں۔“' WHERE id = 4410;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، کہا ہم کو مغیرہ بن نعمان نے خبر دی، انہوں نے کہا کہ میں نے سعید بن جبیر سے سنا اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے خطبہ دیا اور فرمایا کہ اے لوگو! تم اللہ کے پاس جمع کئے جاؤ گے، ننگے پاؤں ننگے جسم اور بغیر ختنہ کے، پھر آپ صلی اللہ علیہ وسلم نے یہ آیت پڑھی «كما بدأنا أول خلق نعيده وعدا علينا إنا كنا فاعلين‏» ”جس طرح ہم نے اول بار پیدا کرنے کے وقت ابتداء کی تھی، اسی طرح اسے دوبارہ زندہ کر دیں گے، ہمارے ذمہ وعدہ ہے، ہم ضرور اسے کر کے ہی رہیں گے۔“ آخر آیت تک۔ پھر فرمایا قیامت کے دن تمام مخلوق میں سب سے پہلے ابراہیم علیہ السلام کو کپڑا پہنایا جائے گا۔ ہاں اور میری امت کے کچھ لوگوں کو لایا جائے گا اور انہیں جہنم کی بائیں طرف لے جایا جائے گا۔ میں عرض کروں گا، میرے رب! یہ تو میرے امتی ہیں؟ مجھ سے کہا جائے گا، آپ کو نہیں معلوم ہے کہ انہوں نے آپ کے بعد نئی نئی باتیں شریعت میں نکالی تھیں۔ اس وقت میں بھی وہی کہوں گا جو عبد صالح عیسیٰ علیہ السلام نے کہا ہو گا «وكنت عليهم شهيدا ما دمت فيهم فلما توفيتني كنت أنت الرقيب عليهم‏» کہ ”میں ان کا حال دیکھتا رہا جب تک میں ان کے درمیان رہا، پھر جب تو نے مجھے اٹھا لیا ( جب سے ) تو ہی ان پر نگراں ہے۔“ مجھے بتایا جائے گا کہ آپ کی جدائی کے بعد یہ لوگ دین سے پھر گئے تھے۔' WHERE id = 4420;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے عبدالواحد نے بیان کیا، انہوں نے کہا ہم سے عمارہ نے بیان کیا، انہوں نے کہا ہم سے ابوزرعہ نے بیان کیا، کہا ہم سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اس وقت تک قیامت قائم نہ ہو گی، جب تک سورج مغرب سے طلوع نہ ہو لے۔ جب لوگ اسے دیکھیں گے تو ایمان لائیں گے لیکن یہ وہ وقت ہو گا جب کسی ایسے شخص کو اس کا ایمان کوئی نفع نہ دے گا جو پہلے سے ایمان نہ رکھتا ہو۔' WHERE id = 4430;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبدالرحیم نے بیان کیا، انہوں نے کہا ہم سے سعید بن سلیمان نے بیان کیا، انہوں نے کہا ہم کو ہشیم نے خبر دی، انہوں نے کہا ہم کو ابوبشر نے خبر دی، ان سے سعید بن جبیر نے بیان کیا کہ میں نے ابن عباس رضی اللہ عنہما سے سورۃ الانفال کے متعلق پوچھا۔ انہوں نے بتلایا کہ غزوہ بدر میں نازل ہوئی تھی۔ «الشوكة» کا معنی دھار نوک۔ «مردفين‏» کے معنی فوج در فوج۔ کہتے ہیں «ردفني وأردفني» یعنی میرے بعد آیا۔ «ذلكم فذوقوه ذوقوا‏» کا معنی یہ ہے کہ یہ عذاب اٹھاؤ اس کا تجربہ کرو، منہ سے چکھنا مراد نہیں ہے۔ «فيركمه‏» کا معنی اس کا جمع کرے۔ «شرد‏» کا معنی جدا کر دے ( یا سخت سزا دے ) ۔ «جنحوا‏» کے معنی طلب کریں۔ «يثخن‏» کا معنی غالب ہوا اور مجاہد نے کہا «مكاء‏» کا معنی انگلیاں منہ پر رکھنا۔ «تصدية‏» سیٹی بجانا۔ «يثبتوك‏» تاکہ تجھ کو قید کر لیں۔' WHERE id = 4440;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا مجھ سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے (کہا) اور مجھے حمید بن عبدالرحمٰن بن عوف نے خبر دی کہ ابوہریرہ رضی اللہ عنہ نے کہا: ابوبکر صدیق رضی اللہ عنہ نے اس حج کے موقع پر ( جس کا نبی کریم صلی اللہ علیہ وسلم نے انہیں امیر بنایا تھا ) مجھے بھی اعلان کرنے والوں میں رکھا تھا، جنہیں نبی کریم صلی اللہ علیہ وسلم نے یوم نحر میں اس لیے بھیجا تھا کہ اعلان کر دیں کہ آئندہ سال سے کوئی مشرک حج کرنے نہ آئے اور کوئی شخص بیت اللہ کا طواف ننگے ہو کر نہ کرے۔ حمید بن عبدالرحمٰن نے کہا کہ پھر اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے علی رضی اللہ عنہ کو پیچھے سے بھیجا اور انہیں سورۃ برات کے احکام کے اعلان کرنے کا حکم دیا۔ ابوہریرہ رضی اللہ عنہ نے کہا، چنانچہ ہمارے ساتھ علی رضی اللہ عنہ نے بھی یوم نحر ہی میں سورۃ برات کا اعلان کیا اور اس کا کہ آئندہ سال سے کوئی مشرک حج نہ کرے اور نہ کوئی ننگے ہو کر طواف کرے۔' WHERE id = 4450;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد جعفی نے بیان کیا، کہا کہ مجھ سے یحییٰ ابن معین نے بیان کیا، کہا ہم سے حجاج بن محمد نے بیان کیا، ان سے ابن جریج نے بیان کیا، ان سے ابن ابی ملیکہ نے بیان کیا کہ ابن عباس اور ابن زبیر رضی اللہ عنہم کے درمیان بیعت کا جھگڑا پیدا ہو گیا تھا۔ میں صبح کو ابن عباس رضی اللہ عنہما کی خدمت میں حاضر ہوا اور عرض کیا آپ عبداللہ بن زبیر رضی اللہ عنہما سے جنگ کرنا چاہتے ہیں، اس کے باوجود کہ اللہ کے حرم کی بےحرمتی ہو گی؟ ابن عباس رضی اللہ عنہما نے فرمایا: معاذاللہ! یہ تو اللہ تعالیٰ نے ابن زبیر اور بنو امیہ ہی کے مقدر میں لکھ دیا ہے کہ وہ حرم کی بےحرمتی کریں۔ اللہ کی قسم! میں کسی صورت میں بھی اس بےحرمتی کے لیے تیار نہیں ہوں۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ لوگوں نے مجھ سے کہا تھا کہ ابن زبیر سے بیعت کر لو۔ میں نے ان سے کہا کہ مجھے ان کی خلافت کو تسلیم کرنے میں کیا تامل ہو سکتا ہے، ان کے والد نبی کریم صلی اللہ علیہ وسلم کے حواری تھے، آپ کی مراد زبیر بن عوام سے تھی۔ ان کے نانا صاحب غار تھے، اشارہ ابوبکر صدیق رضی اللہ عنہ کی طرف تھا۔ ان کی والدہ صاحب نطاقین تھیں یعنی اسماء رضی اللہ عنہا۔ ان کی خالہ ام المؤمنین تھیں، مراد عائشہ رضی اللہ عنہا سے تھی۔ ان کی پھوپھی نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ تھیں، مراد خدیجہ رضی اللہ عنہا سے تھی۔ ابن عباس کی مراد ان باتوں سے یہ تھی کہ وہ بہت سی خوبیوں کے مالک ہیں اور نبی کریم صلی اللہ علیہ وسلم کی پھوپھی ان کی دادی ہیں، اشارہ صفیہ رضی اللہ عنہا کی طرف تھا۔ اس کے علاوہ وہ خود اسلام میں ہمیشہ صاف کردار اور پاک دامن رہے اور قرآن کے عالم ہیں اور اللہ کی قسم! اگر وہ مجھ سے اچھا برتاؤ کریں تو ان کو کرنا ہی چاہئے وہ میرے بہت قریب کے رشتہ دار ہیں اور اگر وہ مجھ پر حکومت کریں تو خیر حکومت کریں وہ ہمارے برابر کے عزت والے ہیں۔ لیکن عبداللہ بن زبیر رضی اللہ عنہما نے تو تویت، اسامہ اور حمید کے لوگوں کو ہم پر ترجیح دی ہے۔ ان کی مراد مختلف قبائل یعنی بنو اسد، بنو تویت، بنو اسامہ اور بنو اسد سے تھی۔ ادھر ابن ابی العاص بڑی عمدگی سے چل رہا ہے یعنی عبدالملک بن مروان مسلسل پیش قدمی کر رہا ہے اور عبداللہ بن زبیر رضی اللہ عنہما نے اس کے سامنے دم دبا لی ہے۔' WHERE id = 4460;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سعید بن مسیب نے اور ان سے ان کے والد مسیب بن حزن نے کہ جب ابوطالب کے انتقال کا وقت ہوا تو نبی کریم صلی اللہ علیہ وسلم ان کے پاس تشریف لے گئے، اس وقت وہاں ابوجہل اور عبداللہ بن ابی امیہ بیٹھے ہوئے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ ( آپ ایک بار زبان سے کلمہ ) لا الہٰ الا اللہ کہہ دیجئیے میں اسی کو ( آپ کی نجات کے لیے وسیلہ بنا کر ) اللہ کی بارگاہ میں پیش کر لوں گا۔ اس پر ابوجہل اور عبداللہ ابی امیہ کہنے لگے: ابوطالب! کیا آپ عبدالمطلب کے دین سے پھر جاؤ گے؟ آپ صلی اللہ علیہ وسلم نے کہا کہ اب میں آپ کے لیے برابر مغفرت کی دعا مانگتا رہوں گا جب تک مجھے اس سے روک نہ دیا جائے، تو یہ آیت نازل ہوئی «ما كان للنبي والذين آمنوا أن يستغفروا للمشركين ولو كانوا أولي قربى من بعد ما تبين لهم أنهم أصحاب الجحيم‏» کہ ”نبی اور ایمان والوں کے لیے جائز نہیں کہ وہ مشرکوں کے لیے بخشش کی دعا کریں۔ اگرچہ وہ ( مشرکین ) رشتہ دار ہی کیوں نہ ہوں۔ جب ان پر یہ ظاہر ہو چکے کہ وہ ( یقیناً ) اہل دوزخ سے ہیں۔“' WHERE id = 4470;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید بن ابی عروبہ اور ہشام بن ابی عبداللہ دستوائی نے بیان کیا، کہا کہ ہم سے قتادہ نے بیان کیا اور ان سے صفوان بن محرز نے کہ ابن عمر رضی اللہ عنہما طواف کر رہے تھے کہ ایک شخص نام نامعلوم آپ کے سامنے آیا اور پوچھا: اے ابوعبدالرحمٰن! یا یہ کہا کہ اے ابن عمر! کیا آپ نے رسول اللہ صلی اللہ علیہ وسلم سے سرگوشی کے متعلق کچھ سنا ہے ( جو اللہ تعالیٰ مؤمنین سے قیامت کے دن کرے گا ) ۔ انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ مومن اپنے رب کے قریب لایا جائے گا۔ اور ہشام نے «يدنو المؤمن» ( بجائے «يدنى المؤمن» کہا ) مطلب ایک ہی ہے۔ یہاں تک کہ اللہ تعالیٰ اپنا ایک جانب اس پر رکھے گا اور اس کے گناہوں کا اقرار کرائے گا کہ فلاں گناہ تجھے یاد ہے؟ بندہ عرض کرے گا، یاد ہے، میرے رب! مجھے یاد ہے، دو مرتبہ اقرار کرے گا۔ پھر اللہ تعالیٰ فرمائے گا کہ میں نے دنیا میں تمہارے گناہوں کو چھپائے رکھا اور آج بھی تمہاری مغفرت کروں گا۔ پھر اس کی نیکیوں کا دفتر لپیٹ دیا جائے گا۔ لیکن دوسرے لوگ یا ( یہ کہا کہ ) کفار تو ان کے متعلق محشر میں اعلان کیا جائے گا کہ یہی وہ لوگ ہیں جنہوں نے اللہ پر جھوٹ باندھا تھا۔ اور شیبان نے بیان کیا، ان سے قتادہ نے کہ ہم سے صفوان نے بیان کیا۔' WHERE id = 4480;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا ہم سے معن بن عیسیٰ نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ غیب کی پانچ کنجیاں ہیں جنہیں اللہ کے سوا کوئی نہیں جانتا۔ اللہ کے سوا کوئی نہیں جانتا کہ کل کیا ہونے والا ہے، اللہ کے سوا کوئی نہیں جانتا کہ عورتوں کے رحم میں کیا کمی بیشی ہوتی رہتی ہے، اللہ کے سوا کوئی نہیں جانتا کہ بارش کب برسے گی، کوئی شخص نہیں جانتا کہ اس کی موت کہاں ہو گی اور اللہ کے سوا کوئی نہیں جانتا کہ قیامت کب قائم ہو گی۔' WHERE id = 4492;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ہارون بن موسیٰ ابوعبداللہ اعور نے بیان کیا، ان سے شعیب نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم دعا کیا کرتے تھے «أعوذ بك من البخل والكسل،‏‏‏‏ وأرذل العمر،‏‏‏‏ وعذاب القبر،‏‏‏‏ وفتنة الدجال،‏‏‏‏ وفتنة المحيا والممات ‏ ‏‏.‏» کہ اے اللہ! میں تیری پناہ مانگتا ہوں بخل سے، سستی سے، ارذل عمر سے ( نکمی اور خراب عمر 80 یا 90 سال کے بعد ) عذاب قبر سے، دجال کے فتنے سے اور زندگی اور موت کے فتنے سے۔' WHERE id = 4502;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے عبدالرزاق بن ہمام نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں ابوسلمہ بن عبدالرحمٰن بن عوف اور سعید بن مسیب اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تنہا نماز پڑھنے کے مقابلے میں جماعت سے نماز پڑھنے کی فضیلت پچیس گنا زیادہ ہے اور صبح کی نماز میں رات کے اور دن کے فرشتے اکٹھے ہو جاتے ہیں۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ اگر تمہارا جی چاہے تو یہ آیت پڑھو «وقرآن الفجر إن قرآن الفجر كان مشهودا‏» یعنی فجر میں قرآت قرآن زیادہ کیا کرو کیونکہ یہ نماز فرشتوں کی حاضری کا وقت ہے۔' WHERE id = 4512;
UPDATE hadiths SET urdu = 'مجھ سے قتیبہ بن سعید نے بیان کیا، کہا کہ مجھ سے سفیان بن عیینہ نے بیان کیا، کہا ان سے عمرو بن دینار نے اور ان سے سعید بن جبیر نے بیان کیا کہ میں نے ابن عباس رضی اللہ عنہما سے عرض کیا۔ نوف بکالی کہتے ہیں کہ موسیٰ علیہ السلام جو اللہ کے نبی تھے وہ نہیں ہیں جنہوں نے خضر علیہ السلام سے ملاقات کی تھی۔ ابن عباس رضی اللہ عنہما نے کہا، دشمن خدا نے غلط بات کہی ہے۔ ہم سے ابی بن کعب نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ موسیٰ علیہ السلام بنی اسرائیل کو وعظ کرنے کے لیے کھڑے ہوئے تو ان سے پوچھا گیا کہ سب سے بڑا عالم کون شخص ہے۔ موسیٰ علیہ السلام نے فرمایا کہ میں ہوں۔ اللہ تعالیٰ نے اس پر غصہ کیا، کیونکہ انہوں نے علم کی نسبت اللہ کی طرف نہیں کی تھی اور ان کے پاس وحی بھیجی کہ ہاں، میرے بندوں میں سے ایک بندہ دو دریاؤں کے ملنے کی جگہ پر ہے اور وہ تم سے بڑا عالم ہے۔ موسیٰ علیہ السلام نے عرض کیا: اے پروردگار! ان تک پہنچنے کا طریقہ کیا ہو گا؟ اللہ تعالیٰ نے فرمایا کہ ایک مچھلی زنبیل میں ساتھ لے لو۔ پھر جہاں وہ مچھلی گم ہو جائے وہیں انہیں تلاش کرو۔ بیان کیا کہ موسیٰ علیہ السلام نکل پڑے اور آپ کے ساتھ آپ کے رفیق سفر یوشع بن نون بھی تھے۔ مچھلی ساتھ تھی۔ جب چٹان تک پہنچے تو وہاں ٹھہر گئے۔ موسیٰ علیہ السلام اپنا سر رکھ کر وہیں سو گئے، عمرو کی روایت کے سوا دوسری روایت کے حوالہ سے سفیان نے بیان کیا کہ اس چٹان کی جڑ میں ایک چشمہ تھا، جسے ”حیات“ کہا جاتا تھا۔ جس چیز پر بھی اس کا پانی پڑ جاتا وہ زندہ ہو جاتی تھی۔ اس مچھلی پر بھی اس کا پانی پڑا تو اس کے اندر حرکت پیدا ہو گئی اور وہ اپنی زنبیل سے نکل کر دریا میں چلی گئی۔ موسیٰ علیہ السلام جب بیدار ہوئے تو انہوں نے اپنے ساتھی سے فرمایا «قال لفتاه آتنا غداءنا‏» کہ ”ہمارا ناشتہ لاؤ“ الآیۃ۔ بیان کیا کہ سفر میں موسیٰ علیہ السلام کو اس وقت تک کوئی تھکن نہیں ہوئی جب تک وہ مقررہ جگہ سے آگے نہیں بڑھ گئے۔ رفیق سفر یوشع بن نون نے اس پر کہا «أرأيت إذ أوينا إلى الصخرة فإني نسيت الحوت‏» ”آپ نے دیکھا جب ہم چٹان کے نیچے بیٹھے ہوئے تھے تو میں مچھلی کے متعلق کہنا بھول گیا“ الآیۃ۔ بیان کیا کہ پھر وہ دونوں الٹے پاؤں واپس لوٹے۔ دیکھا کہ جہاں مچھلی پانی میں گری تھی وہاں اس کے گزرنے کی جگہ طاق کی سی صورت بنی ہوئی ہے۔ مچھلی تو پانی میں چلی گئی تھی لیکن یوشع بن نون کو اس طرح پانی کے رک جانے پر تعجب تھا۔ جب چٹان پر پہنچے تو دیکھا کہ ایک بزرگ کپڑے میں لپٹے ہوئے وہاں موجود ہیں۔ موسیٰ علیہ السلام نے انہیں سلام کیا تو انہوں نے فرمایا کہ تمہاری زمین میں سلام کہاں سے آ گیا؟ آپ نے فرمایا کہ میں موسیٰ ہوں۔ پوچھا بنی اسرائیل کے موسیٰ؟ فرمایا کہ جی ہاں! موسیٰ علیہ السلام نے ان سے کہا کیا آپ کے ساتھ رہ سکتا ہوں تاکہ جو ہدایت کا علم اللہ تعالیٰ نے آپ کو دیا ہے وہ آپ مجھے بھی سکھا دیں۔ خضر علیہ السلام نے جواب دیا کہ آپ کو اللہ کی طرف سے ایسا علم حاصل ہے جو میں نہیں جانتا اور اسی طرح مجھے اللہ کی طرف سے ایسا علم حاصل ہے جو آپ نہیں جانتے۔ موسیٰ علیہ السلام نے فرمایا، لیکن میں آپ کے ساتھ رہوں گا۔ خضر علیہ السلام نے اس پر کہا کہ اگر آپ کو میرے ساتھ رہنا ہی ہے تو پھر مجھ سے کسی چیز کے متعلق نہ پوچھئے گا، میں خود آپ کو بتاؤں گا۔ چنانچہ دونوں حضرات دریا کے کنارے روانہ ہوئے، ان کے قریب سے ایک کشتی گزری تو خضر علیہ السلام کو کشتی والوں نے پہچان لیا اور اپنی کشتی میں ان کو بغیر کرایہ کے چڑھا لیا دونوں کشتی میں سوار ہو گئے۔ بیان کیا کہ اسی عرصہ میں ایک چڑیا کشتی کے کنارے آ کے بیٹھی اور اس نے اپنی چونچ کو دریا میں ڈالا تو خضر علیہ السلام نے موسیٰ علیہ السلام سے فرمایا کہ میرا، آپ کا اور تمام مخلوقات کا علم اللہ کے علم کے مقابلہ میں اس سے زیادہ نہیں ہے جتنا اس چڑیا نے اپنی چونچ میں دریا کا پانی لیا ہے۔ بیان کیا کہ پھر یکدم جب خضر علیہ السلام نے بسولا اٹھایا اور کشتی کو پھاڑ ڈالا تو موسیٰ علیہ السلام اس طرف متوجہ ہوئے اور فرمایا ان لوگوں نے ہمیں بغیر کسی کرایہ کے اپنی کشتی میں سوار کر لیا تھا اور آپ نے اس کا بدلہ یہ دیا ہے کہ ان کی کشتی ہی چیر ڈالی تاکہ اس کے مسافر ڈوب مریں۔ بلاشبہ آپ نے بڑا نا مناسب کام کیا ہے۔ پھر وہ دونوں آگے بڑھے تو دیکھا کہ ایک بچہ جو بہت سے دوسرے بچوں کے ساتھ کھیل رہا تھا، خضر نے اس کا سر پکڑا اور کاٹ ڈالا۔ اس پر موسیٰ علیہ السلام بول پڑے کہ آپ نے بلا کسی خون و بدلہ کے ایک معصوم بچے کی جان لے لی، یہ تو بڑی بری بات ہے۔ خضر علیہ السلام نے فرمایا، میں نے آپ سے پہلے ہی نہیں کہہ دیا تھا کہ آپ میرے ساتھ صبر نہیں کر سکتے، اللہ تعالیٰ کے ارشاد ”پس اس بستی والوں نے ان کی میزبانی سے انکار کیا، پھر اس بستی میں انہیں ایک دیوار دکھائی دی جو بس گرنے ہی والی تھی۔ خضر علیہ السلام نے اپنا ہاتھ یوں اس پر پھیرا اور اسے سیدھا کر دیا۔ موسیٰ علیہ السلام نے فرمایا ہم اس بستی میں آئے تو انہوں نے ہماری میزبانی سے انکار کیا اور ہمیں کھانا بھی نہیں دیا اگر آپ چاہتے تو اس پر اجرت لے سکتے تھے۔ خضر علیہ السلام نے فرمایا بس یہاں سے اب میرے اور آپ کے درمیان جدائی ہے اور میں آپ کو ان کاموں کی وجہ بتاؤں گا جن پر آپ صبر نہیں کر سکے تھے۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم نے فرمایا۔ کاش موسیٰ علیہ السلام نے صبر کیا ہوتا اور اللہ تعالیٰ ان کے سلسلے میں اور واقعات ہم سے بیان کرتا۔ بیان کیا کہ ابن عباس رضی اللہ عنہما «وكان وراءهم ملك» کی بجائے «وكان أمامهم ملك يأخذ كل سفينة صالحة غصبا» قرآت کرتے تھے اور بچہ ( جسے قتل کیا تھا ) اس کے والدین مومن تھے۔ اور یہ بچہ ( مشیت الٰہی میں ) کافر تھا۔' WHERE id = 4522;
UPDATE hadiths SET urdu = 'مجھ سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے روح بن عبادہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے ابوبشر نے بیان کیا، ان سے سعید بن جبیر نے اور ان سے ابن عباس نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم مدینہ تشریف لائے تو یہودی عاشورہ کا روزہ رکھتے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے اس کے متعلق پوچھا تو انہوں نے بتایا کہ اس دن موسیٰ علیہ السلام نے فرعون پر غلبہ پایا تھا۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ پھر ہم ان کے مقابلے میں موسیٰ کے زیادہ حقدار ہیں۔ مسلمانو! تم لوگ بھی اس دن روزہ رکھو ( پھر آپ صلی اللہ علیہ وسلم نے یہود کی مشابہت سے بچنے کے لیے اس کے ساتھ ایک روزہ اور ملانے کا حکم صادر فرمایا جو اب بھی مسنون ہے۔)' WHERE id = 4532;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے ابن ابی عدی نے بیان کیا، ان سے ہشام بن حسان نے ان سے عکرمہ نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے کہ ہلال بن امیہ نے نبی کریم صلی اللہ علیہ وسلم کے سامنے اپنی بیوی پر شریک بن سحماء کے ساتھ تہمت لگائی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کے گواہ لاؤ ورنہ تمہاری پیٹھ پر حد لگائی جائے گی۔ انہوں نے عرض کیا: یا رسول اللہ! ایک شخص اپنی بیوی کے ساتھ ایک غیر کو مبتلا دیکھتا ہے تو کیا وہ ایسی حالت میں گواہ تلاش کرنے جائے گا؟ لیکن آپ یہی فرماتے رہے کہ گواہ لاؤ، ورنہ تمہاری پیٹھ پر حد جاری کی جائے گی۔ اس پر ہلال نے عرض کیا۔ اس ذات کی قسم جس نے آپ کو حق کے ساتھ نبی بنا کر بھیجا ہے میں سچا ہوں اور اللہ تعالیٰ خود ہی کوئی ایسی آیت نازل فرمائے گا۔ جس کے ذریعہ میرے اوپر سے حد دور ہو جائے گی۔ اتنے میں جبرائیل علیہ السلام تشریف لائے اور یہ آیت نازل ہوئی «والذين يرمون أزواجهم‏» سے «إن كان من الصادقين‏» ۔ ( جس میں ایسی صورت میں لعان کا حکم ہے ) جب نزول وحی کا سلسلہ ختم ہوا تو نبی کریم صلی اللہ علیہ وسلم نے ہلال کو آدمی بھیج کر بلوایا وہ آئے اور آیت کے مطابق چار مرتبہ قسم کھائی۔ نبی کریم صلی اللہ علیہ وسلم نے اس موقع پر فرمایا کہ اللہ خوب جانتا ہے کہ تم میں سے ایک ضرور جھوٹا ہے تو کیا وہ توبہ کرنے پر تیار نہیں ہے۔ اس کے بعد ان کی بیوی کھڑی ہوئیں اور انہوں نے بھی قسم کھائی، جب وہ پانچویں پر پہنچیں ( اور چار مرتبہ اپنی برات کی قسم کھانے کے بعد، کہنے لگیں کہ اگر میں جھوٹی ہوں تو مجھ پر اللہ کا غضب ہو ) تو لوگوں نے انہیں روکنے کی کوشش کی اور کہا کہ ( اگر تم جھوٹی ہو تو ) اس سے تم پر اللہ کا عذاب ضرور نازل ہو گا۔ ابن عباس رضی اللہ عنہا نے بیان کیا کہ اس پر وہ ہچکچائیں ہم نے سمجھا کہ اب وہ اپنا بیان واپس لے لیں گی۔ لیکن یہ کہتے ہوئے کہ زندگی بھر کے لیے میں اپنی قوم کو رسوا نہیں کروں گی۔ پانچویں بار قسم کھائی۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دیکھنا اگر بچہ خوب سیاہ آنکھوں والا، بھاری سرین اور بھری بھری پنڈلیوں والا پیدا ہوا تو پھر وہ شریک بن سحماء ہی کا ہو گا۔ چنانچہ جب پیدا ہوا تو وہ اسی شکل و صورت کا تھا نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر کتاب اللہ کا حکم نہ آ چکا ہوتا تو میں اسے رجمی سزا دیتا۔' WHERE id = 4542;
UPDATE hadiths SET urdu = 'اور ابواسامہ حماد بن اسامہ نے ہشام بن عروہ سے بیان کیا کہ انہوں نے کہا کہ مجھے میرے والد عروہ بن زبیر نے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب میرے متعلق ایسی باتیں کہی گئیں جن کا مجھے گمان بھی نہیں تھا تو رسول اللہ صلی اللہ علیہ وسلم میرے معاملہ میں لوگوں کو خطبہ دینے کے لیے کھڑے ہوئے۔ آپ صلی اللہ علیہ وسلم نے شہادت کے بعد اللہ کی حمد و ثنا اس کی شان کے مطابق بیان کی، پھر فرمایا، امابعد! تم لوگ مجھے ایسے لوگوں کے بارے میں مشورہ دو جنہوں نے میری بیوی کو بدنام کیا ہے اور اللہ کی قسم! کہ میں نے اپنی بیوی میں کوئی برائی نہیں دیکھی اور تہمت بھی ایسے شخص ( صفوان بن معطل ) کے ساتھ لگائی ہے کہ اللہ کی قسم! ان میں بھی میں نے کبھی کوئی برائی نہیں دیکھی۔ وہ میرے گھر میں جب بھی داخل ہوا تو میری موجودگی ہی میں داخل ہوا اور اگر میں کبھی سفر کی وجہ سے مدینہ نہیں ہوتا تو وہ بھی نہیں ہوتا اور وہ میرے ساتھ ہی رہتے ہیں۔ اس کے بعد سعد بن معاذ رضی اللہ عنہ کھڑے ہوئے اور عرض کیا: یا رسول اللہ! ہمیں حکم فرمایئے کہ ہم ایسے مردود لوگوں کی گردنیں اڑا دیں۔ اس کے بعد قبیلہ خزرج کے ایک صاحب ( سعد بن عبادہ ) کھڑے ہوئے، حسان بن ثابت کی والدہ اسی قبیلہ خزرج سے تھیں، انہوں نے کھڑے ہو کر کہا کہ تم جھوٹے ہو، اگر وہ لوگ ( تہمت لگانے والے ) قبیلہ اوس کے ہوتے تو تم کبھی انہیں قتل کرنا پسند نہ کرتے۔ نوبت یہاں تک پہنچی کہ مسجد ہی میں اوس و خزرج کے قبائل میں باہم فساد کا خطرہ ہو گیا، اس فساد کی مجھ کو کچھ خبر نہ تھی، اسی دن کی رات میں، میں قضائے حاجت کے لیے باہر نکلی، میرے ساتھ ام مسطح بھی تھیں۔ وہ ( راستے میں ) پھسل گئیں اور ان کی زبان سے نکلا کہ مسطح کو اللہ غارت کرے۔ میں نے کہا، آپ اپنے بیٹے کو کوستی ہیں، اس پر وہ خاموش ہو گئیں، پھر دوبارہ وہ پھسلیں اور ان کی زبان سے وہی الفاظ نکلے کہ مسطح کو اللہ غارت کرے۔ میں نے پھر کہا کہ اپنے بیٹے کو کوستی ہو، پھر وہ تیسری مرتبہ پھسلیں تو میں نے پھر انہیں ٹوکا۔ انہوں نے بتایا کہ اللہ کی قسم! میں تو تیری ہی وجہ سے اسے کوستی ہوں۔ میں نے کہا کہ میرے کس معاملہ میں انہیں آپ کوس رہی ہیں؟ بیان کیا۔ کہ اب انہوں نے طوفان کا سارا قصہ بیان کیا میں نے پوچھا، کیا واقعی یہ سب کچھ کہا گیا ہے؟ انہوں نے کہا کہ ہاں، اللہ کی قسم! پھر میں اپنے گھر گئی۔ لیکن ( ان واقعات کو سن کر غم کا یہ حال تھا کہ ) مجھے کچھ خبر نہیں کہ کس کام کے لیے میں باہر گئی تھی اور کہاں سے آئی ہوں، ذرہ برابر بھی مجھے اس کا احساس نہیں رہا۔ اس کے بعد مجھے بخار چڑھ گیا اور میں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ آپ مجھے ذرا میرے والد کے گھر پہنچوا دیجئیے۔ آپ صلی اللہ علیہ وسلم نے میرے ساتھ ایک بچہ کو کر دیا۔ میں گھر پہنچی تو میں نے دیکھا کہ ام رومان نیچے کے حصہ میں ہیں اور ابوبکر رضی اللہ عنہ بالاخانے میں قرآن پڑھ رہے ہیں۔ والدہ نے پوچھا بیٹی اس وقت کیسے آ گئیں۔ میں نے وجہ بتائی اور واقعہ کی تفصیلات سنائیں ان باتوں سے جتنا غم مجھ کو تھا ایسا معلوم ہوا کہ ان کو اتنا غم نہیں ہے۔ انہوں نے فرمایا، بیٹی اتنا فکر کیوں کرتی ہو کم ہی ایسی کوئی خوبصورت عورت کسی ایسے مرد کے نکاح میں ہو گی جو اس سے محبت رکھتا ہو اور اس کی سوکنیں بھی ہوں اور وہ اس سے حسد نہ کریں اور اس میں سو عیب نہ نکالیں۔ اس تہمت سے وہ اس درجہ بالکل بھی متاثر نہیں معلوم ہوتی تھیں جتنا میں متاثر تھی۔ میں نے پوچھا والد کے علم میں بھی یہ باتیں آ گئیں ہیں؟ انہوں نے کہا کہ ہاں، میں نے پوچھا اور رسول اللہ صلی اللہ علیہ وسلم کے؟ انہوں نے بتایا کہ نبی کریم صلی اللہ علیہ وسلم کے بھی علم میں سب کچھ ہے۔ میں یہ سن کر رونے لگی تو ابوبکر رضی اللہ عنہ نے بھی میری آواز سن لی، وہ گھر کے بالائی حصہ میں قرآن پڑھ رہے تھے، اتر کر نیچے آئے اور والدہ سے پوچھا کہ اسے کیا ہو گیا ہے؟ انہوں نے کہا کہ وہ تمام باتیں اسے بھی معلوم ہو گئی ہیں جو اس کے متعلق کہی جا رہی ہیں۔ ان کی بھی آنکھیں بھر آئیں اور فرمایا: بیٹی! تمہیں قسم دیتا ہوں، اپنے گھر واپس چلی جاؤ چنانچہ میں واپس چلی آئی۔ ( جب میں اپنے والدین کے گھر آ گئی تھی تو ) رسول اللہ صلی اللہ علیہ وسلم میرے حجرہ میں تشریف لائے تھے اور میری خادمہ ( بریرہ ) سے میرے متعلق پوچھا تھا۔ اس نے کہا تھا کہ نہیں، اللہ کی قسم! میں ان کے اندر کوئی عیب نہیں جانتی، البتہ ایسا ہو جایا کرتا تھا ( کم عمری کی غفلت کی وجہ سے ) کہ ( آٹا گوندھتے ہوئے ) سو جایا کرتیں اور بکری آ کر ان کا گندھا ہوا آٹا کھا جاتی۔ رسول اللہ صلی اللہ علیہ وسلم کے بعض صحابہ نے ڈانٹ کر ان سے کہا کہ نبی کریم صلی اللہ علیہ وسلم کو بات صحیح صحیح کیوں نہیں بتا دیتی۔ پھر انہوں نے کھول کر صاف لفظوں میں ان سے واقعہ کی تصدیق چاہی۔ اس پر وہ بولیں کہ سبحان اللہ، میں تو عائشہ رضی اللہ عنہا کو اس طرح جانتی ہوں جس طرح سنار کھرے سونے کو جانتا ہے۔ اس تہمت کی خبر جب ان صاحب کو معلوم ہوئی جن کے ساتھ تہمت لگائی گئی تھی تو انہوں نے کہا کہ سبحان اللہ، اللہ کی قسم! کہ میں نے آج تک کسی ( غیر ) عورت کا کپڑا نہیں کھولا۔ عائشہ رضی اللہ عنہا نے کہا کہ پھر انہوں نے اللہ کے راستے میں شہادت پائی۔ بیان کیا کہ صبح کے وقت میرے والدین میرے پاس آ گئے اور میرے پاس ہی رہے۔ آخر عصر کی نماز سے فارغ ہو کر رسول اللہ صلی اللہ علیہ وسلم بھی تشریف لائے۔ میرے والدین مجھے دائیں اور بائیں طرف سے پکڑے ہوئے تھے، نبی کریم صلی اللہ علیہ وسلم نے اللہ کی حمد و ثنا کی اور فرمایا: امابعد! اے عائشہ! اگر تم نے واقعی کوئی برا کام کیا ہے اور اپنے اوپر ظلم کیا ہے تو پھر اللہ سے توبہ کرو، کیونکہ اللہ اپنے بندوں کی توبہ قبول کرتا ہے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک انصاری خاتون بھی آ گئی تھیں اور دروازے پر بیٹھی ہوئی تھیں، میں نے عرض کی، آپ ان خاتون کا لحاظ نہیں فرماتے کہیں یہ ( اپنی سمجھ کے مطابق کوئی الٹی سیدھی ) بات باہر کہہ دیں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے نصیحت فرمائی، اس کے بعد میں اپنے والد کی طرف متوجہ ہوئی اور ان سے عرض کیا کہ آپ ہی جواب دیجئیے، انہوں نے بھی یہی کہا کہ میں کیا کہوں جب کسی نے میری طرف سے کچھ نہیں کہا تو میں نے شہادت کے بعد اللہ کی شان کے مطابق اس کی حمد و ثنا کی اور کہا: امابعد! اللہ کی قسم! اگر میں آپ لوگوں سے یہ کہوں کہ میں نے اس طرح کی کوئی بات نہیں کی اور اللہ عزوجل گواہ ہے کہ میں اپنے اس دعوے میں سچی ہوں، تو آپ لوگوں کے خیال کو بدلنے میں میری یہ بات مجھے کوئی نفع نہیں پہنچائے گی، کیونکہ یہ بات آپ لوگوں کے دل میں رچ بس گئی ہے اور اگر میں یہ کہہ دوں کہ میں نے واقعتاً یہ کام کیا ہے حالانکہ اللہ خوب جانتا ہے کہ میں نے ایسا نہیں کیا ہے، تو آپ لوگ کہیں گے کہ اس نے تو جرم کا اقرار کر لیا ہے۔ اللہ کی قسم! میری اور آپ لوگوں کی مثال یوسف علیہ السلام کے والد کی سی ہے کہ انہوں نے فرمایا تھا «فصبر جميل والله المستعان على ما تصفون‏» ”پس صبر ہی اچھا ہے اور تم لوگ جو کچھ بیان کرتے ہو اس پر اللہ ہی مدد کرے۔“ میں نے ذہن پر بہت زور دیا کہ یعقوب علیہ السلام کا نام یاد آ جائے لیکن نہیں یاد آیا۔ اسی وقت رسول اللہ صلی اللہ علیہ وسلم پر وحی کا نزول شروع ہو گیا اور ہم سب خاموش ہو گئے۔ پھر آپ سے یہ کیفیت ختم ہوئی تو میں نے دیکھا کہ خوشی نبی کریم صلی اللہ علیہ وسلم کے چہرہ مبارک سے ظاہر ہو رہی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے ( پسینہ سے ) اپنی پیشانی صاف کرتے ہوئے فرمایا کہ عائشہ! تمہیں بشارت ہو اللہ تعالیٰ نے تمہاری پاکی نازل کر دی ہے۔ بیان کیا کہ اس وقت مجھے بڑا غصہ آ رہا تھا۔ میرے والدین نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم کے سامنے کھڑی ہو جاؤ، میں نے کہا کہ اللہ کی قسم! میں نبی کریم صلی اللہ علیہ وسلم کے سامنے کھڑی نہیں ہوں گی نہ آپ کا شکریہ ادا کروں گی اور نہ آپ لوگوں کا شکریہ ادا کروں گی، میں تو صرف اللہ کا شکر ادا کروں گی جس نے میری برات نازل کی ہے۔ آپ لوگوں نے تو یہ افواہ سنی اور اس کا انکار بھی نہ کر سکے، اس کے ختم کرنے کی بھی کوشش نہیں کی۔ عائشہ رضی اللہ عنہا فرماتی تھیں کہ زینب بنت جحش کو اللہ تعالیٰ نے ان کی دینداری کی وجہ سے اس تہمت میں پڑنے سے بچا لیا۔ میری بابت انہوں نے خیر کے سوا اور کوئی بات نہیں کہی، البتہ ان کی بہن حمنہ ہلاک ہونے والوں کے ساتھ ہلاک ہوئیں۔ اس طوفان کو پھیلانے میں مسطح اور حسان اور منافق عبداللہ بن ابی نے حصہ لیا تھا۔ عبداللہ بن ابی منافق ہی تو کھود کھود کر اس کو پوچھتا اور اس پر حاشیہ چڑھاتا، وہی اس طوفان کا بانی مبانی تھا۔ «وهو الذي تولى كبره» سے وہ اور حمنہ مراد ہیں۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر ابوبکر رضی اللہ عنہ نے قسم کھائی کہ مسطح کو کوئی فائدہ آئندہ کبھی وہ نہیں پہنچائیں گے۔ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «ولا يأتل أولو الفضل منكم‏» ”اور جو لوگ تم میں بزرگی والے اور فراخ دست ہیں“ الخ، اس سے مراد ابوبکر رضی اللہ عنہ ہیں۔ ”وہ قرابت والوں اور مسکینوں کو“ اس سے مراد مسطح ہیں۔ ( دینے سے قسم نہ کھا بیٹھیں ) اللہ تعالیٰ کے ارشاد «ألا تحبون أن يغفر الله لكم والله غفور رحيم‏» ”کیا تم یہ نہیں چاہتے کہ اللہ تمہارے قصور معاف کرتا رہے، بیشک اللہ بڑی مغفرت کرنے والا بڑا ہی مہربان ہے“ تک۔ چنانچہ ابوبکر رضی اللہ عنہ نے کہا کہ ہاں، اللہ کی قسم! اے ہمارے رب! ہم تو اسی کے خواہشمند ہیں کہ تو ہماری مغفرت فرما۔ پھر وہ پہلے کی طرح مسطح کو جو دیا کرتے تھے وہ جاری کر دیا۔' WHERE id = 4552;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا ہم سے مسلم نے بیان کیا، ان سے مسروق نے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے کہا ( قیامت کی ) پانچ نشانیاں گزر چکی ہیں۔ دھواں ( اس کا ذکر آیت «يوم تأتي السماء بدخان مبين» میں ہے ) ۔ چاند کا پھٹنا ( اس کا ذکر آیت «اقتربت الساعة وانشق القمر» میں ہے ) ۔ روم کا مغلوب ہونا ( اس کا ذکر سورۃ «غلبت الروم» میں ہے ) ۔ «لبطشة» یعنی اللہ کی پکڑ جو بدر میں ہوئی ( اس کا ذکر «یوم نبطش البطشة الکبرى» میں ہے ) ۔ اور وبال جو قریش پر بدر کے دن آیا ( اس کا ذکر آیت «فسوف یکون لزاما» میں ہے۔)' WHERE id = 4562;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، ان سے جریر نے، ان سے ابوحیان نے، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم ایک دن لوگوں کے ساتھ تشریف رکھتے تھے کہ ایک نیا آدمی خدمت میں حاضر ہوا اور پوچھا: یا رسول اللہ! ایمان کیا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ایمان یہ ہے کہ تم اللہ اور اس کے فرشتوں، رسولوں اور اس کی ملاقات پر ایمان لاؤ اور قیامت کے دن پر ایمان لاؤ۔ انہوں نے پوچھا: یا رسول اللہ! اسلام کیا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسلام یہ ہے کہ تنہا اللہ کی عبادت کرو اور کسی کو اس کا شریک نہ ٹھہراؤ، نماز قائم کرو اور فرض زکوٰۃ ادا کرو اور رمضان کے روزے رکھو۔ انہوں نے پوچھا: یا رسول اللہ! احسان کیا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ احسان یہ ہے کہ تم اللہ کی اس طرح عبادت کرو گویا کہ تم اسے دیکھ رہے ہو ورنہ یہ عقیدہ لازماً رکھو کہ اگر تم اسے نہیں دیکھتے تو وہ تمہیں ضرور دیکھ رہا ہے۔ انہوں نے پوچھا: یا رسول اللہ! قیامت کب قائم ہو گی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس سے پوچھا جا رہا ہے خود وہ سائل سے زیادہ اس کے واقع ہونے کے متعلق نہیں جانتا۔ البتہ میں تمہیں اس کی چند نشانیاں بتاتا ہوں۔ جب عورت ایسی اولاد جنے جو اس کے آقا بن جائیں تو یہ قیامت کی نشانی ہے، جب ننگے پاؤں، ننگے جسم والے لوگ لوگوں پر حاکم ہو جائیں تو یہ قیامت کی نشانی ہے۔ قیامت بھی ان پانچ چیزوں میں سے ہے جسے اللہ کے سوا اور کوئی نہیں جانتا، بیشک اللہ ہی کے پاس قیامت کا علم ہے۔ وہی مینہ برساتا ہے اور وہی جانتا ہے کہ ماں کے رحم میں کیا ہے ( لڑکا یا لڑکی ) پھر وہ صاحب اٹھ کر چلے گئے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں میرے پاس واپس بلا لاؤ۔ لوگوں نے انہیں تلاش کیا تاکہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں دوبارہ لائیں لیکن ان کا کہیں پتہ نہیں تھا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ صاحب جبرائیل تھے ( انسانی صورت میں ) لوگوں کو دین کی باتیں سکھانے آئے تھے۔' WHERE id = 4572;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، کہا ہم سے معلی بن منصور نے بیان کیا، اسے حماد بن زید نے کہا ہم سے ثابت نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ آیت «وتخفي في نفسك ما الله مبديه‏» ”اور آپ اپنے دل میں وہ چھپاتے رہے جسے اللہ ظاہر کرنے والا تھا۔“ زینب بنت جحش رضی اللہ عنہا اور زید بن حارثہ رضی اللہ عنہما کے معاملہ میں نازل ہوئی تھی۔' WHERE id = 4582;
UPDATE hadiths SET urdu = 'مجھ سے سعید بن یحییٰ نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے مسعر نے بیان کیا، ان سے حکم نے، ان سے ابن ابی لیلیٰ نے اور ان سے کعب بن عجرہ رضی اللہ عنہ نے کہ عرض کیا گیا: یا رسول اللہ! آپ پر سلام کا طریقہ تو ہمیں معلوم ہو گیا ہے، لیکن آپ پر «صلاة» کا کیا طریقہ ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یوں پڑھا کرو «اللهم صل على محمد وعلى آل محمد،‏‏‏‏ كما صليت على آل إبراهيم،‏‏‏‏ إنك حميد مجيد،‏‏‏‏ اللهم بارك على محمد وعلى آل محمد،‏‏‏‏ كما باركت على آل إبراهيم،‏‏‏‏ إنك حميد مجيد‏ ‏‏.» ۔' WHERE id = 4592;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبداللہ ذہلی نے بیان کیا، کہا ہم سے محمد بن عبید طنافسی نے، ان سے عوام بن حوشب نے بیان کیا کہ میں نے مجاہد سے سورۃ ص میں سجدہ کے متعلق پوچھا تو انہوں نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے پوچھا تھا کہ اس سورت میں آیت سجدہ کے لیے دلیل کیا ہے؟ انہوں نے کہا کیا تم ( سورت انعام ) میں یہ نہیں پڑھتے «ومن ذريته داود وسليمان‏» کہ ”اور ان کی نسل سے داؤد اور سلیمان ہیں، یہی وہ لوگ ہیں جنہیں اللہ نے یہ ہدایت دی تھی، سو آپ بھی ان کی ہدایت کی اتباع کریں۔“ داؤد علیہ السلام بھی ان میں سے تھے جن کی اتباع کا نبی کریم صلی اللہ علیہ وسلم کو حکم تھا ( چونکہ داؤد علیہ السلام کے سجدہ کا اس میں ذکر ہے اس لیے نبی کریم صلی اللہ علیہ وسلم نے بھی اس موقع پر سجدہ کیا ) ۔ «عجاب‏» کا معنی عجیب۔ «القط» کہتے ہیں کاغذ کے ٹکڑے ( پرچے ) کو یہاں نیکیوں کا پرچہ مراد ہے ( یا حساب کا پرچہ ) ۔ اور مجاہد رحمہ اللہ نے کہا «في عزة‏» کا معنی یہ ہے کہ وہ شرارت و سرکشی کرنے والے ہیں۔ «الملة الآخرة‏» سے مراد قریش کا دین ہے۔ «اختلاق» سے مراد جھوٹ۔ «الأسباب» آسمان کے راستے، دروازے مراد ہیں۔ «جند ما هنالك مهزوم‏» الایۃ سے قریش کے لوگ مراد ہیں۔ «أولئك الأحزاب‏» سے اگلی امتیں مراد ہیں۔ جن پر اللہ کا عذاب اترا۔ «فواق‏» کا معنی پھرنا، لوٹنا۔ «عجل لنا قطنا‏» میں «قط» سے عذاب مراد ہے۔ «اتخذناهم سخريا‏» ہم نے ان کو ٹھٹھے میں گھیر لیا تھا۔ «أتراب» جوڑ والے۔ اور ابن عباس رضی اللہ عنہما نے کہا «أيد» کا معنی عبادت کی قوت۔ «الأبصار» اللہ کے کاموں کو غور سے دیکھنے والے۔ «حب الخير عن ذكر ربي‏» میں «عن من» کے معنی میں ہے۔ «طفق مسحا‏» گھوڑوں کے پاؤں اور ایال پر محبت سے ہاتھ پھیرنا شروع کیا۔ یا بقول بعض تلوار سے ان کو کاٹنے لگے۔ «الأصفاد‏» کے معنی زنجیریں۔' WHERE id = 4602;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، انہوں نے کہا کہ ہم سے منصور نے بیان کیا، انہوں نے کہا کہ ہم سے مجاہد نے بیان کیا، ان سے ابومعمر نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیاکہ خانہ کعبہ کے پاس دو قریشی اور ایک ثقفی یا ایک قریشی اور دو ثقفی مرد بیٹھے ہوئے تھے۔ ان کے پیٹ بہت موٹے تھے لیکن عقل سے کورے۔ ایک نے ان میں سے کہا، تمہارا کیا خیال ہے کیا اللہ ہماری باتوں کو سن رہا ہے؟ دوسرے نے کہا اگر ہم زور سے بولیں تو سنتا ہے لیکن آہستہ بولیں تو نہیں سنتا۔ تیسرے نے کہا اگر اللہ زور سے بولنے پر سن سکتا ہے تو آہستہ بولنے پہ بھی ضرور سنتا ہو گا۔ اس پر یہ آیت اتری «وما كنتم تستترون أن يشهد عليكم سمعكم ولا أبصاركم ولا جلودكم‏» کہ ”اور تم اس بات سے اپنے کو چھپا ہی نہیں سکتے کہ تمہارے کان اور تمہاری آنکھیں اور تمہارے چمڑے گواہی دیں گے۔“ آخر آیت تک۔ سفیان ہم سے یہ حدیث بیان کرتے تھے اور کہا کہ ہم سے منصور نے یا ابن نجیح نے یا حمید نے ان میں سے کسی ایک نے یا کسی دو نے یہ حدیث بیان کی، پھر آپ منصور ہی کا ذکر کرتے تھے اور دوسروں کا ذکر ایک سے زیادہ مرتبہ نہیں کیا۔' WHERE id = 4612;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے، ان سے یوسف بن ماہک نے بیان کیا کہ مروان کو معاویہ رضی اللہ عنہ نے حجاز کا امیر ( گورنر ) بنایا تھا۔ اس نے ایک موقع پر خطبہ دیا اور خطبہ میں یزید بن معاویہ کا باربار ذکر کیا، تاکہ اس کے والد ( معاویہ رضی اللہ عنہ ) کے بعد اس سے لوگ بیعت کریں۔ اس پر عبدالرحمٰن بن ابی بکر رضی اللہ عنہما نے اعتراضاً کچھ فرمایا۔ مروان نے کہا اسے پکڑ لو۔ عبدالرحمٰن اپنی بہن عائشہ رضی اللہ عنہا کے گھر میں چلے گئے تو وہ لوگ پکڑ نہیں سکے۔ اس پر مروان بولا کہ اسی شخص کے بارے میں قرآن کی یہ آیت نازل ہوئی تھی «والذي قال لوالديه أف لكما أتعدانني‏» کہ ”اور جس شخص نے اپنے ماں باپ سے کہا کہ تف ہے تم پر کیا تم مجھے خبر دیتے ہو۔“ اس پر عائشہ رضی اللہ عنہا نے کہا کہ ہمارے ( آل ابی بکر کے ) بارے میں اللہ تعالیٰ نے کوئی آیت نازل نہیں کی بلکہ تہمت سے میری برات ضرور نازل کی تھی۔' WHERE id = 4622;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی سلمہ نے بیان کیا، ان سے ہلال بن ابی ہلال نے، ان سے عطاء بن یسار نے اور ان سے عبداللہ بن عمرو بن عاص نے کہ یہ آیت جو قرآن میں ہے «يا أيها النبي إنا أرسلناك شاهدا ومبشرا ونذيرا‏» ”اے نبی! بیشک ہم نے آپ کو گواہی دینے والا اور ڈرانے والا بنا کر بھیجا ہے۔“ تو نبی کریم صلی اللہ علیہ وسلم کے متعلق یہی اللہ تعالیٰ نے توریت میں بھی فرمایا تھا ”اے نبی! بیشک ہم نے آپ کو گواہی دینے والا اور بشارت دینے والا اور ان پڑھوں ( عربوں ) کی حفاظت کرنے والا بنا کر بھیجا ہے۔ آپ میرے بندے ہیں اور میرے رسول ہیں۔ میں نے آپ کا نام متوکل رکھا، آپ نہ بدخو ہیں اور نہ سخت دل اور نہ بازاروں میں شور کرنے والے اور نہ وہ برائی کا بدلہ برائی سے دیں گے بلکہ معافی اور درگزر سے کام لیں گے اور اللہ ان کی روح اس وقت تک قبض نہیں کرے گا جب تک کہ وہ کج قوم ( عربی ) کو سیدھا نہ کر لیں یعنی جب تک وہ ان سے «لا إله إلا الله» کا اقرار نہ کرا لیں پس اس کلمہ توحید کے ذریعہ وہ اندھی آنکھوں کو اور بہرے کانوں کو اور پردہ پڑے ہوئے دلوں کو کھول دیں گے۔“' WHERE id = 4632;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا، کہا ہم سے حرمی نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جہنم میں دوزخیوں کو ڈالا جائے گا اور وہ کہے گی «هل من مزيد‏.‏» کہ کچھ اور بھی ہے؟ یہاں تک کہ اللہ رب العزت اپنا قدم اس پر رکھے گا اور وہ کہے گی کہ بس بس۔' WHERE id = 4642;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم نخعی نے، ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے آیت «لقد رأى من آيات ربه الكبرى‏» یعنی ”آپ نے اپنے رب کی عظیم نشانیاں دیکھیں“ کے متعلق بتلایا کہ نبی کریم صلی اللہ علیہ وسلم نے «رفرف» ( سبز فرش ) کو دیکھا جس نے آسمان کے کناروں کو ڈھانپ لیا تھا۔' WHERE id = 4652;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے شعبہ نے، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ چاند دو ٹکڑوں میں پھٹ گیا تھا۔' WHERE id = 4662;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا، کہا ہم سے عبدالعزیز بن عبدالصمد العمی نے بیان کیا، کہا ہم سے ابوعمران الجونی نے بیان کیا، ان سے ابوبکر بن عبداللہ بن قیس نے اور ان سے ان کے والد (عبداللہ بن قیس ابوموسیٰ اشعری) نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ( جنت میں ) دو باغ ہوں گے جن کے برتن اور تمام دوسری چیزیں چاندی کی ہوں گی اور دو دوسرے باغ ہوں گے جن کے برتن اور تمام دوسری چیزیں سونے کے ہوں گے اور جنت عدن سے جنتیوں کے اپنے رب کے دیدار میں کوئی چیز سوائے کبریائی کی چادر کے جو اس کے منہ پر ہو گی، حائل نہ ہو گی۔' WHERE id = 4672;
UPDATE hadiths SET urdu = 'مجھ سے یعقوب بن ابراہیم بن کثیر نے بیان کیا، کہا کہ ہم سے اسامہ نے بیان کیا، کہا ہم سے فضیل بن غزوان نے بیان کیا، ان سے ابوحازم اشجعی نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک صاحب خود ( ابوہریرہ رضی اللہ عنہ ) حاضر ہوئے اور عرض کیا: یا رسول اللہ! میں فاقہ سے ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں ازواج مطہرات کے پاس بھیجا ( کہ وہ آپ کی دعوت کریں ) لیکن ان کے پاس کوئی چیز کھانے کی نہیں تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا کوئی شخص ایسا نہیں جو آج رات اس مہمان کی میزبانی کرے؟ اللہ اس پر رحم کرے گا۔ اس پر ایک انصاری صحابی ( ابوطلحہ ) کھڑے ہوئے اور عرض کیا: یا رسول اللہ! یہ آج میرے مہمان ہیں پھر وہ انہیں اپنے ساتھ گھر لے گئے اور اپنی بیوی سے کہا کہ یہ رسول اللہ صلی اللہ علیہ وسلم کے مہمان ہیں، کوئی چیز ان سے بچا کے نہ رکھنا۔ بیوی نے کہا اللہ کی قسم میرے پاس اس وقت بچوں کے کھانے کے سوا اور کوئی چیز نہیں ہے۔ انصاری صحابی نے کہا اگر بچے کھانا مانگیں تو انہیں سلا دو اور آؤ یہ چراغ بھی بجھا دو، آج رات ہم بھوکے ہی رہ لیں گے۔ بیوی نے ایسا ہی کیا۔ پھر وہ انصاری صحابی صبح کے وقت رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے فلاں ( انصاری صحابی ) اور ان کی بیوی ( کے عمل ) کو پسند فرمایا۔ یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) اللہ تعالیٰ مسکرایا پھر اللہ تعالیٰ نے یہ آیت نازل کی «ويؤثرون على أنفسهم ولو كان بهم خصاصة‏» یعنی اور اپنے سے مقدم رکھتے ہیں اگرچہ خود فاقہ میں ہی ہوں۔' WHERE id = 4682;
UPDATE hadiths SET urdu = 'مجھ سے حفص بن عمر نے بیان کیا، کہا ہم سے خالد بن عبداللہ نے بیان کیا، ان سے حصین نے بیان کیا، ان سے سالم بن ابی الجعد نے اور ابوسفیان نے جابر بن عبداللہ رضی اللہ عنہما سے، انہوں نے بیان کیا کہ جمعہ کے دن سامان تجارت لیے ہوئے اونٹ آئے ہم اس وقت نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھے انہیں دیکھ کر سوائے بارہ آدمی کے سب لوگ ادھر ہی دوڑ پڑے۔ اس پر اللہ تبارک و تعالیٰ نے یہ آیت نازل کی «وإذا رأوا تجارة أو لهوا انفضوا إليها‏» الایۃ یعنی اور بعض لوگوں نے جب کبھی ایک سودے یا تماشے کی چیز کو دیکھا تو اس کی طرف دوڑے ہوئے پھیل گئے۔' WHERE id = 4692;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے یحییٰ نے بیان کیا، کہا مجھے ابوسلمہ بن عبدالرحمٰن نے خبر دی، انہوں نے بیان کیا کہ ایک شخص ابن عباس رضی اللہ عنہما کے پاس آیا ابوہریرہ رضی اللہ عنہ بھی ان کے پاس بیٹھے ہوئے تھے۔ آنے والے نے پوچھا کہ آپ مجھے اس عورت کے متعلق مسئلہ بتائیے جس نے اپنے شوہر کی وفات کے چار مہینے بعد بچہ جنا؟ ابن عباس رضی اللہ عنہما نے کہا کہ جس کا خاوند فوت ہو وہ عدت کی دو مدتوں میں جو مدت لمبی ہو اس کی رعایت کرے۔ ( ابوسلمہ نے بیان کیا کہ ) میں نے عرض کیا کہ ( قرآن مجید میں تو ان کی عدت کا یہ حکم ہے ) حمل والیوں کی عدت ان کے حمل کا پیدا ہو جانا ہے۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ میں بھی اس مسئلہ میں اپنے بھتیجے کے ساتھ ہوں۔ ان کی مراد ابوسلمہ بن عبدالرحمٰن سے تھی آخر ابن عباس رضی اللہ عنہما نے اپنے غلام کریب کو ام المؤمنین ام سلمہ رضی اللہ عنہا کی خدمت میں بھیجا یہی مسئلہ پوچھنے کے لیے۔ ام المؤمنین نے بتایا کہ سبیعہ اسلمیہ کے شوہر ( سعد بن خولہ رضی اللہ عنہما ) شہید کر دیئے گئے تھے وہ اس وقت حاملہ تھیں شوہر کی موت کے چالیس دن بعد ان کے یہاں بچہ پیدا ہوا پھر ان کے پاس نکاح کا پیغام پہنچا اور رسول اللہ صلی اللہ علیہ وسلم نے ان کا نکاح کر دیا۔ ابوالسنابل بھی ان کے پاس پیغام نکاح بھیجنے والوں میں سے تھے۔' WHERE id = 4702;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے خالد بن یزید نے، ان سے سعید بن ابی ہلال نے، ان سے زید بن اسلم نے، ان سے عطا بن یسار اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ ہمارا رب قیامت کے دن اپنی پنڈلی کھولے گا اس وقت ہر مومن مرد اور ہر مومنہ عورت اس کے لیے سجدہ میں گر پڑیں گے۔ صرف وہ باقی رہ جائیں گے جو دنیا میں دکھاوے اور ناموری کے لیے سجدہ کرتے تھے۔ جب وہ سجدہ کرنا چاہیں گے تو ان کی پیٹھ تختہ ہو جائے گی اور وہ سجدہ کے لیے نہ مڑ سکیں گے۔' WHERE id = 4712;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے موسیٰ بن ابی عائشہ نے، ان سے سعید بن جبیر نے، ان سے ابن عباس رضی اللہ عنہما نے اللہ تعالیٰ کے ارشاد «لا تحرك به لسانك لتعجل به‏» الایۃ یعنی ”آپ اس کو جلدی جلدی لینے کے لیے اس پر زبان نہ ہلایا کریں“ کے متعلق بتلایا کہ جب جبرائیل آپ پر وحی نازل کرتے تو رسول اللہ صلی اللہ علیہ وسلم اپنی زبان اور ہونٹ ہلایا کرتے تھے اور آپ پر یہ بہت سخت گزرتا، یہ آپ کے چہرے سے بھی ظاہر ہوتا تھا۔ اس لیے اللہ تعالیٰ نے وہ آیت نازل کی جو سورۃ «لا أقسم بيوم القيامة‏» میں ہے یعنی «لا تحرك به لسانك» الایۃ یعنی ”آپ اس کو جلدی جلدی لینے کے لیے اس پر زبان نہ ہلایا کریں۔ یہ تو ہمارے ذمہ ہے اس کا جمع کر دینا اور اس کا پڑھوانا، پھر جب ہم اسے پڑھنے لگیں تو آپ اس کے پیچھے یاد کرتے جایا کریں۔ یعنی جب ہم وحی نازل کریں تو آپ غور سے سنیں۔ پھر اس کا بیان کرا دینا بھی ہمارے ذمہ ہے۔“ یعنی یہ بھی ہمارے ذمہ ہے کہ ہم اسے آپ کی زبانی لوگوں کے سامنے بیان کرا دیں۔ بیان کیا کہ چنانچہ اس کے بعد جب جبرائیل علیہ السلام وحی لے کر آتے تو نبی کریم صلی اللہ علیہ وسلم خاموش ہو جاتے اور جب چلے جاتے تو پڑھتے جیسا کہ اللہ تعالیٰ نے آپ سے وعدہ کیا تھا۔ آیت «أولى لك فأولى‏» میں «تهديد» یعنی ڈرانا دھمکانا مراد ہے۔' WHERE id = 4722;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے عثمان بن اسود نے بیان کیا، انہوں نے ابن ابی ملیکہ سے سنا اور انہوں نے عائشہ رضی اللہ عنہا سے سنا، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا۔' WHERE id = 4733;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے اعمش نے بیان کیا، کہا کہ میں نے سعد بن عبیدہ سے سنا، ان سے ابوعبدالرحمٰن سلمی بیان کرتے تھے کہ علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ایک جنازے میں تشریف رکھتے تھے۔ پھر آپ صلی اللہ علیہ وسلم نے ایک چیز لی اور اس سے زمین کریدنے لگے اور فرمایا، تم میں کوئی ایسا شخص نہیں جس کا جہنم کا ٹھکانا یا جنت کا ٹھکانا لکھا نہ جا چکا ہو۔ صحابہ نے عرض کیا کہ یا رسول اللہ! تو پھر ہم کیوں اپنی تقدیر پر بھروسہ نہ کر لیں اور نیک عمل کرنا چھوڑ دیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نیک عمل کرو، ہر شخص کو ان اعمال کی توفیق دی جاتی ہے جن کے لیے وہ پیدا کیا گیا ہے جو شخص نیک ہو گا اسے نیکوں کے عمل کی توفیق ملی ہوتی ہے اور جو بدبخت ہوتا ہے اسے بدبختوں کے عمل کی توفیق ملتی ہے پھر آپ صلی اللہ علیہ وسلم نے آیت «فأما من أعطى واتقى * وصدق بالحسنى‏» آخر تک پڑھی یعنی ”سو جس نے دیا اور اللہ سے ڈرا اور اچھی بات کو سچا سمجھا، سو ہم اس کے لیے نیک عملوں کو آسان کر دیں گے۔“' WHERE id = 4744;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، میں نے قتادہ سے سنا اور انہوں نے انس بن مالک رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے ابی بن کعب سے فرمایا کہ اللہ تعالیٰ نے مجھے حکم دیا ہے کہ تمہیں سورۃ «لم يكن الذين كفروا‏» پڑھ کر سناؤں۔ ابی بن کعب رضی اللہ عنہ نے عرض کیا، کیا اللہ تعالیٰ نے میرا نام بھی لیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، اس پر وہ رونے لگے۔' WHERE id = 4754;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی شیبہ نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، ان سے سفیان ثوری نے، ان سے حبیب بن ابی ثابت نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ عمر رضی اللہ عنہ نے بوڑھے بدری صحابہ سے اللہ تعالیٰ کے ارشاد «إذا جاء نصر الله والفتح‏» یعنی ”جب اللہ کی مدد اور فتح آ پہنچی“ کے متعلق پوچھا تو انہوں نے جواب دیا کہ اس سے اشارہ بہت سے شہروں اور ملکوں کے فتح ہونے کی طرف ہے۔ عمر رضی اللہ عنہ نے کہا: ابن عباس تمہارا کیا خیال ہے؟ ابن عباس رضی اللہ عنہما نے جواب دیا کہ اس میں آپ کی وفات کی خبر یا ایک مثال ہے گویا آپ کی موت کی آپ کو خبر دی گئی ہے۔' WHERE id = 4764;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا ہم سے سعد مقبری نے بیان کیا، ان سے ان کے والد کیسان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر نبی کو ایسے ایسے معجزات عطا کئے گئے کہ ( انہیں دیکھ کر لوگ ) ان پر ایمان لائے ( بعد کے زمانے میں ان کا کوئی اثر نہیں رہا ) اور مجھے جو معجزہ دیا گیا ہے وہ وحی ( قرآن ) ہے جو اللہ تعالیٰ نے مجھ پر نازل کی ہے۔ ( اس کا اثر قیامت تک باقی رہے گا ) اس لیے مجھے امید ہے کہ قیامت کے دن میرے تابع فرمان لوگ دوسرے پیغمبروں کے تابع فرمانوں سے زیادہ ہوں گے۔' WHERE id = 4775;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عبیداللہ بن عبداللہ نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جبرائیل علیہ السلام نے مجھ کو ( پہلے ) عرب کے ایک ہی محاورے پر قرآن پڑھایا۔ میں نے ان سے کہا ( اس میں بہت سختی ہو گی ) میں برابر ان سے کہتا رہا کہ اور محاوروں میں بھی پڑھنے کی اجازت دو۔ یہاں تک کہ سات محاوروں کی اجازت ملی۔' WHERE id = 4785;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، انہیں اعمش نے، انہیں ابراہیم نخعی نے، ان سے علقمہ نے بیان کیا کہ ہم حمص میں تھے ابن مسعود رضی اللہ عنہ نے سورۃ یوسف پڑھی تو ایک شخص بولا کہ اس طرح نہیں نازل ہوئی تھی۔ ابن مسعود رضی اللہ عنہ نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کے سامنے اس سورت کی تلاوت کی تھی اور آپ نے میری قرآت کی تحسین فرمائی تھی۔ انہوں نے محسوس کیا کہ اس معترض کے منہ سے شراب کی بدبو آ رہی ہے فرمایا کہ اللہ کی کتاب کے متعلق جھوٹا بیان اور شراب پینا جیسے گناہ ایک ساتھ کرتا ہے۔ پھر انہوں نے اس پر حد جاری کرا دی۔' WHERE id = 4795;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، کہا ہم سے ابواسحاق نے بیان کیا اور ان سے براء بن عازب رضی اللہ عنہ نے کہ ایک صحابی ( اسید بن حضیر ) سورۃ الکہف پڑھ رہے تھے۔ ان کے ایک طرف ایک گھوڑا دو رسوں سے بندھا ہوا تھا۔ اس وقت ایک ابر اوپر سے آیا اور نزدیک سے نزدیک تر ہونے لگا۔ ان کا گھوڑا اس کی وجہ سے بدکنے لگا۔ پھر صبح کے وقت وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ سے اس کا ذکر کیا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ ( ابر کا ٹکڑا ) «سكينة» تھا جو قرآن کی تلاوت کی وجہ سے اترا تھا۔' WHERE id = 4805;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، ان سے یحییٰ بن سعید انصاری نے بیان کیا، ان سے سفیان ثوری نے کہا کہ مجھ سے عبداللہ بن دینار نے بیان کیا، کہا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مسلمانو! گزری امتوں کی عمروں کے مقابلہ میں تمہاری عمر ایسی ہے جیسے عصر سے سورج ڈوبنے تک کا وقت ہوتا ہے اور تمہاری اور یہود و نصاریٰ کی مثال ایسی ہے کہ کسی شخص نے کچھ مزدور کام پر لگائے اور ان سے کہا کہ ایک قیراط مزدوری پر میرا کام صبح سے دوپہر تک کون کرے گا؟ یہ کام یہودیوں نے کیا۔ پھر اس نے کہا کہ اب میرا کام آدھے دن سے عصر تک ( ایک ہی قیراط مزدوری پر ) کون کرے گا؟ یہ کام نصاریٰ نے کیا۔ پھر تم نے عصر سے مغرب تک دو دو قیراط مزدوری پر کام کیا۔ یہود و نصاریٰ قیامت کے دن کہیں گے ہم نے کام زیادہ کیا لیکن مزدوری کم پائی؟ اللہ تعالیٰ فرمائے گا کیا تمہارا کچھ حق مارا گیا؟ وہ کہیں گے کہ نہیں۔ پھر اللہ تعالیٰ فرمائے گا کہ پھر یہ میرا فضل ہے، میں جسے چاہوں اور جتنا چاہوں عطا کروں۔' WHERE id = 4815;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ حافظ قرآن کی مثال رسی سے بندھے ہوئے اونٹ کے مالک جیسی ہے اور وہ اس کی نگرانی رکھے گا تو وہ اسے روک سکے گا ورنہ وہ رسی تڑوا کر بھاگ جائے گا۔' WHERE id = 4825;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا کہ مجھ کو عروہ بن زبیر نے مسعود بن مخرمہ اور عبدالرحمٰن بن عبدالقاری سے خبر دی کہ ان دونوں نے عمر بن خطاب رضی اللہ عنہ سے سنا، انہوں نے کہا کہ میں نے ہشام بن حکیم بن حزام رضی اللہ عنہ کو رسول اللہ صلی اللہ علیہ وسلم کی زندگی میں سورۃ الفرقان پڑھتے سنا۔ میں ان کی قرآت کو غور سے سننے لگا تو معلوم ہوا کہ وہ ایسے بہت سے طریقوں میں تلاوت کر رہے تھے جنہیں رسول اللہ صلی اللہ علیہ وسلم نے ہمیں نہیں سکھایا تھا۔ ممکن تھا کہ میں نماز ہی میں ان کا سر پکڑ لیتا لیکن میں نے انتظار کیا اور جب انہوں نے سلام پھیرا تو میں نے ان کے گلے میں چادر لپیٹ دی اور پوچھا یہ سورتیں جنہیں ابھی ابھی تمہیں پڑھتے ہوئے میں نے سنا ہے تمہیں کس نے سکھائی ہیں؟ انہوں نے کہا کہ مجھے اس طرح ان سورتوں کو رسول اللہ صلی اللہ علیہ وسلم نے سکھایا ہے۔ میں نے کہا کہ تم جھوٹ بول رہے ہو۔ خود نبی کریم صلی اللہ علیہ وسلم نے مجھے بھی یہ سورتیں پڑھائی ہیں جو میں نے تم سے سنیں۔ میں انہیں کھینچتے ہوئے آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا: یا رسول اللہ! میں نے خود سنا کہ یہ شخص سورۃ الفرقان ایسی قرآت سے پڑھ رہا تھا۔ جس کی تعلیم آپ نے ہمیں نہیں دی ہے آپ مجھے بھی سورۃ الفرقان پڑھا چکے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہشام! پڑھ کر سناؤ۔ انہوں نے اسی طرح اس کی قرآت کی جس طرح میں ان سے سن چکا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسی طرح یہ سورت نازل ہوئی ہے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ عمر! اب تم پڑھو۔ میں نے بھی اسی طرح قرآت کی جس طرح نبی کریم صلی اللہ علیہ وسلم نے مجھے سکھایا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسی طرح یہ سورت نازل ہوئی تھی۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ قرآن مجید سات قسم کی قراتوں پر نازل ہوا ہے بس تمہارے لیے جو آسان ہو اس کے مطابق پڑھو۔' WHERE id = 4837;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا کہا، ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ مجھ سے ابن شبرمہ نے بیان کیا (جو کوفہ کے قاضی تھے) کہ میں نے غور کیا کہ نماز میں کتنا قرآن پڑھنا کافی ہو سکتا ہے۔ پھر میں نے دیکھا کہ ایک سورت میں تین آیتوں سے کم نہیں ہے۔ اس لیے میں نے یہ رائے قائم کی کہ کسی کے لیے تین آیتوں سے کم پڑھنا مناسب نہیں۔ علی المدینی نے بیان کیا کہ ہم سے سفیان ثوری نے بیان کیا، کہا ہم کو منصور نے خبر دی، انہیں ابراہیم نے، انہیں عبدالرحمٰن بن یزید نے، انہیں علقمہ نے خبر دی اور انہیں ابومسعود رضی اللہ عنہ نے ( علقمہ نے بیان کیا کہ ) میں نے ان سے ملاقات کی تو وہ بیت اللہ کا طواف کر رہے تھے۔ انہوں نے نبی کریم صلی اللہ علیہ وسلم کا ذکر کیا ( کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا ) کہ جس نے سورۃ البقرہ کے آخری کی دو آیتیں رات میں پڑھ لیں وہ اس کے لیے کافی ہیں۔' WHERE id = 4847;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی فلاس نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، ان سے سلام بن ابی مطیع نے بیان کیا، ان سے ابوعمران جونی نے اور ان سے جندب بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس قرآن کو جب ہی تک پڑھو جب تک تمہارے دل ملے جلے یا لگے رہیں۔ جب اختلاف اور جھگڑا کرنے لگو تو اٹھ کھڑے ہو۔ ( قرآن مجید پڑھنا موقوف کر دو ) سلام کے ساتھ اس حدیث کو حارث بن عبید اور سعید بن زید نے بھی ابوعمران جونی سے روایت کیا اور حماد بن سلمہ اور ابان نے اس کو مرفوع نہیں بلکہ موقوفاً روایت کیا ہے اور غندر محمد بن جعفر نے بھی شعبہ سے، انہوں نے ابوعمران سے یوں روایت کیا کہ میں نے جندب سے سنا، وہ کہتے تھے۔ ( لیکن موقوفاً روایت کیا ) اور عبداللہ بن عون نے اس کو ابوعمران سے، انہوں نے عبداللہ بن صامت سے، انہوں نے عمر رضی اللہ عنہ سے ان کا قول روایت کیا ( مرفوعاً نہیں کیا ) اور جندب کی روایت زیادہ صحیح ہے۔' WHERE id = 4858;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ہم سے اسماعیل نے بیان کیا، ان سے قیس نے بیان کیا اور ان سے ابن مسعود رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ جہاد کیا کرتے تھے اور ہمارے ساتھ بیویاں نہیں تھیں۔ اس لیے ہم نے کہا کہ یا رسول اللہ! ہم اپنے آپ کو خصی کیوں نہ کر لیں؟ آپ صلی اللہ علیہ وسلم نے ہمیں اس سے منع فرمایا۔' WHERE id = 4868;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم سے لیث بن سعد نے، ان سے یزید بن حبیب نے، ان سے عراک بن مالک نے اور ان سے عروہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے عائشہ رضی اللہ عنہا سے شادی کے لیے ابوبکر صدیق رضی اللہ عنہ سے کہا۔ ابوبکر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے عرض کی کہ میں آپ کا بھائی ہوں۔ ( تو عائشہ سے کیسے نکاح کریں گے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کے دین اور اس کی کتاب پر ایمان لانے کے رشتہ سے تم میرے بھائی ہو اور عائشہ میرے لیے حلال ہے۔' WHERE id = 4878;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن حمزہ نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے، ان سے ان کے والد سلمہ بن دینار نے، ان سے سہل بن سعد ساعدی نے بیان کیا کہ ایک صاحب ( جو مالدار تھے ) رسول اللہ صلی اللہ علیہ وسلم کے سامنے سے گزرے۔ نبی کریم صلی اللہ علیہ وسلم نے اپنے پاس موجود صحابہ سے پوچھا کہ یہ کیسا شخص ہے؟ صحابہ نے عرض کیا کہ یہ اس لائق ہے کہ اگر یہ نکاح کا پیغام بھیجے تو اس سے نکاح کیا جائے، اگر کسی کی سفارش کرے تو اس کی سفارش قبول کی جائے، اگر کوئی بات کہے تو غور سے سنی جائے۔ سہل نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اس پر چپ ہو رہے۔ پھر ایک دوسرے صاحب گزرے، جو مسلمانوں کے غریب اور محتاج لوگوں میں شمار کئے جاتے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ اس کے متعلق تمہارا کیا خیال ہے؟ صحابہ نے عرض کیا کہ یہ اس قابل ہے کہ اگر کسی کے یہاں نکاح کا پیغام بھیجے تو اس سے نکاح نہ کیا جائے اگر کسی کی سفارش کرے تو اس کی سفارش قبول نہ کی جائے، اگر کوئی بات کہے تو اس کی بات نہ سنی جائے۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ یہ شخص اکیلا پہلے شخص کی طرح دنیا بھر سے بہتر ہے۔' WHERE id = 4888;
UPDATE hadiths SET urdu = 'ہم سے حکم بن نافع نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں عروہ بن زبیر نے خبر دی، انہیں زینب بنت ابی سلمہ نے خبر دی اور انہیں ام المؤمنین ام حبیبہ بنت ابی سفیان نے خبر دی کہ انہوں نے عرض کیا کہ یا رسول اللہ! میری بہن ( ابوسفیان کی لڑکی ) سے نکاح کر لیجئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا تم اسے پسند کرو گی ( کہ تمہاری سوکن بہن بنے ) ؟ میں نے عرض کیا جی ہاں، میں تو پسند کرتی ہوں اگر میں اکیلی آپ کی بیوی ہوتی تو پسند نہ کرتی۔ پھر میری بہن اگر میرے ساتھ بھلائی میں شریک ہو تو میں کیونکر نہ چاہوں گی ( غیروں سے تو بہن ہی اچھی ہے ) آپ صلی اللہ علیہ وسلم نے فرمایا وہ میرے لیے حلال نہیں ہے۔ ام حبیبہ رضی اللہ عنہا نے کہا: یا رسول اللہ! لوگ کہتے ہیں آپ ابوسلمہ کی بیٹی سے جو ام سلمہ کے پیٹ سے ہے، نکاح کرنے والے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر وہ میری ربیبہ اور میری پرورش میں نہ ہوتی ( یعنی میری بیوی کی بیٹی نہ ہوتی ) جب بھی میرے لیے حلال نہ ہوتی۔ وہ دوسرے رشتے سے میری دودھ بھتیجی ہے، مجھ کو اور ابوسلمہ کے باپ کو دونوں کو ثوبیہ نے دودھ پلایا ہے۔ دیکھو، ایسا مت کرو اپنی بیٹیوں اور بہنوں کو مجھ سے نکاح کرنے کے لیے نہ کہو۔ عروہ راوی نے کہا ثوبیہ ابولہب کی لونڈی تھی۔ ابولہب نے اس کو آزاد کر دیا تھا۔ ( جب اس نے نبی کریم صلی اللہ علیہ وسلم کے پیدا ہونے کی خبر ابولہب کو دی تھی ) پھر اس نے نبی کریم صلی اللہ علیہ وسلم کو دودھ پلایا تھا جب ابولہب مر گیا تو اس کے کسی عزیز نے مرنے کے بعد اس کو خواب میں برے حال میں دیکھا تو پوچھا کیا حال ہے کیا گزری؟ وہ کہنے لگا جب سے میں تم سے جدا ہوا ہوں کبھی آرام نہیں ملا مگر ایک ذرا سا پانی ( پیر کے دن مل جاتا ہے ) ابولہب نے اس گڑھے کی طرف اشارہ کیا جو انگوٹھے اور کلمہ کے انگلی کے بیچ میں ہوتا ہے یہ بھی اس وجہ سے کہ میں نے ثوبیہ کو آزاد کر دیا تھا۔' WHERE id = 4898;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے محمد بن فضیل نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے بیان کیا کہ خولہ بنت حکیم رضی اللہ عنہا ان عورتوں میں سے تھیں جنہوں نے اپنے آپ کو رسول اللہ صلی اللہ علیہ وسلم کے لیے ہبہ کیا تھا۔ اس پر عائشہ رضی اللہ عنہا نے کہا کہ ایک عورت اپنے آپ کو کسی مرد کے لیے ہبہ کرتے شرماتی نہیں۔ پھر جب آیت «ترجئ من تشاء منهن‏» ”اے پیغمبر! تو اپنی جس بیوی کو چاہے پیچھے ڈال دے اور جسے چاہے اپنے پاس جگہ دے“ نازل ہوئی تو میں نے کہا: یا رسول اللہ! اب میں سمجھی اللہ تعالیٰ جلد جلد آپ کی خوشی کو پورا کرتا ہے۔ اس حدیث کو ابوسعید ( محمد بن مسلم ) ، مؤدب اور محمد بن بشر اور عبدہ بن سلیمان نے بھی ہشام سے، انہوں نے اپنے والد سے، انہوں نے عائشہ رضی اللہ عنہا سے روایت کیا ہے۔ ایک نے دوسرے سے کچھ زیادہ مضمون نقل کیا ہے۔' WHERE id = 4909;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ( نکاح سے پہلے ) میں نے تمہیں خواب میں دیکھا کہ ایک فرشتہ ( جبرائیل علیہ السلام ) ریشم کے ایک ٹکڑے میں تمہیں لپیٹ کر لے آیا ہے اور مجھ سے کہہ رہا ہے کہ یہ تمہاری بیوی ہے۔ میں نے اس کے چہرے سے کپڑا ہٹایا تو وہ تم تھیں۔ میں نے کہا کہ اگر یہ خواب اللہ کی طرف سے ہے تو وہ اسے خود ہی پورا کر دے گا۔' WHERE id = 4920;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم سے امام مالک نے خبر دی، انہیں ابوحازم مسلم بن دینار نے اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ ایک عورت رسول اللہ صلی اللہ علیہ وسلم کے پاس آئی اور کہا کہ میں اپنے آپ کو آپ کے لیے ہبہ کرتی ہوں۔ پھر وہ دیر تک کھڑی رہی۔ اتنے میں ایک مرد نے کہا کہ اگر نبی کریم صلی اللہ علیہ وسلم کو اس کی ضرورت نہ ہو تو اس کا نکاح مجھ سے فرما دیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تمہارے پاس انہیں مہر میں دینے کے لیے کوئی چیز ہے؟ اس نے کہا کہ میرے پاس اس تہمد کے سوا اور کچھ نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر تم اپنا یہ تہمد اس کو دے دو گے تو تمہارے پاس پہننے کے لیے تہمد بھی نہیں رہے گا۔ کوئی اور چیز تلاش کر لو۔ اس مرد نے کہا کہ میرے پاس کچھ بھی نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کچھ تو تلاش کرو، ایک لوہے کی انگوٹھی ہی سہی! اسے وہ بھی نہیں ملی تو نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا۔ کیا تمہارے پاس کچھ قرآن مجید ہے؟ انہوں نے عرض کیا کہ جی ہاں! فلاں فلاں سورتیں ہیں، ان سورتوں کا انہوں نے نام لیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر ہم نے تیرا نکاح اس عورت سے ان سورتوں کے کے بدلے کیا جو تم کو یاد ہیں۔' WHERE id = 4930;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے بشر بن مفضل نے بیان کیا، کہا ہم سے خالد بن ذکوان نے بیان کیا، کہ ربیع بنت معوذ ابن عفراء رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور جب میں دلہن بنا کر بٹھائی گئی نبی کریم صلی اللہ علیہ وسلم اندر تشریف لائے اور میرے بستر پر بیٹھے اسی طرح جیسے تم اس وقت میرے پاس بیٹھے ہوئے ہو۔ پھر ہمارے یہاں کی کچھ لڑکیاں دف بجانے لگیں اور میرے باپ اور چچا جو جنگ بدر میں شہید ہوئے تھے، ان کا مرثیہ پڑھنے لگیں۔ اتنے میں، ان میں سے ایک لڑکی نے پڑھا، اور ہم میں ایک نبی ہے جو ان باتوں کی خبر رکھتے ہے جو کچھ کل ہونے والی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ چھوڑ دو۔ اس کے سوا جو کچھ تم پڑھ رہی تھیں وہ پڑھو۔' WHERE id = 4941;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے عبداللہ بن المبارک نے بیان کیا، ان سے معمر بن راشد نے، ان سے ہمام نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ گزشتہ انبیاء میں سے ایک نبی ( یوشع علیہ السلام یا داؤد علیہ السلام ) نے غزوہ کیا اور ( غزوہ سے پہلے ) اپنی قوم سے کہا کہ میرے ساتھ کوئی ایسا شخص نہ چلے جس نے کسی نئی عورت سے شادی کی ہو اور اس کے ساتھ صحبت کرنے کا ارادہ رکھتا ہو اور ابھی صحبت نہ کی ہو۔' WHERE id = 4951;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ مجھ سے حمید طویل نے بیان کیا اور انہوں نے انس رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے عبدالرحمٰن بن عوف رضی اللہ عنہ سے پوچھا، انہوں نے قبیلہ انصار کی ایک عورت سے شادی کی تھی کہ مہر کتنا دیا ہے؟ انہوں نے کہا کہ ایک گٹھلی کے وزن کے برابر سونا۔ اور حمید سے روایت ہے کہ میں نے انس رضی اللہ عنہ سے سنا اور انہوں نے بیان کیا کہ جب ( نبی کریم صلی اللہ علیہ وسلم اور مہاجرین صحابہ ) مدینہ ہجرت کر کے آئے تو مہاجرین نے انصار کے یہاں قیام کیا عبدالرحمٰن بن عوف رضی اللہ عنہ نے سعد بن ربیع رضی اللہ عنہ کے یہاں قیام کیا۔ سعد رضی اللہ عنہ نے ان سے کہا کہ میں آپ کو اپنا مال تقسیم کر دوں گا اور اپنی دو بیویوں میں سے ایک کو آپ کے لیے چھوڑ دوں گا۔ عبدالرحمٰن نے کہا کہ اللہ آپ کے اہل و عیال اور مال میں برکت دے پھر وہ بازار نکل گئے اور وہاں تجارت شروع کی اور پنیر اور گھی نفع میں کمایا۔ اس کے بعد شادی کی تو نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ دعوت ولیمہ کر خواہ ایک بکری ہی کی ہو۔' WHERE id = 4961;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ولیمہ کا وہ کھانا بدترین کھانا ہے جس میں صرف مالداروں کو اس کی طرف دعوت دی جائے اور محتاجوں کو نہ کھلایا جائے اور جس نے ولیمہ کی دعوت قبول کرنے سے انکار کیا اس نے اللہ اور اس کے رسول کی نافرمانی کی۔' WHERE id = 4971;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن عبدالرحمٰن اور علی بن حجر نے بیان کیا، ان دونوں نے کہا کہ ہم کو عیسیٰ بن یونس نے خبر دی، اس نے کہا کہ ہم سے ہشام بن عروہ نے بیان کیا، انہوں نے اپنے بھائی عبداللہ بن عروہ سے، انہوں نے اپنے والد عروہ بن زبیر سے، انہوں نے عائشہ رضی اللہ عنہا سے انہوں نے کہا کہ گیارہ عورتوں کا ایک اجتماع ہوا جس میں انہوں نے آپس میں یہ طے کیا کہ مجلس میں وہ اپنے اپنے خاوند کا صحیح صحیح حال بیان کریں کوئی بات نہ چھپاویں۔ چنانچہ پہلی عورت ( نام نامعلوم ) بولی میرے خاوند کی مثال ایسی ہے جیسے دبلے اونٹ کا گوشت جو پہاڑ کی چوٹی پر رکھا ہوا ہو نہ تو وہاں تک جانے کا راستہ صاف ہے کہ آسانی سے چڑھ کر اس کو کوئی لے آوے اور نہ وہ گوشت ہی ایسا موٹا تازہ ہے جسے لانے کے لیے اس پہاڑ پر چڑھنے کی تکلیف گوارا کرے۔ دوسری عورت ( عمرہ بنت عمرو تمیمی نامی ) کہنے لگی میں اپنے خاوند کا حال بیان کروں تو کہاں تک بیان کروں ( اس میں اتنے عیب ہیں ) میں ڈرتی ہوں کہ سب بیان نہ کر سکوں گی اس پر بھی اگر بیان کروں تو اس کے کھلے اور چھپے سارے عیب بیان کر سکتی ہوں۔ تیسری عورت ( حیی بنت کعب یمانی ) کہنے لگی، میرا خاوند کیا ہے ایک تاڑ کا تاڑ ( لمبا تڑنگا ) ہے اگر اس کے عیب بیان کروں تو طلاق تیار ہے اگر خاموش رہوں تو ادھر لٹکی رہوں۔ چوتھی عورت ( مہدو بنت ابی ہرومہ ) کہنے لگی کہ میرا خاوند ملک تہامہ کی رات کی طرح معتدل نہ زیادہ گرم نہ بہت ٹھنڈا نہ اس سے مجھ کو خوف ہے نہ اکتاہٹ ہے۔ پانچوں عورت ( کبشہ نامی ) کہنے لگی کہ میرا خاوند ایسا ہے کہ گھر میں آتا ہے تو وہ ایک چیتا ہے اور جب باہر نکلتا ہے تو شیر ( بہادر ) کی طرح ہے۔ جو چیز گھر میں چھوڑ کر جاتا ہے اس کے بارے میں پوچھتا ہی نہیں ( کہ وہ کہاں گئی؟ ) اتنا بےپرواہ ہے جو آج کمایا اسے کل کے لیے اٹھا کر رکھتا ہی نہیں اتنا سخی ہے۔ چھٹی عورت ( ہند نامی ) کہنے لگی کہ میرا خاوند جب کھانے پر آتا ہے تو سب کچھ چٹ کر جاتا ہے اور جب پینے پر آتا ہے تو ایک بوند بھی باقی نہیں چھوڑتا اور جب لیٹتا ہے تو تنہا ہی اپنے اوپر کپڑا لپیٹ لیتا ہے اور الگ پڑ کر سو جاتا ہے میرے کپڑے میں کبھی ہاتھ بھی نہیں ڈالتا کہ کبھی میرا دکھ درد کچھ تو معلوم کرے۔ ساتویں عورت ( حیی بنت علقمہ ) میرا خاوند تو جاہل یا مست ہے۔ صحبت کے وقت اپنا سینہ میرے سینے سے اوندھا پڑ جاتا ہے۔ دنیا میں جتنے عیب لوگوں میں ایک ایک کر کے جمع ہیں وہ سب اس کی ذات میں جمع ہیں ( کم بخت سے بات کروں تو ) سر پھوڑ ڈالے یا ہاتھ توڑ ڈالے یا دونوں کام کر ڈالے۔ آٹھویں عورت ( یاسر بنت اوس ) کہنے لگی میرا خاوند چھونے میں خرگوش کی طرح نرم ہے اور خوشبو میں سونگھو تو زعفران جیسا خوشبودار ہے۔ نویں عورت ( نام نامعلوم ) کہنے لگی کہ میرے خاوند کا گھر بہت اونچا اور بلند ہے وہ قدآور بہادر ہے، اس کے یہاں کھانا اس قدر پکتا ہے کہ راکھ کے ڈھیر کے ڈھیر جمع ہیں۔ ( غریبوں کو خوب کھلاتا ہے ) لوگ جہاں صلاح و مشورہ کے لیے بیٹھتے ہیں ( یعنی پنچائت گھر ) وہاں سے اس کا گھر بہت نزدیک ہے۔ دسویں عورت ( کبشہ بنت رافع ) کہنے لگی میرے خاوند کا کیا پوچھنا جائیداد والا ہے، جائیداد بھی کیسی بڑی جائیداد ویسی کسی کے پاس نہیں ہو سکتی بہت سارے اونٹ جو جابجا اس کے گھر کے پاس جٹے رہتے ہیں اور جنگل میں چرنے کم جاتے ہیں۔ جہاں ان اونٹوں نے باجے کی آواز سنی بس ان کو اپنے ذبح ہونے کا یقین ہو گیا۔ گیارھویں عورت ( ام زرع بنت اکیمل بنت ساعدہ ) کہنے لگی میرا خاوند ابوزرع ہے اس کا کیا کہنا اس نے میرے کانوں کو زیوروں سے بوجھل کر دیا ہے اور میرے دونوں بازو چربی سے پھلا دئیے ہیں مجھے خوب کھلا کر موٹا کر دیا ہے کہ میں بھی اپنے تئیں خوب موٹی سمجھنے لگی ہوں۔ شادی سے پہلے میں تھوڑی سے بھیڑ بکریوں میں تنگی سے گزر بسر کرتی تھی۔ ابوزرعہ نے مجھ کو گھوڑوں، اونٹوں، کھیت کھلیان سب کا مالک بنا دیا ہے اتنی بہت جائیداد ملنے پر بھی اس کا مزاج اتنا عمدہ ہے کہ بات کہوں تو برا نہیں مانتا مجھ کو کبھی برا نہیں کہتا۔ سوئی پڑی رہوں تو صبح تک مجھے کوئی نہیں جگاتا۔ پانی پیوں تو خوب سیراب ہو کر پی لوں رہی ابوزرعہ کی ماں ( میری ساس ) تو میں اس کی کیا خوبیاں بیان کروں۔ اس کا توشہ کھانا مال و اسباب سے بھرا ہوا، اس کا گھر بہت ہی کشادہ۔ ابوزرعہ کا بیٹا وہ بھی کیسا اچھا خوبصورت ( نازک بدن دبلا پتلا ) ہری چھالی یا ننگی تلوار کے برابر اس کے سونے کی جگہ ایسا کم خوراک کہ بکری کے چار ماہ کے بچے کا دست کا گوشت اس کا پیٹ بھر دے۔ ابوزرعہ کی بیٹی وہ بھی سبحان اللہ کیا کہنا اپنے باپ کی پیاری، اپنی ماں کی پیاری ( تابع فرمان اطاعت گزار ) کپڑا بھر پور پہننے والی ( موٹی تازی ) سوکن کی جلن۔ ابوزرعہ کی لونڈی اس کی بھی کیا پوچھتے ہو کبھی کوئی بات ہماری مشہور نہیں کرتی ( گھر کا بھید ہمیشہ پوشیدہ رکھتی ہے ) کھانے تک نہیں چراتی گھر میں کوڑا کچڑا نہیں چھوڑتی مگر ایک دن ایسا ہوا کہ لوگ مکھن نکالنے کو دودھ متھ رہے تھے۔ ( صبح ہی صبح ) ابوزرعہ باہر گیا اچانک اس نے ایک عورت دیکھی جس کے دو بچے چیتوں کی طرح اس کی کمر کے تلے دو اناروں سے کھیل رہے تھے ( مراد اس کی دونوں چھاتیاں ہیں جو انار کی طرح تھیں ) ۔ ابوزرعہ نے مجھ کو طلاق دے کر اس عورت سے نکاح کر لیا۔ اس کے بعد میں نے ایک اور شریف سردار سے نکاح کر لیا جو گھوڑے کا اچھا سوار، عمدہ نیزہ باز ہے، اس نے بھی مجھ کو بہت سے جانور دے دئیے ہیں اور ہر قسم کے اسباب میں سے ایک ایک جوڑا دیا ہوا ہے اور مجھ سے کہا کرتا ہے کہ ام زرع! خوب کھا پی، اپنے عزیز و اقرباء کو بھی خوب کھلا پلا تیرے لیے عام اجازت ہے مگر یہ سب کچھ بھی جو میں نے تجھ کو دیا ہوا ہے اگر اکٹھا کروں تو تیرے پہلے خاوند ابوزرعہ نے جو تجھ کو دیا تھا، اس میں کا ایک چھوٹا برتن بھی نہ بھرے۔' WHERE id = 4982;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو اوزاعی نے خبر دی، کہا کہ مجھ سے یحییٰ ابن ابی کثیر نے بیان کیا، کہا کہ مجھ سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا، کہا کہ مجھ سے عبداللہ بن عمرو بن العاص رضی اللہ عنہما نے بیان کیا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ عبداللہ! کیا میری یہ اطلاع صحیح ہے کہ تم ( روزانہ ) دن میں روزے رکھتے ہو اور رات بھر عبادت کرتے ہو؟ میں نے عرض کیا: جی ہاں یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ایسا نہ کرو، روزے بھی رکھو اور بغیر روزے بھی رہو۔ رات میں عبادت بھی کرو اور سوؤ بھی۔ کیونکہ تمہارے بدن کا بھی تم پر حق ہے، تمہاری آنکھ کا بھی تم پر حق ہے اور تمہاری بیوی کا بھی تم پر حق ہے۔' WHERE id = 4992;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عبدالواحد بن ایمن نے، کہا کہ مجھ سے ابن ابی ملیکہ نے، ان سے قاسم نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم جب سفر کا ارادہ کرتے تو اپنی ازواج کے لیے قرعہ ڈالتے۔ ایک مرتبہ قرعہ عائشہ اور حفصہ رضی اللہ عنہما کے نام نکلا۔ نبی کریم صلی اللہ علیہ وسلم رات کے وقت معمولاً چلتے وقت عائشہ رضی اللہ عنہا کے ساتھ باتیں کرتے ہوئے چلتے۔ ایک مرتبہ حفصہ رضی اللہ عنہا نے ان سے کہا کہ آج رات کیوں نہ تم میرے اونٹ پر سوار ہو جاؤ اور میں تمہارے اونٹ پر تاکہ تم بھی نئے مناظر دیکھ سکو اور میں بھی۔ انہوں نے یہ تجویز قبول کر لی اور ( ہر ایک دوسرے کے اونٹ پر ) سوار ہو گئیں۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم عائشہ کے اونٹ کے پاس تشریف لائے۔ اس وقت اس پر حفصہ رضی اللہ عنہا بیٹھی ہوئی تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں سلام کیا، پھر چلتے رہے، جب پڑاؤ ہوا تو نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوا کہ عائشہ رضی اللہ عنہا اس میں نہیں ہیں ( اس غلطی پر عائشہ کو اس درجہ رنج ہوا کہ ) جب لوگ سواریوں سے اتر گئے تو ام المؤمنین نے اپنے پاؤں اذخر گھاس میں ڈال لیے اور دعا کرنے لگی کہ اے میرے رب! مجھ پر کوئی بچھو یا سانپ مسلط کر دے جو مجھ کو ڈس لے۔ عائشہ رضی اللہ عنہا کہتی ہیں کہ میں نبی کریم صلی اللہ علیہ وسلم سے تو کچھ کہہ نہیں سکتی تھی کیونکہ یہ حرکت خود میری ہی تھی۔' WHERE id = 5003;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد عروہ بن زبیر نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اے امت محمد! اللہ سے بڑھ کر غیرت مند اور کوئی نہیں کہ وہ اپنے بندے یا بندی کو زنا کرتے ہوئے دیکھے۔ اے امت محمد! اگر تمہیں وہ معلوم ہوتا جو مجھے معلوم ہے تو تم ہنستے کم اور روتے زیادہ۔' WHERE id = 5013;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر حوضی نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میں تم سے وہ حدیث بیان کروں گا جو میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنی ہے، میرے سوا یہ حدیث تم سے کوئی اور نہیں بیان کرنے والا ہے۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ قیامت کی نشانیوں میں سے یہ بھی ہے کہ قرآن و حدیث کا علم اٹھا لیا جائے گا اور جہالت بڑھ جائے گی۔ زنا کی کثرت ہو جائے گی اور شراب لوگ زیادہ پینے لگیں گے۔ مرد کم ہو جائیں گے اور عورتوں کی تعداد زیادہ ہو جائے گی۔ حالت یہ ہو جائے گی کہ پچاس پچاس عورتوں کا سنبھالنے والا ( خبر گیر ) ایک مرد ہو گا۔' WHERE id = 5023;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے اعمش نے بیان کیا، کہا کہ مجھ سے شقیق نے بیان کیا، کہا میں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کوئی عورت کسی عورت سے مل کر اپنے شوہر سے اس کے حلیہ نہ بیان کرے گویا کہ وہ اسے دیکھ رہا ہے۔' WHERE id = 5033;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ اویسی نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ انہوں نے اپنی بیوی ( آمنہ بنت غفار ) کو رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں ( حالت حیض میں ) طلاق دے دی۔ عمر بن خطاب رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے اس کے متعلق پوچھا: تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ عبداللہ بن عمر رضی اللہ عنہما سے کہو کہ اپنی بیوی سے رجوع کر لیں اور پھر اپنے نکاح میں باقی رکھیں۔ جب ماہواری ( حیض ) بند ہو جائے، پھر ماہواری آئے اور پھر بند ہو، تب اگر چاہیں تو اپنی بیوی کو اپنی نکاح میں باقی رکھیں اور اگر چاہیں تو طلاق دے دیں ( لیکن طلاق اس طہر میں ) ان کے ساتھ ہمبستری سے پہلے ہونا چاہئے۔ یہی ( طہر کی ) وہ مدت ہے جس میں اللہ تعالیٰ نے عورتوں کو طلاق دینے کا حکم دیا ہے۔' WHERE id = 5043;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن قطان نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، کہا ہم سے عامر نے بیان کیا، ان سے مسروق نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے ”اختیار“ کے متعلق سوال کیا تو انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں اختیار دیا تھا تو کیا محض یہ اختیار طلاق بن جاتا۔ مسروق نے کہا کہ اختیار دینے کے بعد اگر تم مجھے پسند کر لیتی ہو تو اس کی کوئی حیثیت نہیں، چاہے میں ایک مرتبہ اختیار دوں یا سو مرتبہ ( طلاق نہیں ہو گی ) ۔' WHERE id = 5055;
UPDATE hadiths SET urdu = 'اور ابن ابی تمیمہ سے روایت ہے، ان سے عکرمہ نے، ان سے ابن عباس رضی اللہ عنہما نے، انہوں نے بیان کیا کہ ثابت بن قیس رضی اللہ عنہ کی بیوی رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور عرض کیا: یا رسول اللہ! مجھے ثابت کے دین اور ان کے اخلاق کی وجہ سے کوئی شکایت نہیں ہے لیکن میں ان کے ساتھ گزارہ نہیں کر سکتی۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ پھر کیا تم ان کا باغ واپس کر سکتی ہو؟ انہوں نے عرض کیا جی ہاں۔' WHERE id = 5066;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے نافع نے کہ ابن عمر رضی اللہ عنہما سے اگر یہودی یا انصاری عورتوں سے نکاح کے متعلق سوال کیا جاتا تو وہ کہتے کہ اللہ تعالیٰ نے مشرک عورتوں سے نکاح مومنوں کے لیے حرام قرار دیا ہے اور میں نہیں سمجھتا کہ اس سے بڑھ کر اور کیا شرک ہو گا کہ ایک عورت یہ کہے کہ اس کے رب عیسیٰ علیہ السلام ہیں حالانکہ وہ اللہ کے مقبول بندوں میں سے ایک مقبول بندے ہیں۔' WHERE id = 5076;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے ابواسحاق شیبانی نے اور ان سے عبداللہ بن ابی اوفی نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھے۔ جب سورج ڈوب گیا تو نبی کریم صلی اللہ علیہ وسلم نے ایک صحابی ( بلال رضی اللہ عنہ ) سے فرمایا کہ اتر کر میرے لیے ستو گھول ( کیونکہ آپ صلی اللہ علیہ وسلم روزہ سے تھے ) انہوں نے عرض کیا: یا رسول اللہ! اگر اندھیرا ہونے دیں تو بہتر ہے۔ نبی کریم صلی اللہ علیہ وسلم نے پھر فرمایا کہ اتر کر ستو گھول۔ انہوں نے عرض کیا: یا رسول اللہ! اگر آپ اور اندھیرا ہو لینے دیں تو بہتر ہے، ابھی دن باقی ہے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اترو اور ستو گھول لو۔ آخر تیسری مرتبہ کہنے پر انہوں نے اتر کر نبی کریم صلی اللہ علیہ وسلم کا ستو گھولا۔ نبی کریم صلی اللہ علیہ وسلم نے اسے پیا، پھر آپ نے اپنے ہاتھ سے مشرق کی طرف اشارہ کیا اور فرمایا کہ جب تم دیکھو کہ رات ادھر سے آ رہی ہے تو روزہ دار کو افطار کر لینا چاہیئے۔' WHERE id = 5088;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے ابن ابی عدی نے بیان کیا، ان سے ہشام بن حسان نے، کہا کہ ہم سے عکرمہ نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے کہ ہلال بن امیہ نے اپنی بیوی پر تہمت لگائی، پھر وہ آئے اور گواہی دی۔ نبی کریم صلی اللہ علیہ وسلم نے اس وقت فرمایا کہ اللہ خوب جانتا ہے کہ تم میں سے ایک جھوٹا ہے، تو کیا تم میں سے کوئی ( جو واقعی گناہ کا مرتکب ہوا ہو ) رجوع کرے گا؟ اس کے بعد ان کی بیوی کھڑی ہوئیں اور انہوں نے گواہی دی اپنے بَری ہونے کی۔' WHERE id = 5098;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے (دوسری سند اور امام بخاری رحمہ اللہ نے کہا کہ) ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے عبدہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رفاعہ قرظی رضی اللہ عنہ نے ایک خاتون سے نکاح کیا، پھر انہیں طلاق دے دی، اس کے بعد ایک دوسرے صاحب نے ان خاتون سے نکاح کر لیا، پھر وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور اپنے دوسرے شوہر کا ذکر کیا اور کہا کہ وہ تو ان کے پاس آتے ہی نہیں اور یہ کہ ان کے پاس کپڑے کے پلو جیسا ہے ( انہوں نے پہلے شوہر کے ساتھ دوبارہ نکاح کی خواہش ظاہر کی لیکن ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں، جب تک تم اس ( دوسرے شوہر ) کا مزا نہ چکھ لو اور یہ تمہارا مزا نہ چکھ لیں۔' WHERE id = 5108;
UPDATE hadiths SET urdu = 'حمید نے بیان کیا کہ میں نے زینب بنت ام سلمہ رضی اللہ عنہا سے پوچھا کہ اس کا کیا مطلب ہے کہ ”سال بھر تک مینگنی پھینکنی پڑتی تھی؟“ انہوں نے فرمایا کہ زمانہ جاہلیت میں جب کسی عورت کا شوہر مر جاتا تو وہ ایک نہایت تنگ و تاریک کوٹھڑی میں داخل ہو جاتی۔ سب سے برے کپڑے پہنتی اور خوشبو کا استعمال ترک کر دیتی۔ یہاں تک کہ اسی حالت میں ایک سال گزر جاتا پھر کسی چوپائے گدھے یا بکری یا پرندہ کو اس کے پاس لایا جاتا اور وہ عدت سے باہر آنے کے لیے اس پر ہاتھ پھیرتی۔ ایسا کم ہوتا تھا کہ وہ کسی جانور پر ہاتھ پھیر دے اور وہ مر نہ جائے۔ اس کے بعد وہ نکالی جاتی اور اسے مینگنی دی جاتی جسے وہ پھینکتی۔ اب وہ خوشبو وغیرہ کوئی بھی چیز استعمال کر سکتی تھی۔ امام مالک سے پوچھا گیا کہ «تفتض به» کا کیا مطلب ہے تو آپ نے فرمایا وہ اس کا جسم چھوتی تھی۔' WHERE id = 5124;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ بن حجاج نے بیان کیا، کہا ہم سے عون بن ابی جحیفہ نے بیان کیا، ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے گودنے والی اور گدوانے والی، سود کھانے والے اور کھلانے والے پر لعنت بھیجی اور آپ نے کتے کی قیمت اور زانیہ کی کمائی کھانے سے منع فرمایا اور تصویر بنانے والوں پر لعنت کی۔' WHERE id = 5134;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو وکیع نے خبر دی، ان سے ابن عیینہ نے کہا کہ مجھ سے معمر نے بیان کیا کہ ان سے ثوری نے پوچھا کہ تم نے ایسے شخص کے بارے میں بھی سنا ہے جو اپنے گھر والوں کے لیے سال بھر کا یا سال سے کم کا خرچ جمع کر لے۔ معمر نے بیان کیا کہ اس وقت مجھے یاد نہیں آیا پھر بعد میں یاد آیا کہ اس بارے میں ایک حدیث ابن شہاب نے ہم سے بیان کی تھی، ان سے مالک بن اوس نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم بنی نضیر کے باغ کی کھجوریں بیچ کر اپنے گھر والوں کے لیے سال بھر کی روزی جمع کر دیا کرتے تھے۔' WHERE id = 5144;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے حماد بن زید نے، ان سے عمرو نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ میرے والد شہید ہو گئے اور انہوں نے سات لڑکیاں چھوڑیں یا ( راوی نے کہا کہ ) نو لڑکیاں۔ چنانچہ میں نے ایک پہلے کی شادی شدہ عورت سے نکاح کیا۔ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے دریافت فرمایا کہ جابر! تم نے شادی کی ہے؟ میں نے کہا جی ہاں۔ فرمایا، کنواری سے یا بیاہی سے۔ میں نے عرض کیا کہ بیاہی سے۔ فرمایا تم نے کسی کنواری لڑکی سے شادی کیوں نہ کی۔ تم اس کے ساتھ کھیلتے اور وہ تمہارے ساتھ کھیلتی۔ تم اس کے ساتھ ہنسی مذاق کرتے اور وہ تمہارے ساتھ ہنسی کرتی۔ جابر رضی اللہ عنہ نے بیان کیا کہ اس پر میں نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا کہ عبداللہ ( میرے والد ) شہید ہو گئے اور انہوں نے کئی لڑکیاں چھوڑی ہیں، اس لیے میں نے یہ پسند نہیں کیا کہ ان کے پاس ان ہی جیسی لڑکی بیاہ لاؤں، اس لیے میں نے ایک ایسی عورت سے شادی کی ہے جو ان کی دیکھ بھال کر سکے اور ان کی اصلاح کا خیال رکھے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ اللہ تمہیں برکت دے یا ( راوی کو شک تھا ) نبی کریم صلی اللہ علیہ وسلم نے «خيرا‏.‏» فرمایا یعنی اللہ تم کو خیر عطا کرے۔' WHERE id = 5154;
UPDATE hadiths SET urdu = 'مجھ سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، انہوں نے کہا کہ مجھ سے محمد بن جعفر نے بیان کیا، ان سے محمد بن عمرو بن حلحلہ دیلی نے بیان کیا، ان سے وہب بن کیسان ابونعیم نے بیان کیا، ان سے عمر بن ابی سلمہ رضی اللہ عنہ نے، وہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا کے (ابوسلمہ سے) بیٹے ہیں۔ بیان کیا کہ ایک دن میں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ کھانا کھایا اور برتن کے چاروں طرف سے کھانے لگا تو نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ اپنے نزدیک سے کھا۔' WHERE id = 5164;
UPDATE hadiths SET urdu = 'ہم سے سعید بن مریم نے بیان کیا، کہا ہم کو محمد بن جعفر نے خبر دی، کہا مجھ کو حمید نے خبر دی اور انہوں نے انس رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے صفیہ رضی اللہ عنہا سے نکاح کے بعد ان کے ساتھ راستے میں قیام کیا اور میں نے مسلمانوں کو آپ کے ولیمہ کی دعوت میں بلایا۔ نبی کریم صلی اللہ علیہ وسلم نے دستر خوان بچھانے کا حکم دیا اور وہ بچھایا گیا، پھر آپ نے اس پر کھجور، پنیر اور گھی ڈال دیا اور عمرو بن ابی عمرو نے کہا، ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے صفیہ رضی اللہ عنہا کے ساتھ صحبت کی، پھر ایک چمڑے کے دستر خوان پر ( کھجور، گھی، پنیر ملا کر بنا ہوا ) حلوہ رکھا۔' WHERE id = 5174;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے عدی بن ثابت نے بیان کیا، ان سے ابوحازم نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ ایک صاحب بہت زیادہ کھانا کھایا کرتے تھے، پھر وہ اسلام لائے تو کم کھانے لگے۔ اس کا ذکر رسول اللہ صلی اللہ علیہ وسلم سے کیا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ مومن ایک آنت میں کھاتا ہے اور کافر ساتوں آنتوں میں کھاتا ہے۔' WHERE id = 5184;
UPDATE hadiths SET urdu = 'اور مجھ سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، ان سے ابوحازم نے بیان کیا، ان سے عبداللہ بن ابی قتادہ اسلمی نے، ان سے ان کے والد نے بیان کیا کہ میں ایک دن نبی کریم صلی اللہ علیہ وسلم کے چند صحابہ کے ساتھ مکہ کے راستہ میں ایک منزل پر بیٹھا ہوا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے ہمارے آگے پڑاؤ کیا تھا۔ صحابہ کرام رضی اللہ عنہم احرام کی حالت میں تھے لیکن میں احرام میں نہیں تھا۔ لوگوں نے ایک گورخر کو دیکھا۔ میں اس وقت اپنا جوتا ٹانکنے میں مصروف تھا۔ ان لوگوں نے مجھے اس گورخر کے متعلق بتایا کچھ نہیں لیکن چاہتے تھے کہ میں کسی طرح دیکھ لوں۔ چنانچہ میں متوجہ ہوا اور میں نے اسے دیکھ لیا، پھر میں گھوڑے کے پاس گیا اور اسے زین پہنا کر اس پر سوار ہو گیا لیکن کوڑا اور نیزہ بھول گیا تھا۔ میں نے ان لوگوں سے کہا کہ کوڑا اور نیزہ مجھے دے دو۔ انہوں نے کہا کہ نہیں اللہ کی قسم! ہم تمہاری شکار کے معاملہ میں کوئی مدد نہیں کریں گے۔ ( کیونکہ ہم محرم ہیں ) میں غصہ ہو گیا اور میں نے اتر کر خود یہ دونوں چیزیں اٹھائیں پھر سوار ہو کر اس پر حملہ کیا اور ذبح کر لیا۔ جب وہ ٹھنڈا ہو گیا تو میں اسے ساتھ لایا پھر پکا کر میں نے اور سب نے کھایا لیکن بعد میں انہیں شبہ ہوا کہ احرام کی حالت میں اس ( شکار کا گوشت ) کھانا کیسا ہے؟ پھر ہم روانہ ہوئے اور میں نے اس کا گوشت چھپا کر رکھا۔ جب نبی کریم صلی اللہ علیہ وسلم کے پاس آئے تو ہم نے آپ سے اس کے متعلق پوچھا۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، تمہارے پاس کچھ بچا ہوا بھی ہے؟ میں نے وہی دست پیش کیا اور آپ صلی اللہ علیہ وسلم نے بھی اسے کھایا۔ یہاں تک کہ اس کا گوشت آپ نے اپنے دانتوں سے کھینچ کھینچ کر کھایا اور آپ احرام میں تھے۔ محمد بن جعفر نے بیان کیا کہ مجھ سے زید بن اسلم نے یہ واقعہ بیان کیا، ان سے عطاء بن یسار نے اور ان سے ابوقتادہ رضی اللہ عنہ نے اسی طرح سارا واقعہ بیان کیا۔' WHERE id = 5194;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل بن خالد نے، ان سے ابن شہاب زہری نے، ان سے عروہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے کہ جب کسی گھر میں کسی کی وفات ہو جاتی اور اس کی وجہ سے عورتیں جمع ہوتیں اور پھر وہ چلی جاتیں۔ صرف گھر والے اور خاص خاص عورتیں رہ جاتیں تو آپ ہانڈی میں تلبینہ پکانے کا حکم دیتیں۔ وہ پکایا جاتا پھر ثرید بنایا جاتا اور تلبینہ اس پر ڈالا جاتا۔ پھر ام المؤمنین عائشہ رضی اللہ عنہا فرماتیں کہ اسے کھاؤ کیونکہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے آپ صلی اللہ علیہ وسلم فرماتے تھے کہ تلبینہ مریض کے دل کو تسکین دیتا ہے اور اس کا غم دور کرتا ہے۔' WHERE id = 5204;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا ہم سے ابوعوانہ نے بیان کیا، ان سے قتادہ نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اس مومن کی مثال جو قرآن پڑھتا ہو سنگترے جیسی ہے جس کی خوشبو بھی پاکیزہ ہے اور مزہ بھی پاکیزہ ہے اور اس مومن کی مثال جو قرآن نہیں پڑھتا کھجور جیسی ہے جس میں کوئی خوشبو نہیں ہوتی لیکن مزہ میٹھا ہوتا ہے اور منافق کی مثال جو قرآن پڑھتا ہو، ریحانہ ( پھول ) جیسی ہے جس کی خوشبو تو اچھی ہوتی ہے لیکن مزہ کڑوا ہوتا ہے اور جو منافق قرآن بھی نہیں پڑھتا اس کی مثال اندرائن جیسی ہے جس میں کوئی خوشبو نہیں ہوتی اور جس کا مزہ بھی کڑوا ہوتا ہے۔' WHERE id = 5214;
UPDATE hadiths SET urdu = 'ہم سے حکیم ابونعیم نے بیان کیا، کہا ہم سے مالک بن انس نے، ان سے اسحاق بن عبداللہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں شوربہ لایا گیا۔ اس میں کدو اور سوکھے گوشت کے ٹکڑے تھے، پھر میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم اس میں سے کدو کے قتلے تلاش کر کر کے کھا رہے تھے۔' WHERE id = 5224;
UPDATE hadiths SET urdu = 'مجھ سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے بیان کیا اور انہوں نے ابن عمر رضی اللہ عنہما سے سنا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو کھجور کو ککڑی کے ساتھ کھاتے ہوئے دیکھا۔' WHERE id = 5235;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا کہ مجھ سے محمد بن فلیح نے بیان کیا، کہا کہ مجھ سے میرے والد نے، ان سے سعید بن الحارث نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ سعید بن الحارث نے جابر رضی اللہ عنہ سے ایسی چیز کے ( کھانے کے بعد ) جو آگ پر رکھی ہو وضو کے متعلق پوچھا ( کہ کیا ایسی چیز کھانے سے وضو ٹوٹ جاتا ہے؟ ) تو انہوں نے کہا کہ نہیں۔ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں ہمیں اس طرح کا کھانا ( جو پکا ہوا ہوتا ) بہت کم میسر آتا تھا اور اگر میسر آ بھی جاتا تھا تو سوا ہماری ہتھیلیوں بازوؤں اور پاؤں کے کوئی رومال نہیں ہوتا تھا ( اور ہم انہیں سے اپنے ہاتھ صاف کر کے ) نماز پڑھ لیتے تھے اور وضو۔' WHERE id = 5245;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن نضر نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا کہ مجھ سے یزید نے بیان کیا، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ میرے یہاں ایک لڑکا پیدا ہوا تو میں اسے لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ نبی کریم صلی اللہ علیہ وسلم نے اس کا نام ابراہیم رکھا اور کھجور کو اپنے دندان مبارک سے نرم کر کے اسے چٹایا اور اس کے لیے برکت کی دعا کی پھر مجھے دے دیا۔ یہ ابوموسیٰ رضی اللہ عنہ کے سب سے بڑے لڑکے تھے۔' WHERE id = 5255;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے منصور بن معتمر نے، ان سے ابراہیم نخعی نے، ان سے ہمام بن حارث نے اور ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! ہم سکھائے ہوئے کتے ( شکار پر ) چھوڑتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شکار وہ صرف تمہارے لیے رکھے اسے کھاؤ۔ میں نے عرض کیا اگرچہ کتے شکار کو مار ڈالیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ( ہاں ) اگرچہ مار ڈالیں! میں نے عرض کیا کہ ہم بے پر کے تیر یا لکڑی سے شکار کرتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر ان کی دھار اس کو زخمی کر کے پھاڑ ڈالے تو کھاؤ لیکن اگر ان کے عرض سے شکار مارا جائے تو اسے نہ کھاؤ ( وہ مردار ہے ) ۔' WHERE id = 5266;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن سلام نے بیان کیا، کہا ہم کو محمد ابن فضل نے خبر دی، ان سے بیان بن بشر نے، ان سے عامر شعبی نے اور ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کہ ہم اس قوم میں سکونت رکھتے ہیں جو ان کتوں سے شکار کرتی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم اپنا سکھایا ہوا کتا چھوڑو اور اس پر اللہ کا نام لے لو تو اگر وہ کتا تمہارے لیے شکار لایا ہو تو تم اسے کھا سکتے ہو لیکن اگر کتے نے خود بھی کھا لیا ہو تو وہ شکار نہ کھاؤ کیونکہ اندیشہ ہے کہ اس نے وہ شکار خود اپنے لیے پکڑا ہے اور اگر اس کتے کے ساتھ کوئی دوسرا کتا بھی شکار میں شریک ہو جائے تو پھر شکار نہ کھاؤ۔' WHERE id = 5276;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، انہوں نے کہا کہ مجھ سے یزید بن ابی عبیدہ نے بیان کیا، ان سے سلمہ بن الاکوع رضی اللہ عنہ نے بیان کیا کہ فتح خیبر کی شام کو لوگوں نے آگ روشن کی تو نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ یہ آگ تم لوگوں نے کس لیے روشن کی ہے؟ لوگوں نے بتایا کہ گدھے کا گوشت ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہانڈیوں میں کچھ ( گدھے کا گوشت ) ہے اسے پھینک دو اور ہانڈیوں کو توڑ ڈالو۔ ایک شخص نے کھڑے ہو کر کہا ہانڈی میں جو کچھ ( گوشت وغیرہ ) ہے اسے ہم پھینک دیں اور برتن دھو لیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ بھی کر سکتے ہو۔' WHERE id = 5286;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبیداللہ نے بیان کیا، کہا ہم سے اسامہ بن حفص مدنی نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ( گاؤں کے ) کچھ لوگ ہمارے یہاں گوشت ( بیچنے ) لاتے ہیں اور ہمیں معلوم نہیں کہ انہوں نے اس پر اللہ کا نام بھی ( ذبح کرتے وقت ) لیا تھا یا نہیں؟ آپ نے فرمایا کہ تم ان پر کھاتے وقت اللہ کا نام لیا کرو اور کھا لیا کرو۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ یہ لوگ ابھی اسلام میں نئے نئے داخل ہوئے تھے۔ اس کی متابعت علی نے دراوردی سے کی اور اس کی متابعت ابوخالد اور طفاوی نے کی۔' WHERE id = 5296;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، انہوں نے کہا ہم سے وکیع نے بیان کیا، ان سے سفیان نے بیان کیا، ان سے ایوب نے، ان سے ابوقلابہ نے، ان سے زہدم جرمی نے، ان سے ابوموسیٰ یعنی الاشعری رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو مرغی کھاتے دیکھا ہے۔' WHERE id = 5306;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عمرو نے بیان کیا کہ میں نے جابر بن زید رضی اللہ عنہما سے پوچھا کہ لوگوں کا خیال ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے پالتو گدھوں کا گوشت کھانے سے منع کیا تھا؟ انہوں نے کہا کہ حکم بن عمرو غفاری رضی اللہ عنہ نے ہمیں بصرہ میں یہی بتایا تھا لیکن علم کے سمندر ابن عباس رضی اللہ عنہما نے اس سے انکار کیا اور ( استدلال میں ) اس آیت کی تلاوت کی «قل لا أجد فيما أوحي إلى محرما‏» ۔' WHERE id = 5317;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، انہیں یونس نے، انہیں محمد بن عبداللہ بن شہاب زہری نے کہ اگر کوئی جانور چوہا یا کوئی اور جمے ہوئے یا غیر جمے ہوئے گھی یا تیل میں پڑ جائے تو اس کے متعلق کہا کہ ہمیں یہ حدیث پہنچی ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے چوہے کہ متعلق جو گھی میں مر گیا تھا، حکم دیا کہ اسے اور اس کے چاروں طرف سے گھی نکال کر پھینک دیا جائے اور پھر باقی گھی کھایا گیا۔ ہمیں یہ حدیث عبیداللہ بن عبداللہ کی سند سے پہنچی ہے۔' WHERE id = 5327;
UPDATE hadiths SET urdu = 'ہم سے صدقہ نے بیان کیا، کہا ہم کو ابن علیہ نے خبر دی، انہیں ایوب نے، انہیں محمد بن سیرین نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے قربانی کے دن فرمایا کہ جس نے نماز عید سے پہلے قربانی ذبح کر لی ہے وہ دوبارہ قربانی کرے اس پر ایک صاحب نے کھڑے ہو کر عرض کیا: یا رسول اللہ! یہ وہ دن ہے جس میں گوشت کھانے کی خواہش ہوتی ہے پھر انہوں نے اپنے پڑوسیوں کا ذکر کیا اور ( کہا کہ ) میرے پاس ایک سال سے کم کا بکری کا بچہ ہے جس کا گوشت دو بکریوں کے گوشت سے بہتر ہے تو نبی کریم صلی اللہ علیہ وسلم نے انہیں اس کی اجازت دے دی۔ مجھے نہیں معلوم کہ یہ اجازت دوسروں کو بھی ہے یا نہیں۔ پھر نبی کریم صلی اللہ علیہ وسلم دو مینڈھوں کی طرف مڑے اور انہیں ذبح کیا پھر لوگ بکریوں کی طرف بڑھے اور انہیں تقسیم کر کے ( ذبح کیا ) ۔' WHERE id = 5337;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عبدالرحمٰن بن قاسم نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ مقام سرف میں رسول اللہ صلی اللہ علیہ وسلم میرے پاس تشریف لائے اور میں رو رہی تھی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کیا بات ہے، کیا تمہیں حیض آ گیا ہے؟ میں نے عرض کیا جی ہاں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ تو اللہ تعالیٰ نے آدم کی بیٹیوں کی تقدیر میں لکھ دیا ہے۔ اس لیے حاجیوں کی طرح تمام اعمال حج انجام دو صرف کعبہ کا طواب نہ کرو اور نبی کریم صلی اللہ علیہ وسلم نے اپنے بیویوں کی طرف سے گائے کی قربانی کی۔' WHERE id = 5347;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے یزید بن ابی عبید نے اور ان سے سلمہ بن الاکوع رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے تم میں سے قربانی کی تو تیسرے دن وہ اس حالت میں صبح کرے کہ اس کے گھر میں قربانی کے گوشت میں سے کچھ بھی باقی نہ ہو۔ دوسرے سال صحابہ کرام رضی اللہ عنہم نے عرض کیا: یا رسول اللہ! کیا ہم اس سال بھی وہی کریں جو پچھلے سال کیا تھا۔ ( کہ تین دن سے زیادہ قربانی کا گوشت بھی نہ رکھیں ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اب کھاؤ، کھلاؤ اور جمع کرو۔ پچھلے سال تو چونکہ لوگ تنگی میں مبتلا تھے، اس لیے میں نے چاہا کہ تم لوگوں کی مشکلات میں ان کی مدد کرو۔' WHERE id = 5357;
UPDATE hadiths SET urdu = 'ہم سے حسن بن صباح نے بیان کیا، کہا ہم سے محمد بن سابق نے بیان کیا، کہا ہم سے امام مالک نے جو مغول کے صاحبزادے ہیں، بیان کیا ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ جب شراب حرام کی گئی تو انگور کی شراب مدینہ منورہ میں نہیں ملتی تھی۔' WHERE id = 5367;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے عبداللہ بن ابی السفر نے بیان کیا، ان سے شعبی نے ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ عمر رضی اللہ عنہ نے کہا کہ شراب پانچ چیزوں سے بنتی تھی کشمش، کھجور، گیہوں، جَو اور شہد سے۔' WHERE id = 5377;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی شیبہ نے بیان کیا، انہوں نے کہا ہم سے ابواسامہ نے بیان کیا، انہوں نے کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے باپ (عروہ بن زبیر) نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم حلوا اور شہد کو دوست رکھتے تھے۔' WHERE id = 5387;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے امام اوزاعی نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عبیداللہ بن عبداللہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے دودھ پیا پھر کلی کی اور فرمایا کہ اس میں چکناہٹ ہوتی ہے۔' WHERE id = 5397;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں پانی ملا ہوا دودھ پیش کیا گیا نبی کریم صلی اللہ علیہ وسلم کے داہنی طرف ایک دیہاتی تھا اور بائیں طرف ابوبکر رضی اللہ عنہ۔ نبی کریم صلی اللہ علیہ وسلم نے پی کر باقی دیہاتی کو دیا اور فرمایا کہ دائیں طرف سے، پس دائیں طرف سے۔' WHERE id = 5407;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے خالد حذاء نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مشک کے منہ سے پانی پینے کو منع فرمایا تھا۔' WHERE id = 5417;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے سالم بن ابی الجعد نے اور ان سے جابر بن عبداللہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھا اور عصر کی نماز کا وقت ہو گیا تھوڑے سے بچے ہوئے پانی کے سوا ہمارے پاس اور کوئی پانی نہیں تھا اسے ایک برتن میں رکھ کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لایا گیا نبی کریم صلی اللہ علیہ وسلم نے اس میں اپنا ہاتھ ڈالا اور اپنی انگلیاں پھیلا دیں پھر فرمایا آؤ وضو کر لو یہ اللہ کی طرف سے برکت ہے۔ میں نے دیکھا کہ پانی نبی کریم صلی اللہ علیہ وسلم کی انگلیوں کے درمیان سے پھوٹ پھوٹ کر نکل رہا تھا چنانچہ سب لوگوں نے اس سے وضو کیا اور پیا بھی۔ میں نے اس کی پرواہ کئے بغیر کہ پیٹ میں کتنا پانی جا رہا ہے خوب پانی پیا کیونکہ مجھے معلوم ہو گیا تھا کہ برکت کا پانی ہے۔ میں نے جابر رضی اللہ عنہ سے پوچھا آپ لوگ اس وقت کتنی تعداد میں تھے؟ بتلایا کہ ایک ہزار چار سو۔ اس روایت کی متابعت عمرو نے جابر رضی اللہ عنہ سے کی ہے اور حسین اور عمرو بن مرہ نے سالم سے بیان کیا اور ان سے جابر رضی اللہ عنہ نے کہ صحابہ کی اس وقت تعداد پندرہ سو تھی۔ اس کی متابعت سعید بن مسیب نے جابر رضی اللہ عنہ سے کی ہے۔' WHERE id = 5427;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ابن المنکدر نے، انہوں نے جابر بن عبداللہ سے سنا، انہوں نے بیان کیا کہ میں ایک مرتبہ بیمار پڑا تو نبی کریم صلی اللہ علیہ وسلم اور ابوبکر صدیق رضی اللہ عنہ پیدل میری عیادت کو تشریف لائے ان بزرگوں نے دیکھا کہ مجھ پر بے ہوشی غالب ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے وضو کیا اور اپنے وضو کا پانی مجھ پر چھڑکا، اس سے مجھے ہوش آ گیا تو میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم تشریف رکھتے ہیں، میں نے عرض کیا: یا رسول اللہ! میں اپنے مال میں کیا کروں کس طرح اس کا فیصلہ کروں؟ نبی کریم صلی اللہ علیہ وسلم نے مجھے کوئی جواب نہیں دیا۔ یہاں تک کہ میراث کی آیت نازل ہوئی۔' WHERE id = 5438;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، انہوں نے کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اعمش نے بیان کیا، ان سے ابراہیم تیمی نے، ان سے حارث بن سوید نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں جب آپ بیمار تھے حاضر ہوا۔ میں نے آپ کا جسم چھوا، آپ کو تیز بخار تھا۔ میں نے عرض کیا آپ کو تو بڑا تیز بخار ہے یہ اس لیے ہو گا کہ آپ کو دگنا ثواب ملے گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں اور کسی مسلمان کو بھی جب کوئی تکلیف پہنچتی ہے تو اس کے گناہ اس طرح جھڑ جاتے ہیں جیسے درخت کے پتے جھڑ جاتے ہیں۔' WHERE id = 5448;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے ثابت بنانی نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کسی تکلیف میں اگر کوئی شخص مبتلا ہو تو اسے موت کی تمنا نہیں کرنی چاہیئے اور اگر کوئی موت کی تمنا کرنے ہی لگے تو یہ کہنا چاہیئے «اللهم أحيني ما كانت الحياة خيرا لي،‏‏‏‏ وتوفني إذا كانت الوفاة خيرا لي» ”اے اللہ! جب تک زندگی میرے لیے بہتر ہے مجھے زندہ رکھ اور جب موت میرے لیے بہتر ہو تو مجھ کو اٹھا لے۔“' WHERE id = 5458;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، انہوں نے کہا ہم کو سریج بن یونس ابوحارث نے خبر دی، انہوں نے کہا ہم سے مروان بن شجاع نے بیان کیا، ان سے سالم افطس نے بیان کیا، ان سے سعید بن جبیر نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ شفاء تین چیزوں میں ہے پچھنا لگوانے میں، شہد پینے میں اور آگ سے داغنے میں مگر میں اپنی امت کو آگ سے داغنے سے منع کرتا ہوں۔' WHERE id = 5468;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے وہیب بن خالد نے بیان کیا، ان سے عبداللہ ابن طاؤس نے، ان سے ان کے والد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے پچھنا لگوایا اور پچھنا لگانے والے کو اس کی مزدوری دی اور ناک میں دوا ڈلوائی۔' WHERE id = 5478;
UPDATE hadiths SET urdu = 'اور عفان بن مسلم (امام بخاری رحمہ اللہ کے شیخ) نے کہا (ان کو ابونعیم نے وصل کیا) ہے کہ ہم سے سلیم بن حیان نے بیان کیا، ان سے سعید بن میناء نے بیان کیا، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ چھوت لگنا، بدشگونی لینا، الو کا منحوس ہونا اور صفر کا منحوس ہونا یہ سب لغو خیالات ہیں البتہ جذامی شخص سے ایسے بھاگتا رہ جیسے کہ شیر سے بھاگتا ہے۔' WHERE id = 5491;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، انہوں نے کہا ان سے امام مالک نے بیان کیا، ان سے ہشام نے بیان کیا، ان سے فاطمہ بنت منذر نے بیان کیا کہ اسماء بنت ابی بکر صدیق رضی اللہ عنہما کے ہاں جب کوئی بخار میں مبتلا عورت لائی جاتی تھی تو وہ اس کے لیے دعا کرتیں اور اس کے گریبان میں پانی ڈالتیں وہ بیان کرتی تھیں کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں حکم دیا تھا کہ بخار کو پانی سے ٹھنڈا کریں۔' WHERE id = 5503;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو حبان نے خبر دی، کہا ہم سے داؤد بن ابی الفرت نے بیان کیا، کہا ہم سے عبداللہ بن بریدہ نے، ان سے یحییٰ بن عمر نے اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے خبر دی کہ آپ نے رسول اللہ صلی اللہ علیہ وسلم سے طاعون کے متعلق پوچھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ ایک عذاب تھا اللہ تعالیٰ جس پر چاہتا اس پر اس کو بھیجتا تھا پھر اللہ تعالیٰ نے اسے مومنین ( امت محمدیہ کے لیے ) رحمت بنا دیا اب کوئی بھی اللہ کا بندہ اگر صبر کے ساتھ اس شہر میں ٹھہرا رہے جہاں طاعون پھوٹ پڑا ہو اور یقین رکھتا ہے کہ جو کچھ اللہ تعالیٰ نے اس کے لیے لکھ دیا ہے اس کے سوا اس کو اور کوئی نقصان نہیں پہنچ سکتا اور پھر طاعون میں اس کا انتقال ہو جائے تو اسے شہید جیسا ثواب ملے گا۔ حبان بن حلال کے ساتھ اس حدیث کو نضر بن شمیل نے بھی داؤد سے روایت کیا ہے۔' WHERE id = 5513;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن ابی رجاء نے بیان کیا، کہا ہم سے نضر بن شمیل نے بیان کیا، ان سے ہشام بن عروہ نے، انہیں ان کے والد نے خبر دی اور انہیں عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم دم کیا کرتے تھے اور یہ دعا پڑھتے تھے «امسح الباس رب الناس،‏‏‏‏ ‏‏‏‏بيدك الشفاء،‏‏‏‏ ‏‏‏‏لا كاشف له إلا أنت‏ ‏‏.‏» ”تکلیف کو دور کر دے، اے لوگوں کے پالنہار! تیرے ہی ہاتھ میں شفاء ہے، تیرے سوا تکلیف کو دور کرنے والا کوئی اور نہیں ہے۔“' WHERE id = 5523;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا ہم کو عبیداللہ بن عبداللہ بن عتبہ نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بدشگونی کی کوئی اصل نہیں البتہ نیک فال لینا کچھ برا نہیں ہے۔“ صحابہ کرام رضی اللہ عنہم نے عرض کیا: نیک فال کیا چیز ہے؟ فرمایا ”کوئی ایسی بات سننا۔“' WHERE id = 5533;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم پر جادو کر دیا گیا تھا اور اس کا اثر یہ تھا کہ آپ کو خیال ہوتا کہ آپ کوئی چیز کر چکے ہیں حالانکہ وہ چیز نہ کی ہوتی ایک دن نبی کریم صلی اللہ علیہ وسلم میرے یہاں تشریف رکھتے تھے اور مسلسل دعائیں کر رہے تھے، پھر فرمایا: عائشہ! تمہیں معلوم ہے اللہ تعالیٰ سے جو بات میں نے پوچھی تھی اس کا جواب اس نے مجھے دے دیا ہے۔ میں نے عرض کی وہ کیا بات ہے یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا میرے پاس دو فرشتے ( جبرائیل و میکائیل علیہما السلام ) آئے اور ایک میرے سر کے پاس کھڑا ہو گیا اور دوسرا پاؤں کی طرف پھر ایک نے اپنے دوسرے ساتھی سے کہا ان صاحب کی تکلیف کیا ہے؟ دوسرے نے جواب دیا کہ ان پر جادو کیا گیا ہے۔ پوچھا کس نے ان پر جادو کیا ہے؟ فرمایا بنی زریق کے لبید بن اعصم یہودی نے، پوچھا کس چیز میں؟ جواب دیا کہ کنگھے اور بال میں جو نر کھجور کے خوشے میں رکھا ہوا ہے۔ پوچھا اور وہ جادو رکھا کہاں ہے؟ جواب دیا کہ ذروان کے کنویں میں۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم اپنے چند صحابہ کے ساتھ اس کنویں پر تشریف لے گئے اور اسے دیکھا وہاں کھجور کے درخت بھی تھے پھر آپ واپس عائشہ رضی اللہ عنہا کے یہاں تشریف لائے اور فرمایا صلی اللہ علیہ وسلم اللہ کی قسم! اس کا پانی مہندی کے عرق جیسا ( سرخ ) ہے اور اس کے کھجور کے درخت شیاطین کے سروں جیسے ہیں۔ میں نے عرض کیا: یا رسول اللہ! وہ کنگھی بال وغیرہ غلاف سے نکلوائے یا نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں، سن لو اللہ نے تو مجھ کو شفاء دے دی، تندرست کر دیا اب میں ڈرا کہیں لوگوں میں ایک شور نہ پھیلے اور نبی کریم صلی اللہ علیہ وسلم نے اس سامان کے گاڑ دینے کا حکم دیا وہ گاڑ دیا گیا۔' WHERE id = 5544;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی نے بیان کیا، انہوں نے کہا ہم کو احمد بن بشیر ابوبکر نے خبر دی، انہوں نے کہا ہم کو ہاشم بن ہاشم نے خبر دی، کہا کہ مجھے عامر بن سعد نے خبر دی، انہوں نے کہا کہ میں نے اپنے والد سے سنا، انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص صبح کے وقت سات عجوہ کھجوریں کھا لے اسے اس دن زہر نقصان پہنچا سکے گا اور نہ جادو۔“' WHERE id = 5555;
UPDATE hadiths SET urdu = 'ہم سے مطر بن فضل نے بیان کیا، کہا ہم سے شبابہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ میں نے محارب بن دثار قاضی سے ملاقات کی، وہ گھوڑے پر سوار تھے اور مکان عدالت میں آ رہے تھے جس میں وہ فیصلہ کیا کرتے تھے۔ میں نے ان سے یہی حدیث پوچھی تو انہوں نے مجھ سے بیان کیا، کہا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو آپ اپنا کپڑا غرور کی وجہ سے گھسیٹتا ہوا چلے گا، قیامت کے دن اس کی طرف اللہ تعالیٰ نظر نہیں کرے گا۔“ ( شعبہ نے کہا کہ ) میں نے محارب سے پوچھا کیا ابن عمر رضی اللہ عنہما نے تہمد کا ذکر کیا تھا؟ انہوں نے فرمایا کہ تہمد یا قمیص کسی کی انہوں نے تخصیص نہیں کی تھی۔ محارب کے ساتھ اس حدیث کو جبلہ بن سحیم اور زید بن اسلم اور زید بن عبداللہ نے بھی عبداللہ بن عمر رضی اللہ عنہما سے روایت کیا، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔ اور لیث نے نافع سے، انہوں نے ابن عمر رضی اللہ عنہما سے ایسی ہی روایت کی اور نافع کے ساتھ اس کو موسیٰ بن عقبہ اور عمر بن محمد اور قدامہ بن موسیٰ نے بھی سالم سے، انہوں نے ابن عمر رضی اللہ عنہما سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کی اس میں یوں ہے کہ جو شخص اپنا کپڑا ( ازراہ تکبر ) لٹکائے۔' WHERE id = 5566;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یزید بن ابی حبیب نے، ان سے ابوالخیر نے اور ان سے عقبہ بن عامر رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کو ریشم کی فروج ( قباء ) ہدیہ میں دی گئی۔ نبی کریم صلی اللہ علیہ وسلم نے اسے پہنا ( ریشم کا مردوں کے لیے حرمت کے حکم سے پہلے ) اور اسی کو پہنے ہوئے نماز پڑھی۔ پھر آپ صلی اللہ علیہ وسلم نے اسے بڑی تیزی کے ساتھ اتار ڈالا جیسے آپ اس سے ناگواری محسوس کرتے ہوں پھر فرمایا کہ یہ متقیوں کے لیے مناسب نہیں ہے۔ اس روایت کی متابعت عبداللہ بن یوسف نے کی ان سے لیث نے اور عبداللہ بن یوسف کے علاوہ دوسروں نے کہا کہ «فروج حرير‏.‏» ۔' WHERE id = 5576;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھ سے سعید بن مسیب نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میری امت میں سے جنت میں ستر ہزار کی ایک جماعت داخل ہو گی ان کے چہرے چاند کی طرح چمک رہے ہوں گے۔ عکاشہ بن محصن اسدی رضی اللہ عنہ اپنی دھاری دار چادر سنبھالتے ہوئے اٹھے اور عرض کیا: یا رسول اللہ! میرے لیے بھی دعا کیجئے کہ اللہ تعالیٰ مجھے انہیں میں سے بنا دے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے اللہ! عکاشہ کو بھی انہیں میں سے بنا دے۔ اس کے بعد قبیلہ انصار کے ایک صحابی سعد بن عبادہ رضی اللہ عنہ کھڑے ہوئے اور عرض کیا: یا رسول اللہ! دعا فرمائیں کہ اللہ تعالیٰ مجھے بھی ان میں سے بنا دے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم سے پہلے عکاشہ دعا کرا چکا۔' WHERE id = 5586;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے اسحاق بن سعید نے بیان کیا، ان سے ان کے والد نے، ان سے سعید بن فلاں یعنی عمرو بن سعید بن عاص نے اور ان سے ام خالد بنت خالد رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں کچھ کپڑے لائے گئے جس میں ایک چھوٹی کالی کملی بھی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارا کیا خیال ہے یہ چادر کسے دی جائے؟ صحابہ کرام رضی اللہ عنہم خاموش رہے پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا: ام خالد کو میرے پاس بلا لاؤ۔ انہیں گود میں اٹھا کر لایا گیا ( کیونکہ بچی تھیں ) اور نبی کریم صلی اللہ علیہ وسلم نے وہ چادر اپنے ہاتھ میں لی اور انہیں پہنایا اور دعا دی کہ جیتی رہو۔ اس چادر میں ہرے اور زرد نقش و نگار تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ام خالد! یہ نقش و نگار ”سناہ“ ہیں۔ ”سناہ“ حبشی زبان میں خوب اچھے کے معنی میں آتا ہے۔' WHERE id = 5597;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت نے بیان کیا کہ میں نے ابن زبیر رضی اللہ عنہ سے سنا، انہوں نے خطبہ دیتے ہوئے کہا کہ محمد صلی اللہ علیہ وسلم نے فرمایا ہے کہ جس مرد نے دنیا میں ریشم پہنا وہ آخرت میں اسے نہیں پہن سکے گا۔' WHERE id = 5607;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے، ان سے یحییٰ بن سعید نے، ان سے عبید بن حنین نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ میں عمر رضی اللہ عنہ سے ان عورتوں کے بارے میں جنہوں نے نبی کریم صلی اللہ علیہ وسلم کے معاملہ میں اتفاق کر لیا تھا، پوچھنے کا ارادہ کرتا رہا لیکن ان کا رعب سامنے آ جاتا تھا۔ ایک دن ( مکہ کے راستہ میں ) ایک منزل پر قیام کیا اور پیلو کے درختوں میں ( وہ قضائے حاجت کے لیے ) تشریف لے گئے۔ جب قضائے حاجت سے فارغ ہو کر واپس تشریف لائے تو میں نے پوچھا انہوں نے بتلایا کہ عائشہ اور حفصہ رضی اللہ عنہما ہیں پھر کہا کہ جاہلیت میں ہم عورتوں کو کوئی حیثیت نہیں دیتے تھے۔ جب اسلام آیا اور اللہ تعالیٰ نے ان کا ذکر کیا ( اور ان کے حقوق ) مردوں پر بتائے تب ہم نے جانا کہ ان کے بھی ہم پر کچھ حقوق ہیں لیکن اب بھی ہم اپنے معاملات میں ان کا دخیل بننا پسند نہیں کرتے تھے۔ میرے اور میری بیوی میں کچھ گفتگو ہو گئی اور اس نے تیز و تند جواب مجھے دیا تو میں نے اس سے کہا اچھا اب نوبت یہاں تک پہنچ گئی۔ اس نے کہا تم مجھے یہ کہتے ہو اور تمہاری بیٹی نبی کریم صلی اللہ علیہ وسلم کو بھی تکلیف پہنچاتی ہے۔ میں ( اپنی بیٹی ام المؤمنین ) حفصہ کے پاس آیا اور اس سے کہا میں تجھے تنبیہ کرتا ہوں کہ اللہ اور اس کے رسول کی نافرمانی کرے۔ نبی کریم صلی اللہ علیہ وسلم کو تکلیف پہنچانے کے معاملہ میں سب سے پہلے میں ہی حفصہ کے یہاں گیا پھر میں ام سلمہ کے پاس آیا اور ان سے بھی یہی بات کہی لیکن انہوں نے کہا کہ حیرت ہے تم پر عمر! تم ہمارے معاملات میں دخیل ہو گئے ہو۔ صرف رسول اللہ صلی اللہ علیہ وسلم اور آپ کی ازواج کے معاملات میں دخل دینا باقی تھا۔ ( سو اب وہ بھی شروع کر دیا ) انہوں نے میری بات رد کر دی۔ قبیلہ انصار کے ایک صحابی تھے جب وہ نبی کریم صلی اللہ علیہ وسلم کی صحبت میں موجود نہ ہوتے اور میں حاضر ہوتا تو تمام خبریں ان سے آ کر بیان کرتا تھا اور جب میں نبی کریم صلی اللہ علیہ وسلم کی صحبت سے غیر حاضر ہوتا اور وہ موجود ہوتے تو وہ نبی کریم صلی اللہ علیہ وسلم کے متعلق تمام خبریں مجھے آ کر سناتے تھے۔ آپ کے چاروں طرف جتنے ( بادشاہ وغیرہ ) تھے ان سب سے آپ کے تعلقات ٹھیک تھے۔ صرف شام کے ملک غسان کا ہمیں خوف رہتا تھا کہ وہ کہیں ہم پر حملہ نہ کر دے۔ میں نے جو ہوش و حواس درست کئے تو وہی انصاری صحابی تھے اور کہہ رہے تھے کہ ایک حادثہ ہو گیا۔ میں نے کہا کیا بات ہوئی۔ کیا غسان چڑھ آیا ہے۔ انہوں نے کہا کہ اس سے بھی بڑا حادثہ کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی ازواج کو طلاق دے دی۔ میں جب ( مدینہ ) حاضر ہوا تو تمام ازواج کے حجروں سے رونے کی آواز آ رہی تھی۔ نبی کریم صلی اللہ علیہ وسلم اپنے بالا خانہ پر چلے گئے تھے اور بالا خانہ کے دروازہ پر ایک نوجوان پہرے دار موجود تھا میں نے اس کے پاس پہنچ کر اس سے کہا کہ میرے لیے نبی کریم صلی اللہ علیہ وسلم سے اندر حاضر ہونے کی اجازت مانگ لو پھر میں اندر گیا تو آپ ایک چٹائی پر تشریف رکھتے تھے جس کے نشانات آپ کے پہلو پر پڑے ہوئے تھے اور آپ کے سر کے نیچے ایک چھوٹا سا چمڑے کا تکیہ تھا۔ جس میں کھجور کی چھال بھری ہوئی تھی۔ چند کچی کھالیں لٹک رہی تھیں اور ببول کے پتے تھے۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے اپنی ان باتوں کا ذکر کیا جو میں نے حفصہ اور ام سلمہ سے کہی تھیں اور وہ بھی جو ام سلمہ نے میری بات رد کرتے ہوئے کہا تھا۔ نبی کریم صلی اللہ علیہ وسلم اس پر مسکرا دیئے۔ آپ نے اس بالا خانہ میں انتیس دن تک قیام کیا پھر آپ وہاں سے نیچے اتر آئے۔' WHERE id = 5617;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عمرو بن دینار نے، ان سے جابر بن زید نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس کے پاس احرام باندھنے کے لیے تہبند نہ ہو وہ پاجامہ پہن لے ( اس کا کاٹنا ضروری نہیں ہے ) اور جس کے پاس جوتے نہ ہوں وہ موزے ہی پہن لے لیکن ٹخنوں کے نیچے تک ان کو کاٹ ڈالے ( جیسا کہ پچھلی حدیث میں ہے ) ۔' WHERE id = 5627;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم کو اشعث بن سلیم نے کہا کہ میں نے معاویہ بن سوید بن مقرن سے سنا، انہوں نے کہا کہ میں نے براء بن عازب رضی اللہ عنہ سے سنا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں سات چیزوں سے روکا تھا۔ آپ صلی اللہ علیہ وسلم نے ہمیں سونے کی انگوٹھی سے یا راوی نے کہا کہ سونے کے چھلے سے، ریشم سے، استبرق سے، دیبا سے، سرخ میثرہ سے، قسی سے اور چاندی کے برتن سے منع فرمایا تھا اور ہمیں آپ صلی اللہ علیہ وسلم نے سات چیزوں یعنی بیمار کی مزاج پرسی کرنے، جنازہ کے پیچھے چلنے، چھینکنے والے کا جواب دینے، سلام کے جواب دینے، دعوت کرنے والے کی دعوت قبول کرنے، ( کسی بات پر ) قسم کھا لینے والے قسم پوری کرانے اور مظلوم کی مدد کرنے کا حکم فرمایا تھا۔' WHERE id = 5637;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام بیکندی نے بیان کیا، کہا ہم کو عبداللہ بن نمیر نے خبر دی، انہیں عبیداللہ عمری نے، انہیں نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے چاندی کی ایک انگوٹھی بنوائی۔ وہ انگوٹھی آپ کے ہاتھ میں، اس کے بعد عمر رضی اللہ عنہ کے ہاتھ میں، اس کے بعد عثمان رضی اللہ عنہ کے ہاتھ میں رہتی تھی لیکن ان کے زمانہ میں وہ اریس کے کنویں میں گر گئی اس کا نقش «محمد رسول الله» تھا۔' WHERE id = 5647;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھے عدی بن ثابت نے خبر دی، کہا کہ میں نے سعید بن جبیر سے سنا اور انہوں نے ابن عباس رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے عید کے دن دو رکعتیں پڑھائیں نہ اس کے پہلے کوئی نماز پڑھی اور نہ اس کے بعد پھر آپ عورتوں کی طرف تشریف لائے، آپ کے ساتھ بلال رضی اللہ عنہ تھے۔ آپ نے عورتوں کو صدقہ کا حکم فرمایا تو وہ اپنی بالیاں بلال رضی اللہ عنہ کی جھولی میں ڈالنے لگیں۔' WHERE id = 5657;
UPDATE hadiths SET urdu = 'مجھ سے محمد نے حدیث بیان کی، انہوں نے کہا ہمیں عبدہ نے خبر دی، انہیں عبیداللہ بن عمر نے خبر دی، انہیں نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مونچھیں خوب کتروایا لیا کرو اور داڑھی کو بڑھاؤ۔“' WHERE id = 5667;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم کو حبان نے خبر دی، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، کہا ہم سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم کے بال مونڈھوں تک پہنچتے تھے۔' WHERE id = 5677;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، انہوں نے کہا ہم سے شہاب نے بیان کیا، ان سے عبیداللہ بن عبداللہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو اگر کسی مسئلہ میں کوئی حکم معلوم نہ ہوتا تو آپ اس میں اہل کتاب کے عمل کو اپناتے تھے۔ اہل کتاب اپنے سر کے بال لٹکائے رکھتے اور مشرکین مانگ نکالتے تھے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم بھی ( اہل کتاب کی موافقت میں ) پہلے سر کے بال پیشانی کی طرف لٹکاتے لیکن بعد میں آپ بیچ میں سے مانگ نکالنے لگے۔' WHERE id = 5689;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد ہمدانی نے بیان کیا، کہا ہم سے ہشام بن یوسف صنعانی نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سعید بن المسیب نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” ( کہ اللہ تعالیٰ نے فرمایا ) ابن آدم کا ہر عمل اس کا ہے سوا روزہ کے کہ یہ میرا ہے اور میں خود اس کا بدلہ دوں گا اور روزہ دار کے منہ کے خوشبو اللہ کے نزدیک مشک کی خوشبو سے بھی بڑھ کر ہے۔“' WHERE id = 5699;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو عبیداللہ عمری نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ نے مصنوعی بال جوڑنے والیوں پر، جڑوانے والیوں پر، گودنے والیوں پر اور گدوانے والیوں پر لعنت بھیجی ہے۔“ نافع نے کہا کہ گودنا کبھی مسوڑے پر بھی گودا جاتا ہے۔' WHERE id = 5709;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، انہیں عبیداللہ نے خبر دی، کہا مجھ کو خبر دی نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مصنوعی بال لگانے والی اور لگوانے والی اور گودنے والی اور گدوانے والی پر لعنت بھیجی ہے۔' WHERE id = 5720;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے جویریہ نے بیان کیا، ان سے نافع نے، ان سے قاسم بن محمد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ انہوں نے ایک گدا خریدا جس پر تصویریں تھیں۔ رسول اللہ صلی اللہ علیہ وسلم ( اسے دیکھ کر ) دروازے پر کھڑے ہو گئے اور اندر تشریف نہیں لائے۔ میں نے عرض کیا کہ یا رسول اللہ! میں نے جو غلطی کی ہے اس سے میں اللہ سے معافی مانگتی ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ گدا کس لیے ہے؟ میں نے عرض کیا کہ آپ کے بیٹھنے اور اس پر ٹیک لگانے کے لیے ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ان مورت کے بنانے والوں کو قیامت کے دن عذاب دیا جائے گا اور ان سے کہا جائے گا کہ جو تم نے پیدا کیا ہے اسے زندہ بھی کر کے دکھاؤ اور فرشتے اس گھر میں نہیں داخل ہوتے جس میں مورت ہو۔' WHERE id = 5730;
UPDATE hadiths SET urdu = 'ہم سے ہدبہ بن خالد نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، کہا ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا، ان سے معاذ بن جبل نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی سواری پر آپ کے پیچھے بیٹھا ہوا تھا اور میرے اور نبی کریم صلی اللہ علیہ وسلم کے درمیان کجاوہ کی پچھلی لکڑی کے سوا اور کوئی چیز حائل نہیں تھی اسی حالت میں نبی کریم صلی اللہ علیہ وسلم نے فرمایا: یامعاذ! میں بولا یا رسول اللہ! میں حاضر ہوں، آپ کی اطاعت اور فرمابرداری کے لیے تیار ہوں۔ پھر آپ نے تھوڑی دیر تک چلتے رہے۔ اس کے بعد فرمایا: یا معاذ! میں بولا، یا رسول اللہ! حاضر ہوں آپ کی اطاعت کے لیے تیار ہوں۔ پھر آپ تھوڑی دیر چلتے رہے اس کے بعد فرمایا: یا معاذ! میں نے عرض کیا حاضر ہوں، یا رسول اللہ! آپ کی اطاعت کے لیے تیار ہوں۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے فرمایا تمہیں معلوم ہے اللہ کے اپنے بندوں پر کیا حق ہیں؟ میں نے عرض کیا اللہ اور اس کے رسول ہی کو زیادہ علم ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ کے بندوں پر حق یہ ہیں کہ بندے خاص اس کی عبادت کریں اور اس کے ساتھ کسی کو شریک نہ بنائیں پھر آپ تھوڑی دیر چلتے رہے۔ اس کے بعد فرمایا: معاذ! میں نے عرض کیا، حاضر ہوں یا رسول اللہ! آپ کی اطاعت کے لیے تیار ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں معلوم ہے بندوں کا اللہ پر کیا حق ہے۔ جب کہ وہ یہ کام کر لیں۔ میں نے عرض کیا اللہ اور اس کے رسول کو زیادہ علم ہے۔ فرمایا کہ پھر بندوں کا اللہ پر حق ہے کہ وہ انہیں عذاب نہ کرے۔' WHERE id = 5740;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ولید نے بیان کیا، انہوں نے کہا ہم سے محمد بن جعفر نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ مجھ سے عبیداللہ بن ابی بکر نے بیان کیا، انہوں نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے کبائر کا ذکر کیا یا ( انہوں نے کہا کہ ) نبی کریم صلی اللہ علیہ وسلم سے کبائر کے متعلق پوچھا گیا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کے ساتھ شرک کرنا، کسی کی ( ناحق ) جان لینا، والدین کی نافرمانی کرنا پھر فرمایا کیا میں تمہیں سب سے بڑا گناہ نہ بتا دوں؟ فرمایا کہ جھوٹی بات یا فرمایا کہ جھوٹی شہادت ( سب سے بڑا گناہ ہے ) شعبہ نے بیان کیا کہ میرا غالب گمان یہ ہے کہ نبی کریم صلی اللہ علیہ وسلم نے جھوٹی گواہی فرمایا تھا۔' WHERE id = 5750;
UPDATE hadiths SET urdu = 'مجھ سے بشر بن محمد نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معاویہ بن ابی مزرد نے خبر دی، کہا کہ میں نے اپنے چچا سعید بن یسار سے سنا، وہ ابوہریرہ رضی اللہ عنہ سے بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے فرمایا اللہ تعالیٰ نے مخلوق پیدا کی اور جب اس سے فراغت ہوئی تو رحم نے عرض کیا کہ یہ اس شخص کی جگہ ہے جو قطع رحمی سے تیری پناہ مانگے۔ اللہ تعالیٰ نے فرمایا کہ ہاں کیا تم اس پر راضی نہیں کہ میں اس سے جوڑوں گا جو تم سے اپنے آپ کو جوڑے اور اس سے توڑ لوں گا جو تم سے اپنے آپ کو توڑ لے؟ رحم نے کہا کیوں نہیں، اے رب! اللہ تعالیٰ نے فرمایا کہ پس یہ تجھ کو دیا۔ رسول اللہ صلی اللہ علیہ وسلم نے اس کے بعد فرمایا کہ اگر تمہارا جی چاہے تو یہ آیت پڑھ لو «فهل عسيتم إن توليتم أن تفسدوا في الأرض وتقطعوا أرحامكم‏» یعنی ”کچھ عجیب نہیں کہ اگر تم کو حکومت مل جائے تو تم ملک میں فساد برپا کرو اور رشتے ناطے توڑ ڈالو۔“' WHERE id = 5760;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے خبر دی، ان سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے حسن بن علی رضی اللہ عنہ کو بوسہ دیا۔ نبی کریم صلی اللہ علیہ وسلم کے پاس اقرع بن حابس رضی اللہ عنہ بیٹھے ہوئے تھے۔ اقرع رضی اللہ عنہ نے اس پر کہا کہ میرے دس لڑکے ہیں اور میں نے ان میں سے کسی کو بوسہ نہیں دیا۔ نبی کریم صلی اللہ علیہ وسلم نے ان کی طرف دیکھا اور فرمایا کہ جو اللہ کی مخلوق پر رحم نہیں کرتا اس پر بھی رحم نہیں کیا جاتا۔' WHERE id = 5770;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ثور بن زید نے، ان سے ابوالغیث نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بیواؤں اور مسکینوں کے لیے کوشش کرنے والا اللہ کے راستے میں جہاد کرنے والے کی طرح ہے۔ عبداللہ قعنبی کو اس میں شک ہے۔ امام مالک نے اس حدیث میں یہ بھی کہا تھا اس شخص کے برابر ثواب ملتا ہے جو نماز میں کھڑا رہتا ہے تھکتا ہی نہیں اور اس شخص کے برابر جو روزے برابر رکھے چلا جاتا ہے افطار ہی نہیں کرتا ہے۔' WHERE id = 5780;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث نے بیان کیا، کہا ہم سے سعید نے بیان کیا وہ سعید مقبری ہیں، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم فرمایا کرتے تھے ”اے مسلمان عورتو! تم میں سے کوئی عورت اپنی کسی پڑوسن کے لیے کسی بھی چیز کو ( ہدیہ میں ) دینے کے لیے حقیر نہ سمجھے خواہ بکری کا پایہ ہی کیوں نہ ہو۔“' WHERE id = 5790;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر بن حارث ابوعمرو حوش نے بیان کیا، کہا ہم سے شعبہ بن حجاج نے بیان کیا، ان سے سلیمان نے، انہوں نے ابووائل شقیق بن سلمہ سے سنا، انہوں نے مسروق سے سنا، انہوں نے بیان کیا کہ عمر رضی اللہ عنہ نے کہا (دوسری سند) امام بخاری رحمہ اللہ نے کہا ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے شقیق بن سلمہ نے اور ان سے مسروق نے بیان کیا کہ جب معاویہ رضی اللہ عنہ کے ساتھ عبداللہ بن عمرو بن عاص کوفہ تشریف لائے تو ہم ان کی خدمت میں حاضر ہوئے۔ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کا ذکر کیا اور بتلایا کہ نبی کریم صلی اللہ علیہ وسلم بدگو نہ تھے اور نہ آپ بدزبان تھے اور انہوں نے یہ بھی بیان کیا کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سب سے بہتر وہ آدمی ہے، جس کے اخلاق سب سے اچھے ہوں۔' WHERE id = 5801;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حکم نے، ان سے ابراہیم نخعی نے، ان سے اسود نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم اپنے گھر میں کیا کرتے تھے؟ فرمایا نبی کریم صلی اللہ علیہ وسلم اپنے گھر کے کام کاج کرتے اور جب نماز کا وقت ہو جاتا تو نماز کے لیے مسجد تشریف لے جاتے تھے۔' WHERE id = 5811;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے بشر بن مفضل نے بیان کیا، ان سے حمید نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا کہ مجھ سے عبادہ بن صامت رضی اللہ عنہ نے کہا، نبی کریم صلی اللہ علیہ وسلم لوگوں کو لیلۃ القدر کی بشارت دینے کے لیے حجرے سے باہر تشریف لائے، لیکن مسلمانوں کے دو آدمی اس وقت آپس میں کسی بات پر لڑنے لگے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہیں ( لیلۃ القدر کے متعلق ) بتانے کے لیے نکلا تھا لیکن فلاں فلاں آپس میں لڑنے لگے اور ( میرے علم سے ) وہ اٹھا لی گئی۔ ممکن ہے کہ یہی تمہارے لیے اچھا ہو۔ اب تم اسے 29 رمضان اور 27 رمضان اور 25 رمضان کی راتوں میں تلاش کرو۔' WHERE id = 5821;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، انہیں اعمش نے، انہیں ابووائل نے اور ان سے ابن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے کچھ مال تقسیم کیا تو انصار میں سے ایک شخص نے کہا کہ اللہ کی قسم! محمد صلی اللہ علیہ وسلم کو اس تقسیم سے اللہ کی رضا مقصود نہ تھی۔ میں نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر اس شخص کی یہ بات آپ کو سنائی تو نبی کریم صلی اللہ علیہ وسلم کے چہرے کا رنگ بدل گیا اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ موسیٰ علیہ السلام پر رحم کرے، انہیں اس سے بھی زیادہ ایذا دی گئی، لیکن انہوں نے صبر کیا۔' WHERE id = 5831;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے، ان سے ان کے بھتیجے ابن شہاب نے، ان سے ابن شہاب (محمد بن مسلم) نے، ان سے سالم بن عبداللہ نے بیان کیا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میری تمام امت کو معاف کیا جائے گا سوا گناہوں کو کھلم کھلا کرنے والوں کے اور گناہوں کو کھلم کھلا کرنے میں یہ بھی شامل ہے کہ ایک شخص رات کو کوئی ( گناہ کا ) کام کرے اور اس کے باوجود کہ اللہ نے اس کے گناہ کو چھپا دیا ہے مگر صبح ہونے پر وہ کہنے لگے کہ اے فلاں! میں نے کل رات فلاں فلاں برا کام کیا تھا۔ رات گزر گئی تھی اور اس کے رب نے اس کا گناہ چھپائے رکھا، لیکن جب صبح ہوئی تو وہ خود اللہ کے پردے کو کھولنے لگا۔' WHERE id = 5841;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے حمید طویل نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ جب عبدالرحمٰن بن عوف ہمارے یہاں آئے تو نبی کریم صلی اللہ علیہ وسلم نے ان میں اور سعد بن ربیع میں بھائی چارگی کرائی تو پھر ( جب عبدالرحمٰن بن عوف نے نکاح کیا تو ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اب ولیمہ کر خواہ ایک بکری کا ہو۔' WHERE id = 5852;
UPDATE hadiths SET urdu = 'ہم سے محمد بن محبوب نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے (دوسری سند) اور مجھ سے خلیفہ نے بیان کیا، کہا ہم کو یزید بن زریع نے بیان کیا، ان سے سعید نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ ایک صاحب جمعہ کے دن نبی کریم صلی اللہ علیہ وسلم کے پاس آئے نبی کریم صلی اللہ علیہ وسلم اس وقت مدینہ میں جمعہ کا خطبہ دے رہے تھے، انہوں نے عرض کیا بارش کا قحط پڑ گیا ہے، آپ اپنے رب سے بارش کی دعا کیجئے۔ نبی کریم صلی اللہ علیہ وسلم نے آسمان کی طرف دیکھا کہیں ہمیں بادل نظر نہیں آ رہا تھا۔ پھر آپ نے بارش کی دعا کی، اتنے میں بادل اٹھا اور بعض ٹکڑے بعض کی طرف بڑھے اور بارش ہونے لگی، یہاں تک کہ مدینہ کے نالے بہنے لگے۔ اگلے جمعہ تک اسی طرح بارش ہوتی رہی سلسلہ ٹوٹتا ہی نہ تھا چنانچہ وہی صاحب یا کوئی دوسرے ( اگلے جمعہ کو ) کھڑے ہوئے، نبی کریم صلی اللہ علیہ وسلم خطبہ دے رہے تھے اور انہوں نے عرض کیا: ہم ڈوب گئے، اپنے رب سے دعا کریں کہ اب بارش بند کر دے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اے اللہ! ہمارے چاروں طرف بارش ہو، ہم پر نہ ہو۔ دو یا تین مرتبہ آپ صلی اللہ علیہ وسلم نے یہ فرمایا، چنانچہ مدینہ منورہ سے بادل چھٹنے لگے، بائیں اور دائیں، ہمارے چاروں طرف دوسرے مقامات پر بارش ہونے لگی اور ہمارے یہاں بارش یکدم بند ہو گئی۔ یہ اللہ نے لوگوں کو نبی کریم صلی اللہ علیہ وسلم کا معجزہ اور اپنے پیغمبر صلی اللہ علیہ وسلم کی کرامت اور دعا کی قبولیت بتلائی۔' WHERE id = 5862;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یحییٰ ذہلی (یا محمد بن بشار) اور احمد بن سعید دارمی نے بیان کیا، انہوں نے کہا کہ ہم سے عثمان بن عمر نے بیان کیا، کہا ہم کو علی بن مبارک نے خبر دی، انہیں یحییٰ بن ابی کثیر نے، انہیں ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب کوئی شخص اپنے کسی بھائی کو کہتا ہے کہ اے کافر! تو ان دونوں میں سے ایک کافر ہو گیا۔ اور عکرمہ بن عمار نے یحییٰ سے بیان کیا کہ ان سے عبداللہ بن یزید نے کہا، انہوں نے ابوسلمہ سے سنا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 5872;
UPDATE hadiths SET urdu = 'اور مکی بن ابراہیم نے بیان کیا انہوں نے کہا کہ ہم سے عبداللہ بن سعید نے بیان کیا (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے محمد بن زیاد نے بیان کیا، انہوں نے کہا ہم سے محمد بن جعفر نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن سعید نے بیان کیا، انہوں نے کہا کہ مجھ سے عمر بن عبیداللہ کے غلام سالم ابوالنضر نے بیان کیا، ان سے بسر بن سعید نے بیان کیا اور ان سے زید بن ثابت رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے کھجور کی شاخوں یا بوریئے سے ایک مکان چھوٹے سے حجرے کی طرح بنا لیا تھا۔ وہاں آ کر آپ تہجد کی نماز پڑھا کرتے تھے، چند لوگ بھی وہاں آ گئے اور انہوں نے آپ کی اقتداء میں نماز پڑھی پھر سب لوگ دوسری رات بھی آ گئے اور ٹھہرے رہے لیکن آپ گھر ہی میں رہے اور باہر ان کے پاس تشریف نہیں لائے۔ لوگ آواز بلند کرنے لگے اور دروازے پر کنکریاں ماریں تو نبی کریم صلی اللہ علیہ وسلم غصہ کی حالت میں باہر تشریف لائے اور فرمایا تم چاہتے ہو کہ ہمیشہ یہ نماز پڑھتے رہو تاکہ تم پر فرض ہو جائے ( اس وقت مشکل ہو ) دیکھو تم نفل نمازیں اپنے گھروں میں ہی پڑھا کرو۔ کیونکہ فرض نمازوں کے سوا آدمی کی بہترین نفل نماز وہ ہے جو گھر میں پڑھی جائے۔' WHERE id = 5882;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے مرحوم بن عبدالعزیز نے بیان کیا، انہوں نے کہا کہ میں نے کہا کہ میں نے ثابت سے سنا اور انہوں نے انس رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ایک خاتون نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور اپنے آپ کو نبی کریم صلی اللہ علیہ وسلم کے نکاح کے لیے پیش کیا اور عرض کیا: کیا نبی کریم صلی اللہ علیہ وسلم کو مجھ سے نکاح کی ضرورت ہے؟ اس پر انس رضی اللہ عنہ کی صاحبزادی بولیں، وہ کتنی بےحیا تھی۔ انس رضی اللہ عنہ نے کہا کہ وہ تم سے تو اچھی تھیں انہوں نے اپنے آپ کو نبی کریم صلی اللہ علیہ وسلم کے نکاح کے لیے پیش کیا۔' WHERE id = 5892;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا ان سے عقیل نے بیان کیا، ان سے زہری نے، ان سے ابن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مومن کو ایک سوراخ سے دوبارہ ڈنگ نہیں لگ سکتا۔“' WHERE id = 5902;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہوں نے کہا مجھ کو ابوبکر بن عبدالرحمٰن نے خبر دی، انہیں مروان بن حکم نے خبر دی، انہیں عبدالرحمٰن بن اسود بن عبد یغوث نے خبر دی، انہیں ابی بن کعب رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”بعض شعروں میں دانائی ہوتی ہے۔“' WHERE id = 5913;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، انہوں نے کہا مجھ سے میرے والد نے بیان کیا، انہوں کہا ہم سے اعمش نے بیان کیا، کہا کہ میں نے ابوصالح سے سنا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سے فرمایا ”اگر تم میں سے کوئی شخص اپنا پیٹ پیپ سے بھر لے تو یہ اس سے بہتر ہے کہ وہ شعروں سے بھر جائے۔“' WHERE id = 5923;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن عبدالرحمٰن نے بیان کیا، انہوں نے کہا ہم سے ولید نے بیان کیا، انہوں نے کہا ہم سے ابوعمرو اوزاعی نے بیان کیا، کہا کہ مجھ سے ابن شہاب زہری نے بیان کیا، ان سے عطاء بن یزید لیثی نے اور ان سے ابو سعید خدری نے کہ ایک دیہاتی نے کہا: یا رسول اللہ! ہجرت کے بارے میں مجھے کچھ بتائیے ( اس کی نیت ہجرت کی تھی ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تجھ پر افسوس! ہجرت کو تو نے کیا سمجھا ہے یہ بہت مشکل ہے۔ تمہارے پاس کچھ اونٹ ہیں۔ انہوں نے عرض کیا کہ جی ہاں، نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کیا تم ان کی زکوٰۃ ادا کرتے ہو؟ انہوں نے عرض کیا کہ جی ہاں، فرمایا کہ پھر سات سمندر پار عمل کرتے رہو۔ اللہ تمہارے کسی عمل کے ثواب کو ضائع نہ کرے گا۔' WHERE id = 5933;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے عبیداللہ عمری نے، ان سے نافع نے ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”عہد توڑنے والے کے لیے قیامت میں ایک جھنڈا اٹھایا جائے گا اور پکار دیا جائے گا کہ یہ فلاں بن فلاں کی دغا بازی کا نشان ہے۔“' WHERE id = 5943;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے خالد نے بیان کیا، کہا ہم سے حصین نے بیان کیا، ان سے سالم نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ ہم میں سے ایک شخص کے یہاں بچہ پیدا ہوا تو انہوں نے اس کا نام قاسم رکھا۔ صحابہ نے ان سے کہا کہ جب تک ہم نبی کریم صلی اللہ علیہ وسلم سے نہ پوچھ لیں۔ ہم اس نام پر تمہاری کنیت نہیں ہونے دیں گے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میرے نام پر نام رکھو لیکن میری کنیت نہ اختیار کرو۔' WHERE id = 5953;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابوعوانہ نے بیان کیا، انہوں نے کہا ہم سے ابوحصین نے بیان کیا، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم میرے نام پر نام رکھو لیکن تم میری کنیت نہ اختیار کرو اور جس نے مجھے خواب میں دیکھا تو اس نے مجھے ہی دیکھا کیونکہ شیطان میری صورت میں نہیں آ سکتا اور جس نے قصداً میری طرف کوئی جھوٹی بات منسوب کی اس نے اپنا ٹھکانا جہنم میں بنا لیا۔“' WHERE id = 5963;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے (دوسری سند) اور ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے میرے بھائی عبدالحمید نے بیان کیا، ان سے سلیمان نے بیان کیا، ان سے محمد بن ابی عتیق نے بیان کیا، ان سے ابن ابی شہاب نے بیان کیا، ان سے عروہ بن زبیر نے اور انہیں اسامہ بن زید رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ایک گدھے پر سوار ہوئے جس پر فدک کا بنا ہوا ایک کپڑا بچھا ہوا تھا، اسامہ آپ کے پیچھے سوار تھے۔ نبی کریم صلی اللہ علیہ وسلم بنی حارث بن خزرج میں سعد بن عبادہ رضی اللہ عنہ کی عیادت کے لیے تشریف لے جا رہے تھے، یہ واقعہ غزوہ بدر سے پہلے کا ہے یہ دونوں روانہ ہوئے اور راستے میں ایک مجلس سے گزرے جس میں عبداللہ بن ابی ابن سلول بھی تھا۔ عبداللہ نے ابھی تک اپنے اسلام کا اعلان نہیں کیا تھا۔ اس مجلس میں کچھ مسلمان بھی تھے۔ بتوں کی پرستش کرنے والے کچھ مشرکین بھی تھے اور کچھ یہودی بھی تھے۔ مسلمان شرکاء میں عبداللہ بن رواحہ بھی تھے۔ جب مجلس پر ( نبی کریم صلی اللہ علیہ وسلم کی ) سواری کا غبار اڑ کر پڑا تو عبداللہ بن ابی نے اپنی چادر ناک پر رکھ لی اور کہنے لگا کہ ہم پر غبار نہ اڑاؤ، اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے ( قریب پہنچنے کے بعد ) انہیں سلام کیا اور کھڑے ہو گئے۔ پھر سواری سے اتر کر انہیں اللہ کی طرف بلایا اور قرآن مجید کی آیتیں انہیں پڑھ کر سنائیں۔ اس پر عبداللہ بن ابی ابن سلول نے کہا کہ بھلے آدمی جو کلام تم نے پڑھا اس سے بہتر کلام نہیں ہو سکتا۔ اگرچہ واقعی یہ حق ہے مگر ہماری مجلسوں میں آ کر اس کی وجہ سے ہمیں تکلیف نہ دیا کرو۔ جو تمہارے پاس جائے بس اس کو یہ قصے سنا دیا کرو۔ عبداللہ بن رواحہ رضی اللہ عنہ نے عرض کیا: ضرور، یا رسول اللہ! آپ ہماری مجلسوں میں بھی تشریف لایا کریں کیونکہ ہم اسے پسند کرتے ہیں۔ اس معاملہ پر مسلمانوں، مشرکوں اور یہودیوں کا جھگڑا ہو گیا اور قریب تھا کہ ایک دوسرے کے خلاف ہاتھ اٹھا دیں۔ لیکن نبی کریم صلی اللہ علیہ وسلم انہیں خاموش کرتے رہے آخر جب سب لوگ خاموش ہو گئے تو نبی کریم صلی اللہ علیہ وسلم اپنی سواری پر بیٹھے اور روانہ ہوئے۔ جب سعد بن عبادہ کے یہاں پہنچے تو ان سے فرمایا کہ اے سعد! تم نے نہیں سنا آج ابوحباب نے کس طرح باتیں کی ہیں۔ آپ کا اشارہ عبداللہ بن ابی کی طرف تھا کہ اس نے یہ باتیں کہی ہیں سعد بن عبادہ رضی اللہ عنہ بولے، میرا باپ آپ پر صدقے ہو، یا رسول اللہ! آپ اسے معاف فرما دیں اور اس سے درگذر فرمائیں، اس ذات کی قسم جس نے آپ پر کتاب نازل کی ہے اللہ نے آپ کو سچا کلام دے کر یہاں بھیجا جو آپ پر اتارا۔ آپ کے تشریف لانے سے پہلے اس شہر ( مدینہ منورہ ) کے باشندے اس پر متفق ہو گئے تھے کہ اسے ( عبداللہ بن ابی کو ) شاہی تاج پہنا دیں اور شاہی عمامہ باندھ دیں لیکن اللہ نے سچا کلام دے کر آپ کو یہاں بھیج دیا اور یہ تجویز موقوف رہی تو وہ اس کی وجہ سے چڑ گیا اور جو کچھ آپ نے آج ملاحظہ کیا، وہ اسی جلن کی وجہ سے ہے۔ نبی کریم صلی اللہ علیہ وسلم نے عبداللہ بن ابی کو معاف کر دیا۔ نبی کریم صلی اللہ علیہ وسلم اور آپ کے صحابہ، مشرکین اور اہل کتاب سے جیسا کہ انہیں اللہ تعالیٰ نے حکم دیا تھا۔ درگزر کیا کرتے تھے اور ان کی طرف سے پہنچنے والی تکلیفوں پر صبر کیا کرتے تھے۔ اللہ تعالیٰ نے بھی ارشاد فرمایا ہے کہ ”تم ان لوگوں سے جنہیں کتاب دی گئی ہے ( اذیت دہ باتیں ) سنو گے۔“ دوسرے موقع پر ارشاد فرمایا ”بہت سے اہل کتاب خواہش رکھتے ہیں۔“ الخ۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم انہیں معاف کرنے کے لیے اللہ کے حکم کے مطابق توجیہ کیا کرتے تھے۔ بالآخر آپ کو ( جنگ کی ) اجازت دی گئی۔ جب نبی کریم صلی اللہ علیہ وسلم نے غزوہ بدر کیا اور اللہ کے حکم سے اس میں کفار کے بڑے بڑے بہادر اور قریش کے سردار قتل کئے گئے تو نبی کریم صلی اللہ علیہ وسلم اپنے صحابہ کے ساتھ فتح مند اور غنیمت کا مال لیے ہوئے واپس ہوئے، ان کے ساتھ کفار قریش کے کتنے ہی بہادر سردار قید بھی کر کے لائے تو اس وقت عبداللہ بن ابی بن سلول اور اس کے بت پرست مشرک ساتھی کہنے لگے کہ اب ان کا کام جم گیا تو نبی کریم صلی اللہ علیہ وسلم سے بیعت کر لو، اس وقت انہوں نے اسلام پر بیعت کی اور بظاہر مسلمان ہو گئے ( مگر دل میں نفاق رہا ) ۔' WHERE id = 5973;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا کہا ہم سے ابن ابی عدی نے بیان کیا، ان سے شعبہ نے، ان سے سلیمان و منصور نے، ان سے سعد بن عبیدہ نے ان سے ابوعبدالرحمٰن سلمی نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک جنازہ میں شریک تھے۔ نبی کریم صلی اللہ علیہ وسلم کے ہاتھ میں ایک چھڑی تھی اس کو آپ زمین پر مار رہے تھے پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم میں کوئی ایسا نہیں ہے جس کا جنت یا دوزخ کا ٹھکانا طے نہ ہو چکا ہو۔ صحابہ نے عرض کیا: پھر کیوں نہ ہم اس پر بھروسہ کر لیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عمل کرتے رہو کیونکہ ہر شخص جس ٹھکانے کے لیے پیدا کیا گیا ہے اس کو ویسی ہی توفیق دی جائے گی۔ جیسا کہ قرآن شریف کے سورۃ واللیل میں ہے «فأما من أعطى واتقى‏» ”جس نے للہ خیرات کی اور اللہ تعالیٰ سے ڈرا“ آخر تک۔' WHERE id = 5983;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، ان سے معمر نے، ان سے ہمام نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ نے آدم کو اپنی صورت پر بنایا، ان کی لمبائی ساٹھ ہاتھ تھی۔ جب انہیں پیدا کر چکا تو فرمایا کہ جاؤ اور ان فرشتوں کو جو بیٹھے ہوئے ہیں، سلام کرو اور سنو کہ تمہارے سلام کا کیا جواب دیتے ہیں، کیونکہ یہی تمہارا اور تمہاری اولاد کا سلام ہو گا۔ آدم علیہ السلام نے کہا: السلام علیکم! فرشتوں نے جواب دیا، السلام علیک ورحمۃ اللہ، انہوں نے آدم کے سلام پر ”ورحمۃ اللہ“ بڑھا دیا۔ پس جو شخص بھی جنت میں جائے گا آدم علیہ السلام کی صورت کے مطابق ہو کر جائے گا۔“ اس کے بعد سے پھر خلقت کا قد و قامت کم ہوتا گیا، اب تک ایسا ہی ہوتا رہا۔' WHERE id = 5993;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے زہری نے بیان کیا، ان سے عطاء بن یزید لیثی نے اور ان سے ابوایوب رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کسی مسلمان کے لیے جائز نہیں کہ وہ اپنے کسی ( مسلمان ) بھائی سے تین دن سے زیادہ تعلق کاٹے کہ جب وہ ملیں تو یہ ایک طرف منہ پھیر لے اور دوسرا دوسری طرف اور دونوں میں اچھا وہ ہے جو سلام پہلے کرے۔“ اور سفیان نے کہا کہ انہوں نے یہ حدیث زہری سے تین مرتبہ سنی ہے۔' WHERE id = 6003;
UPDATE hadiths SET urdu = 'ہم سے علی بن الجعد نے بیان کیا، انہوں نے کہا ہم کو شعبہ نے خبر دی، انہیں سیار نے انہوں نے ثابت بنانی سے روایت کی، انہیں انس بن مالک رضی اللہ عنہ نے کہ آپ بچوں کے پاس سے گزرے تو انہیں سلام کیا اور فرمایا کہ نبی کریم صلی اللہ علیہ وسلم بھی ایسا ہی کرتے تھے۔' WHERE id = 6013;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب تمہیں یہودی سلام کریں اور اگر ان میں سے کوئی «السام عليك‏.‏» کہے تو تم اس کے جواب میں صرف «وعليك» ( اور تمہیں بھی ) کہہ دیا کرو۔“' WHERE id = 6023;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے، ان سے انس رضی اللہ عنہ نے اور ان سے معاذ رضی اللہ عنہ نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی سواری پر نبی کریم صلی اللہ علیہ وسلم کے پیچھے سوار تھا آپ صلی اللہ علیہ وسلم نے فرمایا کہ اے معاذ! میں نے کہا «لبيك وسعديك‏.‏» ( حاضر ہوں ) ۔ پھر نبی کریم صلی اللہ علیہ وسلم نے تین مرتبہ مجھے اسی طرح مخاطب کیا اس کے بعد فرمایا تمہیں معلوم ہے کہ بندوں پر اللہ کا کیا حق ہے؟ ( پھر خود ہی جواب دیا ) کہ یہ کہ اسی کی عبادت کریں اور اس کے ساتھ کسی کو شریک نہ ٹھہرائیں پھر آپ تھوڑی دیر چلتے رہے اور فرمایا کہ اے معاذ! میں نے عرض کی «لبيك وسعديك‏.‏» فرمایا تمہیں معلوم ہے کہ جب وہ یہ کر لیں تو اللہ پر بندوں کا کیا حق ہے؟ یہ کہ انہیں عذاب نہ دے۔' WHERE id = 6033;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن شاہین واسطی نے بیان کیا، کہا ہم سے خالد نے بیان کیا (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، ان سے عمرو بن عون نے بیان کیا، ان سے خالد (خالد بن عبداللہ طحان) نے بیان کیا، ان سے خالد (خالد حذاء) نے، ان سے ابوقلابہ نے بیان کیا، کہا کہ مجھے ابوالملیح عامر بن زید نے خبر دی، انہوں نے (ابوقلابہ) کو (خطاب کر کے) کہا کہ میں تمہارے والد زید کے ساتھ عبداللہ بن عمر رضی اللہ عنہما کی خدمت میں حاضر ہوا، انہوں نے ہم سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے میرے روزے کا ذکر کیا گیا۔ نبی کریم صلی اللہ علیہ وسلم میرے یہاں تشریف لائے میں نے آپ کے لیے چمڑے کا ایک گدا، جس میں کھجور کی چھال بھری ہوئی تھی بچھا دیا۔ نبی کریم صلی اللہ علیہ وسلم زمین پر بیٹھے اور گدا میرے اور نبی کریم صلی اللہ علیہ وسلم کے درمیان ویسا ہی پڑا رہا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ کیا تمہارے لیے ہر مہینے میں تین دن کے ( روزے ) کافی نہیں؟ میں نے عرض کیا: یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے فرمایا پھر پانچ دن رکھا کر۔ میں نے عرض کیا: یا رسول اللہ! فرمایا سات دن۔ میں نے عرض کیا: یا رسول اللہ! فرمایا نو دن۔ میں نے عرض کیا: یا رسول اللہ! فرمایا گیارہ دن۔ میں نے عرض کیا یا رسول اللہ! فرمایا داؤد علیہ السلام کے روزے سے زیادہ کوئی روزہ نہیں ہے۔ زندگی کے نصف ایام، ایک دن کا روزہ اور ایک دن بغیر روزہ کے رہنا۔' WHERE id = 6043;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ محمد بن میمون نے، ان سے اعمش نے، ان سے شقیق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک مرتبہ کچھ مال تقسیم فرمایا اس پر انصار کے ایک شخص نے کہا کہ یہ ایسی تقسیم ہے جس سے اللہ کی خوشنودی مقصود نہ تھی میں نے کہا کہ ہاں! اللہ کی قسم میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں جاؤں گا۔ چنانچہ میں گیا، نبی کریم صلی اللہ علیہ وسلم اس وقت مجلس میں بیٹھے ہوئے تھے میں نے نبی کریم صلی اللہ علیہ وسلم کے کان میں چپکے سے یہ بات کہی تو آپ غصہ ہو گئے اور آپ کا چہرہ سرخ ہو گیا پھر آپ نے فرمایا کہ موسیٰ علیہ السلام پر اللہ کی رحمت ہو انہیں اس سے بھی زیادہ تکلیف پہنچائی گئی لیکن انہوں نے صبر کیا ( پس میں بھی صبر کروں گا ) ۔' WHERE id = 6055;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے بیان کیا، کہا کہ مجھے حمید بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم میں سے جس نے قسم کھائی اور کہا کہ لات و عزیٰ کی قسم، تو پھر وہ «لا إله إلا الله» کہے اور جس نے اپنے ساتھی سے کہا کہ آؤ جوا کھیلیں تو اسے صدقہ کر دینا چاہئے۔“' WHERE id = 6065;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے معتمر بن سلیمان نے بیان کیا، کہا کہ میں نے منصور سے سنا، ان سے سعد بن عبیدہ نے بیان کیا کہ مجھ سے براء بن عازب رضی اللہ عنہ نے بیان کیا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب تو سونے لگے تو نماز کے وضو کی طرح وضو کر پھر دائیں کروٹ لیٹ جا اور یہ دعا پڑھ «اللهم أسلمت نفسي إليك،‏‏‏‏ وفوضت أمري إليك،‏‏‏‏ وألجأت ظهري إليك،‏‏‏‏ رهبة ورغبة إليك،‏‏‏‏ لا ملجأ ولا منجا منك إلا إليك،‏‏‏‏ آمنت بكتابك الذي أنزلت،‏‏‏‏ وبنبيك الذي أرسلت‏.‏» ”اے اللہ! میں نے اپنے آپ کو تیری اطاعت میں دے دیا۔ اپنا سب کچھ تیرے سپرد کر دیا۔ اپنے معاملات تیرے حوالے کر دئیے۔ خوف کی وجہ سے اور تیری ( رحمت و ثواب کی ) امید میں کوئی پناہ گاہ کوئی مخلص تیرے سوا نہیں میں تیری کتاب پر ایمان لایا جو تو نے نازل کی ہے اور تیرے نبی پر جن کو تو نے بھیجا ہے۔“ اس کے بعد اگر تم مر گئے تو فطرت ( دین اسلام پر مرو گے پس ان کلمات کو ( رات کی ) سب سے آخری بات بناؤ جنہیں تم اپنی زبان سے ادا کرو ( براء بن عازب رضی اللہ عنہ نے بیان کیا ) میں نے عرض کی «وبرسولك الذي أرسلت‏.‏» کہنے میں کیا وجہ ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں «وبنبيك الذي أرسلت» کہو۔' WHERE id = 6075;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے ابوعبداللہ الاغر اور ابوسلمہ بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ہمارا رب تبارک و تعالیٰ ہر رات آسمان دنیا کی طرف نزول فرماتا ہے، اس وقت جب رات کا آخری تہائی حصہ باقی رہ جاتا ہے اور فرماتا ہے کون ہے جو مجھ سے دعا کرتا ہے کہ میں اس کی دعا قبول کروں، کون ہے جو مجھ سے مانگتا ہے کہ میں اسے دوں، کون ہے جو مجھ سے بخشش طلب کرتا ہے کہ میں اس کی بخشش کروں۔' WHERE id = 6085;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے مسلم کے مولیٰ یزید بن ابی عبیدہ نے اور ان سے سلمہ بن الاکوع رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ خیبر گئے ( راستہ میں ) مسلمانوں میں سے کسی شخص نے کہا عامر! اپنی حدی سناؤ۔ وہ حدی پڑھنے لگے اور کہنے لگے۔ اللہ کی قسم! اگر اللہ نہ ہوتا تو ہم ہدایت نہ پاتے“ اس کے علاوہ دوسرے اشعار بھی انہوں نے پڑھے مجھے وہ یاد نہیں ہیں۔ ( اونٹ حدی سن کر تیز چلنے لگے تو ) رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ یہ سواریوں کو کون ہنکا رہا ہے، لوگوں نے کہا کہ عامر بن اکوع ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ اس پر رحم کرے۔ مسلمانوں میں سے ایک شخص نے عرض کیا: یا رسول اللہ! کاش ابھی آپ ان سے ہمیں اور فائدہ اٹھانے دیتے۔ پھر جب صف بندی ہوئی تو مسلمانوں نے کافروں سے جنگ کی اور عامر رضی اللہ عنہ کی تلوار چھوٹی تھی جو خود ان کے پاؤں پر لگ گئی اور ان کی موت ہو گئی۔ شام ہوئی تو لوگوں نے جگہ جگہ آگ جلائی۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ یہ آگ کیسی ہے، اسے کیوں جلایا گیا ہے؟ صحابہ نے کہا کہ پالتو گدھوں ( کا گوشت پکانے ) کے لیے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو کچھ ہانڈیوں میں گوشت ہے اسے پھینک دو اور ہانڈیوں کو توڑ دو۔ ایک صحابی نے عرض کیا کہ یا رسول اللہ! اجازت ہو تو ایسا کیوں نہ کر لیں کہ ہانڈیوں میں جو کچھ ہے اسے پھینک دیں اور ہانڈیوں کو دھو لیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اچھا یہی کر لو۔' WHERE id = 6095;
UPDATE hadiths SET urdu = 'ابوعبداللہ امام بخاری رحمہ اللہ نے کہا اور عبدالعزیز بن عبداللہ اویسی نے کہا مجھ سے محمد بن جعفر نے بیان کیا، ان سے یحییٰ بن سعید اور شریک بن ابی نمر نے، انہوں نے انس رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے ہاتھ اتنے اٹھائے کہ میں نے آپ کی بغلوں کی سفیدی دیکھی۔' WHERE id = 6105;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، انہوں نے کہا ہم کو اسماعیل بن علیہ نے خبر دی، انہوں نے کہا ہمیں عبدالعزیز بن صہیب نے بتایا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم میں سے کوئی شخص کسی تکلیف کی وجہ سے جو اسے ہونے لگی ہو، موت کی تمنا نہ کرے۔ اگر موت کی تمنا ضروری ہی ہو جائے تو یہ کہے کہ اے اللہ! جب تک میرے لیے زندگی بہتر ہے مجھے زندہ رکھیو اور جب میرے لیے موت بہتر ہو تو مجھے اٹھا لیجیو۔“' WHERE id = 6115;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھے یونس نے خبر دی، انہیں ابن شہاب نے، کہا کہ مجھ کو سعید بن مسیب نے خبر دی اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے اللہ! میں نے جس مومن کو بھی برا بھلا کہا ہو تو اس کے لیے اسے قیامت کے دن اپنی قربت کا ذریعہ بنا دے۔' WHERE id = 6125;
UPDATE hadiths SET urdu = 'ہم سے اس حدیث کو ابومعمر نے بیان کیا، انہوں نے کہا ہم سے عبدالوارث بن سعید نے بیان کیا، ان سے عبدالعزیز بن صہیب نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم پناہ مانگتے تھے اور کہتے تھے کہ «اللهم إني أعوذ بك من الكسل،‏‏‏‏ وأعوذ بك من الجبن،‏‏‏‏ وأعوذ بك من الهرم،‏‏‏‏ وأعوذ بك من البخل» ”اے اللہ! میں تیری پناہ مانگتا ہوں سستی سے اور تیری پناہ مانگتا ہوں بزدلی سے اور تیری پناہ مانگتا ہوں ناکارہ بڑھاپے سے اور تیری پناہ مانگتا ہوں بخل سے۔“' WHERE id = 6135;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، ان سے ابوایوب سختیانی نے بیان کیا، ان سے ابوعثمان نہدی نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھے جب ہم کسی بلند جگہ پر چڑھتے تو تکبیر کہتے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”لوگو! اپنے اوپر رحم کرو، تم کسی بہرے غائب رب کو نہیں پکارتے ہو تم تو اس ذات کو پکارتے ہو جو بہت زیادہ سننے والا، بہت زیادہ دیکھنے والا ہے۔“ پھر نبی کریم صلی اللہ علیہ وسلم میرے پاس تشریف لائے۔ میں اس وقت زیر لب کہہ رہا تھا «لا حول ولا قوة إلا بالله» نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”عبداللہ بن قیس کہو «لا حول ولا قوة إلا بالله» کیونکہ یہ جنت کے خزانوں میں سے ایک خزانہ ہے“ یا نبی کریم صلی اللہ علیہ وسلم نے یہ فرمایا ”میں تمہیں ایک ایسا کلمہ نہ بتا دوں جو جنت کے خزانوں میں سے ایک خزانہ «لا حول ولا قوة إلا بالله» ہے۔“' WHERE id = 6146;
UPDATE hadiths SET urdu = 'ہم سے حسن بن ربیع نے بیان کیا، کہا ہم سے ابوالاحوص نے بیان کیا، ان سے عاصم نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک مہم بھیجی، جس میں شریک لوگوں کو قراء ( یعنی قرآن مجید کے قاری ) کہا جاتا تھا۔ ان سب کو شہید کر دیا گیا۔ میں نے نہیں دیکھا کہ نبی کریم صلی اللہ علیہ وسلم کو کبھی کسی چیز کا اتنا غم ہوا ہو جتنا آپ کو ان کی شہادت کا غم ہوا تھا۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے ایک مہینے تک فجر کی نماز میں ان کے لیے بددعا کی، آپ کہتے کہ عصیہ نے اللہ اور اس کے رسول کی نافرمانی کی۔' WHERE id = 6156;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے عبدالملک بن عمرو نے، کہا کہ ہم سے عمر بن ابی زائد نے، ان سے ابواسحاق سبیعی نے، ان سے عمرو بن میمون نے بیان کیا کہ جس نے یہ کلمہ دس مرتبہ پڑھ لیا وہ ایسا ہو گا جیسے اس نے ایک عربی غلام آزاد کیا۔ اسی سند سے عمر بن ابی زائدہ نے بیان کیا کہ ہم سے عبداللہ بن ابی السفر نے بیان کیا، ان سے شعبی نے، ان سے ربیع بن خثیم نے یہی مضمون تو میں نے ربیع بن خثیم سے پوچھا کہ تم نے کس سے یہ حدیث سنی ہے؟ انہوں نے کہا کہ عمرو بن میمون اودی سے۔ پھر میں عمرو بن میمون کے پاس آیا اور ان سے دریافت کیا کہ تم نے یہ حدیث کس سے سنی ہے؟ انہوں نے کہا کہ ابن ابی لیلیٰ سے۔ ( پھر میں ) ابن ابی لیلیٰ کے پاس آیا اور پوچھا کہ تم نے یہ حدیث کس سے سنی ہے؟ انہوں نے کہا کہ ابوایوب انصاری رضی اللہ عنہ سے، وہ یہ حدیث نبی کریم صلی اللہ علیہ وسلم سے بیان کرتے تھے اور ابراہیم بن یوسف نے بیان کیا، ان سے ان کے والد یوسف بن اسحاق نے، ان سے ابواسحاق سبیعی نے، انہوں نے کہا کہ مجھ سے عمرو بن میمون اودی نے بیان کیا، ان سے عبدالرحمٰن بن ابی لیلیٰ نے اور ان سے ابوایوب انصاری رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے یہی حدیث نقل کی۔ اور موسیٰ بن اسماعیل نے بیان کیا کہ ہم سے وہیب بن خالد نے بیان کیا، ان سے داؤد بن ابی ہند نے،، ان سے عامر شعبی نے، ان سے عبدالرحمٰن بن ابی لیلیٰ نے اور ان سے ابوایوب رضی اللہ عنہ نے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔ اور اسماعیل بن ابی خالد نے بیان کیا، ان سے شعبی نے، ان سے ربیع نے موقوفاً ان کا قول نقل کیا۔ اور آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے عبدالملک بن میسرہ نے بیان کیا، کہا میں نے ہلال بن یساف سے سنا، ان سے ربیع بن خثیم اور عمرو بن میمون دونوں نے اور ان سے ابن مسعود رضی اللہ عنہ نے۔ اور اعمش اور حصین دونوں نے ہلال سے بیان کیا، ان سے ربیع بن خثیم نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے، یہی حدیث روایت کی۔ اور ابو محمد حضرمی نے ابوایوب رضی اللہ عنہ سے، انہوں نبی کریم صلی اللہ علیہ وسلم سے مرفوعاً اسی حدیث کو روایت کیا۔' WHERE id = 6166;
UPDATE hadiths SET urdu = 'ہم سے احمد بن مقدام نے بیان کیا، کہا ہم سے فضیل بن سلیمان نے بیان کیا، کہا ہم سے ابوحازم نے بیان کیا، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ غزوہ خندق کے موقع پر موجود تھے، نبی کریم صلی اللہ علیہ وسلم بھی خندق کھودتے جاتے تھے اور ہم مٹی کو اٹھاتے جاتے اور نبی کریم صلی اللہ علیہ وسلم ہمارے قریب سے گزرتے ہوئے فرماتے «اللهم لا عيش إلا عيش الآخره،‏‏‏‏ فاغفر للأنصار والمهاجره» ”اے اللہ! زندگی تو بس آخرت ہی کی زندگی ہے، پس تو انصار و مہاجرین کی مغفرت کر۔“ اس روایت کی متابعت سہل بن سعد رضی اللہ عنہ نے بھی نبی کریم صلی اللہ علیہ وسلم سے کی ہے۔' WHERE id = 6176;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے عمرو بن ابی عمرو نے، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ فرماتا ہے کہ میرے اس مومن بندے کا جس کی، میں کوئی عزیز چیز دنیا سے اٹھا لوں اور وہ اس پر ثواب کی نیت سے صبر کر لے، تو اس کا بدلہ میرے یہاں جنت کے سوا اور کچھ نہیں۔“' WHERE id = 6186;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن حماد نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے بیان بن بشر نے، ان سے قیس بن ابی حازم نے اور ان سے مرداس اسلمی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”نیک لوگ یکے بعد دیگرے گزر جائیں گے اس کے بعد جَو کہ بھوسے یا کھجور کے کچرے کی طرح کچھ لوگ دنیا میں رہ جائیں گے جن کی اللہ پاک کو کچھ ذرا بھی پروا نہ ہو گی۔“ امام بخاری رحمہ اللہ نے کہا «حفالة» اور «حثالة‏.‏» دونوں کے ایک معنی ہیں۔' WHERE id = 6196;
UPDATE hadiths SET urdu = 'ہم سے حسن بن ربیع نے بیان کیا، کہا ہم سے ابوالاحوص (سلام بن سلیم) نے بیان کیا، ان سے اعمش نے، ان سے زید بن وہب نے کہ ابوذرغفاری رضی اللہ عنہ نے کہا میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ مدینہ کے پتھریلے علاقہ میں چل رہا تھا کہ احد پہاڑ ہمارے سامنے آ گیا۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا: ابوذر! میں نے عرض کیا، حاضر ہوں یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے اس سے بالکل خوشی نہیں ہو گی کہ میرے پاس اس احد کے برابر سونا ہو اور اس پر تین دن اس طرح گذر جائیں کہ اس میں سے ایک دینار بھی باقی رہ جائے سوا اس تھوڑی سی رقم کے جو میں قرض کی ادائیگی کے لیے چھوڑ دوں بلکہ میں اسے اللہ کے بندوں میں اس طرح خرچ کروں اپنی دائیں طرف سے، بائیں طرف سے اور پیچھے سے۔ پھر نبی کریم صلی اللہ علیہ وسلم چلتے رہے، اس کے بعد فرمایا، زیادہ مال جمع رکھنے والے ہی قیامت کے دن مفلس ہوں گے سوا اس شخص کے جو اس مال کو اس اس طرح دائیں طرف سے، بائیں طرف سے اور پیچھے سے خرچ کرے اور ایسے لوگ کم ہیں۔ پھر مجھ سے فرمایا، یہیں ٹھہرے رہو، یہاں سے اس وقت تک نہ جانا جب تک میں آ نہ جاؤں۔ پھر نبی کریم صلی اللہ علیہ وسلم رات کی تاریکی میں چلے گئے اور نظروں سے اوجھل ہو گئے۔ اس کے بعد میں نے آواز سنی جو بلند تھی۔ مجھے ڈر لگا کہ کہیں نبی کریم صلی اللہ علیہ وسلم کو کوئی دشواری نہ پیش آ گئی ہو۔ میں نے آپ کی خدمت میں پہنچنے کا ارادہ کیا لیکن آپ کا ارشاد یاد آیا کہ اپنی جگہ سے نہ ہٹنا، جب تک میں نہ آ جاؤں۔ چنانچہ جب تک نبی کریم صلی اللہ علیہ وسلم تشریف نہیں لائے میں وہاں سے نہیں ہٹا۔ پھر آپ آئے میں نے عرض کیا: یا رسول اللہ! میں نے ایک آواز سنی تھی، مجھے ڈر لگا لیکن پھر آپ کا ارشاد یاد آیا۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کیا تم نے سنا تھا؟ میں نے عرض کیا، جی ہاں۔ فرمایا کہ وہ جبرائیل علیہ السلام تھے اور انہوں نے کہا کہ آپ کی امت کا جو شخص اس حال میں مر جائے کہ اس نے اللہ کے ساتھ کسی کو شریک نہ کیا ہو تو جنت میں جائے گا۔ میں نے پوچھا خواہ اس نے زنا اور چوری بھی کی ہو؟ انہوں نے کہا ہاں زنا اور چوری ہی کیوں نہ کی ہو۔' WHERE id = 6206;
UPDATE hadiths SET urdu = 'مجھ سے عثمان بن ابی شیبہ نے بیان کیا، کہا مجھ سے جریر بن عبدالحمید نے، ان سے منصور نے، ان سے ابراہیم نے، ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ محمد صلی اللہ علیہ وسلم کے گھر والوں کو مدینہ آنے کے بعد کبھی تین دن تک برابر گیہوں کی روٹی کھانے کے لیے نہیں ملی، یہاں تک کی نبی کریم صلی اللہ علیہ وسلم کی روح قبض ہو گئی۔' WHERE id = 6216;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے سلیمان نے بیان کیا، ان سے موسیٰ بن عقبہ نے، ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”درمیانی چال اختیار کرو اور بلند پروازی نہ کرو اور عمل کرتے رہو، تم میں سے کسی کا عمل اسے جنت میں نہیں داخل کر سکے گا، میرے نزدیک سب سے پسندیدہ عمل وہ ہے جس پر ہمیشگی کی جائے خواہ کم ہی کیوں نہ ہو۔“' WHERE id = 6226;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابوبکر مقدمی نے بیان کیا، کہا ہم سے عمر بن علی نے بیان کیا، انہوں نے ابوحازم سے سنا، انہوں نے سہل بن سعد رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میرے لیے جو شخص دونوں جبڑوں کے درمیان کی چیز ( زبان ) اور دونوں ٹانگوں کے درمیان کی چیز ( شرمگاہ ) کی ذمہ داری دیدے میں اس کے لیے جنت کی ذمہ داری دیتا ہوں۔“' WHERE id = 6236;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے زکریا نے بیان کیا، ان سے عامر نے بیان کیا، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مسلمان وہ ہے جو مسلمانوں کو اپنی زبان اور ہاتھ سے ( تکلیف پہنچنے سے ) محفوظ رکھے اور مہاجر وہ ہے جو ان چیزوں سے رک جائے جس سے اللہ نے منع کیا ہے۔“' WHERE id = 6246;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا کہ مجھ سے عطاء بن یزید نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ سوال کیا گیا: اے اللہ کے رسول! محمد بن یوسف نے بیان کیا، ان سے اوزاعی نے بیان کیا، ان سے زہری نے بیان کیا، ان سے عطاء بن یزید لیثی نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ایک اعرابی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور پوچھا: یا رسول اللہ! کون شخص سب سے اچھا ہے؟ فرمایا کہ وہ شخص جس نے اپنی جان اور مال کے ذریعہ جہاد کیا اور وہ شخص جو کسی پہاڑ کی کھوہ میں ٹھہرا ہوا اپنے رب کی عبادت کرتا ہے اور لوگوں کو اپنی برائی سے محفوظ رکھتا ہے۔ اس روایت کی متابعت زبیدی، سلیمان بن کثیر اور نعمان نے زہری سے کی۔ اور معمر نے زہری سے بیان کیا، ان سے عطاء یا عبیداللہ نے، ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے اور یونس و ابن مسافر اور یحییٰ بن سعید نے ابن شہاب ( زہری ) سے بیان کیا، ان سے عطاء نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کے کسی صحابی نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔' WHERE id = 6256;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد جعفی نے بیان کیا، کہا ہم سے وہب بن جریر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ اور ابوالتیاح نے اور ان سے انس رضی اللہ عنہ کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں اور قیامت ان دونوں ( انگلیوں ) کی طرح ( نزدیک نزدیک ) بھیجے گئے ہیں۔“' WHERE id = 6266;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا ہم سے عبداللہ بن ابی بکر بن عمرو بن حزم نے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میت کے ساتھ تین چیزیں چلتی ہیں دو تو واپس آ جاتی ہیں صرف ایک کام اس کے ساتھ رہ جاتا ہے، اس کے ساتھ اس کے گھر والے اس کا مال اور اس کا عمل چلتا ہے اس کے گھر والے اور مال تو واپس آ جاتا ہے اور اس کا عمل اس کے ساتھ باقی رہ جاتا ہے۔“' WHERE id = 6276;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا کہ عمرو بن دینار نے کہا کہ میں نے سعید بن جبیر سے سنا، انہوں نے ابن عباس رضی اللہ عنہما سے سنا اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”تم اللہ سے قیامت کے دن ننگے پاؤں، ننگے بدن اور پیدل چل کر بن ختنہ ملو گے۔“ سفیان نے کہا کہ یہ حدیث ان ( نو یا دس حدیثوں ) میں سے ہے جن کے متعلق ہم سمجھتے ہیں کہ ابن عباس رضی اللہ عنہما نے خود ان کو نبی کریم صلی اللہ علیہ وسلم سے سنا۔' WHERE id = 6286;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس نے اپنے کسی بھائی پر ظلم کیا ہو تو اسے چاہئے کہ اس سے ( اس دنیا میں ) معاف کرا لے۔ اس لیے کہ آخرت میں روپے پیسے نہیں ہوں گے۔ اس سے پہلے ( معاف کرا لے ) کہ اس کے بھائی کے لیے اس کی نیکیوں میں سے حق دلایا جائے گا اور اگر اس کے پاس نیکیاں نہ ہوں گی تو اس ( مظلوم ) بھائی کی برائیاں اس پر ڈال دی جائیں گی۔“' WHERE id = 6296;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے صالح نے، کہا ہم سے نافع نے بیان کیا اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب اہل جنت جنت میں اور اہل جہنم جہنم میں داخل ہو جائیں گے تو ایک آواز دینے والا ان کے درمیان کھڑا ہو کر پکارے گا کہ اے جہنم والو! اب تمہیں موت نہیں آئے گی اور اے جنت والو! تمہیں بھی موت نہیں آئے گی بلکہ ہمیشہ یہیں رہنا ہو گا۔“' WHERE id = 6306;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ابوحازم بن دینار نے، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میری امت میں ستر ہزار یا سات لاکھ آدمی جنت میں جائیں گے۔“ راوی کو شک ہوا کہ سہل سے کون سی تعداد بیان ہوئی تھی، ” ( وہ جنت میں اس طرح داخل ہوں گے کہ ) وہ ایک دوسرے کو تھامے ہوئے ہوں گے۔ ان کا پہلا ابھی اندر داخل نہ ہونے پائے گا کہ جب تک آخری بھی داخل نہ ہو جائے۔ ان کے چہرے چودھویں رات کے چاند کی طرح روشن ہوں گے۔“' WHERE id = 6316;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن حمزہ نے بیان کیا، انہوں نے کہا ہم سے ابن ابی حازم اور دراوردی نے بیان کیا، ان سے یزید بن عبداللہ بن ہاد نے بیان کیا، ان سے عبداللہ بن خباب نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم کے سامنے آپ کے چچا ابوطالب کا ذکر کیا گیا تھا، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ممکن ہے قیامت کے دن میری شفاعت ان کے کام آ جائے اور انہیں جہنم میں ٹخنوں تک رکھا جائے جس سے ان کا بھیجا کھولتا رہے گا۔' WHERE id = 6326;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن حماد نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے سلیمان نے، ان سے شقیق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے کہ میں تم سے پہلے ہی حوض پر موجود رہوں گا۔' WHERE id = 6336;
UPDATE hadiths SET urdu = 'احمد بن شبیب بن سعید حبطی نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، ان سے سعید بن مسیب نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ وہ بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے دن میرے صحابہ میں سے ایک جماعت مجھ پر پیش کی جائے گی۔ پھر وہ حوض سے دور کر دئیے جائیں گے۔ میں عرض کروں گا: اے میرے رب! یہ تو میرے صحابہ ہیں۔ اللہ تعالیٰ فرمائے گا کہ تمہیں معلوم نہیں کہ انہوں نے تمہارے بعد کیا کیا نئی چیزیں گھڑ لی تھیں؟ یہ لوگ ( دین سے ) الٹے قدموں واپس لوٹ گئے تھے۔“ ( دوسری سند ) شعیب بن ابی حمزہ نے بیان کیا، ان سے زہری نے کہ ابوہریرہ رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے حوالے سے «فيجلون» ( بجائے «فيحلؤون» ) کے بیان کرتے تھے۔ اور عقیل «فيحلؤون» بیان کرتے تھے اور زبیدی نے بیان کیا، ان سے زہری نے، ان سے محمد بن علی نے، ان سے عبیداللہ بن ابی رافع نے، ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 6346;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد نے بیان کیا، ان سے عبیداللہ بن ابوبکر بن انس نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ نے رحم مادر پر ایک فرشتہ مقرر کر دیا ہے اور وہ کہتا رہتا ہے کہ اے رب! یہ «نطفة» قرار پایا ہے۔ اے رب! اب «علقة» یعنی جما ہوا خون بن گیا ہے۔ اے رب! اب «مضغة‏.‏» ( گوشت کا لوتھڑا ) بن گیا ہے۔ پھر جب اللہ تعالیٰ چاہتا ہے کہ اس کی پیدائش پوری کرے تو وہ پوچھتا ہے اے رب لڑکا ہے یا لڑکی؟ نیک ہے یا برا؟ اس کی روزی کیا ہو گی؟ اس کی موت کب ہو گی؟ اسی طرح یہ سب باتیں ماں کے پیٹ ہی میں لکھ دی جاتی ہیں، دنیا میں اسی کے مطابق ظاہر ہوتا ہے۔' WHERE id = 6356;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم سے ابوغسان نے بیان کیا، کہا مجھ سے ابوحازم نے بیان کیا اور ان سے سہل بن سعد رضی اللہ عنہ نے کہ ایک شخص جو مسلمانوں کی طرف سے بڑی بہادری سے لڑ رہا تھا اور اس غزوہ میں نبی کریم صلی اللہ علیہ وسلم بھی موجود تھے۔ نبی کریم صلی اللہ علیہ وسلم نے دیکھا اور فرمایا کہ جو کسی جہنمی شخص کو دیکھنا چاہتا ہے وہ اس شخص کو دیکھ لے چنانچہ وہ شخص جب اسی طرح لڑنے میں مصروف تھا اور مشرکین کو اپنی بہادری کی وجہ سے سخت تر تکالیف میں مبتلا کر رہا تھا تو ایک مسلمان اس کے پیچھے پیچھے چلا، آخر وہ شخص زخمی ہو گیا اور جلدی سے مر جانا چاہا، اس لیے اس نے اپنی تلوار کی دھار اپنے سینے پر لگا لی اور تلوار اس کے شانوں کو پار کرتی ہوئی نکل گئی۔ اس کے بعد پیچھا کرنے والا شخص نبی کریم صلی اللہ علیہ وسلم کی خدمت میں دوڑتا ہوا حاضر ہوا اور عرض کیا، میں گواہی دیتا ہوں کہ آپ اللہ کے رسول ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بات کیا ہے؟ ان صاحب نے کہا کہ آپ نے فلاں شخص کے بارے میں فرمایا تھا کہ جو کسی جہنمی کو دیکھنا چاہتا ہے وہ اس شخص کو دیکھ لے حالانکہ وہ شخص مسلمانوں کی طرف سے بڑی بہادری سے لڑ رہا تھا۔ میں سمجھا کہ وہ اس حالت میں نہیں مرے گا۔ لیکن جب وہ زخمی ہو گیا تو جلدی سے مر جانے کی خواہش میں اس نے خودکشی کر لی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بندہ دوزخیوں کے سے کام کرتا رہتا ہے حالانکہ وہ جنتی ہوتا ہے ( اسی طرح دوسرا بندہ ) جنتیوں کے کام کرتا رہتا ہے حالانکہ وہ دوزخی ہوتا ہے، بلاشبہ عملوں کا اعتبار خاتمہ پر ہے۔' WHERE id = 6367;
UPDATE hadiths SET urdu = 'ہم سے ابوالحسن محمد بن مقاتل نے بیان کیا، انہوں نے کہا ہم کو عبداللہ نے خبر دی، انہوں نے کہا ہم کو موسیٰ بن عقبہ نے خبر دی، ان سے سالم نے بیان کیا اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ اکثر نبی کریم صلی اللہ علیہ وسلم قسم کھایا کرتے تھے کہ نہیں! دلوں کو پھیرنے والے کی قسم۔' WHERE id = 6377;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے عبداللہ بن دینار نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک فوج بھیجی اور اس کا امیر اسامہ بن زید کو بنایا۔ بعض لوگوں نے ان کے امیر بنائے جانے پر اعتراض کیا تو نبی کریم صلی اللہ علیہ وسلم کھڑے ہوئے اور فرمایا کہ اگر تم لوگ اس کے امیر بنائے جانے پر اعتراض کرتے ہو تو تم اس سے پہلے اس کے والد زید کے امیر بنائے جانے پر بھی اعتراض کر چکے ہو اور اللہ کی قسم! «وايم الله» زید امیر بنائے جانے کے قابل تھے اور مجھے سب لوگوں سے زیادہ عزیز تھے اور یہ ( اسامہ ) ان کے بعد مجھے سب سے زیادہ عزیز تھے۔' WHERE id = 6387;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے عبدالرحمٰن اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”سلیمان علیہ السلام نے ایک دن کہا کہ آج میں رات میں اپنی نوے بیویوں کے پاس جاؤں گا اور ہر ایک کے یہاں ایک گھوڑ سوار بچہ پیدا ہو گا جو اللہ کے راستہ میں جہاد کرے گا۔ اس پر ان کے ساتھی نے کہا کہ ان شاءاللہ۔ لیکن سلیمان علیہ السلام نے ان شاءاللہ نہیں کہا۔ چنانچہ وہ اپنی تمام بیویوں کے پاس گئے لیکن ایک عورت کے سوا کسی کو حمل نہیں ہوا اور اس سے بھی ناقص بچہ پیدا ہوا اور اس ذات کی قسم جس کے ہاتھ میں محمد کی جان ہے! اگر انہوں نے ان شاءاللہ کہہ دیا ہوتا تو ( تمام بیویوں کے یہاں بچے پیدا ہوتے ) اور سب گھوڑوں پر سوار ہو کر اللہ کے راستے میں جہاد کرنے والے ہوتے۔“' WHERE id = 6398;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے عبدالوہاب نے، ان سے ایوب نے، ان سے ابوقلابہ اور قاسم تیمی نے اور ان سے زہدم نے بیان کیا کہ ان قبائل، جرم اور اشعر کے درمیان بھائی چارہ تھا۔ ہم ابوموسیٰ اشعری رضی اللہ عنہ کی خدمت میں موجود تھے تو ان کے لیے کھانا لایا گیا۔ اس میں مرغی بھی تھی۔ ان کے پاس بنی تیم اللہ کا ایک سرخ رنگ کا آدمی بھی موجود تھا۔ غالباً وہ غلاموں میں سے تھا۔ ابوموسیٰ اشعری رضی اللہ عنہ نے اسے کھانے پر بلایا تو اس نے کہا کہ میں نے مرغی کو گندگی کھاتے دیکھا تو مجھے گھن آئی اور پھر میں نے قسم کھا لی کہ اب میں اس کا گوشت نہیں کھاؤں گا۔ ابوموسیٰ اشعری رضی اللہ عنہ نے کہا کہ کھڑے ہو جاؤ تو میں تمہیں اس کے بارے میں ایک حدیث سناؤں۔ میں رسول اللہ صلی اللہ علیہ وسلم کے پاس قبیلہ اشعر کے چند لوگوں کے ساتھ آیا اور ہم نے نبی کریم صلی اللہ علیہ وسلم سے سواری کا جانور مانگا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کی قسم میں تمہیں سواری نہیں دے سکتا اور نہ میرے پاس ایسا کوئی جانور ہے جو تمہیں سواری کے لیے دے سکوں، پھر نبی کریم صلی اللہ علیہ وسلم کے پاس کچھ مال غنیمت کے اونٹ آئے تو نبی کریم صلی اللہ علیہ وسلم نے پوچھا کہ اشعری لوگ کہاں ہیں پھر آپ نے ہم کو پانچ عمدہ قسم کے اونٹ دئیے جانے کا حکم فرمایا۔ جب ہم ان کو لے کر چلے تو ہم نے کہا یہ ہم نے کیا کیا رسول اللہ صلی اللہ علیہ وسلم تو قسم کھا چکے تھے کہ ہم کو سواری نہیں دیں گے اور درحقیقت آپ صلی اللہ علیہ وسلم کے پاس اس وقت سواری موجود بھی نہ تھی پھر آپ نے ہم کو سوار کرا دیا۔ ہم نے رسول اللہ صلی اللہ علیہ وسلم کو آپ کی قسم سے غافل کر دیا۔ قسم اللہ کی ہم اس حرکت کے بعد کبھی فلاح نہیں پا سکیں گے۔ پس ہم آپ کی طرف لوٹ کر آئے اور آپ سے ہم نے تفصیل بالا کو عرض کیا کہ ہم آپ کے پاس آئے تھے تاکہ آپ ہم کو سواری پر سوار کرا دیں پس آپ نے قسم کھا لی تھی کہ آپ ہم کو سوار نہیں کرائیں گے اور درحقیقت اس وقت آپ کے پاس سواری موجود بھی نہ تھی۔ آپ صلی اللہ علیہ وسلم نے یہ سب سن کر فرمایا کہ میں نے تم کو سوار نہیں کرایا بلکہ اللہ نے تم کو سوار کرا دیا۔ اللہ کی قسم جب میں کوئی قسم کھا لیتا ہوں بعد میں اس سے بہتر اور معاملہ دیکھتا ہوں تو میں وہی کرتا ہوں جو بہتر ہوتا ہے اور اس قسم کا کفارہ ادا کر دیتا ہوں۔' WHERE id = 6408;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جہنم برابر یہی کہتی رہے گی کہ کیا کچھ اور ہے کیا کچھ اور ہے؟ آخر اللہ تبارک و تعالیٰ اپنا قدم اس میں رکھ دے گا تو وہ کہہ اٹھے گی بس بس میں بھر گئی، تیری عزت کی قسم! اور اس کا بعض حصہ بعض کو کھانے لگے گا۔“ اس روایت کو شعبہ نے قتادہ سے نقل کیا۔' WHERE id = 6419;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم نے بیان کیا، انہوں نے عبدالعزیز بن عبدالصمد سے سنا، کہا ہم سے منصور بن معتمر نے بیان کیا، ان سے ابراہیم نخعی نے، ان سے علقمہ نے اور ان سے ابن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے انہیں ظہر کی نماز پڑھائی اور نماز میں کوئی چیز زیادہ یا کم کر دی۔ منصور نے بیان کیا کہ مجھے معلوم نہیں ابراہیم کو شبہ ہوا تھا یا علقمہ کو۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم سے کہا گیا کہ یا رسول اللہ! نماز میں کچھ کمی کر دی گئی ہے یا آپ بھول گئے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا، کیا بات ہے؟ لوگوں نے کہا کہ آپ نے اس اس طرح نماز پڑھائی ہے۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے ان کے ساتھ دو سجدے ( سہو کے ) کئے اور فرمایا یہ دو سجدے اس شخص کے لیے ہیں جسے یقین نہ ہو کہ اس نے اپنی نماز میں کمی یا زیادہ کر دی ہے اسے چاہئے کہ صحیح بات تک پہنچنے کے لیے ذہن پر زور ڈالے اور جو باقی رہ گیا ہو اسے پورا کرے پھر دو سجدے ( سہو کے ) کر لے۔' WHERE id = 6429;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے شقیق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اور میں نے ( اسی پر قیاس کرتے ہوئے ) دوسرا کلمہ کہا ( کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ) جو شخص اس حال میں مر جائے گا کہ اللہ کے ساتھ کسی کو شریک ٹھہراتا ہو گا تو وہ جہنم میں جائے گا۔“ اور میں نے دوسری بات کہی کہ جو شخص اس حال میں مر جائے گا کہ اللہ کے ساتھ کسی کو شریک نہ ٹھہراتا ہو گا وہ جنت میں جائے گا۔' WHERE id = 6440;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے منصور نے، انہوں نے کہا ہم کو عبداللہ بن مرہ نے خبر دی، اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے نذر سے منع فرمایا تھا اور فرمایا تھا کہ وہ کسی چیز کو واپس نہیں کر سکتی، البتہ اس کے ذریعہ بخیل کا مال نکالا جا سکتا ہے۔' WHERE id = 6450;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، انہیں ابن جریج نے خبر دی، کہا کہ مجھے سلیمان احول نے خبر دی، انہیں طاؤس نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم گزرے تو کعبہ کا ایک شخص اس طرح طواف کر رہا تھا کہ دوسرا شخص اس کی ناک میں رسی باندھ کر اس کے آگے سے اس کی رہنمائی کر رہا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے وہ رسی اپنے ہاتھ سے کاٹ دی، پھر حکم دیا کہ ہاتھ سے اس کی رہنمائی کرے۔' WHERE id = 6460;
UPDATE hadiths SET urdu = 'ہم سے منذر بن الولید الجارودی نے بیان کیا، کہا ہم سے ابوقتیبہ، سلم شعیری نے بیان کیا، کہا ہم سے امام مالک نے، ان سے نافع نے بیان کیا کہ ابن عمر رضی اللہ عنہما رمضان کا فطرانہ نبی کریم صلی اللہ علیہ وسلم ہی کے پہلے مد کے وزن سے دیتے تھے اور قسم کا کفارہ بھی نبی کریم صلی اللہ علیہ وسلم کے مد سے ہی دیتے تھے۔ ابوقتیبہ نے اسی سند سے بیان کیا کہ ہم سے امام مالک نے بیان کیا کہ ہمارا مد تمہارے مد سے بڑا ہے اور ہمارے نزدیک ترجیح صرف نبی کریم صلی اللہ علیہ وسلم ہی کے مد کو ہے۔ اور مجھ سے امام مالک نے بیان کیا کہ اگر ایسا کوئی حاکم آیا جو نبی کریم صلی اللہ علیہ وسلم کے مد سے چھوٹا مد مقرر کر دے تو تم کس حساب سے ( صدقہ فطر وغیرہ ) نکا لو گے؟ میں نے عرض کیا کہ ایسی صورت میں ہم نبی کریم صلی اللہ علیہ وسلم ہی کے مد کے حساب سے فطرہ نکالا کریں گے؟ انہوں نے کہا کہ کیا تم دیکھتے نہیں کہ معاملہ ہمیشہ نبی کریم صلی اللہ علیہ وسلم ہی کے مد کی طرف لوٹتا ہے۔' WHERE id = 6470;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے محمد بن منکدر نے، انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ میں بیمار پڑا تو رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ میری عیادت کے لیے تشریف لائے، دونوں حضرات پیدل چل کر آئے تھے۔ دونوں حضرات جب آئے تو مجھ پر غشی طاری تھی، نبی کریم صلی اللہ علیہ وسلم نے وضو کیا اور وضو کا پانی میرے اوپر چھڑکا مجھے ہوش ہوا تو میں نے عرض کیا: یا رسول اللہ! اپنے مال کی ( تقسیم ) کس طرح کروں؟ یا اپنے مال کا کس طرح فیصلہ کروں؟ نبی کریم صلی اللہ علیہ وسلم نے مجھے کوئی جواب نہیں دیا، یہاں تک کہ میراث کی آیتیں نازل ہوئیں۔' WHERE id = 6480;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، کہا ہم سے عبداللہ ابن طاؤس نے بیان کیا، ان سے ان کے والد نے اور ان سے ابن عباس نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”پہلے میراث ان کے وارثوں تک پہنچا دو اور جو باقی رہ جائے وہ اس کو ملے گا جو مرد میت کا بہت نزدیکی رشتہ دار ہو۔“' WHERE id = 6491;
UPDATE hadiths SET urdu = 'ہم سے محمود نے بیان کیا، انہوں نے کہا ہم کو اسرائیل نے خبر دی، انہیں ابوحصین نے، انہیں ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میں مسلمانوں کا خود ان کی ذات سے بھی زیادہ ولی ہوں۔ پس جو شخص مر جائے اور مال چھوڑ جائے تو وہ اس کے وارثوں کا حق ہے اور جس نے بیوی بچے چھوڑے ہوں یا قرض ہو، تو میں ان کا ولی ہوں، ان کے لیے مجھ سے مانگا جائے۔“' WHERE id = 6501;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم تیمی نے، ان سے ان کے والد نے بیان کیا کہ علی رضی اللہ عنہ نے بتلایا کہ ہمارے پاس کوئی کتاب نہیں ہے جسے ہم پڑھیں، سوا اللہ کی کتاب قرآن کے اور اس کے علاوہ یہ صحیفہ بھی ہے۔ بیان کیا کہ پھر وہ صحیفہ نکالا تو اس میں زخموں ( کے قصاص ) اور اونٹوں کی زکوٰۃ کے مسائل تھے۔ راوی نے بیان کیا کہ اس میں یہ بھی تھا کے عیر سے ثور تک مدینہ حرم ہے جس نے اس دین میں کوئی نئی بات پیدا کی یا نئی بات کرنے والے کو پناہ دی تو اس پر اللہ اور فرشتوں اور انسانوں سب کی لعنت ہے اور قیامت کے دن اس کا کوئی نیک عمل مقبول نہ ہو گا اور جس نے اپنے مالکوں کی اجازت کے بغیر دوسرے لوگوں سے مولات قائم کر لی تو اس پر فرشتوں اور انسانوں سب کی لعنت ہے، قیامت کے دن اس کا کوئی نیک عمل مقبول نہ ہو گا اور مسلمانوں کا ذمہ ( قول و قرار، کسی کو پناہ دینا وغیرہ ) ایک ہے۔ ایک ادنی مسلمان کے پناہ دینے کو بھی قائم رکھنے کی کوشش کی جائے گی۔ پس جس نے کسی مسلمان کی دی ہوئی پناہ کو توڑا، اس پر اللہ کی، فرشتوں اور انسانوں سب کی لعنت ہے قیامت کے دن اس کا کوئی نیک عمل قبول نہیں کیا جائے گا۔' WHERE id = 6511;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ سعد بن ابی وقاص اور عبد بن زمعہ رضی اللہ عنہا کا ایک لڑکے کے بارے میں جھگڑا ہوا۔ سعد رضی اللہ عنہ نے کہا کہ یا رسول اللہ! یہ میرے بھائی عتبہ بن ابی وقاص کا لڑکا ہے، اس نے مجھے وصیت کی تھی کہ یہ اس کا لڑکا ہے آپ اس کی مشابہت اس میں دیکھئیے اور عبد بن زمعہ نے کہا کہ میرا بھائی ہے یا رسول اللہ! میرے والد کے بستر پر ان کی لونڈی سے پیدا ہوا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے لڑکے کی صورت دیکھی تو اس کی عتبہ کے ساتھ صاف مشابہت واضح تھی، لیکن آپ صلی اللہ علیہ وسلم نے فرمایا، عبد! لڑکا بستر والے کا ہوتا ہے اور زانی کے حصہ میں پتھر ہیں اور اے سودہ بنت زمعہ! ( ام المؤمنین رضی اللہ عنہا ) اس لڑکے سے پردہ کیا کر چنانچہ پھر اس لڑکے نے ام المؤمنین کو نہیں دیکھا۔' WHERE id = 6521;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، ان سے ابوضمرہ نے بیان کیا، ان سے انس نے بیان کیا، ان سے یزید بن الہاد نے بیان کیا، ان سے محمد بن ابراہیم نے بیان کیا، ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کے پاس ایک شخص کو لایا گیا جو شراب پیے ہوئے تھا تو آپ صلی اللہ علیہ وسلم نے فرمایا اسے مارو، ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم میں بعض وہ تھے جنہوں نے اسے ہاتھ سے مارا، بعض نے جوتے سے مارا اور بعض نے اپنے کپڑے سے مارا۔ جب مار چکے تو کسی نے کہا کہ اللہ تجھے رسوا کرے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس طرح کے جملے نہ کہو، اس کے معاملہ میں شیطان کی مدد نہ کر۔' WHERE id = 6532;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ اسامہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے ایک عورت کی ( جس پر حدی مقدمہ ہونے والا تھا ) سفارش کی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم سے پہلے کے لوگ اس لیے ہلاک ہو گئے کہ وہ کمزوروں پر تو حد قائم کرتے اور بلند مرتبہ لوگوں کو چھوڑ دیتے تھے۔ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے۔ اگر فاطمہ ( رضی اللہ عنہا ) نے بھی ( چوری ) کی ہوتی تو میں اس کا بھی ہاتھ کاٹ لیتا۔' WHERE id = 6542;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے عبیداللہ نے بیان کیا، کہا مجھ سے نافع نے بیان کیا، ان سے عبداللہ رضی اللہ عنہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک ڈھال پر ہاتھ کاٹا تھا جس کی قیمت تین درہم تھی۔' WHERE id = 6552;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر نے بیان کیا، کہا ہم سے عمر بن علی نے بیان کیا۔ (دوسری سند امام بخاری رحمہ اللہ نے کہا) اور مجھ سے خلیفہ بن حیاط نے بیان کیا، ان سے عمر بن علی نے، ان سے ابوحازم سلمہ بن دینار نے بیان کیا، ان سے سہل بن سعد ساعدی نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے مجھے اپنے دونوں پاؤں کے درمیان یعنی ( شرمگاہ ) کی اور اپنے دونوں جبڑوں کے درمیان ( یعنی زبان ) کی ضمانت دے دی تو میں اسے جنت میں جانے کا بھروسہ دلاتا ہوں۔“' WHERE id = 6562;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عثمان نے بیان کیا، کہا ہم سے خالد بن مخلد نے بیان کیا، ان سے سلیمان بن بلال نے، ان سے عبداللہ بن دینار نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے پاس ایک یہودی مرد اور ایک یہودی عورت کو لایا گیا، جنہوں نے زنا کیا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے پوچھا کہ تمہاری کتاب تورات میں اس کی سزا کیا ہے؟ انہوں نے کہا کہ ہمارے علماء نے ( اس کی سزا ) چہرہ کو سیاہ کرنا اور گدھے پر الٹا سوار کرنا تجویز کی ہوئی ہے۔ اس پر عبداللہ بن سلام رضی اللہ عنہ نے کہا: یا رسول اللہ! ان سے توریت منگوائیے۔ جب توریت لائی گئی تو ان میں سے ایک نے رجم والی آیت پر اپنا ہاتھ رکھ لیا اور اس سے آگے اور پیچھے کی آیتیں پڑھنے لگا۔ عبداللہ بن سلام رضی اللہ عنہ نے اس سے کہا کہ اپنا ہاتھ ہٹاؤ ( اور جب اس نے اپنا ہاتھ ہٹایا تو ) آیت رجم اس کے ہاتھ کے نیچے تھی۔ نبی کریم صلی اللہ علیہ وسلم نے ان دونوں کے متعلق حکم دیا اور انہیں رجم کر دیا گیا۔ ابن عمر رضی اللہ عنہما نے بیان کیا کہ انہیں بلاط ( مسجد نبوی کے قریب ایک جگہ ) میں رجم کیا گیا۔ میں نے دیکھا کہ یہودی عورت کو مرد بچانے کے لیے اس پر جھک جھک پڑتا تھا۔' WHERE id = 6573;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے سعید مقبری نے، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے، انہوں نے ابوہریرہ رضی اللہ عنہ کو یہ کہتے ہوئے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر کنیز زنا کرائے اور اس کا زنا کھل جائے تو اسے کوڑے مارنے چاہئیں لیکن لعنت ملامت نہ کرنی چاہئے پھر اگر وہ دوبارہ زنا کرے تو پھر چاہئے کہ کوڑے مارے لیکن ملامت نہ کرے پھر اگر تیسری مرتبہ زنا کرائے تو بیچ دے خواہ بالوں کی ایک رسی ہی قیمت پر ہو۔ اس روایت کی متابعت اسماعیل بن امیہ نے سعید سے کی، ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔' WHERE id = 6588;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے وصال ( مسلسل افطار کے بغیر کئی دن کے روزے رکھنے ) سے منع فرمایا تو بعض صحابہ نے عرض کیا: یا رسول اللہ! آپ خود تو وصال کرتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے کون مجھ جیسا ہے؟ میرا تو حال یہ ہے کہ مجھے میرا رب کھلاتا ہے اور پلاتا ہے لیکن وصال کرنے سے صحابہ نہیں رکے تو نبی کریم صلی اللہ علیہ وسلم نے ان کے ساتھ ایک دن کے بعد دوسرے دن کا وصال کیا پھر اس کے بعد لوگوں نے چاند دیکھ لیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر ( عید کا ) چاند نہ دکھائی دیتا تو میں اور وصال کرتا۔ یہ آپ نے تنبیہاً فرمایا تھا کیونکہ وہ وصال کرنے پر مصر تھے۔ اس روایت کی متابعت شعیب، یحییٰ بن سعید اور یونس نے زہری سے کی ہے اور عبدالرحمٰن بن خالد فہمی نے بیان کیا، ان سے ابن شہاب نے، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے بیان کیا۔' WHERE id = 6599;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن یعقوب نے بیان کیا، انہوں نے کہا ہم سے اسحاق نے بیان کیا، انہوں نے کہا میں نے اپنے والد سے سنا، وہ عبداللہ بن عمر رضی اللہ عنہما سے بیان کرتے تھے کہ ہلاکت کا بھنور جس میں گرنے کے بعد پھر نکلنے کی امید نہیں ہے وہ ناحق خون کرنا ہے، جس کو اللہ تعالیٰ نے حرام کیا ہے۔' WHERE id = 6610;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحمٰن بن المبارک نے بیان کیا، کہا ہم سے حماد بن زید نے، کہا ہم سے ایوب اور یونس نے، ان سے امام حسن بصری نے، ان سے احنف بن قیس نے کہ میں ان صاحب ( علی بن ابی طالب رضی اللہ عنہ ) کی جنگ جمل میں مدد کے لیے تیار تھا کہ ابوبکرہ رضی اللہ عنہ سے میری ملاقات ہوئی۔ انہوں نے پوچھا، کہاں کا ارادہ ہے؟ میں نے کہا کہ ان صاحب کی مدد کے لیے جانا چاہتا ہوں۔ انہوں نے فرمایا کہ واپس چلے جاؤ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے نبی کریم صلی اللہ علیہ وسلم فرماتے تھے کہ جب دو مسلمان تلوار کھینچ کر ایک دوسرے سے بھڑ جائیں تو قاتل اور مقتول دونوں دوزخ میں جاتے ہیں۔ میں نے عرض کیا: یا رسول اللہ! ایک تو قاتل تھا لیکن مقتول کو سزا کیوں ملے گی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ بھی اپنے قاتل کے قتل پر آمادہ تھا۔' WHERE id = 6621;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک یہودی کو ایک لڑکی کے بدلہ میں قتل کرا دیا تھا، یہودی نے اس لڑکی کو چاندی کے زیورات کے لالچ میں قتل کر دیا تھا۔' WHERE id = 6631;
UPDATE hadiths SET urdu = 'اور مجھ سے ابن بشار نے بیان کیا، ان سے یحییٰ نے، ان سے عبیداللہ نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ ایک لڑکے اصیل نامی کو دھوکے سے قتل کر دیا گیا تھا۔ عمر رضی اللہ عنہ نے کہا کہ سارے اہل صنعاء ( یمن کے لوگ ) اس کے قتل میں شریک ہوتے تو میں سب کو قتل کرا دیتا۔ اور مغیرہ بن حکیم نے اپنے والد سے بیان کیا کہ چار آدمیوں نے ایک بچے کو قتل کر دیا تھا تو عمر رضی اللہ عنہ نے یہ بات فرمائی تھی۔ ابوبکر، ابن زبیر، علی اور سوید بن مقرن رضی اللہ عنہما نے چانٹے کا بدلہ دلوایا تھا اور عمر رضی اللہ عنہ نے درے کی جو مار ایک شخص کو ہوئی تھی اس کا بدلہ لینے کے لیے فرمایا اور علی رضی اللہ عنہ نے تین کوڑوں کا قصاص لینے کا حکم دیا اور شریح نے کوڑے اور خراش لگانے کی سزا دی تھی۔' WHERE id = 6642;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے بنی لحیان کی ایک عورت کے جنین ( کے گرنے ) پر ایک غلام یا کنیز کا فیصلہ کیا تھا۔ پھر وہ عورت جس کے متعلق نبی کریم صلی اللہ علیہ وسلم نے دیت دینے کا فیصلہ کیا تھا اس کا انتقال ہو گیا تو رسول اللہ صلی اللہ علیہ وسلم نے فیصلہ کیا کہ اس کی میراث اس کے لڑکوں اور اس کے شوہر کو ملے گی اور دیت اس کے ددھیال والوں کو دینی ہو گی۔' WHERE id = 6654;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے بشر بن مفضل نے، کہا ہم سے سعید بن ایاس جریری نے، (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے قیس بن حفص نے بیان کیا، کہا ہم سے اسماعیل بن ابراہیم نے، کہا ہم کو سعید جریری نے خبر دی، کہا ہم سے عبدالرحمٰن بن ابی بکرہ نے بیان کیا، انہوں نے اپنے والد (ابوبکرہ صحابی) سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بڑے سے بڑا گناہ اللہ تعالیٰ کے ساتھ شرک کرنا ہے اور ماں باپ کو ستانا ( ان کی نافرمانی کرنا ) اور جھوٹی گواہی دینا، جھوٹی گواہی دینا، تین بار یہی فرمایا یا یوں فرمایا اور جھوٹ بولنا برابر باربار آپ صلی اللہ علیہ وسلم یہی فرماتے رہے یہاں تک کہ ہم نے آرزو کی کہ کاش آپ خاموش ہو جاتے۔' WHERE id = 6664;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا ہم سے عبدالوہاب نے بیان کیا، کہا میں نے یحییٰ بن سعید انصاری سے سنا، کہا مجھ کو محمد بن ابراہیم تیمی نے خبر دی، انہوں نے ابوسلمہ بن عبدالرحمٰن اور عطاء بن یسار سے، وہ دونوں ابو سعید خدری رضی اللہ عنہ کے پاس آئے اور ان سے پوچھا کیا تم نے حروریہ کے بارے میں کچھ نبی کریم صلی اللہ علیہ وسلم سے سنا ہے؟ انہوں نے کہا حروریہ ( دروریہ ) تو میں جانتا نہیں مگر میں نے نبی کریم صلی اللہ علیہ وسلم سے یہ سنا ہے آپ صلی اللہ علیہ وسلم فرماتے تھے کہ اس امت میں اور یوں نہیں فرمایا اس امت میں سے کچھ لوگ ایسے پیدا ہوں گے کہ تم اپنی نماز کو ان کی نماز کے سامنے حقیر جانو گے اور قرآن کی تلاوت بھی کریں گے مگر قرآن ان کے حلقوں سے نیچے نہیں اترے گا۔ وہ دین سے اس طرح نکل جائیں گے جیسے تیر جانور میں سے پار نکل جاتا ہے اور پھر تیر پھینکنے والا اپنے تیر کو دیکھتا ہے اس کے بعد جڑ میں ( جو کمان سے لگی رہتی ہے ) اس کو شک ہوتا ہے شاید اس میں خون لگا ہو مگر وہ بھی صاف۔' WHERE id = 6675;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن حوشب الطائفی نے بیان کیا، انہوں نے کہا ہم سے عبدالوہاب ثقفی نے بیان کیا، انہوں نے کہا ہم سے ایوب نے بیان کیا، ان سے ابوقلابہ نے بیان کیا، اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تین خصوصیتیں ایسی ہیں کہ جس میں پائی جائیں گی وہ ایمان کی شیرینی پا لے گا اول یہ کہ اللہ اور اس کے رسول اسے سب سے زیادہ عزیز ہوں۔ دوسرے یہ کہ وہ کسی شخص سے محبت صرف اللہ ہی کے لیے کرے تیسرے یہ کہ اسے کفر کی طرف لوٹ کر جانا اتنا ناگوار ہو جیسے آگ میں پھینک دیا جانا۔“' WHERE id = 6685;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں سالم نے خبر دی اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مسلمان مسلمان کا بھائی ہے نہ اس پر ظلم کرے اور نہ اسے ( کسی ظالم کے ) سپرد کرے اور جو شخص اپنے کسی بھائی کی ضرورت پوری کرنے میں لگا ہو گا اللہ تعالیٰ اس کی ضرورت اور حاجت پوری کرے گا۔“' WHERE id = 6695;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے امام مالک نے ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے بیع نجش سے منع فرمایا۔' WHERE id = 6706;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعبنی نے بیان کیا، کہا ہم سے امام مالک نے، ان سے ابن شہاب نے، ان سے عبداللہ ابن عامر بن ربیعہ نے کہ عمر بن خطاب رضی اللہ عنہ ( سنہ 18 ھ ماہ ربیع الثانی میں ) شام تشریف لے گئے۔ جب مقام سرغ پر پہنچے تو ان کو یہ خبر ملی کہ شام وبائی بیماری کی لپیٹ میں ہے۔ پھر عبدالرحمٰن بن عوف رضی اللہ عنہ نے انہیں خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ جب تمہیں معلوم ہو جائے کہ کسی سر زمین میں وبا پھیلی ہوئی ہے تو اس میں داخل مت ہو، لیکن اگر کسی جگہ وبا پھوٹ پڑے اور تم وہیں موجود ہو تو وبا سے بھاگنے کے لیے تم وہاں سے نکلو بھی مت۔ چنانچہ عمر رضی اللہ عنہ مقام سرغ سے واپس آ گئے۔ اور ابن شہاب سے روایت ہے، ان سے سالم بن عبداللہ نے کہ عمر رضی اللہ عنہ عبدالرحمٰن بن عوف رضی اللہ عنہ کی حدیث سن کر واپس ہو گئے تھے۔' WHERE id = 6716;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، انہوں نے کہا ہم سے امام مالک نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کسی نیک آدمی کا اچھا خواب نبوت کا چھیالیسواں حصہ ہے۔“' WHERE id = 6726;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، انہیں یونس نے، انہیں زہری نے، کہا مجھ سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے مجھے خواب میں دیکھا تو کسی دن مجھے بیداری میں بھی دیکھے گا اور شیطان میری صورت میں نہیں آ سکتا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ ابن سیرین نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم کو کوئی شخص آپ کی صورت میں دیکھے۔' WHERE id = 6736;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی اور انہیں زہری نے یہی حدیث بیان کی اور بیان کیا کہ (نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ) میں نہیں جانتا کہ میرے ساتھ کیا کیا جائے گا۔ انہوں نے بیان کیا کہ اس کا مجھے رنج ہوا۔ ( کہ عثمان رضی اللہ عنہ کے متعلق کوئی بات یقین کے ساتھ معلوم نہیں ہے ) چنانچہ میں سو گئی اور میں نے خواب میں دیکھا کہ عثمان رضی اللہ عنہ کے لیے ایک جاری چشمہ ہے۔ میں نے اس کی اطلاع نبی کریم صلی اللہ علیہ وسلم کو دی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ان کا نیک عمل ہے۔' WHERE id = 6746;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ازہر نے بیان کیا، کہا ہم سے ابن عون نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ اور مجھ سے خلیفہ نے بیان کیا، ان سے معاذ نے بیان کیا، ان سے ابن عون نے بیان کیا، ان سے محمد نے، ان سے قیس بن عباد نے بیان کیا اور ان سے عبداللہ بن سلام رضی اللہ عنہ نے بیان کیا کہ میں نے ( خواب ) دیکھا کہ گویا میں ایک باغ میں ہوں اور باغ کے بیچ میں ایک ستون ہے جس کے اوپر کے سرے پر ایک حلقہ ہے۔ کہا گیا کہ اس پر چڑھ جاؤ۔ میں نے کہا کہ میں اس کی طاقت نہیں رکھتا۔ پھر میرے پاس خادم آیا اور اس نے میرے کپڑے چڑھا دئیے پھر میں اوپر چڑھ گیا اور میں نے حلقہ پکڑ لیا، ابھی میں اسے پکڑے ہی ہوئے تھا کہ آنکھ کھل گئی۔ پھر میں نے اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ باغ اسلام کا باغ تھا اور وہ ستون اسلام کا ستون تھا اور وہ حلقہ «عروة الوثقى» تھا، تم ہمیشہ اسلام پر مضبوطی سے جمے رہو گے یہاں تک کہ تمہاری وفات ہو جائے گی۔' WHERE id = 6756;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے خبر دی، انہیں سالم بن عبداللہ ابن عمر نے خبر دی، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میں سویا ہوا تھا کہ میں نے اپنے آپ کو کعبہ کا طواف کرتے دیکھا۔ اچانک ایک صاحب نظر آئے، گندم گوں بال لٹکے ہوئے تھے اور دو آدمیوں کے درمیان ( سہارا لیے ہوئے تھے ) ان کے سر سے پانی ٹپک رہا تھا۔ میں نے پوچھا یہ کون ہیں؟ کہا کہ عیسیٰ ابن مریم علیہ السلام، پھر میں مڑا تو ایک دوسرا شخص سرخ، بھاری جسم والا، گھنگریالے بال والا اور ایک آنکھ سے کانا جیسے اس کی آنکھ پر خشک انگور ہو نظر آیا۔ میں نے پوچھا یہ کون ہیں؟ کہا کہ یہ دجال ہے۔ اس کی صورت عبدالعزیٰ بن قطن سے بہت ملتی تھی۔“ یہ عبدالعزیٰ بن قطن مطلق میں تھا جو قبیلہ خزاعہ کی ایک شاخ ہے۔' WHERE id = 6767;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، انہوں نے کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید بن عبداللہ ابن ابی بردہ نے بیان کیا، ان سے ان کے دادا ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے مجھ کو یقین ہے کہ نبی کریم صلی اللہ علیہ وسلم سے کہ نبی کریم صلی اللہ علیہ وسلم نے یوں فرمایا کہ میں نے ایک تلوار ہلائی تو وہ بیچ سے ٹوٹ گئی۔ اس کی تعبیر احد کی جنگ میں مسلمانوں کے شہید ہونے کی صورت میں سامنے آئی پھر دوبارہ میں نے اسے ہلایا تو وہ پہلے سے بھی اچھی شکل میں ہو گئی۔ اس کی تعبیر فتح اور مسلمانوں کے اتفاق و اجتماع کی صورت میں سامنے آئی۔' WHERE id = 6779;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے عبدالوارث بن سعید نے بیان کیا، ان سے جعد صیرفی نے، ان سے ابورجاء عطاردی نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص اپنے امیر میں کوئی ناپسند بات دیکھے تو صبر کرے ( خلیفہ ) کی اطاعت سے اگر کوئی بالشت بھر بھی باہر نکلا تو اس کی موت جاہلیت کی موت ہو گی۔“' WHERE id = 6791;
UPDATE hadiths SET urdu = 'اور ابوعوانہ نے بیان کیا، ان سے عاصم نے، ان سے ابووائل نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ انہوں نے عبداللہ رضی اللہ عنہ سے کہا آپ وہ حدیث جانتے ہیں جو نبی کریم صلی اللہ علیہ وسلم نے «هرج» کے دنوں وغیرہ کے متعلق بیان کی۔ ابن مسعود رضی اللہ عنہ نے کہا کہ میں نے آپ صلی اللہ علیہ وسلم کو یہ فرماتے سنا تھا کہ وہ بدبخت ترین لوگوں میں سے ہوں گے جن کی زندگی میں قیامت آئے گی۔' WHERE id = 6803;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، کہا مجھ کو واقد نے خبر دی، انہیں ان کے والد نے اور انہیں ابن عمر رضی اللہ عنہما نے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرے بعد کفر کی طرف نہ لوٹ جانا کہ ایک دوسرے کی گردن مارنے لگو۔' WHERE id = 6813;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے حاتم نے بیان کیا، ان سے یزید بن ابی عبید نے بیان کیا، ان سے سلمہ بن الاکوع رضی اللہ عنہ نے بیان کیا کہ وہ حجاج کے یہاں گئے تو اس نے کہا کہ اے ابن الاکوع! تم گاؤں میں رہنے لگے ہو کیا الٹے پاؤں پھر گئے؟ کہا کہ نہیں بلکہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے جنگل میں رہنے کی اجازت دی تھی۔ اور یزید بن ابی عبید سے روایت ہے، انہوں نے کہا کہ جب عثمان بن عفان رضی اللہ عنہ شہید کئے گئے تو سلمہ بن الاکوع رضی اللہ عنہ ربذہ چلے گئے اور وہاں ایک عورت سے شادی کر لی اور وہاں ان کے بچے بھی پیدا ہوئے۔ وہ برابر وہیں پر رہے، یہاں تک کہ وفات سے چند دن پہلے مدینہ آ گئے تھے۔' WHERE id = 6823;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم کو محمد بن جعفر نے خبر دی، انہیں شریک بن عبداللہ نے، انہیں سعید بن مسیب نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم مدینہ کے باغات میں کسی باغ کی طرف اپنی کسی ضرورت کے لیے گئے، میں بھی آپ کے پیچھے پیچھے گیا۔ جب نبی کریم صلی اللہ علیہ وسلم باغ میں داخل ہوئے تو میں اس کے دروازے پر بیٹھ گیا اور اپنے دل میں کہا کہ آج میں آپ کا دربان بنوں گا حالانکہ آپ نے مجھے اس کا حکم نہیں دیا تھا۔ آپ اندر چلے گئے اور اپنی حاجت پوری کی۔ پھر آپ کنوئیں کی منڈیر پر بیٹھ گئے اور اپنی دونوں پنڈلیوں کو کھول کر انہیں کنوئیں میں لٹکا لیا۔ پھر ابوبکر رضی اللہ عنہ آئے اور اندر جانے کی اجازت چاہی۔ میں نے ان سے کہا کہ آپ یہیں رہیں، میں آپ کے لیے اجازت لے کر آتا ہوں۔ چنانچہ وہ کھڑے رہے اور میں نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر عرض کیا: یا نبی اللہ! ابوبکر رضی اللہ عنہ آپ کے پاس آنے کی اجازت چاہتے ہیں۔ فرمایا کہ انہیں اجازت دے دو اور انہیں جنت کی بشارت سنا دو۔ چنانچہ وہ اندر آ گئے اور نبی کریم صلی اللہ علیہ وسلم کی دائیں جانب آ کر انہوں نے بھی اپنی پنڈلیوں کو کھول کر کنوئیں میں لٹکا لیا۔ اتنے میں عمر رضی اللہ عنہ آئے۔ میں نے کہا ٹھہرو میں نبی کریم صلی اللہ علیہ وسلم سے اجازت لے لوں ( اور میں نے اندر جا کر آپ سے عرض کیا ) آپ صلی اللہ علیہ وسلم نے فرمایا ان کو بھی اجازت دے اور بہشت کی خوشخبری بھی۔ خیر وہ بھی آئے اور اسی کنوئیں کی منڈیر پر نبی کریم صلی اللہ علیہ وسلم کے بائیں جانب بیٹھے اور اپنی پنڈلیاں کھول کر کنوئیں میں لٹکا دیں۔ اور کنوئیں کی منڈیر بھر گئی اور وہاں جگہ نہ رہی۔ پھر عثمان رضی اللہ عنہ آئے اور میں نے ان سے بھی کہا کہ یہیں رہئیے یہاں تک کہ آپ کے لیے نبی کریم صلی اللہ علیہ وسلم سے اجازت مانگ لوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں اجازت دو اور جنت کی بشارت دے دو اور اس کے ساتھ ایک آزمائش ہے جو انہیں پہنچے گی۔ پھر وہ بھی داخل ہوئے، ان کے ساتھ بیٹھنے کے لیے کوئی جگہ نہ تھی۔ چنانچہ وہ گھوم کر ان کے سامنے کنوئیں کے کنارے پر آ گئے پھر انہوں نے اپنی پنڈلیاں کھول کر کنوئیں میں پاؤں لٹکا لیے، پھر میرے دل میں بھائی ( غالباً ابوبردہ یا ابورہم ) کی تمنا پیدا ہوئی اور میں دعا کرنے لگا کہ وہ بھی آ جاتے، ابن المسیب نے بیان کیا کہ میں نے اس سے ان کی قبروں کی تعبیر لی کہ سب کی قبریں ایک جگہ ہوں گی لیکن عثمان رضی اللہ عنہ کی الگ بقیع غرقد میں ہے۔' WHERE id = 6833;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے واصل احدب نے، ان سے ابووائل نے اور ان سے حذیفہ بن الیمان نے بیان کیا کہ آج کل کے منافق نبی کریم صلی اللہ علیہ وسلم کے زمانے کے منافقین سے بدتر ہیں۔ اس وقت چھپاتے تھے اور آج اس کا کھلم کھلا اظہار کر رہے ہیں۔' WHERE id = 6845;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا کہا ہم سے وہیب نے کہا ہم سے ایوب سختیانی نے انہوں نے نافع سے انہوں نے ابن عمر رضی اللہ عنہما سے امام بخاری رحمہ اللہ نے کہا میں سمجھتا ہوں کہ ابن عمر رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم سے روایت کی آپ صلی اللہ علیہ وسلم نے فرمایا ”دجال داہنی آنکھ سے کانا ہو گا اس کی آنکھ کیا ہے گویا پھولا ہوا انگور۔“' WHERE id = 6855;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے نعیم بن عبداللہ بن المجمر نے بیان کیا، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مدینہ منورہ کے راستوں پر فرشتے پہرہ دیتے ہیں نہ یہاں طاعون آ سکتی ہے اور نہ دجال آ سکتا ہے۔“' WHERE id = 6865;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے حماد نے بیان کیا، ان سے جعد نے بیان کیا اور ان سے ابورجاء نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے اپنے امیر میں کوئی برا کام دیکھا تو اسے صبر کرنا چاہئے کیونکہ کوئی اگر جماعت سے ایک بالشت بھی جدا ہو تو وہ جاہلیت کی موت مرے گا۔“' WHERE id = 6875;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، انہوں نے کہا ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے سالم بن ابی الجعد نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے کہا کہ میں اور نبی کریم صلی اللہ علیہ وسلم مسجد سے نکل رہے تھے کہ ایک شخص مسجد کی چوکھٹ پر آ کر ہم سے ملا اور دریافت کیا: یا رسول اللہ! قیامت کب ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم نے قیامت کے لیے کیا تیاری کی ہے؟“ اس پر وہ شخص خاموش سا ہو گیا، پھر اس نے کہا: یا رسول اللہ! میں نے بہت زیادہ روزے، نماز اور صدقہ قیامت کے لیے نہیں تیار کئے ہیں لیکن میں اللہ اور اس کے رسول سے محبت رکھتا ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم اس کے ساتھ ہو گے جس سے تم محبت رکھتے ہو۔“' WHERE id = 6885;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہیں نمر کے بھانجے سائب بن یزید نے خبر دی، انہیں حویطب بن عبدالعزیٰ نے خبر دی، انہیں عبداللہ بن السعیدی نے خبر دی کہ وہ عمر رضی اللہ عنہ کے پاس ان کے زمانہ خلافت میں آئے تو ان سے عمر رضی اللہ عنہ نے پوچھا: کیا مجھ سے یہ جو کہا گیا ہے وہ صحیح ہے کہ تمہیں لوگوں کے کام سپرد کئے جاتے ہیں اور جب اس کی تنخواہ دی جاتی ہے تو تم اسے لینا پسند نہیں کرتے؟ میں نے کہا کہ یہ صحیح ہے۔ عمر رضی اللہ عنہ نے کہا کہ تمہارا اس سے مقصد کیا ہے؟ میں نے عرض کیا کہ میرے پاس گھوڑے اور غلام ہیں اور میں خوشحال ہوں اور میں چاہتا ہوں کہ میری تنخواہ مسلمانوں پر صدقہ ہو جائے۔ عمر رضی اللہ عنہ نے فرمایا کہ ایسا نہ کرو کیونکہ میں نے بھی اس کا ارادہ کیا تھا جس کا تم نے ارادہ کیا ہے نبی کریم صلی اللہ علیہ وسلم مجھے عطا کرتے تھے تو میں عرض کر دیتا تھا کہ اسے مجھ سے زیادہ اس کے ضرورت مند کو عطا فرما دیجئیے۔ آخر آپ نے ایک مرتبہ مجھے مال عطا کیا اور میں نے وہی بات دہرائی کہ اسے ایسے شخص کو دے دیجئیے جو اس کا مجھ سے زیادہ ضرورت مند ہو تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے لو اور اس کے مالک بننے کے بعد اس کا صدقہ کرو۔ یہ مال جب تمہیں اس طرح ملے کہ تم اس کے نہ خواہشمند ہو اور نہ اسے مانگا تو اسے لے لیا کرو اور اگر اس طرح نہ ملے تو اس کے پیچھے نہ پڑا کرو۔' WHERE id = 6895;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے سفیان نے، کہا مجھ سے منصور نے بیان کیا، ان سے ابوائل نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیدیوں کو چھڑاؤ اور دعوت کرنے والے کی دعوت قبول کرو۔“' WHERE id = 6905;
UPDATE hadiths SET urdu = 'ہم سے ابن نمیر نے بیان کیا، کہا ہم سے محمد بن بشر نے بیان کیا، کہا ہم سے اسماعیل نے بیان کیا، کہا ہم سے سلمہ بن کہیل نے بیان کیا، ان سے عطاء نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوا کہ آپ کے صحابہ میں سے ایک نے اپنے غلام کو مدبر بنا دیا ہے ( کہ ان کی موت کے بعد وہ آزاد ہو جائے گا ) چونکہ ان کے پاس اس کے سوا اور کوئی مال نہیں تھا اس لیے نبی کریم صلی اللہ علیہ وسلم نے اس غلام کو آٹھ سو درہم میں بیچ دیا اور اس کی قیمت انہیں بھیج دی۔' WHERE id = 6916;
UPDATE hadiths SET urdu = 'ہم سے اصبغ نے بیان کیا، کہا ہم کو ابن وہب نے خبر دی، انہیں یونس نے خبر دی، انہیں ابن شہاب نے، انہیں ابوسلمہ نے اور انہیں ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ نے جب بھی کوئی نبی بھیجا یا کسی کو خلیفہ بنایا تو اس کے ساتھ دو رفیق تھے ایک تو انہیں نیکی کے لیے کہتا اور اس پر ابھارتا اور دوسرا انہیں برائی کے لیے کہتا اور اس پر ابھارتا۔ پس معصوم وہ ہے جسے اللہ بچائے رکھے۔“ اور سلیمان بن بلال نے اس حدیث کو یحییٰ بن سعید انصاری سے روایت کیا، کہا مجھ کو ابن شہاب نے خبر دی ( اس کو اسماعیلی نے وصل کیا ) اور ابن ابی عتیق اور موسیٰ بن عقبہ سے بھی، ان دونوں نے ابن شہاب سے یہی حدیث ( اس کو بیہقی نے وصل کیا ) اور شعیب بن ابی حمزہ نے زہری سے یوں روایت کی، مجھ سے ابوسلمہ نے بیان کیا، انہوں نے ابو سعید خدری رضی اللہ عنہ سے ان کا قول ( یعنی حدیث کوث موقوفاً نقل کیا ) اور امام اوزاعی اور معاویہ بن سلام نے کہا، مجھ سے زہری نے بیان کیا، کہا مجھ سے ابوسلمہ بن عبدالرحمٰن نے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے اور عبداللہ بن عبدالرحمٰن بن ابی حسین اور سعید بن زیاد نے اس کو ابوسلمہ سے روایت کیا ‘، انہوں نے ابوسعید خدری رضی اللہ عنہ سے موقوفاً ( یعنی ابوسعید کا قول ) اور عبداللہ بن ابی جعفر نے کہا، مجھ سے صفوان بن سلیم نے بیان کیا، انہوں نے ابوسلمہ سے، انہوں نے ابوایوب سے، کہا میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا۔' WHERE id = 6927;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم سے ابوحمزہ محمد بن سیرین نے بیان کیا، ان سے اعمش نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تین آدمی ایسے ہیں جن سے اللہ تعالیٰ قیامت کے دن بات نہیں کرے گا اور نہ انہیں پاک کرے گا اور ان کے لیے بہت سخت دکھ دینے والا عذاب ہو گا۔ ایک وہ شخص جس کے پاس راستے میں زیادہ پانی ہو اور وہ مسافر کو اس میں سے نہ پلائے دوسرا وہ شخص جو امام سے بیعت کرے اور بیعت کی غرض صرف دنیا کمانا ہو اگر وہ امام اسے کچھ دنیا دیدے تو بیعت پوری کرے ورنہ توڑ دے۔ تیسرا وہ شخص جو کسی دوسرے سے کچھ مال متاع عصر کے بعد بیچ رہا ہو اور قسم کھائے کہ اسے اس سامان کی اتنی اتنی قیمت مل رہی تھی اور پھر خریدنے والا اسے سچا سمجھ کر اس مال کو لے لے حالانکہ اسے اس کی اتنی قیمت نہیں مل رہی تھی۔“' WHERE id = 6940;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اس ذات کی قسم جس کے ہاتھ میں میری جان ہے! میرا ارادہ ہوا کہ میں لکڑیوں کے جمع کرنے کا حکم دوں، پھر نماز کے لیے اذان دینے کا، پھر کسی سے کہوں کہ وہ لوگوں کو نماز پڑھائے اور میں اس کے بجائے ان لوگوں کے پاس جاؤں ( جو جماعت میں شریک نہیں ہوتے ) اور انہیں ان کے گھروں سمیت جلا دوں۔ قسم ہے اس ذات کی جس کے ہاتھ میں میری جان ہے کہ تم سے کسی کو اگر یہ امید ہو کہ وہاں موٹی ہڈی یا دو «مرماة حسنتين» بکری کے کھر کے درمیان کا گوشت ملے گا تو وہ ضرور ( نماز ) عشاء میں شریک ہو۔' WHERE id = 6951;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا ہم سے عبدہ نے بیان کیا، ان سے ابن ابی خالد نے، ان سے قیس نے بیان کیا کہ ہم خباب بن ارت رضی اللہ عنہ کی خدمت میں ان کی عبادت کے لیے حاضر ہوئے۔ انہوں نے سات داغ لگوائے تھے، پھر انہوں نے کہا کہ اگر رسول اللہ صلی اللہ علیہ وسلم نے ہمیں موت کی دعا کرنے سے منع نہ کیا ہوتا تو میں اس کی دعا کرتا۔' WHERE id = 6961;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہوں نے کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اگر ہجرت ( کی فضیلت ) نہ ہوتی تو میں انصار کا ایک فرد بننا ( پسند کرتا ) اور اگر دوسرے لوگ کسی وادی میں چلیں اور انصار ایک وادی یا گھاٹی میں چلیں تو میں انصار کی وادی یا گھاٹی میں چلوں گا۔“' WHERE id = 6971;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ بن حجاج نے بیان کیا، کہا ہم سے ابواسحاق نے، ان سے صلہ بن زفر نے اور ان سے حذیفہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے اہل نجران سے فرمایا ”میں تمہارے پاس ایک امانت دار آدمی جو حقیقی امانت دار ہو گا بھیجوں گا۔“ نبی کریم صلی اللہ علیہ وسلم کے صحابہ منتظر رہے ( کہ کون اس صفت سے موصوف ہے ) تو آپ نے ابوعبیدہ رضی اللہ عنہ کو بھیجا۔' WHERE id = 6981;
UPDATE hadiths SET urdu = 'ہم سے علی بن الجعد نے بیان کیا، کہا ہم کو شعبہ نے خبر دی (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ اور مجھ سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو نضر بن شمیل نے خبر دی، کہا ہم کو شعبہ نے خبر دی، ان سے ابوجمرہ نے بیان کیا کہ ابن عباس رضی اللہ عنہما مجھے خاص اپنے تخت پر بٹھا لیتے تھے۔ انہوں نے ایک بار بیان کیا کہ قبیلہ عبدالقیس کا وفد آیا جب وہ لوگ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پہنچے نبی کریم صلی اللہ علیہ وسلم نے پوچھا کس قوم کا وفد ہے؟ انہوں نے کہا کہ ربیعہ قبیلہ کا ( عبدالقیس اسی قبیلے کا ایک شاخ ہے ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مبارک ہو اس وفد کو یا یوں فرمایا کہ مبارک ہو بلا رسوائی اور شرمندگی اٹھائے آئے ہو۔ انہوں نے کہا: یا رسول اللہ! ہمارے اور آپ کے بیچ میں مضر کافروں کا ملک پڑتا ہے۔ آپ ہمیں ایسی بات کا حکم دیجئیے جس سے ہم جنت میں داخل ہوں اور پیچھے رہ جانے والوں کو بھی بتائیں۔ پھر انہوں نے شراب کے برتنوں کے متعلق پوچھا تو نبی کریم صلی اللہ علیہ وسلم نے انہیں چار چیزوں سے روکا اور چار چیزوں کا حکم دیا۔ آپ نے ایمان بااللہ کا حکم دیا۔ دریافت فرمایا جانتے ہو ایمان باللہ کیا چیز ہے؟ انہوں نے کہا کہ اللہ اور اس کا رسول زیادہ جانتے ہیں۔ فرمایا کہ گواہی دینا کہ اللہ کے سوا اور کوئی معبود نہیں اور محمد صلی اللہ علیہ وسلم اللہ کے رسول ہیں اور نماز قائم کرنے کا ( حکم دیا ) اور زکوٰۃ دینے کا۔ میرا خیال ہے کہ حدیث میں رمضان کے روزوں کا بھی ذکر ہے اور غنیمت میں سے پانچواں حصہ ( بیت المال ) میں دینا اور آپ نے انہیں دباء، حنتم، مزفت اور نقیر کے برتن ( جن میں عرب لوگ شراب رکھتے اور بناتے تھے ) کے استعمال سے منع کیا اور بعض اوقات مقیر کہا۔ فرمایا کہ انہیں یاد رکھو اور انہیں پہنچا دو جو نہیں آ سکے ہیں۔' WHERE id = 6992;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ میں نے اعمش سے پوچھا تو انہوں نے زید بن وہب سے بیان کیا کہ میں نے حذیفہ بن یمان رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ امانت داری آسمان سے بعض لوگوں کے دلوں کی جڑوں میں اتری، ( یعنی ان کی فطرت میں داخل ہے ) اور قرآن مجید نازل ہوا تو انہوں نے قرآن مجید کا مطلب سمجھا اور سنت کا علم حاصل کیا تو قرآن و حدیث دونوں سے اس ایمانداری کو جو فطرتی تھی پوری قوت مل گئی۔' WHERE id = 7002;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، انہوں نے کہا ہم کو عفان بن مسلم نے خبر دی، انہوں نے کہا ہم سے وہیب نے بیان کیا، کہا ہم سے موسیٰ ابن عقبہ نے بیان کیا، کہا میں نے ابوالنضر سے سنا، انہوں نے بسر بن سعید سے بیان کیا، ان سے زید بن ثابت رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے مسجد نبوی میں چٹائی سے گھیر کر ایک حجرہ بنا لیا اور رمضان کی راتوں میں اس کے اندر نماز پڑھنے لگے پھر اور لوگ بھی جمع ہو گئے تو ایک رات نبی کریم صلی اللہ علیہ وسلم کی آواز نہیں آئی۔ لوگوں نے سمجھا کہ نبی کریم صلی اللہ علیہ وسلم سو گئے ہیں۔ اس لیے ان میں سے بعض کھنگارنے لگے تاکہ آپ باہر تشریف لائیں، پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تم لوگوں کے کام سے واقف ہوں، یہاں تک کہ مجھے ڈر ہوا کہ کہیں تم پر یہ نماز تراویح فرض نہ کر دی جائے اور اگر فرض کر دی جائے تو تم اسے قائم نہیں رکھ سکو گے۔ پس اے لوگو! اپنے گھروں میں یہ نماز پڑھو کیونکہ فرض نماز کے سوا انسان کی سب سے افضل نماز اس کے گھر میں ہے۔' WHERE id = 7014;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے، کہا ہم سے اعمش نے بیان کیا، کہا مجھ سے ابراہیم تیمی نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا کہ علی رضی اللہ عنہ نے ہمیں اینٹ کے بنے ہوئے منبر کر کھڑا ہو کر خطبہ دیا۔ آپ تلوار لیے ہوئے تھے جس میں ایک صحیفہ لٹکا ہوا تھا۔ آپ نے فرمایا: واللہ! ہمارے پاس کتاب اللہ کے سوا کوئی اور کتاب نہیں جسے پڑھا جائے اور سوا اس صحیفہ کے۔ پھر انہوں نے اسے کھولا تو اس میں دیت میں دئیے جانے والے اونٹوں کی عمروں کا بیان تھا۔ ( کہ دیت میں اتنی اتنی عمر کے اونٹ دئیے جائیں ) اور اس میں یہ بھی تھا کہ مدینہ طیبہ کی زمین عیر پہاڑی سے ثور پہاڑی تک حرم ہے۔ پس اس میں جو کوئی نئی بات ( بدعت ) نکالے گا اس پر اللہ کی لعنت ہے اور فرشتوں کی اور تمام لوگوں کی۔ اللہ اس سے کسی فرض یا نفل عبادت کو قبول نہیں کرے گا اور اس میں یہ بھی تھا کہ مسلمانوں کی ذمہ داری ( عہد یا امان ) ایک ہے اس کا ذمہ دار ان میں سب سے ادنیٰ مسلمان بھی ہو سکتا ہے پس جس نے کسی مسلمان کا ذمہ توڑا، اس پر اللہ کی لعنت ہے اور فرشتوں کی اور تمام لوگوں کی۔ اللہ اس کی نہ فرض عبادت قبول کرے گا اور نہ نفل عبادت اور اس میں یہ بھی تھا کہ جس نے کسی سے اپنی والیوں کی اجازت کے بغیر ولاء کا رشتہ قائم کیا اس پر اور فرشتوں اور تمام انسانوں کی لعنت ہے، اللہ نہ اس کی فرض نماز قبول کرے گا نہ نفل۔' WHERE id = 7024;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے عبدالرحمٰن بن الاصبہانی نے، ان سے ابوصالح ذکوان نے اور ان سے ابوسعید رضی اللہ عنہ نے کہ ایک خاتون نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور کہا: یا رسول اللہ! آپ کی تمام احادیث مرد لے گئے، ہمارے لیے بھی آپ کوئی دن اپنی طرف سے مخصوص کر دیں جس میں ہم آپ کے پاس آئیں اور آپ ہمیں وہ تعلیمات دیں جو اللہ نے آپ کو سکھائی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ فلاں فلاں دن فلاں فلاں جگہ جمع ہو جاؤ۔ چنانچہ عورتیں جمع ہوئیں اور نبی کریم صلی اللہ علیہ وسلم ان کے پاس آئے اور انہیں اس کی تعلیم دی جو اللہ نے آپ صلی اللہ علیہ وسلم کو سکھایا تھا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا ”تم میں سے جو عورت بھی اپنی زندگی میں اپنے تین بچے آگے بھیج دے گی۔ ( یعنی ان کی وفات ہو جائے گی ) تو وہ اس کے لیے دوزخ سے رکاوٹ بن جائیں گے۔ اس پر ان میں سے ایک خاتون نے کہا: یا رسول اللہ! دو؟ انہوں نے اس کلمہ کو دو مرتب دہرایا، پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہاں دو، دو، دو بھی یہی درجہ رکھتے ہیں۔“' WHERE id = 7034;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا مجھ سے امام مالک نے بیان کیا، انہوں نے محمد بن منکدر سے، انہوں نے جابر بن عبداللہ انصاری رضی اللہ عنہ سے کہ ایک گنوار ( قیس بن ابی حازم یا قیس بن حازم یا اور کوئی ) نے نبی کریم صلی اللہ علیہ وسلم سے اسلام پر بیعت کی، پھر مدینہ میں اس کو تپ آنے لگی۔ وہ نبی کریم صلی اللہ علیہ وسلم کے پاس آیا۔ کہنے لگا: یا رسول اللہ! میری بیعت توڑ دیجئے۔ نبی کریم صلی اللہ علیہ وسلم نے انکار کیا۔ وہ پھر آیا اور کہنے لگا: یا رسول اللہ! میری بیعت فسخ کر دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے پھر انکار کیا۔ اس کے بعد وہ مدینہ سے نکل کر اپنے جنگل کو چلا گیا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مدینہ لوہار کی بھٹی کی طرح ہے جو اپنی میل کچیل کو دور کر دیتی ہے اور کھرے پاکیزہ مال کو رکھ لیتی ہے۔' WHERE id = 7045;
UPDATE hadiths SET urdu = 'ہم سے ابن ابی مریم نے بیان کیا، کہا ہم سے ابوغسان نے بیان کیا، کہا مجھ سے ابوحازم نے بیان کیا، ان سے سہل رضی اللہ عنہ نے کہ مسجد نبوی کی قبلہ کی طرف دیوار اور منبر کے درمیان بکریوں کے گزرنے جتنا فاصلہ تھا۔' WHERE id = 7056;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو معمر نے، انہیں زہری نے، انہیں سالم نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فجر کی نماز میں یہ دعا رکوع سے سر اٹھانے کے بعد پڑھتے تھے «اللهم ربنا ولك الحمد» ”اے اللہ! ہمارے رب تیرے ہی لیے تمام تعریفیں ہیں۔“ پھر آپ صلی اللہ علیہ وسلم نے فرمایا ”اے اللہ! فلاں اور فلاں کو اپنی رحمت سے دور کر دے۔“ اس پر اللہ عزوجل نے یہ آیت نازل کی کہ آپ کو اس معاملہ میں کوئی اختیار نہیں ہے اللہ! ان کی توبہ قبول کر لے یا انہیں عذاب دے کہ بلاشبہ وہ حد سے تجاوز کرنے والے ہیں۔' WHERE id = 7067;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ ام حفید بنت حارث بن حزن رضی اللہ عنہا نے رسول اللہ صلی اللہ علیہ وسلم کو گھی اور پنیر اور بھنا ہوا سانڈا ہدیہ میں بھیجا نبی کریم صلی اللہ علیہ وسلم نے یہ چیزیں قبول فرما لیں اور آپ کے دستر خوان پر انہیں کھایا گیا لیکن نبی کریم صلی اللہ علیہ وسلم نے اس ( سانڈے کو ) ہاتھ نہیں لگایا، جیسے آپ کو پسند نہ ہو اور اگر وہ حرام ہوتا تو آپ کے دستر خوان پر نہ کھایا جاتا اور نہ آپ کھانے کے لیے کہتے۔' WHERE id = 7078;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث بن سعید نے بیان کیا، ان سے حسین بن ذکوان معلم نے، ان سے عبیداللہ بن بریدہ نے، کہا مجھ سے عبداللہ بن مغفل مزنی نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مغرب کی نماز سے پہلے بھی نماز پڑھو اور تیسری مرتبہ میں فرمایا کہ جس کا جی چاہے کیونکہ آپ صلی اللہ علیہ وسلم پسند نہیں کرتے تھے کہ اسے لوگ لازمی سنت بنا لیں۔' WHERE id = 7088;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ نے، ان سے اعمش نے، ان سے سعید بن جبیر نے، ان سے ابوعبدالرحمٰن سلمی نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تکلیف دہ بات سن کر اللہ سے زیادہ صبر کرنے والا کوئی نہیں ہے، کم بخت مشرک کہتے ہیں کہ اللہ اولاد رکھتا ہے اور پھر بھی وہ انہیں معاف کرتا ہے اور انہیں روزی دیتا ہے۔“' WHERE id = 7098;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا ہم سے معن بن عیسیٰ نے بیان کیا، کہا مجھ سے عبدالرحمٰن بن ابی الموالی نے بیان کیا، کہا کہ میں نے محمد بن المنکدر سے سنا، وہ عبداللہ بن حسن سے بیان کرتے تھے، انہوں نے کہا کہ مجھے جابر بن عبداللہ سلمیٰ رضی اللہ عنہ نے خبر دی، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم اپنے صحابہ کو ہر مباح کام میں استخارہ کرنا سکھاتے تھے جس طرح آپ قرآن کی سورت سکھاتے تھے۔ آپ صلی اللہ علیہ وسلم فرماتے کہ جب تم میں سے کوئی کسی کام کا مقصد کرے تو اسے چاہئے کہ فرض کے سوا دو رکعت نفل نماز پڑھے، پھر سلام کے بعد یہ دعا کرے ”اے اللہ! میں تیرے علم کے طفیل اس کام میں خیریت طلب کرتا ہوں اور تیری قدرت کے طفیل طاقت مانگتا ہوں اور تیرا فضل۔ کیونکہ تجھے قدرت ہے اور مجھے نہیں ‘، تو جانتا ہے اور میں نہیں جانتا اور تو غیوب کا بہت جاننے والا ہے۔ اے اللہ! پس اگر تو یہ بات جانتا ہے ( اس وقت استخارہ کرنے والے کو اس کام کا نام لینا چاہئیے ) کہ اس کام میں میرے لیے دنیا و آخرت میں بھلائی ہے یا اس طرح فرمایا کہ ”میرے دین میں اور گزران میں اور میرے ہر انجام کے اعتبار سے بھلائی ہے تو اس پر مجھے قادر بنا دے اور میرے لیے اسے آسان کر دے، پھر اس میں میرے لیے برکت عطا فرما۔ اے اللہ! اور اگر تو جانتا ہے کہ یہ کام میرے لیے برا ہے۔ میرے دین اور گزراہ کے اعتبار سے اور میرے انجام کے اعتبار سے، یا فرمایا کہ میری دنیا و دین کے اعتبار سے تو مجھے اس کام سے دور کر دے اور میرے لیے بھلائی مقدر کر دے جہاں بھی وہ ہو اور پھر مجھے اس پر راضی اور خوش رکھ۔' WHERE id = 7109;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر حوضی نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے اسود بن قیس نے اور ان سے جندب رضی اللہ عنہ نے کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ذی الحجہ کی دسویں تاریخ کو موجود تھے آپ صلی اللہ علیہ وسلم نے نماز پڑھائی پھر خطبہ دیا اور فرمایا ”جس نے نماز سے پہلے جانور ذبح کر لیا تو اس کی جگہ دوسرا جانور ذبح کرے اور جس نے ذبح ابھی نہ کیا ہو تو وہ اللہ کا نام لے کر ذبح کرے۔“' WHERE id = 7119;
UPDATE hadiths SET urdu = 'مجھ سے معاذ بن فضالہ نے بیان کیا، کہا ہم سے ہشام دستوائی نے، انہوں نے قتادہ بن دعامہ سے، انہوں نے انس رضی اللہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ قیامت کے دن اسی طرح جیسے ہم دنیا میں جمع ہوتے ہیں، مومنوں کو اکٹھا کرے گا ( وہ گرمی وغیرہ سے پریشان ہو کر ) کہیں گے کاش ہم کسی کی سفارش اپنے مالک کے پاس لے جاتے تاکہ ہمیں اپنی اس حالت سے آرام ملتا۔ چنانچہ سب مل کر آدم علیہ السلام کے پاس آئیں گے۔ ان سے کہیں گے آدم! آپ لوگوں کا حال نہیں دیکھتے کس بلا میں گرفتار ہیں۔ آپ کو اللہ تعالیٰ نے ( خاص ) اپنے ہاتھ سے بنایا اور فرشتوں سے آپ کو سجدہ کرایا اور ہر چیز کے نام آپ کو بتلائے ( ہر لغت میں بولنا بات کرنا سکھلایا ) کچھ سفارش کیجئے تاکہ ہم لوگوں کو اس جگہ سے نجات ہو کر آرام ملے۔ کہیں گے میں اس لائق نہیں، ان کو وہ گناہ یاد آ جائے گا جو انہوں نے کیا تھا ( ممنوع درخت میں سے کھانا ) ۔ ( وہ کہیں گے ) مگر تم لوگ ایسا کرو نوح علیہ السلام پیغمبر کے پاس جاؤ وہ پہلے پیغمبر ہیں جن کو اللہ تعالیٰ نے زمین والوں کی طرف بھیجا تھا۔ آخر وہ لوگ سب نوح علیہ السلام کے پاس آئیں گے، وہ بھی یہی جواب دیں گے، میں اس لائق نہیں اپنی خطا جو انہوں نے ( دنیا میں ) کی تھی یاد کریں گے۔ کہیں گے تم لوگ ایسا کرو پیغمبر ابراہیم علیہ السلام کے پاس جاؤ جو اللہ کے خلیل ہیں ( لوگ ان کے پاس جائیں گے ) وہ بھی اپنی خطائیں یاد کر کے کہیں گے میں اس لائق نہیں تم موسیٰ علیہ السلام پیغمبر کے پاس جاؤ اللہ نے ان کو توراۃ عنائت فرمائی، ان سے بول کر باتیں کیں۔ یہ لوگ موسیٰ علیہ السلام کے پاس آئیں گے وہ بھی یہی کہیں گے میں اس لائق نہیں اپنی خطا جو انہوں نے دنیا میں کی تھی یاد کریں گے مگر تم ایسا کرو عیسیٰ علیہ السلام پیغمبر کے پاس جاؤ وہ اللہ کے بندے، اس کے رسول، اس کے خاص کلمہ اور خاص روح ہیں۔ یہ لوگ عیسیٰ علیہ السلام کے پاس آئیں گے وہ کہیں گے میں اس لائق نہیں تم ایسا کرو محمد صلی اللہ علیہ وسلم کے پاس جاؤ وہ اللہ کے ایسے بندے ہیں جن کی اگلی پچھلی خطائیں سب بخش دی گئی ہیں۔ آخر یہ سب لوگ جمع ہو کر میرے پاس آئیں گے۔ میں چلوں گا اور اپنے پروردگار کی بارگاہ میں حاضر ہونے کی اجازت مانگوں گا، مجھ کو اجازت ملے گی۔ میں اپنے پروردگار کو دیکھتے ہی سجدے میں گر پڑوں گا اور جب تک اس کو منظور ہے وہ مجھ کو سجدے ہی میں پڑا رہنے دے گا۔ اس کے بعد حکم ہو گا ”محمد صلی اللہ علیہ وسلم اپنا سر اٹھاؤ اور عرض کرو تمہاری عرض سنی جائے گی تمہاری درخواست منظور ہو گی، تمہاری سفارش مقبول ہو گی اس وقت میں اپنے مالک کی ایسی ایسی تعریفیں کروں گا جو وہ مجھ کو سکھا چکا ہے۔ ( یا سکھلائے گا ) پھر لوگوں کی سفارش شروع کر دوں گا۔ سفارش کی ایک حد مقرر کر دی جائے گی۔ میں ان کو بہشت میں لے جاؤں گا، پھر لوٹ کر اپنے پروردگار کے پاس حاضر ہوں گا اور اس کو دیکھتے ہی سجدے میں گر پڑوں گا جب تک پروردگار چاہے گا مجھ کو سجدے میں پڑا رہنے دے گا۔ اس کے بعد ارشاد ہو گا ”محمد اپنا سر اٹھاؤ جو تم کہو گے سنا جائے گا اور سفارش کرو گے تو قبول ہو گی پھر میں اپنے پروردگار کی ایسی تعریفیں کروں گا جو اللہ نے مجھ کو سکھلائیں ( یا سکھلائے گا ) اس کے بعد سفارش کر دوں گا لیکن سفارش کی ایک حد مقرر کر دی جائے گی۔ میں ان کو بہشت میں لے جاؤں گا پھر لوٹ کر اپنے پروردگار کے پاس حاضر ہوں گا اس کو دیکھتے ہی سجدے میں گر پڑوں گا جب تک پروردگار چاہے گا مجھ کو سجدے میں پڑا رہنے دیے گا۔ اس کے بعد ارشاد ہو گا محمد اپنا سر اٹھاؤ جو تم کہو گے سنا جائے گا اور سفارش کرو گے تو قبول ہو گی پھر میں اپنے پروردگار کی ایسی تعریفیں کروں گا جو اللہ نے مجھ کو سکھلائیں ( یا سکھلائے گا ) اس کے بعد سفارش شروع کر دوں گا لیکن سفارش کی ایک حد مقرر کر دی جائے گی۔ میں ان کو بہشت میں لے جاؤں گا پھر لوٹ کر اپنے پروردگار کے پاس حاضر ہوں گا۔ عرض کروں گا: یا پاک پروردگار! اب تو دوزخ میں ایسے ہی لوگ رہ گئے ہیں جو قرآن کے بموجب دوزخ ہی میں ہمیشہ رہنے کے لائق ہیں ( یعنی کافر اور مشرک ) ۔ انس رضی اللہ عنہ نے کہا نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دوزخ سے وہ لوگ نکال لیے جائیں گے جنہوں نے ( دنیا میں ) لا الہٰ الا اللہ کہا ہو گا اور ان کے دل میں ایک جَو برابر ایمان ہو گا پھر وہ لوگ بھی نکال لیے جائیں گے جنہوں نے لا الہٰ الا اللہ کہا ہو گا اور ان کے دل میں گیہوں برابر ایمان ہو گا۔ ( گیہوں جَو سے چھوٹا ہوتا ہے ) پھر وہ بھی نکال لیے جائیں گے جنہوں نے لا الہٰ الا اللہ کہا ہو گا اور ان کے دل میں چیونٹی برابر ( یا بھنگے برابر ) ایمان ہو گا۔' WHERE id = 7129;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہوں نے کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ نے جب مخلوق پیدا کی تو عرش کے اوپر اپنے پاس لکھ دیا کہ میری رحمت میرے غصہ سے بڑھ کر ہے۔“' WHERE id = 7140;
UPDATE hadiths SET urdu = 'ہم سے عمر بن عون نے بیان کیا، کہا ہم سے خالد اور ہشیم نے بیان کیا، ان سے اسماعیل نے، ان سے قیس نے اور ان سے جریر رضی اللہ عنہ نے کہ ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بیٹھے تھے کہ آپ نے چاند کی طرف دیکھا، چودھوریں رات کا چاند تھا اور فرمایا کہ تم لوگ اپنے رب کو اسی طرح دیکھو گے جس طرح اس چاند کو دیکھ رہے ہو اور اس کے دیکھنے میں کوئی دھکم پیل نہیں ہو گی۔ پس اگر تمہیں اس کی طاقت ہو کہ سورج طلوع ہونے کے پہلے اور سورج غروب ہونے کے بعد کی نمازوں میں سستی نہ ہو تو ایسا کر لو۔' WHERE id = 7151;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے کہا ہم سے عبدالملک بن اعین اور جامع بن ابی راشد نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس نے کسی مسلمان کا مال جھوٹی قسم کھا کر مار لیا تو وہ اللہ سے اس حال میں ملے گا کہ وہ اس پر غضبناک ہو گا۔“ عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے تصدیقاً قرآن مجید کی اس آیت کی تلاوت کی «إن الذين يشترون بعهد الله وأيمانهم ثمنا قليلا أولئك لا خلاق لهم في الآخرة ولا يكلمهم الله‏» ”بلاشبہ جو لوگ اللہ کے عہد اور اس کی قسموں کو تھوڑی پونجی کے بدلے بیچتے ہیں یہی وہ لوگ ہیں جن کا آخرت میں کوئی حصہ نہیں اور اللہ ان سے بات نہیں کرے گا۔“ آخر آیت تک۔' WHERE id = 7161;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے عمر بن زر نے بیان کیا، کہا ہم نے اپنے والد ذر بن عبداللہ سے سنا، وہ سعید بن جبیر سے بیان کرتے تھے اور وہ ابن عباس رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے جبرائیل! آپ کو ہمارے پاس اس سے زیادہ آنے میں کیا رکاوٹ ہے جتنا آپ آتے رہتے ہیں؟ اس پر یہ آیت نازل ہوئی «وما نتنزل إلا بأمر ربك له ما بين أيدينا وما خلفنا‏» ”اور ہم نازل نہیں ہوتے لیکن آپ کے رب کے حکم سے، اسی کا ہے وہ سب کچھ جو ہمارے سامنے ہے اور جو ہمارے پیچھے ہے“ الآیہ۔ بیان کیا کہ محمد صلی اللہ علیہ وسلم کو یہی جواب آیت میں اترا۔' WHERE id = 7171;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، (دوسری سند) اور ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا مجھ سے میرے بھائی عبدالحمید نے بیان کیا، ان سے سلیمان نے، ان سے محمد بن ابی عتیق نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے علی بن حسین نے بیان کیا، حسین بن علی رضی اللہ عنہ نے انہیں خبر دی اور نہیں علی بن ابی طالب رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ان کے اور فاطمہ رضی اللہ عنہا کے گھر رات میں تشریف لائے اور ان سے کہا کیا تم لوگ نماز تہجد نہیں پڑھتے۔ علی رضی اللہ عنہ نے کہا کہ میں نے عرض کیا: یا رسول اللہ! ہماری جانیں اللہ کے ہاتھ میں ہیں، جب وہ ہمیں اٹھانا چاہے گا اٹھا دے گا۔ جب میں نے یہ بات کہی تو نبی کریم صلی اللہ علیہ وسلم واپس چلے گے اور مجھے کوئی جواب نہیں دیا۔ البتہ میں نے آپ کو واپس جاتے وقت یہ کہتے سنا۔ آپ اپنی ران پر ہاتھ مار کر یہ فرما رہے تھے «وكان الإنسان أكثر شىء جدلا‏» کہ ”انسان بڑا ہی بحث کرنے والا ہے۔“' WHERE id = 7181;
UPDATE hadiths SET urdu = 'ہم سے یسرہ بن صفوان بن جمیل اللحمی نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے زہری نے، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میں سویا ہوا تھا کہ میں نے اپنے آپ کو ایک کنویں پر دیکھا۔ پھر میں نے جتنا اللہ تعالیٰ نے چاہا اس میں سے پانی نکالا۔ اس کے بعد ابوبکر بن ابی قحافہ رضی اللہ عنہ نے ڈول لے لیا اور انہوں نے بھی ایک دو ڈول پانی نکالا البتہ ان کے کھینچنے میں کمزوری تھی اور اللہ انہیں معاف کرے۔ پھر عمر رضی اللہ عنہ نے اسے لے لیا اور وہ ان کے ہاتھ میں ایک بڑا ڈول بن گیا۔ میں نے کسی قوی و بہادر کو اس طرح ڈول پر ڈول نکالتے نہیں دیکھا، یہاں تک کہ لوگوں نے ان کے چاروں طرف مویشیوں کے لیے باڑیں بنا لیں۔“' WHERE id = 7191;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، انہوں نے کہا ہم سے عبدالصمد نے بیان کے ‘، کہا ہم سے عبدالرحمٰن بن عبداللہ بن دینار نے بیان کیا، ان سے ان کے والد نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب اللہ تعالیٰ کسی بندہ سے محبت کرتا ہے تو جبرائیل علیہ السلام کو آواز دیتا ہے کہ اللہ فلاں سے محبت کرتا ہے تم بھی اس سے محبت کرو۔ چنانچہ جبرائیل علیہ السلام بھی اس سے محبت کرتے ہیں۔ پھر وہ آسمان میں آواز دیتے ہیں کہ اللہ فلاں سے محبت کرتا ہے تم بھی اس سے محبت کرو چنانچہ اہل آسمان بھی اس سے محبت کرنے لگتے ہیں اور اس طرح روئے زمین میں بھی اسے مقبولیت حاصل ہو جاتی ہے۔“' WHERE id = 7201;
UPDATE hadiths SET urdu = 'ہم سے زہیر بن حرب نے بیان کیا، کہا ہم سے محمد بن فضیل نے بیان کیا، ان سے عمارہ بن قعقاع نے، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ ( جبرائیل علیہ السلام نے کہا: یا رسول اللہ! ) یہ خدیجہ رضی اللہ عنہا جو آپ کے پاس برتن میں کھانا یا پانی لے کر آتی ہیں انہیں ان کے رب کی طرف سے سلام کہئیے اور انہیں خولدار موتی کے ایک محل کی جنت میں خوشخبری سنائیے جس میں نہ شور ہو گا اور نہ کوئی تکلیف ہو گی۔' WHERE id = 7212;
UPDATE hadiths SET urdu = 'ہم سے احمد بن اسحاق نے بیان کیا، انہوں نے کہا ہم سے عمرو بن عاصم نے بیان کیا، انہوں نے کہا ہم سے ہمام نے بیان کیا، انہوں نے ہم سے اسحاق بن عبداللہ نے، انہوں نے عبدالرحمٰن بن ابی عمرہ سے سنا، کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایک بندے نے بہت گناہ کئے اور کہا: اے میرے رب! میں تیرا ہی گنہگار بندہ ہوں تو مجھے بخش دے۔ اللہ رب العزت نے فرمایا: میرا بندہ جانتا ہے کہ اس کا کوئی رب ضرور ہے جو گناہ معاف کرتا ہے اور گناہ کی وجہ سے سزا بھی دیتا ہے میں نے اپنے بندے کو بخش دیا پھر بندہ رکا رہا جتنا اللہ نے چاہا اور پھر اس نے گناہ کیا اور عرض کیا: اے میرے رب! میں نے دوبارہ گناہ کر لیا، اسے بھی بخش دے۔ اللہ تعالیٰ نے فرمایا: میرا بندہ جانتا ہے کہ اس کا رب ضرور ہے جو گناہ معاف کرتا ہے اور اس کے بدلے میں سزا بھی دیتا ہے، میں نے اپنے بندے کو بخش دیا۔ پھر جب تک اللہ نے چاہا بندہ گناہ سے رکا رہا اور پھر اس نے گناہ کیا اور اللہ کے حضور میں عرض کیا: اے میرے رب! میں نے گناہ پھر کر لیا ہے تو مجھے بخش دے۔ اللہ تعالیٰ نے فرمایا میرا بندہ جانتا ہے کہ اس کا ایک رب ضرور ہے جو گناہ معاف کرتا ورنہ اس کی وجہ سی سزا بھی دیتا ہے میں نے اپنے بندے کو بخش دیا۔ تین مرتبہ، پس اب جو چاہے عمل کرے۔' WHERE id = 7222;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، انہوں نے کہا مجھ سے سلیمان بن بلال نے بیان کیا، ان سے شریک بن عبداللہ بن ابی نے بیان کیا، انہوں نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا انہوں نے وہ واقعہ بیان کیا جس رات رسول اللہ صلی اللہ علیہ وسلم کو مسجد کعبہ سے معراج کے لیے لے جایا گیا کہ وحی آنے سے پہلے آپ کے پاس فرشتے آئے۔ نبی کریم صلی اللہ علیہ وسلم مسجد الحرام میں سوئے ہوئے تھے۔ ان میں سے ایک نے پوچھا کہ وہ کون ہیں؟ دوسرے نے جواب دیا کہ وہ ان میں سب سے بہتر ہیں تیسرے نے کہا کہ ان میں جو سب سے بہتر ہیں انہیں لے لو۔ اس رات کو بس اتنا ہی واقعہ پیش آیا اور نبی کریم صلی اللہ علیہ وسلم نے اس کے بعد انہیں نہیں دیکھا۔ یہاں تک کہ وہ دوسری رات آئے جب کہ آپ کا دل دیکھ رہا تھا اور آپ کی آنکھیں سو رہی تھیں۔ لیکن دل نہیں سو رہا تھا۔ انبیاء کا یہی حال ہوتا ہے۔ ان کی آنکھیں سوتی ہیں لیکن ان کے دل نہیں سوتے۔ چنانچہ انہوں نے آپ سے بات نہیں کی۔ بلکہ آپ کو اٹھا کر زمزم کے کنویں کے پاس لائے۔ یہاں جبرائیل علیہ السلام نے آپ کا کام سنبھالا اور آپ کے گلے سے دل کے نیچے تک سینہ چاک کیا اور سینے اور پیٹ کو پاک کر کے زمزم کے پانی سے اسے اپنے ہاتھ سے دھویا یہاں تک کہ آپ کا پیٹ صاف ہو گیا۔ پھر آپ کے پاس سونے کا طشت لایا گیا جس میں سونے کا ایک برتن ایمان و حکمت سے بھرا ہوا تھا۔ اس سے آپ کے سینے اور حلق کی رگوں کو سیا اور اسے برابر کر دیا۔ پھر آپ کو لے کر آسمان دنیا پر چڑھے اور اس کے دروازوں میں سے ایک دروازے پر دستک دی۔ آسمان والوں نے ان سے پوچھا آپ کون ہیں؟ انہوں نے کہا کہ جبرائیل انہوں نے پوچھا اور آپ کے ساتھ کون ہے؟ جواب دیا کہ میرے ساتھ محمد صلی اللہ علیہ وسلم ہیں۔ پوچھا: کیا انہیں بلایا گیا ہے؟ جواب دیا کہ ہاں۔ آسمان والوں نے کہا خوب اچھے آئے اور اپنے ہی لوگوں میں آئے ہو۔ آسمان والے اس سے خوش ہوئے۔ ان میں سے کسی کو معلوم نہیں ہوتا کہ اللہ تعالیٰ زمین میں کیا کرنا چاہتا ہے جب تک وہ انہیں بتا نہ دے۔ نبی کریم صلی اللہ علیہ وسلم نے آسمان دنیا پر آدم علیہ السلام کو پایا۔ جبرائیل علیہ السلام نے آپ سے کہا کہ یہ آپ کے بزرگ ترین دادا آدم ہیں آپ انہیں سلام کیجئے۔ آدم علیہ السلام نے سلام کا جواب دیا۔ کہا کہ خوب اچھے آئے اور اپنے ہی لوگوں میں آئے ہو۔ مبارک ہو اپنے بیٹے کو، آپ کیا ہی اچھے بیٹے ہیں۔ آپ نے آسمان دنیا میں دو نہریں دیکھیں جو بہہ رہی تھیں۔ پوچھا اے جبرائیل! یہ نہریں کیسی ہیں؟ جبرائیل علیہ السلام نے جواب دیا کہ یہ نیل اور فرات کا منبع ہے۔ پھر آپ آسمان پر اور چلے تو دیکھا کہ ایک دوسری نہر ہے جس کے اوپر موتی اور زبرجد کا محل ہے۔ اس پر اپنا ہاتھ مارا تو وہ مشک ہے۔ پوچھا: جبرائیل! یہ کیا ہے؟ جواب دیا کہ یہ کوثر ہے جسے اللہ نے آپ کے لیے محفوظ رکھا ہے۔ پھر آپ دوسرے آسمان پر چڑھے۔ فرشتوں نے یہاں بھی وہی سوال کیا جو پہلے آسمان پر کیا تھا۔ کون ہیں؟ کہا: جبرائیل۔ پوچھا آپ کے ساتھ کون ہیں؟ کہا محمد صلی اللہ علیہ وسلم ۔ پوچھا کیا انہیں بلایا گیا ہے؟ انہوں نے کہا کہ ہاں۔ فرشتے بولے انہیں مرحبا اور بشارت ہو۔ پھر آپ کو لے کر تیسرے آسمان پر چڑھے اور یہاں بھی وہی سوال کیا جو پہلے اور دوسرے آسمان پر کیا تھا۔ پھر چوتھے آسمان پر لے کر چڑھے اور یہاں بھی وہی سوال کیا۔ پھر پانچویں آسمان پر آپ کو لے کر چڑھے اور یہاں بھی وہی سوال کیا پھر چھٹے آسمان پر آپ کو لے کر چڑھے اور یہاں بھی وہی سوال کیا۔ پھر آپ کو لے کر ساتویں آسمان پر چڑھے اور یہاں بھی وہی سوال کیا۔ ہر آسمان پر انبیاء ہیں جن کے نام آپ نے لیے۔ مجھے یہ یاد ہے کہ ادریس علیہ السلام دوسرے آسمان پر، ہارون علیہ السلام چوتھے آسمان پر، اور دوسرے نبی پانچویں آسمان پر۔ جن کے نام مجھے یاد نہیں اور ابراہیم علیہ السلام چھٹے آسمان پر اور موسیٰ علیہ السلام ساتویں آسمان پر۔ یہ انہیں اللہ تعالیٰ نے شرف ہم کلامی کی وجہ سے فضیلت ملی تھی۔ موسیٰ علیہ السلام نے کہا: میرے رب! میرا خیال نہیں تھا کہ کسی کو مجھ سے بڑھایا جائے گا۔ پھر جبرائیل علیہ السلام انہیں لے کر اس سے بھی اوپر گئے جس کا علم اللہ کے سوا اور کسی کو نہیں یہاں تک کہ آپ کو سدرۃ المنتہیٰ پر لے کر آئے اور رب العزت اللہ تبارک وتعالیٰ سے قریب ہوئے اور اتنے قریب جیسے کمان کے دونوں کنارے یا اس سے بھی قریب۔ پھر اللہ نے اور دوسری باتوں کے ساتھ آپ کی امت پر دن اور رات میں پچاس نمازوں کی وحی کی۔ پھر آپ اترے اور جب موسیٰ علیہ السلام کے پاس پہنچے تو انہوں نے آپ کو روک لیا اور پوچھا: اے محمد! آپ کے رب نے آپ سے کیا عہد لیا ہے؟ فرمایا کہ میرے رب نے مجھ سے دن اور رات میں پچاس نمازوں کا عہد لیا ہے۔ موسیٰ علیہ السلام نے فرمایا کہ آپ کی امت میں اس کی طاقت نہیں۔ واپس جائیے اور اپنی اور اپنی امت کی طرف سے کمی کی درخواست کیجئے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم جبرائیل علیہ السلام کی طرف متوجہ ہوئے اور انہوں نے بھی اشارہ کیا کہ ہاں اگر چاہیں تو بہتر ہے۔ چنانچہ آپ پھر انہیں لے کر اللہ تعالیٰ کی بارگاہ میں حاضر ہوئے اور اپنے مقام پر کھڑے ہو کر عرض کیا: اے رب! ہم سے کمی کر دے کیونکہ میری امت اس کی طاقت نہیں رکھتی۔ چنانچہ اللہ تعالیٰ نے دس نمازوں کی کمی کر دی۔ پھر آپ موسیٰ علیہ السلام کے پاس آئے تو انہوں نے آپ کو روکا۔ موسیٰ علیہ السلام آپ کو اسی طرح برابر اللہ رب العزت کے پاس واپس کرتے رہے۔ یہاں تک کہ پانچ نمازیں ہو گئیں۔ پانچ نمازوں پر بھی انہوں نے نبی کریم صلی اللہ علیہ وسلم کو روکا اور کہا: اے محمد! میں نے اپنی قوم بنی اسرائیل کا تجربہ اس سے کم پر کیا ہے وہ ناتواں ثابت ہوئے اور انہوں نے چھوڑ دیا۔ آپ کی امت تو جسم، دل، بدن، نظر اور کان ہر اعتبار سے کمزور ہے، آپ واپس جائیے اور اللہ رب العزت اس میں بھی کمی کر دے گا۔ ہر مرتبہ نبی کریم صلی اللہ علیہ وسلم جبرائیل علیہ السلام کی طرف متوجہ ہوتے تھے تاکہ ان سے مشورہ لیں اور جبرائیل علیہ السلام اسے ناپسند نہیں کرتے تھے۔ جب وہ آپ کو پانچویں مرتبہ بھی لے گئے تو عرض کیا: اے میرے رب! میری امت جسم، دل، نگاہ اور بند ہر حیثیت سے کمزور ہے، پس ہم سے اور کمی کر دے۔ اللہ تعالیٰ نے اس پر فرمایا کہ وہ قول میرے یہاں بدلا نہیں جاتا جیسا کہ میں نے تم پر ام الکتاب میں فرض کیا ہے۔ اور فرمایا کہ ہر نیکی کا ثواب دس گناہ ہے پس یہ ام الکتاب میں پچاس نمازیں ہیں لیکن تم پر فرض پانچ ہی ہیں۔ چنانچہ آپ موسیٰ علیہ السلام کے پاس واپس آئے اور انہوں نے پوچھا: کیا ہوا؟ آپ نے کہا کہ ہم سے یہ تخفیف کی کہ ہر نیکی کے بدلے دس کا ثواب ملے گا۔ موسیٰ علیہ السلام نے کہا کہ میں نے بنی اسرائیل کو اس سے کم پر آزمایا ہے اور انہوں نے چھوڑ دیا۔ پس آپ واپس جائیے اور مزید کمی کرائیے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر کہا: اے موسیٰ، واللہ! مجھے اپنے رب سے اب شرم آتی ہے کیونکہ باربار آ جا چکا ہوں۔ انہوں نے کہا کہ پھر اللہ کا نام لے کر اتر جاؤ۔ پھر جب آپ بیدار ہوئے تو مسجد الحرام میں تھے۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم مسجد الحرام ہی میں تھے کہ جاگ اٹھے، جاگ اٹھنے سے یہ مراد ہے کہ وہ حالت معراج کی جاتی رہی اور آپ اپنی حالت میں آ گئے۔' WHERE id = 7232;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے ابوعاصم نے، کہا ہم کو ابن جریج نے خبر دی، کہا ہم کو ابن شہاب نے خبر دی، انہیں ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو خوش آوازی سے قرآن نہیں پڑھتا وہ ہم مسلمانوں کے طریق پر نہیں ہے۔“ اور ابوہریرہ رضی اللہ عنہ کے سوا دوسرے لوگوں نے اس حدیث میں اتنا زیادہ کیا ہے یعنی اس کو پکار کر نہ پڑھے۔' WHERE id = 7242;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے (دوسری سند) اور امام بخاری رحمہ اللہ نے کہا کہ مجھ سے خلفیہ بن خیاط نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، ان سے سعید نے، ان سے قتادہ نے، ان سے ابوالعالیہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے پروردگار سے روایت کیا پروردگار نے فرمایا کہ کسی بندے کے لیے مناسب نہیں کہ یہ کہے کہ میں یونس بن متی علیہ السلام سے بہتر ہوں اور آپ نے یونس علیہ السلام کو ان کے باپ کی طرف نسبت دی۔' WHERE id = 7254;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے منصور نے، ان سے ان کی والدہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اس وقت بھی قرآن پڑھتے تھے جب آپ کا سر مبارک میری گود میں ہوتا اور میں حالت حیض میں ہوتی۔' WHERE id = 7264;
